"use strict";(self.webpackChunkarmeria_site=self.webpackChunkarmeria_site||[]).push([["2207"],{58693(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"/2021/07/15/customizing-armeria-metrics","metadata":{"permalink":"/blog/ko/2021/07/15/customizing-armeria-metrics","editUrl":"https://github.com/line/armeria/edit/main/site-new/src/content/blog/ko/2021-07-15-customizing-armeria-metrics.mdx","source":"@site/src/content/blog/ko/2021-07-15-customizing-armeria-metrics.mdx","title":"Armeria \uC9C0\uD45C \uCEE4\uC2A4\uD130\uB9C8\uC774\uC9D5\uD558\uAE30","description":"\uC2DC\uC791\uD558\uBA70","date":"2021-07-15T00:00:00.000Z","tags":[],"readingTime":5.1,"hasTruncateMarker":true,"authors":[{"name":"\uC8FC\uC2B9\uD658","title":"LINE\uC5D0\uC11C OpenChat \uC11C\uBE44\uC2A4\uC758 \uBC31\uC5D4\uB4DC \uAC1C\uBC1C\uC744 \uB2F4\uB2F9\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4.","imageURL":"/img/author-seunghwanjoo.jpeg","key":"seunghwanjoo","page":null}],"frontMatter":{"authors":["seunghwanjoo"],"other_languages":{"en":"/blog/2021/08/04/customizing-armeria-metrics"}},"unlisted":false,"nextItem":{"title":"Armeria\uC5D0\uC11C Prometheus \uC9C0\uD45C \uBAA8\uB2C8\uD130\uB9C1\uD558\uAE30","permalink":"/blog/ko/2021/06/28/monitoring-prometheus-metrics-from-armeria"}},"content":"## \uC2DC\uC791\uD558\uBA70\\n\\n\uC774\uC804 \uAE00 [Armeria\uC5D0\uC11C Prometheus \uC9C0\uD45C \uBAA8\uB2C8\uD130\uB9C1\uD558\uAE30](/blog/ko/2021/06/28/monitoring-prometheus-metrics-from-armeria)\uC5D0\uC11C Armeria \uC9C0\uD45C\uB97C Grafana\uB85C \uBAA8\uB2C8\uD130\uB9C1\uD558\uB294 \uBC29\uBC95\uC744 \uC0B4\uD3B4\uBD24\uC2B5\uB2C8\uB2E4.\\n\uC774\uBC88 \uAE00\uC5D0\uB294 Armeria\uC5D0\uC11C \uD544\uC694\uC5D0 \uB530\uB77C \uC9C0\uD45C\uB97C \uCEE4\uC2A4\uD130\uB9C8\uC774\uC9D5\uD558\uB294 \uBC29\uBC95\uC744 \uC54C\uC544\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n{/* truncate */}\\n\\n> \uC774\uBC88 \uAE00\uC5D0\uC11C \uC0AC\uC6A9\uD55C \uCF54\uB4DC\uB294 [Armeria\uC5D0\uC11C Prometheus \uC9C0\uD45C \uBAA8\uB2C8\uD130\uB9C1\uD558\uAE30](/blog/ko/2021/06/28/monitoring-prometheus-metrics-from-armeria) \uAE00\uC758 \uC608\uC81C \uCF54\uB4DC\uB97C \uC7AC\uC0AC\uC6A9\uD588\uC2B5\uB2C8\uB2E4.\\n\\n## MeterIdPrefixFunction \uC774\uC6A9\uD574 \uC9C0\uD45C \uD504\uB9AC\uD53D\uC2A4 \uC774\uB984 \uCEE4\uC2A4\uD130\uB9C8\uC774\uC9D5\uD558\uAE30\\n\\n\uC774\uC804 \uAE00\uC5D0\uC11C `MeterIdPrefixFunction#ofDefault` \uD568\uC218\uB97C \uC774\uC6A9\uD574 \uC9C0\uD45C\uC758 \uAE30\uBCF8 \uD504\uB9AC\uD53D\uC2A4 \uC774\uB984\uC744 \uC124\uC815\uD560 \uC218 \uC788\uB2E4\uB294 \uAC83\uC744 \uB9D0\uC500\uB4DC\uB838\uB294\uB370\uC694. \uC774\uB54C `MeterIdPrefixFunction#andThen` \uD568\uC218\uB97C \uC774\uC6A9\uD558\uBA74 \uC774 \uD504\uB9AC\uD53D\uC2A4 \uC774\uB984\uC744 \uB354\uC6B1 \uB2E4\uC591\uD558\uAC8C \uCEE4\uC2A4\uD130\uB9C8\uC774\uC9D5\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\nHTTP \uBA54\uC11C\uB4DC \uC774\uB984\uC744 \uBA54\uD2B8\uB9AD\uC758 \uD504\uB9AC\uD53D\uC2A4 \uC774\uB984\uC73C\uB85C \uCD94\uAC00\uD558\uACE0 \uC2F6\uB2E4\uACE0 \uAC00\uC815\uD574\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n- AS-IS: `my_http_service`\\n- TO-BE: `my_http_service_{HTTP method}`\\n\\n\uBA3C\uC800 `MeterIdPrefixFunctionCustomizer`\uB97C \uAD6C\uD604\uD55C \uD074\uB798\uC2A4\uB97C \uC0DD\uC131\uD574\uC57C \uD569\uB2C8\uB2E4. `MeterIdPrefixFunctionCustomizer#apply` \uD568\uC218 \uC548\uC5D0\uC11C \uAE30\uC874 `MeterIdPrefix`\uC5D0 HTTP \uBA54\uC11C\uB4DC \uC774\uB984\uC744 \uCD94\uAC00\uD558\uB3C4\uB85D \uAD6C\uD604\uD588\uC2B5\uB2C8\uB2E4.\\n\\n\uC774\uB54C [RequestLog#requestHeaders](<https://javadoc.io/doc/com.linecorp.armeria/armeria-javadoc/1.8.0/com/linecorp/armeria/common/logging/RequestOnlyLog.html#requestHeaders()>)\uB97C \uD1B5\uD574 \uC694\uCCAD HTTP \uBA54\uC11C\uB4DC \uC774\uB984\uC744 \uAC00\uC838\uC62C \uC218 \uC788\uC2B5\uB2C8\uB2E4. [RequestLog](https://javadoc.io/doc/com.linecorp.armeria/armeria-javadoc/1.8.0/com/linecorp/armeria/common/logging/RequestLog.html)\uC5D0\uB294 \uC774\uC678\uC5D0\uB3C4 \uD558\uB098\uC758 \uC694\uCCAD\uC744 \uCC98\uB9AC\uD558\uBA74\uC11C \uBC1C\uC0DD\uD558\uB294 \uB2E4\uC591\uD55C \uC815\uBCF4\uB4E4\uC774 \uC218\uC9D1\uB418\uB294\uB370\uC694. \uC790\uC138\uD55C \uB0B4\uC6A9\uC740 [Armeria \uACF5\uC2DD \uBE14\uB85C\uADF8](https://armeria.dev/docs/advanced-structured-logging/)\uC5D0\uC11C \uD655\uC778\uD558\uC2E4 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n```java title=\\"MeterIdPrefixFunctionCustomizer.java\\"\\npublic class MyMeterIdPrefixFunction implements MeterIdPrefixFunctionCustomizer {\\n\\n    @Override\\n    public MeterIdPrefix apply(MeterRegistry registry, RequestOnlyLog log, MeterIdPrefix meterIdPrefix) {\\n        return meterIdPrefix.append(log.requestHeaders().method().name());\\n    }\\n}\\n```\\n\\n\uB2E4\uC74C\uC73C\uB85C `MeterIdPrefixFunction#andThen` \uD568\uC218\uB85C \uC774 \uD074\uB798\uC2A4\uC758 \uC778\uC2A4\uD134\uC2A4\uB97C \uB123\uC2B5\uB2C8\uB2E4.\\n\\n```java title=\\"ArmeriaPrometheusApplication.java\\"\\nServerBuilder sb = Server.builder();\\n                         .http(8083)\\n                         .meterRegistry(meterRegistry);\\nsb.annotatedService(...);\\nsb.service(\\"/metrics\\", ...);\\nsb.decorator(MetricCollectingService.builder(MeterIdPrefixFunction.ofDefault(\\"my.http.service\\")\\n                                                                  // \uCD94\uAC00\\n                                                                  .andThen(new MyMeterIdPrefixFunction()))\\n                                                                  .newDecorator());\\nServer server = sb.build();\\n// ... \uC0DD\uB7B5 ...\\n```\\n\\n\uC11C\uBC84\uB97C \uC7AC\uAE30\uB3D9\uD55C \uB4A4 \uC0B4\uD3B4\uBCF4\uBA74 \uC9C0\uD45C \uC774\uB984\uC5D0 HTTP \uBA54\uC11C\uB4DC \uC774\uB984\uC774 \uC798 \uCD94\uAC00\uB41C \uAC83\uC744 \uD655\uC778\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n```\\n$ curl -s http://localhost:8083/metrics | grep \\"my_http_service_\\"\\n# HELP my_http_service_GET_timeouts_total\\n# TYPE my_http_service_GET_timeouts_total counter\\nmy_http_service_GET_timeouts_total{cause=\\"RequestTimeoutException\\",hostname_pattern=\\"*\\",http_status=\\"500\\",method=\\"hello\\",service=\\"com.example.armeria_prometheus.MyAnnotatedService\\",} 0.0\\nmy_http_service_GET_timeouts_total{cause=\\"RequestTimeoutException\\",hostname_pattern=\\"*\\",http_status=\\"200\\",method=\\"hello\\",service=\\"com.example.armeria_prometheus.MyAnnotatedService\\",} 0.0\\n# HELP my_http_service_GET_active_requests\\n# TYPE my_http_service_GET_active_requests gauge\\nmy_http_service_GET_active_requests{hostname_pattern=\\"*\\",method=\\"hello\\",service=\\"com.example.armeria_prometheus.MyAnnotatedService\\",} 0.0\\n...\\n```\\n\\n\uB2E4\uB978 \uBC29\uBC95\uC73C\uB85C, \uC544\uB798\uC640 \uAC19\uC774 Java 8\uBD80\uD130 \uC9C0\uC6D0\uB418\uB294 \uB78C\uB2E4(lambda) \uD45C\uD604\uC2DD\uC744 \uC774\uC6A9\uD574 \uBC14\uB85C \uCD94\uAC00\uD560 \uC218\uB3C4 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n```java title=\\"ArmeriaPrometheusApplication.java\\"\\nMeterIdPrefixFunction.ofDefault(\\"my.http.service\\")\\n                     .andThen((registry, log, prefix) -> prefix.append(log.requestHeaders().method().name())))\\n```\\n\\n## HTTP API \uC751\uB2F5 \uC131\uACF5 \uAE30\uC900 \uCEE4\uC2A4\uD130\uB9C8\uC774\uC9D5\uD558\uAE30\\n\\nArmeria\uC5D0\uC11C\uB294 \uAE30\uBCF8\uC801\uC73C\uB85C HTTP API\uC758 \uC751\uB2F5 \uC0C1\uD0DC \uCF54\uB4DC\uAC00 100\uBCF4\uB2E4 \uC791\uAC70\uB098, 400\uBCF4\uB2E4 \uD06C\uAC70\uB098 \uAC19\uC740 \uACBD\uC6B0\uC5D0 \uC2E4\uD328\uB85C \uAC04\uC8FC\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uC774\uB54C `MetricCollectingServiceBuilder#successFunction`\uB97C \uC774\uC6A9\uD558\uBA74, \uC751\uB2F5 \uC131\uACF5\uACFC \uC2E4\uD328\uC758 \uAE30\uC900\uC744 \uB0B4\uAC00 \uC6D0\uD558\uB294 \uB300\uB85C \uC7AC\uC815\uC758\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n\uBA3C\uC800 API\uC5D0\uC11C 404 \uC0C1\uD0DC \uCF54\uB4DC\uB85C \uC751\uB2F5\uD55C \uC0C1\uD669\uC744 \uAC00\uC815\uD574 \uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n```java title=\\"MyAnnotatedService.java\\"\\npublic class MyAnnotatedService {\\n\\n    @Get(\\"/hello/{seq}\\")\\n    public HttpResponse hello(@Param(\\"seq\\") int seq) {\\n        if (seq % 5 == 0) {\\n            return HttpResponse.of(HttpStatus.NOT_FOUND);\\n        }\\n        // ... \uC0DD\uB7B5 ...\\n    }\\n}\\n```\\n\\n```\\n$ curl http://localhost:8083/hello/5\\n404 Not Found\\n\\n$ curl -s http://localhost:8083/metrics | grep \\"my_http_service_GET_requests_total\\" | grep \\"404\\"\\nmy_http_service_GET_requests_total{hostname_pattern=\\"*\\",http_status=\\"404\\",method=\\"hello\\",result=\\"success\\",service=\\"com.example.armeria_prometheus.MyAnnotatedService\\",} 0.0\\nmy_http_service_GET_requests_total{hostname_pattern=\\"*\\",http_status=\\"404\\",method=\\"hello\\",result=\\"failure\\",service=\\"com.example.armeria_prometheus.MyAnnotatedService\\",} 1.0\\n```\\n\\n\uB9CC\uC57D 404 \uC0C1\uD0DC \uCF54\uB4DC\uB97C \uC2E4\uD328\uAC00 \uC544\uB2CC \uC131\uACF5\uC73C\uB85C \uCC98\uB9AC\uD558\uACE0 \uC2F6\uB2E4\uBA74, [RequestLog#responseHeaders](<https://javadoc.io/static/com.linecorp.armeria/armeria-javadoc/1.8.0/com/linecorp/armeria/common/logging/RequestLog.html#responseHeaders()>)\uC5D0\uC11C HTTP \uC0C1\uD0DC\uB97C \uAC00\uC838\uC640\uC11C \uC544\uB798\uC640 \uAC19\uC774 `MetricCollectingServiceBuilder#successFunction`\uC744 \uAD6C\uD604\uD558\uBA74 \uB429\uB2C8\uB2E4.\\n\\n```java title=\\"ArmeriaPrometheusApplication.java\\"\\n// ... \uC0DD\uB7B5 ...\\nsb.decorator(MetricCollectingService.builder(MeterIdPrefixFunction.ofDefault(\\"my.http.service\\")\\n                                                                  .andThen(new MyMeterIdPrefixFunction()))\\n                                     // \uCD94\uAC00\\n                                     .successFunction((context, log) -> {\\n                                        final int statusCode = log.responseHeaders().status().code();\\n                                        return (statusCode >= 200 && statusCode < 400) || statusCode == 404;\\n                                     })\\n                                     .newDecorator());\\n// ... \uC0DD\uB7B5 ...\\n```\\n\\n\uAD6C\uD604 \uD6C4 \uD14C\uC2A4\uD2B8\uD55C \uACB0\uACFC 404 \uC0C1\uD0DC \uCF54\uB4DC\uB3C4 \uC131\uACF5(success)\uC73C\uB85C \uC9D1\uACC4\uB41C \uAC83\uC744 \uD655\uC778\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n```\\n$ curl -s http://localhost:8083/metrics | grep \\"my_http_service_GET_requests_total\\" | grep \\"404\\"\\nmy_http_service_GET_requests_total{hostname_pattern=\\"*\\",http_status=\\"404\\",method=\\"hello\\",result=\\"success\\",service=\\"com.example.armeria_prometheus.MyAnnotatedService\\",} 1.0\\nmy_http_service_GET_requests_total{hostname_pattern=\\"*\\",http_status=\\"404\\",method=\\"hello\\",result=\\"failure\\",service=\\"com.example.armeria_prometheus.MyAnnotatedService\\",} 0.0\\n```\\n\\n## \uC9C0\uD45C \uD544\uD130\uB9C1\uD558\uAE30\\n\\n`MeterFilter`\uB97C \uC774\uC6A9\uD558\uBA74 \uB0B4\uAC00 \uC6D0\uD558\uC9C0 \uC54A\uB294 \uC9C0\uD45C\uB97C \uC9D1\uACC4\uC5D0\uC11C \uC81C\uC678\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC608\uB97C \uB4E4\uC5B4, JVM \uC9C0\uD45C\uB4E4\uC744 \uC9D1\uACC4\uC5D0\uC11C \uC81C\uC678\uD558\uACE0 \uC2F6\uB2E4\uBA74, \uC544\uB798\uC640 \uAC19\uC774 `MeterFilter`\uB97C \uC124\uC815\uD558\uBA74 \uB429\uB2C8\uB2E4.\\n\\n```java title=\\"ArmeriaPrometheusApplication.java\\"\\npublic static void main(String[] args) {\\n        PrometheusMeterRegistry meterRegistry = new PrometheusMeterRegistry(PrometheusConfig.DEFAULT);\\n        meterRegistry.config()\\n                     .meterFilter(MeterFilter.denyNameStartsWith(\\"jvm\\"));\\n        ServerBuilder sb = Server.builder();\\n                                 .http(8083)\\n                                 .meterRegistry(meterRegistry);\\n        // ... \uC0DD\uB7B5 ...\\n```\\n\\n`jvm_` \uC9C0\uD45C\uB4E4\uC774 \uBAA8\uB450 \uC81C\uC678\uB41C \uAC83\uC744 \uD655\uC778\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n```\\n$ curl -s http://localhost:8083/metrics | grep \\"^jvm\\"\\n```\\n\\n## gRPC \uC9C0\uD45C \uC218\uC9D1\uD558\uAE30\\n\\nArmeria\uC758 [GrpcMeterIdPrefixFunction](https://javadoc.io/doc/com.linecorp.armeria/armeria-javadoc/1.8.0/com/linecorp/armeria/common/grpc/GrpcMeterIdPrefixFunction.html)\uB97C \uC774\uC6A9\uD574 [gRPC \uC0C1\uD0DC \uCF54\uB4DC](https://grpc.github.io/grpc/core/md_doc_statuscodes.html)\uC5D0 \uB300\uD55C \uC9C0\uD45C\uB3C4 \uC218\uC9D1\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC9C0\uD45C\uB97C \uC218\uC9D1\uD558\uAE30 \uC704\uD574\uC11C\uB294 \uBA3C\uC800 \uC544\uB798\uC640 \uAC19\uC774 `armeria-grpc`\uB97C \uB514\uD39C\uB358\uC2DC\uC5D0 \uCD94\uAC00\uD574\uC57C \uD569\uB2C8\uB2E4.\\n\\n```groovy title=\\"build.gradle\\"\\ndependencies {\\n\\n    // Armeria\\n    implementation \\"com.linecorp.armeria:armeria:1.8.0\\"\\n    implementation \\"com.linecorp.armeria:armeria-logback:1.8.0\\"\\n    implementation \\"com.linecorp.armeria:armeria-grpc:1.8.0\\" // \uCD94\uAC00\\n\\n    // ...\\n}\\n```\\n\\n\uD14C\uC2A4\uD2B8\uD558\uAE30 \uC704\uD574 \uC544\uB798\uC640 \uAC19\uC774 \uAC04\uB2E8\uD55C gRPC \uC11C\uBE44\uC2A4\uB97C \uD558\uB098 \uC0DD\uC131\uD588\uC2B5\uB2C8\uB2E4.\\n\\n```protobuf title=\\"hello.proto\\"\\nsyntax = \\"proto3\\";\\n\\npackage com.example.armeria_prometheus;\\n\\noption java_package = \\"com.example.armeria_prometheus.grpc\\";\\n\\nservice HelloService {\\n  rpc Hello (HelloRequest) returns (HelloReply) {}\\n}\\n\\nmessage HelloRequest {\\n  int32 seq = 1;\\n}\\n\\nmessage HelloReply {\\n  string message = 1;\\n}\\n```\\n\\n```java title=\\"MyGrpcService.java\\"\\npublic class MyGrpcService extends HelloServiceGrpc.HelloServiceImplBase {\\n\\n    @Override\\n    public void hello(HelloRequest request, StreamObserver<HelloReply> responseObserver) {\\n        if (request.getSeq() % 3 != 0) {\\n            HelloReply reply = HelloReply.newBuilder()\\n                                         .setMessage(\\"Success\\")\\n                                         .build();\\n            responseObserver.onNext(reply);\\n            responseObserver.onCompleted();\\n            return;\\n        }\\n        responseObserver.onError(Status.INTERNAL.asException());\\n    }\\n}\\n```\\n\\n\uC704\uC5D0\uC11C \uB9CC\uB4E0 gRPC \uC11C\uBE44\uC2A4\uB97C \uC0C8\uB85C\uC6B4 \uC11C\uBE44\uC2A4\uB85C \uCD94\uAC00\uD569\uB2C8\uB2E4. \uAE30\uC874\uC758 HTTP \uC9C0\uD45C \uC218\uC9D1\uC5D0 \uC601\uD5A5\uC744 \uC8FC\uC9C0 \uC54A\uB3C4\uB85D \uAC01 \uC11C\uBE44\uC2A4\uC5D0 `MetricCollectingService` `decorator`\uB97C \uC801\uC6A9\uD558\uB294 \uD615\uD0DC\uB85C \uBCC0\uACBD\uD588\uC2B5\uB2C8\uB2E4.\\n\\n```java title=\\"ArmeriaPrometheusApplication.java\\"\\n// ... \uC0DD\uB7B5 ...\\nsb.annotatedService(new MyAnnotatedService(),\\n                    MetricCollectingService.builder(MeterIdPrefixFunction.ofDefault(\\"my.http.service\\")\\n                                                                          // ... \uC0DD\uB7B5 ...\\nsb.service(GrpcService.builder()\\n                      .addService(new MyGrpcService())\\n                      .build(),\\n           MetricCollectingService.newDecorator(GrpcMeterIdPrefixFunction.of(\\"my.grpc.service\\")));\\nsb.service(\\"/metrics\\", PrometheusExpositionService.of(meterRegistry.getPrometheusRegistry()));\\n// ... \uC0DD\uB7B5 ...\\n```\\n\\n\uAC04\uD3B8\uD558\uAC8C \uD14C\uC2A4\uD2B8\uB97C \uC9C4\uD589\uD558\uAE30 \uC704\uD574 \uBCF5\uC218 \uAC1C\uC758 gRPC \uC694\uCCAD\uC744 \uBC1C\uC0DD\uC2DC\uD0A4\uB294 \uD074\uB77C\uC774\uC5B8\uD2B8 \uCF54\uB4DC\uB3C4 \uC791\uC131\uD588\uC2B5\uB2C8\uB2E4(\uD074\uB77C\uC774\uC5B8\uD2B8 \uC5ED\uC2DC Armeria\uB97C \uC774\uC6A9\uD558\uBA74 \uC27D\uAC8C \uC791\uC131\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4).\\n\\n```java title=\\"RpcClientApplication.java\\"\\npublic class RpcClientApplication {\\n\\n    private static final Logger logger = LoggerFactory.getLogger(RpcClientApplication.class);\\n\\n    public static void main(String[] args) {\\n        HelloServiceBlockingStub helloService = Clients\\n                .newClient(\\"gproto+http://127.0.0.1:8083/\\", HelloServiceBlockingStub.class);\\n        for (int i = 0; i < 100; i++) {\\n            try {\\n                HelloRequest request = HelloRequest.newBuilder().setSeq(i).build();\\n                HelloReply reply = helloService.hello(request);\\n                logger.info(reply.getMessage());\\n            } catch (Exception e) {\\n                logger.error(\\"Error\\", e);\\n            }\\n        }\\n    }\\n}\\n```\\n\\n\uC11C\uBC84\uB97C \uC7AC\uAE30\uB3D9\uD558\uACE0 \uD074\uB77C\uC774\uC5B8\uD2B8 \uCF54\uB4DC\uB97C \uC2E4\uD589\uD574 \uBD05\uB2C8\uB2E4.\\n\\n```\\n$ curl -s http://localhost:8083/metrics | grep \\"my_grpc_service_requests_total\\"\\n# HELP my_grpc_service_requests_total\\n# TYPE my_grpc_service_requests_total counter\\nmy_grpc_service_requests_total{grpc_status=\\"13\\",hostname_pattern=\\"*\\",http_status=\\"200\\",method=\\"Hello\\",result=\\"success\\",service=\\"com.example.armeria_prometheus.HelloService\\",} 0.0\\nmy_grpc_service_requests_total{grpc_status=\\"13\\",hostname_pattern=\\"*\\",http_status=\\"200\\",method=\\"Hello\\",result=\\"failure\\",service=\\"com.example.armeria_prometheus.HelloService\\",} 34.0\\nmy_grpc_service_requests_total{grpc_status=\\"0\\",hostname_pattern=\\"*\\",http_status=\\"200\\",method=\\"Hello\\",result=\\"failure\\",service=\\"com.example.armeria_prometheus.HelloService\\",} 0.0\\nmy_grpc_service_requests_total{grpc_status=\\"0\\",hostname_pattern=\\"*\\",http_status=\\"200\\",method=\\"Hello\\",result=\\"success\\",service=\\"com.example.armeria_prometheus.HelloService\\",} 66.0\\n```\\n\\n\uC2E4\uC9C8\uC801\uC778 gRPC \uC751\uB2F5\uC5D0 \uD574\uB2F9\uD558\uB294 [gRPC \uC0C1\uD0DC \uCF54\uB4DC](https://grpc.github.io/grpc/core/md_doc_statuscodes.html) \uC9C0\uD45C\uB3C4 \uD568\uAED8 \uC218\uC9D1\uB3FC \uCD9C\uB825\uB41C \uAC83\uC744 \uD655\uC778\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n## \uB9C8\uCE58\uBA70\\n\\nArmeria\uC5D0\uC11C\uB294 \uC774 \uBC16\uC5D0\uB3C4 \uC0AC\uC6A9\uC790\uB4E4\uC774 \uAC01\uC790\uC758 \uC694\uAD6C \uC0AC\uD56D\uC5D0 \uB9DE\uAC8C \uC9C0\uD45C\uB97C \uC218\uC9D1\uD560 \uC218 \uC788\uB3C4\uB85D \uB2E4\uC591\uD55C \uAE30\uB2A5\uC744 \uC81C\uACF5\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uC774\uB7F0 \uAE30\uB2A5\uB4E4\uC744 \uD65C\uC6A9\uD574 \uC11C\uBC84 \uAC1C\uBC1C\uC790\uB4E4\uC774 \uBCF4\uB2E4 \uC0DD\uC0B0\uC801\uC73C\uB85C \uBAA8\uB2C8\uD130\uB9C1\uD560 \uC218 \uC788\uAE30\uB97C \uC18C\uB9DD\uD558\uBA70 \uAE00\uC744 \uB9C8\uCE58\uACA0\uC2B5\uB2C8\uB2E4."},{"id":"/2021/06/28/monitoring-prometheus-metrics-from-armeria","metadata":{"permalink":"/blog/ko/2021/06/28/monitoring-prometheus-metrics-from-armeria","editUrl":"https://github.com/line/armeria/edit/main/site-new/src/content/blog/ko/2021-06-28-monitoring-prometheus-metrics-from-armeria.mdx","source":"@site/src/content/blog/ko/2021-06-28-monitoring-prometheus-metrics-from-armeria.mdx","title":"Armeria\uC5D0\uC11C Prometheus \uC9C0\uD45C \uBAA8\uB2C8\uD130\uB9C1\uD558\uAE30","description":"\uC2DC\uC791\uD558\uBA70","date":"2021-06-28T00:00:00.000Z","tags":[],"readingTime":4.41,"hasTruncateMarker":true,"authors":[{"name":"\uC8FC\uC2B9\uD658","title":"LINE\uC5D0\uC11C OpenChat \uC11C\uBE44\uC2A4\uC758 \uBC31\uC5D4\uB4DC \uAC1C\uBC1C\uC744 \uB2F4\uB2F9\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4.","imageURL":"/img/author-seunghwanjoo.jpeg","key":"seunghwanjoo","page":null}],"frontMatter":{"authors":["seunghwanjoo"],"other_languages":{"en":"/blog/2021/07/09/monitoring-prometheus-metrics-from-armeria"}},"unlisted":false,"prevItem":{"title":"Armeria \uC9C0\uD45C \uCEE4\uC2A4\uD130\uB9C8\uC774\uC9D5\uD558\uAE30","permalink":"/blog/ko/2021/07/15/customizing-armeria-metrics"},"nextItem":{"title":"Armeria\uB85C Reactive Streams\uC640 \uB180\uC790! - 2","permalink":"/blog/ko/2020/02/19/reactive-streams-armeria-2"}},"content":"## \uC2DC\uC791\uD558\uBA70\\n\\n\uC774\uBC88 \uAE00\uC5D0\uC11C\uB294 [Armeria](https://armeria.dev/)\uC5D0\uC11C \uC218\uC9D1\uD55C [Prometheus](https://prometheus.io/) \uC9C0\uD45C\uB97C \uBAA8\uB2C8\uD130\uB9C1\uD558\uB294 \uBC29\uBC95\uC744 \uC0B4\uD3B4\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\nArmeria\uB97C \uCC98\uC74C \uC0AC\uC6A9\uD574 \uBCF4\uC2DC\uB294 \uBD84\uB4E4\uB3C4 \uC27D\uAC8C \uB530\uB77C \uD560 \uC218 \uC788\uB3C4\uB85D \uAC04\uB2E8\uD55C \uC2E4\uC2B5 \uC608\uC81C\uC640 \uD568\uAED8 \uC791\uC131\uD588\uC2B5\uB2C8\uB2E4.\\n\\n{/* truncate */}\\n\\n## \uC2E4\uC2B5\\n\\n\uC2E4\uC2B5\uC740 macOS Big Sur \uD658\uACBD\uC5D0\uC11C \uC9C4\uD589\uD588\uC2B5\uB2C8\uB2E4. \uC2E4\uC2B5\uC744 \uC9C4\uD589\uD558\uAE30 \uC704\uD574 Gradle\uACFC Prometheus, [Grafana](https://grafana.com/)\uB97C \uC5B4\uB5BB\uAC8C \uC124\uCE58\uD558\uACE0 \uC124\uC815\uD588\uB294\uC9C0 \uD568\uAED8 \uC54C\uC544\uBCF4\uACE0, \uD14C\uC2A4\uD2B8 \uACB0\uACFC\uB97C \uD655\uC778\uD574\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n### Gradle \uC124\uC815\\n\\nArmeria \uC11C\uBC84\uC758 Prometheus \uC9C0\uD45C\uB97C \uC218\uC9D1\uD558\uAE30 \uC704\uD574 \'build.gradle\' \uD30C\uC77C\uC5D0 \uC544\uB798\uC640 \uAC19\uC740 \uB514\uD39C\uB358\uC2DC\uB97C \uC815\uC758\uD588\uC2B5\uB2C8\uB2E4.\\n\\n```groovy title=\\"build.gradle\\"\\ndependencies {\\n\\n    // Armeria\\n    implementation \\"com.linecorp.armeria:armeria:1.8.0\\"\\n    implementation \\"com.linecorp.armeria:armeria-logback:1.8.0\\"\\n\\n    // Prometheus\\n    implementation \\"io.micrometer:micrometer-registry-prometheus:1.7.0\\"\\n\\n    // ...\\n}\\n```\\n\\n\uB610\uD55C \uC2E4\uC2B5\uC744 \uC704\uD574 \uC544\uB798\uC640 \uAC19\uC774 `/hello/{seq}`\uB85C GET \uC694\uCCAD\uC744 \uC804\uC1A1\uD558\uBA74 \uC131\uACF5 \uD639\uC740 \uC2E4\uD328\uB85C \uC751\uB2F5\uD558\uB294 \uAC04\uB2E8\uD55C REST API\uB97C \uD558\uB098 \uC900\uBE44\uD588\uC2B5\uB2C8\uB2E4.\\n\\n```java title=\\"MyAnnotatedService.java\\"\\npublic class MyAnnotatedService {\\n\\n    @Get(\\"/hello/{seq}\\")\\n    public HttpResponse hello(@Param(\\"seq\\") int seq) {\\n        if (seq % 3 == 0) {\\n            return HttpResponse.of(HttpStatus.INTERNAL_SERVER_ERROR);\\n        }\\n        return HttpResponse.of(HttpStatus.OK, MediaType.PLAIN_TEXT_UTF_8, \\"Success\\");\\n    }\\n}\\n```\\n\\n\uC544\uB798\uB294 Armeria \uC11C\uBC84\uB97C \uC2E4\uD589\uD558\uAE30 \uC704\uD55C `main()` \uD568\uC218 \uCF54\uB4DC\uC785\uB2C8\uB2E4.\\n\\n```java title=\\"ArmeriaPrometheusApplication.java\\"\\npublic class ArmeriaPrometheusApplication {\\n\\n    public static void main(String[] args) {\\n        PrometheusMeterRegistry meterRegistry = new PrometheusMeterRegistry(PrometheusConfig.DEFAULT);\\n        Server server = Server\\n                .builder()\\n                .http(8083)\\n                .meterRegistry(meterRegistry)\\n                .annotatedService(new MyAnnotatedService())\\n                .service(\\"/metrics\\", PrometheusExpositionService.of(meterRegistry.getPrometheusRegistry()))\\n                .decorator(MetricCollectingService.builder(MeterIdPrefixFunction.ofDefault(\\"my.http.service\\"))\\n                                                  .newDecorator())\\n                .build();\\n\\n        CompletableFuture<Void> future = server.start();\\n        future.join();\\n    }\\n}\\n```\\n\\n\uC11C\uBE44\uC2A4 \uC9C0\uD45C\uB97C \uC218\uC9D1\uD558\uAE30 \uC704\uD574\uC11C\uB294 \uBC18\uB4DC\uC2DC \uC544\uB798\uC640 \uAC19\uC774 [MetricCollectingService](https://javadoc.io/doc/com.linecorp.armeria/armeria-javadoc/1.8.0/com/linecorp/armeria/server/metric/MetricCollectingService.html)\uB97C `decorator`\uB85C \uCD94\uAC00\uD574\uC57C \uD569\uB2C8\uB2E4(\uC790\uC138\uD55C \uBC29\uBC95\uC740 [\uACF5\uC2DD \uBB38\uC11C](https://armeria.dev/docs/advanced-metrics/)\uB97C \uCC38\uACE0\uD558\uC2DC\uAE30 \uBC14\uB78D\uB2C8\uB2E4). `MeterIdPrefixFunction.ofDefault()` \uD568\uC218\uC758 \uC778\uC790 \uAC12\uC744 \uC774\uC6A9\uD558\uBA74 \uC9C0\uD45C\uC758 \uAE30\uBCF8 \uD504\uB9AC\uD53D\uC2A4 \uC774\uB984\uC744 \uC6D0\uD558\uB294 \uB300\uB85C \uC124\uC815\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n```java title=\\"ArmeriaPrometheusApplication.java\\"\\n.decorator(new MyAnnotatedService(),\\n           MetricCollectingService.builder(MeterIdPrefixFunction.ofDefault(\\"my.http.service\\"))\\n                                  .newDecorator())\\n```\\n\\n[PrometheusExpositionService](https://javadoc.io/doc/com.linecorp.armeria/armeria-javadoc/1.8.0/com/linecorp/armeria/server/metric/PrometheusExpositionService.html)\uB97C \uC774\uC6A9\uD574 Prometheus \uC9C0\uD45C\uB97C \uB178\uCD9C\uD560 \uACBD\uB85C\uB97C \uC124\uC815\uD569\uB2C8\uB2E4.\\n\\n```java title=\\"ArmeriaPrometheusApplication.java\\"\\n.service(\\"/metrics\\", PrometheusExpositionService.of(meterRegistry.getPrometheusRegistry()))\\n```\\n\\n`/hello` API\uB97C \uC694\uCCAD\uD574 \uC751\uB2F5\uC774 \uC798 \uC624\uB294\uC9C0 \uD655\uC778\uD569\uB2C8\uB2E4.\\n\\n```\\n$ curl http://localhost:8083/hello/1\\nSuccess\\n\\n$ curl http://localhost:8083/hello/3\\n500 Internal Server Error\\n```\\n\\n`/metrics`\uB85C \uC694\uCCAD\uD588\uC744 \uB54C Prometheus \uC9C0\uD45C\uAC00 \uC751\uB2F5\uC73C\uB85C \uC798 \uC804\uB2EC\uB418\uB294\uC9C0\uB3C4 \uD655\uC778\uD569\uB2C8\uB2E4.\\n\\n```\\n$ curl -s http://localhost:8083/metrics | grep \\"my_http_service_requests_total\\"\\n# HELP my_http_service_requests_total\\n# TYPE my_http_service_requests_total counter\\nmy_http_service_requests_total{hostname_pattern=\\"*\\",http_status=\\"500\\",method=\\"hello\\",result=\\"success\\",service=\\"com.example.armeria_prometheus.MyAnnotatedService\\",} 0.0\\nmy_http_service_requests_total{hostname_pattern=\\"*\\",http_status=\\"200\\",method=\\"hello\\",result=\\"failure\\",service=\\"com.example.armeria_prometheus.MyAnnotatedService\\",} 0.0\\nmy_http_service_requests_total{hostname_pattern=\\"*\\",http_status=\\"200\\",method=\\"hello\\",result=\\"success\\",service=\\"com.example.armeria_prometheus.MyAnnotatedService\\",} 1.0\\nmy_http_service_requests_total{hostname_pattern=\\"*\\",http_status=\\"500\\",method=\\"hello\\",result=\\"failure\\",service=\\"com.example.armeria_prometheus.MyAnnotatedService\\",} 1.0\\n```\\n\\n### Prometheus \uC124\uCE58 \uBC0F \uC124\uC815\\n\\n\uBA3C\uC800 [Homebrew](https://brew.sh/index_ko) \uD328\uD0A4\uC9C0 \uB9E4\uB2C8\uC800\uB85C Prometheus\uB97C \uC124\uCE58\uD569\uB2C8\uB2E4.\\n\\n```\\n$ brew install prometheus\\n```\\n\\n\uC124\uCE58\uAC00 \uC644\uB8CC\uB418\uBA74 \uAE30\uBCF8\uC801\uC73C\uB85C \'prometheus.yml\'\uC774\uB77C\uB294 \uD30C\uC77C\uC774 \uD558\uB098 \uC0DD\uC131\uB429\uB2C8\uB2E4. \uC774 YAML \uD30C\uC77C\uC744 \uC774\uC6A9\uD574 Prometheus \uC124\uC815\uC744 \uBCC0\uACBD\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n```\\n$ vi $(brew --prefix)/etc/prometheus.yml\\n```\\n\\n\uC124\uC815 \uD30C\uC77C\uC5D0 Prometheus \uC9C0\uD45C\uB97C \uC218\uC9D1\uD560 \uC218 \uC788\uB294 \uACBD\uB85C\uC640 \uD3EC\uD2B8\uB97C \uC815\uD655\uD558\uAC8C \uAE30\uC785\uD569\uB2C8\uB2E4.\\n\\n```yaml title=\\"prometheus.yml\\"\\nglobal:\\n  scrape_interval: 10s\\n\\nscrape_configs:\\n  - job_name: \'armeria-prometheus\'\\n    metrics_path: \'/metrics\'\\n    static_configs:\\n      - targets: [\'localhost:8083\']\\n```\\n\\n\uBCC0\uACBD\uD55C \uD6C4\uC5D0 Prometheus \uC11C\uBE44\uC2A4\uB97C \uC7AC\uC2DC\uC791\uD574\uC57C \uBCC0\uACBD\uB41C \uC124\uC815\uC774 \uC801\uC6A9\uB429\uB2C8\uB2E4.\\n\\n```\\n$ brew services start prometheus\\n```\\n\\nPrometheus\uAC00 \uC0AC\uC6A9\uD558\uB294 \uAE30\uBCF8 \uD3EC\uD2B8\uB294 `9090`\uC785\uB2C8\uB2E4. \uC6F9 \uBE0C\uB77C\uC6B0\uC800\uC5D0\uC11C `http://localhost:9090` \uC8FC\uC18C\uB85C \uC811\uC18D\uD558\uBA74 \uC544\uB798 \uD654\uBA74\uC744 \uBCFC \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/monitoring-prometheus-metrics-from-armeria-1.png)\\n\\n\uC140\uB809\uD2B8 \uBC15\uC2A4\uB97C \uD074\uB9AD\uD574 Armeria \uAD00\uB828 \uC9C0\uD45C\uAC00 Prometheus \uC11C\uBC84\uC5D0\uC11C \uC798 \uC218\uC9D1\uB410\uB294\uC9C0 \uD655\uC778\uD569\uB2C8\uB2E4.\\n\\n![](/img/monitoring-prometheus-metrics-from-armeria-2.png)\\n\\n`/hello/{seq}` API\uB97C \uBA87 \uBC88 \uC694\uCCAD\uD55C \uB4A4 `my_http_service_requests_total` \uC9C0\uD45C\uAC00 \uC798 \uC99D\uAC00\uD558\uB294\uC9C0 \uADF8\uB798\uD504\uC5D0\uC11C \uD655\uC778\uD569\uB2C8\uB2E4.\\n\\n![](/img/monitoring-prometheus-metrics-from-armeria-3.png)\\n\\n### Grafana \uC124\uCE58 \uBC0F \uC124\uC815\\n\\nPrometheus\uC640 \uB9C8\uCC2C\uAC00\uC9C0\uB85C Grafana\uB3C4 Homebrew\uB85C \uC124\uCE58\uD55C \uD6C4 \uC11C\uBE44\uC2A4\uB97C \uC2DC\uC791\uD569\uB2C8\uB2E4.\\n\\n```\\n$ brew install grafana\\n$ brew services start grafana\\n```\\n\\nGrafana\uC758 \uAE30\uBCF8 \uD3EC\uD2B8\uB294 `3000`\uC785\uB2C8\uB2E4. \uBE0C\uB77C\uC6B0\uC800\uC5D0\uC11C `http://localhost:3000` \uC8FC\uC18C\uB85C \uC811\uC18D\uD558\uBA74 \uC544\uB798 \uB85C\uADF8\uC778 \uD398\uC774\uC9C0\uB97C \uB9CC\uB098\uAC8C \uB429\uB2C8\uB2E4.\\n\\n![](/img/monitoring-prometheus-metrics-from-armeria-4.png)\\n\\n\'\uACC4\uC815\uC744 \uB9CC\uB4E0 \uC801\uC774 \uC5C6\uB294\uB370...?\'\uB77C\uACE0 \uB2F9\uD669\uD558\uC9C0 \uB9C8\uC2DC\uACE0 \uCE68\uCC29\uD558\uAC8C **Email or username**\uACFC **Password**\uC5D0 \'admin\'\uC744 \uC785\uB825\uD558\uBA74 \uB85C\uADF8\uC778\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC774\uB984\uC5D0\uC11C \uC54C \uC218 \uC788\uB4EF\uC774 admin\uC740 \uAE30\uBCF8 \uACC4\uC815\uC774\uBBC0\uB85C \uC2E4\uC81C \uC11C\uBE44\uC2A4\uC5D0\uC11C \uC0AC\uC6A9\uD560 \uB54C\uB294 \uBCF4\uC548\uC744 \uC704\uD574 \uBC18\uB4DC\uC2DC \uACC4\uC815\uC744 \uC0C8\uB85C \uB9CC\uB4E4\uC5B4\uC57C \uD569\uB2C8\uB2E4.\\n\\nGrafana\uC5D0\uC11C Prometheus \uBA54\uD2B8\uB9AD\uC744 \uADF8\uB798\uD504\uB85C \uD45C\uC2DC\uD560 \uC218 \uC788\uB3C4\uB85D, \uC55E\uC5D0\uC11C \uC124\uC815\uD55C Prometheus \uACBD\uB85C\uB97C **Data Source**\uB85C \uCD94\uAC00\uD574\uC57C \uD569\uB2C8\uB2E4.\\n\\n![](/img/monitoring-prometheus-metrics-from-armeria-5.png)\\n\\n\uB2E4\uC74C\uC73C\uB85C \uB300\uC2DC\uBCF4\uB4DC\uB97C \uD558\uB098 \uC0DD\uC131\uD55C \uD6C4, `/hello/{seq}` API\uC758 \uC131\uACF5\uACFC \uC2E4\uD328 \uD69F\uC218\uB97C \uBAA8\uB2C8\uD130\uB9C1\uD560 \uC218 \uC788\uB294 \uD328\uB110\uC744 \uD558\uB098 \uC0DD\uC131\uD558\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/monitoring-prometheus-metrics-from-armeria-6.png)\\n\\n\uCFFC\uB9AC\uB294 \uC544\uB798\uC640 \uAC19\uC774 \uC791\uC131\uD588\uC2B5\uB2C8\uB2E4.\\n\\n- 200: `increase(my_http_service_requests_total{hostname_pattern=\\"*\\", method=\\"hello\\", http_status=\\"200\\", result=\\"success\\", service=\\"com.example.armeria_prometheus.MyAnnotatedService\\"}[1m])`\\n- 500: `increase(my_http_service_requests_total{hostname_pattern=\\"*\\", method=\\"hello\\", http_status=\\"500\\", result=\\"failure\\", service=\\"com.example.armeria_prometheus.MyAnnotatedService\\"}[1m])`\\n\\n\uC5EC\uAE30\uC11C `armeria_server_requests_total` \uC9C0\uD45C\uB294 [Counter](https://prometheus.io/docs/concepts/metric_types/#counter)\uB77C\uB294 \uC9C0\uD45C \uC720\uD615\uC73C\uB85C \uB2E8\uC21C\uD788 \uB204\uC801\uB418\uBA70 \uACC4\uC18D \uC99D\uAC00\uD558\uB294 \uAC12\uC785\uB2C8\uB2E4. \uC2E4\uC81C API \uBAA8\uB2C8\uD130\uB9C1\uC5D0\uC11C\uB294 \uC774 API\uAC00 \uD604\uC7AC\uAE4C\uC9C0 \uC5BC\uB9C8\uB098 \uB9CE\uC774 \uC131\uACF5 \uD639\uC740 \uC2E4\uD328\uD588\uB290\uB0D0\uB294 \uB204\uC801\uAC12\uBCF4\uB2E4\uB294, \uC2DC\uAC04\uBCC4 \uC131\uACF5\uACFC \uC2E4\uD328 \uD69F\uC218\uAC00 \uB354 \uC758\uBBF8 \uC788\uC744 \uAC83\uC785\uB2C8\uB2E4. \uC774\uC5D0 [increase()](https://prometheus.io/docs/prometheus/latest/querying/functions/#increase) \uD568\uC218\uB97C \uC0AC\uC6A9\uD574\uC11C \uB9E4 1\uBD84 \uB3D9\uC548\uC758 \uC131\uACF5\uACFC \uC2E4\uD328 \uD69F\uC218\uB97C \uADF8\uB798\uD504\uB85C \uB098\uD0C0\uB0C8\uC2B5\uB2C8\uB2E4.\\n\\n### \uD14C\uC2A4\uD2B8 \uACB0\uACFC\\n\\n\uC774\uC81C \uC544\uB798 \uD074\uB77C\uC774\uC5B8\uD2B8 \uCF54\uB4DC\uB97C \uC2E4\uD589\uD574 API \uC694\uCCAD\uC744 100\uBC88 \uBCF4\uB0B4\uACA0\uC2B5\uB2C8\uB2E4(Armeria\uC758 [WebClient](https://javadoc.io/doc/com.linecorp.armeria/armeria-javadoc/latest/com/linecorp/armeria/client/WebClient.html)\uB97C \uC0AC\uC6A9\uD588\uC2B5\uB2C8\uB2E4).\\n\\n```java title=\\"HttpClientApplication.java\\"\\npublic class HttpClientApplication {\\n\\n    private static final Logger logger = LoggerFactory.getLogger(HttpClientApplication.class);\\n\\n    public static void main(String[] args) {\\n        WebClient client = WebClient.of(\\"http://localhost:8083/\\");\\n        for (int i = 0; i < 100; i++) {\\n            AggregatedHttpResponse res = client.get(\\"/hello/\\" + i).aggregate().join();\\n            logger.info(res.content(StandardCharsets.UTF_8));\\n        }\\n    }\\n}\\n```\\n\\nGrafana\uC5D0\uC11C `/hello/{seq}` API\uC758 \uC131\uACF5\uACFC \uC2E4\uD328 \uD69F\uC218\uAC00 \uC544\uB984\uB2F5\uAC8C \uADF8\uB798\uD504\uB85C \uD45C\uC2DC\uB418\uB294 \uAC83\uC744 \uD655\uC778\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/monitoring-prometheus-metrics-from-armeria-7.png)\\n\\n## \uB9C8\uCE58\uBA70\\n\\n\uC774\uBC88 \uAE00\uC5D0\uC11C\uB294 Armeria \uC11C\uBC84\uB97C \uC2E4\uD589\uD574\uC11C \uC218\uC9D1\uD55C Prometheus \uC9C0\uD45C\uC640 Grafana \uB300\uC2DC\uBCF4\uB4DC\uB97C \uC774\uC6A9\uD574 \uBAA8\uB2C8\uD130\uB9C1\uD558\uB294 \uBC29\uBC95\uC744 \uC0B4\uD3B4\uBCF4\uC558\uC2B5\uB2C8\uB2E4.\\nArmeria\uC5D0\uC11C\uB294 \uD604\uC7AC \uC9C0\uD45C \uC218\uC9D1\uACFC \uAD00\uB828\uD55C \uB2E4\uC591\uD55C \uAE30\uB2A5\uC744 \uC81C\uACF5\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uB2E4\uC74C \uAE00\uC5D0\uC11C\uB294 \uC774 \uAE30\uB2A5\uC744 \uC774\uC6A9\uD574 Armeria\uC5D0\uC11C \uC218\uC9D1\uB41C \uC9C0\uD45C\uB97C \uB0B4 \uC785\uB9DB\uC5D0 \uB9DE\uAC8C \uCEE4\uC2A4\uD130\uB9C8\uC774\uC9D5\uD574 \uBCF4\uACA0\uC2B5\uB2C8\uB2E4."},{"id":"/2020/02/19/reactive-streams-armeria-2","metadata":{"permalink":"/blog/ko/2020/02/19/reactive-streams-armeria-2","editUrl":"https://github.com/line/armeria/edit/main/site-new/src/content/blog/ko/2020-02-19-reactive-streams-armeria-2.mdx","source":"@site/src/content/blog/ko/2020-02-19-reactive-streams-armeria-2.mdx","title":"Armeria\uB85C Reactive Streams\uC640 \uB180\uC790! - 2","description":"\uC548\uB155\uD558\uC138\uC694.","date":"2020-05-06T11:00:00.000Z","tags":[],"readingTime":11.81,"hasTruncateMarker":true,"authors":[{"name":"\uC5C4\uC775\uD6C8","title":"LINE Plus\uC5D0\uC11C \uC624\uD508\uC18C\uC2A4 Armeria\uC640 Central Dogma\uB97C \uAC1C\uBC1C\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4.","imageURL":"https://github.com/ikhoon.png","key":"ikhunum","page":null}],"frontMatter":{"date":"2020-05-06T11:00","authors":["ikhunum"],"other_languages":{"ja":"/blog/ja/2020/03/26/reactive-streams-armeria-2","en":"/blog/2020/07/03/reactive-streams-armeria-2"}},"unlisted":false,"prevItem":{"title":"Armeria\uC5D0\uC11C Prometheus \uC9C0\uD45C \uBAA8\uB2C8\uD130\uB9C1\uD558\uAE30","permalink":"/blog/ko/2021/06/28/monitoring-prometheus-metrics-from-armeria"},"nextItem":{"title":"Armeria\uB85C Reactive Streams\uC640 \uB180\uC790! - 1","permalink":"/blog/ko/2020/02/18/reactive-streams-armeria-1"}},"content":"\uC548\uB155\uD558\uC138\uC694.\\nLINE+\uC5D0\uC11C \uC624\uD508\uC18C\uC2A4 Armeria\uC640 Central Dogma\uB97C \uAC1C\uBC1C\uD558\uACE0 \uC788\uB294 \uC5C4\uC775\uD6C8\uC785\uB2C8\uB2E4. [\uC9C0\uB09C \uD3EC\uC2A4\uD305](/blog/ko/2020/02/18/reactive-streams-armeria-1)\uC5D0\uC120 Reactive Streams\uC758 \uAC1C\uB150\uC744 \uC0B4\uD3B4\uBCF4\uC558\uB294\uB370\uC694. \uC774\uBC88 \uD3EC\uC2A4\uD305\uC5D0\uC120 Reactive Streams\uB97C \uC624\uD508 \uC18C\uC2A4 \uBE44\uB3D9\uAE30 HTTP/2, RPC, REST \uD074\uB77C\uC774\uC5B8\uD2B8/\uC11C\uBC84 \uB77C\uC774\uBE0C\uB7EC\uB9AC\uC778 Armeria\uC5D0\uC11C \uC0AC\uC6A9\uD558\uB294 \uBC29\uBC95\uC5D0 \uB300\uD574 \uACF5\uC720\uD558\uB824\uACE0 \uD569\uB2C8\uB2E4.\\n\\n{/* truncate */}\\n\\n## What\u2019s Armeria?\\n\\nArmeria\uB294 Java 8 \uBC0F Netty, Thrift, gRPC\uC5D0 \uAE30\uBC18\uD55C \uC624\uD508 \uC18C\uC2A4 \uBE44\uB3D9\uAE30 HTTP/2, RPC, REST \uD074\uB77C\uC774\uC5B8\uD2B8/\uC11C\uBC84 \uB77C\uC774\uBE0C\uB7EC\uB9AC\uC785\uB2C8\uB2E4.\\nArmeria\uB294 \uACBD\uB7C9(Lightweight) \uB9C8\uC774\uD06C\uB85C \uC11C\uBE44\uC2A4 \uD504\uB808\uC784\uC6CC\uD06C\uC9C0\uB9CC \uC9C0\uC6D0\uD558\uB294 \uAE30\uB2A5\uC740 \uB2E4\uB978 \uD480 \uC2A4\uD0DD(full stack) \uC6F9 \uD504\uB808\uC784\uC6CC\uD06C\uC640 \uBE44\uAD50\uD574\uB3C4 \uC190\uC0C9\uC774 \uC5C6\uC2B5\uB2C8\uB2E4.\\n\\n\uBA3C\uC800 Armeria\uC5D0\uC11C Reactive Streams\uB97C \uD65C\uC6A9\uD55C \uC11C\uBC84\uB97C \uAD6C\uD604\uD558\uAE30 \uC704\uD574\uC120 \uAE30\uBCF8\uC801\uC73C\uB85C \uC54C\uC544\uC57C \uD560 \uAC83\uB4E4\uC744 \uC54C\uB824\uB4DC\uB9AC\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n### \uC9C0\uC6D0\uD558\uB294 \uD504\uB85C\uD1A0\uCF5C\\n\\n![](/img/reactive-streams-armeria-2-1.png)\\n\\nArmeria\uC5D0\uC11C\uB294 HTTP/1\uACFC HTTP/2\uB97C \uBAA8\uB450 \uC9C0\uC6D0\uD558\uACE0, \uC774 \uB450 \uAC1C\uC758 \uD504\uB85C\uD1A0\uCF5C\uC740 [cleartext](https://simple.wikipedia.org/wiki/Cleartext)\uC640 TLS(Transport Layer Security) \uC554\uD638\uD654 \uD1B5\uC2E0\uC744 \uBAA8\uB450 \uC9C0\uC6D0\uD569\uB2C8\uB2E4.\\nHTTP/1\uC5D0\uC11C HTTP/2\uB85C\uC758 \uD638\uD658\uC131\uC744 \uC9C0\uC6D0\uD558\uAE30 \uC704\uD55C \uD504\uB85C\uD1A0\uCF5C \uC5C5\uADF8\uB808\uC774\uB4DC \uBA74\uC5D0\uC120, HTTP/2\uC758 \'connection preface\'\uC640 HTTP/1\uC758 \'upgrade request\'\uB97C \uBAA8\uB450 \uC9C0\uC6D0\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n\uB610\uD55C Armeria\uC5D0\uC120 gRPC\uC640 Thrift\uAC00 HTTP/1\uACFC HTTP/2, \uC591\uCABD\uC5D0\uC11C \uBAA8\uB450 \uB3D9\uC791\uD569\uB2C8\uB2E4. \uC774\uB294 Armeria\uB9CC\uC758 \uD2B9\uBCC4\uD55C \uAE30\uB2A5\uC778\uB370\uC694. gRPC\uB294 HTTP/1\uC744 \uC9C0\uC6D0\uD558\uC9C0 \uC54A\uACE0, \uAE30\uC874\uC758 Thrift\uC5D0\uC120 HTTP/2\uB97C \uC9C0\uC6D0\uD558\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4. \uD558\uC9C0\uB9CC Armeria\uC5D0\uC11C\uB294 \uBAA8\uB450 \uC9C0\uC6D0\uD558\uACE0 \uC788\uC5B4\uC11C \uB2E4\uC591\uD55C \uBE44\uC988\uB2C8\uC2A4 \uD658\uACBD\uC5D0\uC11C \uC720\uC5F0\uD558\uAC8C \uC0AC\uC6A9\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uB610\uD55C \uB9AC\uB205\uC2A4 \uD658\uACBD\uC5D0\uC120 JNI(Java Native Interface) \uAE30\uBC18\uC758 \uC18C\uCF13 IO\uC640 BoringSSL \uAE30\uBC18\uC758 TLS\uB97C \uD1B5\uD574\uC11C \uB354\uC6B1\uB354 \uBE60\uB978 \uC131\uB2A5\uC73C\uB85C \uD504\uB85C\uB355\uC158\uC5D0 \uC0AC\uC6A9\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n\uADF8\uB7FC \uC608\uC81C \uCF54\uB4DC\uC640 \uD568\uAED8 Armeria\uC5D0 \uB300\uD574\uC11C \uD558\uB098\uC529 \uC54C\uC544\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n### \uC608\uC81C \uCF54\uB4DC\uB85C \uC54C\uC544\uBCF4\uB294 Armeria\\n\\nArmeria\uB294 \uC0AC\uC6A9\uC790 \uCE5C\uD654\uC801\uC778 API\uC785\uB2C8\uB2E4. \uCF54\uB4DC\uAC00 \uAC04\uACB0\uD558\uACE0 \uC0AC\uC6A9\uD558\uAE30 \uC27D\uC2B5\uB2C8\uB2E4. \'Hello world\' \uC11C\uBC84\uB97C \uC2E4\uD589\uD558\uACE0 \uC2F6\uB2E4\uBA74 \uC544\uB798\uC640 \uAC19\uC774 5\uC904\uB9CC \uC791\uC131\uD558\uBA74 \uB429\uB2C8\uB2E4.\\n\\n```\\n// Build your own server under 5 lines.\\nvar server = Server.builder()\\n       .http(8080)\\n       .service(\u201C/\u201C, (ctx, req) -> HttpResponse.of(\u201CHello, World!\u201D))\\n       .build();\\n\\nserver.start();\\n```\\n\\n\uC11C\uBC84\uB97C \uC27D\uAC8C \uC2E4\uD589\uD560 \uC218 \uC788\uB2E4\uB294 \uC810\uC740 \uB9C8\uC774\uD06C\uB85C \uC11C\uBE44\uC2A4 \uD658\uACBD\uC5D0\uC11C \uAC01\uAC01\uC758 \uBE44\uC988\uB2C8\uC2A4 \uCEF4\uD3EC\uB10C\uD2B8\uB97C \uBD84\uB9AC\uD558\uC5EC \uB3C5\uB9BD\uB41C \uC11C\uBC84\uB85C \uAD00\uB9AC\uD558\uB824\uACE0 \uD560 \uB54C \uD575\uC2EC\uC774 \uB418\uB294 \uC0AC\uD56D\uC785\uB2C8\uB2E4.\\n\\n\uB610\uD55C \uC11C\uBC84 \uC544\uD0A4\uD14D\uCC98\uB97C \uB2E8\uC21C\uD558\uAC8C \uB9CC\uB4E4 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\nHTTPS\uB098 HTTP/2\uB97C \uC0AC\uC6A9\uD558\uAE30 \uC704\uD574 \uBCC4\uB3C4\uB85C [\uC0AC\uC774\uB4DC\uCE74](https://docs.microsoft.com/en-us/azure/architecture/patterns/sidecar)(sidecar)\uC778 Nginx\uB098 Apache Httpd\uC640 \uAC19\uC740 \uC815\uC801 \uC6F9 \uC11C\uBC84\uB97C \uC2E4\uD589\uD560 \uD544\uC694\uAC00 \uC5C6\uC2B5\uB2C8\uB2E4. \uC55E\uC11C \uC5B8\uAE09\uD588\uB4EF, \uB9AC\uB205\uC2A4 \uD658\uACBD\uC5D0\uC11C\uB294 JNI \uAE30\uBC18\uC758 \uC18C\uCF13 IO\uC640 BoringSSL\uC744 \uC9C0\uC6D0\uD558\uAE30 \uB54C\uBB38\uC5D0 \uBCC4\uB3C4\uB85C \uC131\uB2A5 \uC800\uD558\uB97C \uACE0\uB824\uD558\uC9C0 \uC54A\uC544\uB3C4 \uB429\uB2C8\uB2E4. \uB610\uD55C JS\uB098 CSS, \uC774\uBBF8\uC9C0\uC640 \uAC19\uC740 \uC815\uC801 \uD30C\uC77C\uC744 \uC11C\uBE59\uD558\uB294 \uAE30\uB2A5\uB3C4 \uC81C\uACF5\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4([\uCC38\uACE0](https://line.github.io/armeria/server-http-file.html)).\\n\\n```\\nvar server = Server.builder()\\n       .http(8080)\\n       .https(8443) // HTTPS support\\n       .tlsSelfSigned()\\n       .service(\u201C/\u201C, (ctx, req) -> HttpResponse.of(\u201CHello, World!\u201D))\\n       .build();\\nserver.start();\\n```\\n\\n\uB124\uD2B8\uC6CC\uD06C \uD649(hop)\uC744 \uCD94\uAC00\uD558\uC9C0 \uC54A\uC544\uB3C4 \uB418\uAE30 \uB54C\uBB38\uC5D0 \uC7A5\uC560\uC810\uC744 \uC904\uC77C \uC218 \uC788\uACE0, \uB9AC\uC18C\uC2A4\uB97C \uC808\uC57D\uD560 \uC218 \uC788\uC5B4 \uD6A8\uC728\uC801\uC73C\uB85C \uD1B5\uC2E0\uD560 \uC218 \uC788\uC73C\uBA70, \uC544\uD0A4\uD14D\uCC98\uAC00 \uB2E8\uC21C\uD574\uC9C0\uACE0, \uBAA8\uB2C8\uD130\uB9C1\uC774 \uC26C\uC6CC\uC9C0\uBA70, \uC11C\uBC84\uB97C \uC720\uC5F0\uD558\uAC8C \uD655\uC7A5\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n\uADF8 \uC678\uC5D0\uB3C4 \uC720\uC6A9\uD55C \uAE30\uB2A5\uC774 \uB9CE\uC2B5\uB2C8\uB2E4. \uADF8\uC911 \uD558\uB098\uAC00 Armeria\uC5D0\uC11C \uBE4C\uD2B8\uC778\uC73C\uB85C \uC81C\uACF5\uD558\uB294 \uC5B4\uB178\uD14C\uC774\uC158(annotation)\uC785\uB2C8\uB2E4. \uC5B4\uB178\uD14C\uC774\uC158\uC744 \uC774\uC6A9\uD558\uBA74 Armeria\uC758 \uAE30\uB2A5\uC744 \uB354\uC6B1 \uC27D\uAC8C \uC0AC\uC6A9\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC608\uB97C \uB4E4\uC5B4 \uC544\uB798\uC640 \uAC19\uC774 `hello`\uB97C \uD504\uB9AC\uD53D\uC2A4(prefix)\uB85C, `name`\uC744 \uACBD\uB85C \uBCC0\uC218\uB85C \uC124\uC815\uD558\uC5EC \uB77C\uC6B0\uD305\uD558\uB294 \uCF54\uB4DC\uB97C \uC190\uC27D\uAC8C \uC791\uC131\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4([Armeria \uACF5\uC2DD \uBB38\uC11C](https://line.github.io/armeria/server-annotated-service.html)\uB97C \uCC38\uACE0\uD558\uBA74 \uADF8 \uC678 \uB2E4\uC591\uD55C \uC5B4\uB178\uD14C\uC774\uC158\uC744 \uB354\uC6B1 \uC790\uC138\uD558\uAC8C \uC0B4\uD3B4\uBCFC \uC218 \uC788\uC2B5\uB2C8\uB2E4).\\n\\n```\\nimport com.linecorp.armeria.server.annotation.Get;\\nimport com.linecorp.armeria.server.annotation.Param;\\nimport com.linecorp.armeria.server.annotation.PathPrefix;\\n\\n// Use built-in annotations for mapping path and parameter injection\\n@PathPrefix(\u201C/hello\u201D)\\nclass HelloService {\\n   @Get(\u201C/:name\u201D)\\n   public String hello(@Param String name) {\\n       return String.format(\u201CHello, %s!\u201D, name);\\n   }\\n}\\n```\\n\\nArmeria\uC5D0\uB294 \uB2E4\uB978 \uC885\uB958\uC758 RPC \uD504\uB85C\uD1A0\uCF5C\uC744 \uB3D9\uC2DC\uC5D0 \uC11C\uBE59\uD560 \uC218 \uC788\uB294 \uD2B9\uBCC4\uD55C \uAE30\uB2A5\uB3C4 \uC788\uC2B5\uB2C8\uB2E4. \uD558\uB098\uC758 \uC11C\uBC84\uC5D0\uC11C REST API\uC640 gRPC, Thrift\uB97C \uBAA8\uB450 \uC81C\uACF5\uD560 \uC218 \uC788\uC5B4\uC11C \uBE44\uC988\uB2C8\uC2A4 \uC694\uAD6C \uC0AC\uD56D\uC774\uB098 \uC544\uD0A4\uD14D\uCC98\uC758 \uBCC0\uD654\uC5D0 \uC720\uC5F0\uD558\uAC8C \uB300\uC751\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uB610\uD55C \uB2E8\uC77C \uD3EC\uD2B8\uB85C \uC81C\uACF5\uD558\uAE30 \uB54C\uBB38\uC5D0 \uB9AC\uC18C\uC2A4\uB97C \uD6A8\uC728\uC801\uC73C\uB85C \uC0AC\uC6A9\uD558\uBA74\uC11C \uBCF4\uC548 \uCE21\uBA74\uC5D0\uC11C \uBD88\uD544\uC694\uD55C \uB178\uCD9C\uC744 \uCD5C\uC18C\uD654\uD558\uACE0, \uAD00\uB9AC \uD3EC\uC778\uD2B8\uB97C \uC904\uC77C \uC218 \uC788\uB294 \uC7A5\uC810\uC774 \uC788\uC2B5\uB2C8\uB2E4.[[1]](#footnotes)\\n\\n```\\nvar server = Server.builder()\\n   .http(8080)\\n   .service(\u201C/hello/rest\u201D, (ctx, req) -> HttpResponse.of(\u201CHello, world!\u201D))\\n   .service(\u201C/hello/thrift\u201D, THttpService.of(new ThriftHelloService()))\\n   .service(\u201C/hello/grpc\u201D, GrpcService.builder()\\n                                      .addService(new GrpcHelloService())\\n                                      .build())\\n   .build();\\n```\\n\\n\uC5D4\uD130\uD504\uB77C\uC774\uC988 \uC18C\uD504\uD2B8\uC6E8\uC5B4 \uAC1C\uBC1C\uC790\uB4E4\uC740 \uACF5\uD1B5\uC801\uC73C\uB85C \uC778\uC99D, \uB85C\uAE45\uACFC \uAC19\uC740 \uBD80\uBD84\uC744 \uC5B4\uB5BB\uAC8C \uD558\uBA74 \uD6A8\uC728\uC801\uC73C\uB85C \uCC98\uB9AC\uD560 \uC218 \uC788\uC744\uC9C0\uC5D0 \uAD00\uC2EC\uC744 \uAC16\uACE0 \uACE0\uBBFC\uD558\uAC8C \uB429\uB2C8\uB2E4.\\nArmeria\uC5D0\uC11C\uB294 [separation of concerns](https://en.wikipedia.org/wiki/Separation_of_concerns)\uB77C\uACE0 \uBD80\uB974\uB294 \uC774\uB7F0 \uBD80\uBD84\uC744 \uBCC4\uB3C4\uC758 [decorator](https://line.github.io/armeria/server-decorator.html)\uB85C \uAD00\uB9AC\uD560 \uC218 \uC788\uB294 \uAE30\uB2A5\uC744 \uC81C\uACF5\uD569\uB2C8\uB2E4.[[2]](#footnotes)\\n\\n\uB610\uD55C \uAE30\uBCF8 \uC81C\uACF5 \uC678\uC5D0 \uB2E4\uB978 decorator\uAC00 \uD544\uC694\uD558\uB2E4\uBA74, \uC9C1\uC811 \uC190\uC27D\uAC8C \uAD6C\uD604\uD574\uC11C \uD2B9\uC815 \uACBD\uB85C\uB098 \uC11C\uBE44\uC2A4\uC5D0 \uBC14\uC778\uB529\uD574\uC11C \uC0AC\uC6A9\uD560 \uC218\uB3C4 \uC788\uC2B5\uB2C8\uB2E4. \uC608\uB97C \uB4E4\uC5B4 \uC544\uB798 \uADF8\uB9BC\uC5D0\uC11C \uAD6C\uD604\uD55C `AuthService`\uAC19\uC740 \uACBD\uC6B0\uC5D0\uB294 `request`\uC5D0 \uC778\uC99D \uC815\uBCF4\uAC00 \uD3EC\uD568\uB418\uC5B4 \uC788\uC744 \uB54C\uB9CC \uC11C\uBE44\uC2A4\uB97C \uD638\uCD9C\uD558\uACE0, \uADF8\uB807\uC9C0 \uC54A\uC73C\uBA74 \'401 unauthorized\' \uC5D0\uB7EC\uB97C \uBC1C\uC0DD\uC2DC\uD0A4\uB3C4\uB85D \uD588\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/reactive-streams-armeria-2-2.png)\\n\\n\uB2E4\uC74C\uC73C\uB85C Armeria\uC5D0\uC11C Reactive Streams\uB97C \uC5B4\uB5BB\uAC8C \uC9C0\uC6D0\uD558\uACE0 \uC788\uB294\uC9C0 \uC54C\uC544\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n### Armeria \uB0B4 HTTP/2 \uC2A4\uD2B8\uB9BC\\n\\n\uC2A4\uD2B8\uB9BC(stream)\uC740 \uD750\uB974\uB294 \uBB3C\uACFC \uAC19\uC774 \uC720\uAE30\uC801\uC73C\uB85C \uACC4\uC18D \uC5F0\uACB0\uB418\uC5B4 \uC788\uC5B4\uC57C \uD569\uB2C8\uB2E4. \uC5B4\uB290 \uD55C\uACF3\uB9CC \uB6AB\uB824\uC788\uACE0 \uB098\uBA38\uC9C0\uAC00 \uB9C9\uD600 \uC788\uB2E4\uBA74 \uACE7 \uB118\uCCD0 \uBC84\uB9BD\uB2C8\uB2E4.\\nArmeria\uC5D0\uC11C\uB294 \uB370\uC774\uD130\uC758 \uD750\uB984\uC744 \uC720\uAE30\uC801\uC73C\uB85C \uC81C\uC5B4\uD558\uAE30 \uC704\uD574\uC11C \uC11C\uBC84 \uB0B4\uC5D0\uC120 Reactive Streams\uC758 \uBC31 \uD504\uB808\uC154\uB97C \uC774\uC6A9\uD574 \uD2B8\uB798\uD53D\uC744 \uC81C\uC5B4\uD569\uB2C8\uB2E4. \uB610\uD55C [WINDOW_UPDATE](https://http2.github.io/http2-spec/#WINDOW_UPDATE)\uB97C \uC774\uC6A9\uD55C [HTTP/2 stream flow control](https://tools.ietf.org/html/rfc7540#section-5.2)\uB85C, \uBC31 \uD504\uB808\uC154\uAC00 \uD558\uC704 \uB124\uD2B8\uC6CC\uD06C \uB808\uC774\uC5B4\uC5D0\uC11C Armeria \uC11C\uBC84\uC640 \uC5EC\uB7EC\uBD84\uC774 \uAD6C\uD604\uD55C \uC11C\uBE44\uC2A4, \uADF8\uB9AC\uACE0 \uB370\uC774\uD130 \uC800\uC7A5\uC18C\uAE4C\uC9C0 \uC720\uAE30\uC801\uC73C\uB85C \uC5F0\uACB0\uD560 \uC218 \uC788\uB3C4\uB85D \uB9CC\uB4E4\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/reactive-streams-armeria-2-3.png)\\n\\n\uB9CC\uC57D \uC11C\uBE44\uC2A4\uC5D0\uC11C \uC0AC\uC6A9\uD558\uB294 \uC11C\uBC84\uB97C Armeria\uC758 Reactive \uC11C\uBC84\uB85C \uB2F9\uC7A5 \uBC14\uAFB8\uAE30 \uC5B4\uB835\uB2E4\uBA74, \uC544\uB798\uC640 \uAC19\uC774 Armeria\uB97C Reactive \uD504\uB77D\uC2DC \uC11C\uBC84\uB85C \uD65C\uC6A9\uD560 \uC218\uB3C4 \uC788\uC2B5\uB2C8\uB2E4([\uCC38\uACE0](https://github.com/line/armeria-examples/tree/master/proxy-server)).\\n\\n```\\n// Use Armeria\u2019s async & reactive HTTP/2 client.\\nvar client = HttpClient.of(\u201Ch2c://backend\u201D);\\nvar server = Server.builder()\\n    .http(8080)          // Forward all requests reactively\\n    .service(\u201Cprefix:/\u201C, (ctx, req) -> client.execute(req))\\n    .build();\\n```\\n\\nArmeria \uD504\uB77D\uC2DC \uC11C\uBC84\uB97C \uC55E\uC5D0 \uB450\uBA74 \uC5EC\uB7EC\uBD84\uC758 \uC11C\uBC84\uB97C \uD5D8\uB09C\uD55C \uC678\uBD80 \uC778\uD130\uB137\uC73C\uB85C\uBD80\uD130 \uC548\uC804\uD558\uAC8C \uBCF4\uD638\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/reactive-streams-armeria-2-4.png)\\n\\n## Reactive Streams\uC640 Armeria\uC758 \uD1B5\uD569\\n\\nArmeria\uB85C \uC9C1\uC811 Reactive Streams\uB97C \uC9C0\uC6D0\uD558\uB294 \uC11C\uBC84\uB97C \uB9CC\uB4E0\uB2E4\uBA74 \uB354\uC6B1\uB354 \uB2E4\uC591\uD55C \uAE30\uB2A5\uC744 \uC4F8 \uC218 \uC788\uB294\uB370\uC694.\\nArmeria\uC5D0\uC11C Reactive Streams\uB97C \uD65C\uC6A9\uD558\uB294 \uBC29\uBC95\uACFC \uBE4C\uD2B8\uC778 publisher\uC5D0 \uB300\uD574\uC11C \uC880 \uB354 \uC790\uC138\uD788 \uC54C\uC544\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n### Armeria HTTP \uC751\uB2F5 Publisher\\n\\nArmeria\uC758 \uC751\uB2F5\uC740 \uD5E4\uB354\uB97C \uD45C\uD604\uD558\uB294 [HttpHeaders](https://line.github.io/armeria/apidocs/com/linecorp/armeria/common/HttpHeaders.html)\uC640 \uB370\uC774\uD130\uB97C \uD45C\uD604\uD558\uB294 [HttpData](https://line.github.io/armeria/apidocs/com/linecorp/armeria/common/HttpData.html)\uB85C \uAD6C\uC131\uB418\uC5B4 \uC788\uC2B5\uB2C8\uB2E4.\\nRxJava\uC758 [Observable](http://reactivex.io/RxJava/javadoc/io/reactivex/Observable.html)\uC744 Armeria\uC758 [HttpResponse](https://line.github.io/armeria/apidocs/com/linecorp/armeria/common/HttpResponse.html)\uB85C \uBC14\uAFB8\uB294 \uACFC\uC815\uC744 \uB2E8\uACC4\uBCC4\uB85C \uC0B4\uD3B4\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n\uB370\uC774\uD130\uAC00 \uC900\uBE44\uB418\uBA74 \uBA3C\uC800 `Observable`\uC758 `map` \uC5F0\uC0B0\uC790\uB97C \uC774\uC6A9\uD574\uC11C `dataStream`\uC744 `HttpData`\uB85C \uAC10\uC2F8\uC90D\uB2C8\uB2E4.\\n\\n```\\n// 1. Fetch data from Reactive Streams Publisher\\nObservable<String> dataStream = Observable.just(\u201Ca\u201D, \u201Cb\u201D, \u201Cc\u201D, \u201Cd\u201D, \u201Ce\u201D);\\n\\n// 2. Convert string to Armeria HttpData\\nObservable<HttpData> httpDataStream = dataStream.map(HttpData::ofUtf8);\\n```\\n\\n\uC5B4\uB5A4 \uC2DD\uC73C\uB85C \uC751\uB2F5\uD560\uC9C0 \uACB0\uC815\uD558\uC5EC \uC751\uB2F5 \uD5E4\uB354\uB97C \uC900\uBE44\uD55C \uD6C4, `concat` \uC5F0\uC0B0\uC790\uB85C \uC704\uC5D0\uC11C \uC900\uBE44\uD55C `httpDataStream`\uACFC \uD569\uCE58\uBA74, `HttpHeaders`\uC5D0\uC11C `HttpData`\uB85C \uC5F0\uACB0\uB418\uB294 \uD558\uB098\uC758 \uC2A4\uD2B8\uB9BC\uC774 \uC644\uC131\uB429\uB2C8\uB2E4.\\n\\n```\\n// 3. Prepare response headers\\nResponseHeaders httpHeaders = ResponseHeaders.of(HttpStatus.OK);\\n\\n// 4. Concat http header and body stream\\nObservable<HttpObject> responseStream = Observable.concat(Observable.just(httpHeaders), httpDataStream);\\n```\\n\\n`\uC644\uC131\uB41C \uC2A4\uD2B8\uB9BC\uC744 Observable`\uC758 `toFlowable` \uD568\uC218\uB97C \uC774\uC6A9\uD558\uC5EC Reactive Streams\uC758 [Flowable](https://www.baeldung.com/rxjava-2-flowable)\uB85C \uBCC0\uD658\uD55C \uB4A4, \uCD5C\uC885\uC801\uC73C\uB85C Armeria\uC758 `HttpResponse\uB85C` \uAC10\uC2F8\uBA74 \uACFC\uC815\uC774 \uB05D\uB0A9\uB2C8\uB2E4.\\n\\n```\\n// 5. Convert Observable to Armeria Response Stream\\nHttpResponse response = HttpResponse.of(responseStream.toFlowable(BackpressureStrategy.BUFFER));\\n```\\n\\n### Armeria \uBE4C\uD2B8\uC778 Publisher\\n\\n\uC704 \uACFC\uC815\uC774 \uC870\uAE08 \uBCF5\uC7A1\uD558\uAC70\uB098, \uD639\uC740 \uC9C0\uB8E8\uD558\uAC8C \uB290\uAEF4\uC84C\uC744 \uC218\uB3C4 \uC788\uC2B5\uB2C8\uB2E4. \uADF8\uB798\uC11C Armeria\uC5D0\uC11C\uB294 \uC6F9\uC5D0\uC11C \uC2A4\uD2B8\uB9BC \uB370\uC774\uD130\uB97C \uC804\uB2EC\uD558\uB294 \uBC29\uBC95\uC758 \uD45C\uC900\uC778 [JSON Text Sequences(RFC 7464)](https://tools.ietf.org/html/rfc7464)\uC640 HTML5 \uADDC\uACA9\uC778 [Server-sent events](https://en.wikipedia.org/wiki/Server-sent_events)\uC5D0 \uB300\uD55C \uBE4C\uD2B8\uC778 Publisher\uB97C \uC81C\uACF5\uD569\uB2C8\uB2E4. \uC774 publisher\uB97C \uC774\uC6A9\uD558\uBA74 Reactive Streams\uB97C \uC880 \uB354 \uD3B8\uB9AC\uD558\uAC8C \uC6F9\uC73C\uB85C \uC804\uB2EC\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n```\\n// Fetch data from Reactive Streams Publisher\\nPublisher<String> dataStream = Flux.just(\u201Ca\u201D, \u201Cb\u201D, \u201Cc\u201D, \u201Cd\u201D, \u201Ce\u201D);\\n\\n// Convert Publisher to JSON Text Sequences with Armeria HttpResponse\\n// with \u201Capplication/json-seq\u201D MIME type\\nHttpResponse httpResponse = JsonTextSequences.fromPublisher(dataStream);\\n\\n// Convert Publisher to Server-sent Events with Armeria HttpResponse\\n// with \u201Ctext/event-stream\u201D MIME type\\nHttpResponse httpResponse = ServerSentEvents\\n        .fromPublisher(dataStream, SeverSentEvent::ofData);\\n```\\n\\n\uB610\uD55C \uBE4C\uD2B8\uC778 publisher\uB97C \uB354\uC6B1 \uC27D\uAC8C \uC0AC\uC6A9\uD560 \uC218 \uC788\uB3C4\uB85D RxJava \uD1B5\uD569\uC744 \uC9C0\uC6D0\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uC5B4\uB178\uD14C\uC774\uC158\uD55C \uC11C\uBE44\uC2A4\uC5D0 `@ProduceJsonSequence` \uC5B4\uB178\uD14C\uC774\uC158\uC744 \uCD94\uAC00\uD558\uACE0, `Observable`\uC744 \uADF8\uB300\uB85C \uBC18\uD658\uD558\uBA74 Armeria\uC5D0\uC11C \uD574\uB2F9 \uD504\uB85C\uD1A0\uCF5C\uB85C \uC790\uB3D9\uC73C\uB85C \uBCC0\uD658\uD569\uB2C8\uB2E4.\\n\\n```\\nimport io.reactivex.Observable;\\nimport com.linecorp.armeria.server.annotation.ProducesJsonSequences;\\n\\nclass RxJavaService {\\n    @Get(\u201C/json-streaming\u201D)\\n      // Generate JSON Text Sequences\\n    @ProducesJsonSequences\\n    public Observable<String> json() {\\n          // Just return RxJava Observable!\\n        return Observable.just(\u201Ca\u201D, \u201Cb\u201D, \u201Cc\u201D);\\n    }\\n};\\n```\\n\\n\uC544\uB798\uC640 \uAC19\uC774\'JsonTextSequences\'\uB85C \uC778\uCF54\uB529\uD558\uBA74 JSON \uBB38\uC790\uC5F4\uC758 \uC2DC\uC791\uACFC \uB05D\uC5D0 \uB808\uCF54\uB4DC \uAD6C\uBD84\uC790(separator)\uC640 \uB77C\uC778 \uD53C\uB4DC(line feed)\uAC00 \uCD94\uAC00\uB429\uB2C8\uB2E4. \uB610\uD55C \uD604\uC7AC \uD504\uB85C\uD1A0\uCF5C\uC5D0 \uB530\uB77C HTTP/1\uACFC HTTP/2\uB85C \uC804\uC1A1\uB420 \uB54C \uB2E4\uB974\uAC8C \uB3D9\uC791\uD574\uC57C \uD558\uB294\uB370\uC694.\\nArmeria\uC5D0\uC120 \uD604\uC7AC \uC5F0\uACB0\uB41C \uD504\uB85C\uD1A0\uCF5C\uC5D0 \uB530\uB77C \uC54C\uC544\uC11C \uC801\uD569\uD55C \uD615\uD0DC\uC758 \uB370\uC774\uD130\uB85C \uC804\uC1A1\uD569\uB2C8\uB2E4.\\nHTTP/2\uC758 \uACBD\uC6B0\uC5D0\uB294 [Data frame](https://http2.github.io/http2-spec/#DATA)\uC548\uC5D0 JSON \uB370\uC774\uD130\uB97C \uB098\uB204\uC5B4\uC11C \uBCF4\uB0B4\uACE0, HTTP/1\uC758 \uACBD\uC6B0\uC5D0\uB294 [chunked transfer encoding](https://en.wikipedia.org/wiki/Chunked_transfer_encoding)\uC744 \uC774\uC6A9\uD558\uC5EC \uB098\uB204\uC5B4\uC11C \uBCF4\uB0C5\uB2C8\uB2E4.\\n\\n![](/img/reactive-streams-armeria-2-5.png)\\n\\n## Spring WebFlux \uD1B5\uD569\\n\\nArmeria\uB294 \uB2E4\uC591\uD55C \uB77C\uC774\uBE0C\uB7EC\uB9AC \uBC0F \uD504\uB808\uC784\uC6CC\uD06C\uC640\uC758 \uC5F0\uB3D9\uC744 \uC9C0\uC6D0\uD569\uB2C8\uB2E4.\\nReactive Streams\uB97C \uC0AC\uC6A9\uD558\uAE30 \uC704\uD574\uC11C \uC774\uBBF8 [Spring WebFlux](https://docs.spring.io/spring/docs/current/spring-framework-reference/web-reactive.html)\uB97C \uC0AC\uC6A9\uD558\uACE0 \uC788\uB2E4\uBA74, \uBCC4\uB3C4\uC758 \uCF54\uB4DC \uC218\uC815 \uC5C6\uC774 \'armeria-spring-boot-webflux-starter\'\uB97C \uC758\uC874\uC131\uC5D0 \uCD94\uAC00([\uCC38\uACE0](https://line.github.io/armeria/advanced-spring-webflux-integration.html))\uD558\uB294 \uAC83\uB9CC\uC73C\uB85C Armeria\uB85C\uC758 \uB9C8\uC774\uADF8\uB808\uC774\uC158\uC744 \uB05D\uB0BC \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC774\uB7F0 \uBC29\uC2DD\uC73C\uB85C WebFlux\uC758 \uB124\uD2B8\uC6CC\uD06C \uB808\uC774\uC5B4\uC778 [Reactor-Netty](https://github.com/reactor/reactor-netty)\uB97C Armeria\uC758 Reactive \uC5D4\uC9C4\uC73C\uB85C \uAD50\uCCB4\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/reactive-streams-armeria-2-6.png)\\n\\n\uB2E8\uC21C\uD788 \uC5D4\uC9C4\uB9CC \uAD50\uCCB4\uD558\uB294 \uAC70\uB77C\uBA74 \'\uADF8\uB0E5 WebFlux\uB9CC \uC0AC\uC6A9\uD558\uBA74 \uB418\uC9C0 \uC54A\uC744\uAE4C?\'\uB77C\uB294 \uC758\uBB38\uC774 \uC0DD\uAE38 \uC218\uB3C4 \uC788\uB294\uB370\uC694. \uACFC\uC5F0 \uC5B4\uB5A4 \uC774\uC810\uC774 \uC788\uB294 \uAC78\uAE4C\uC694?\\n\\n\uC5D4\uC9C4\uC744 \uAD50\uCCB4\uD558\uBA74 [ArmeriaServerConfigurator](https://line.github.io/armeria/apidocs/com/linecorp/armeria/spring/ArmeriaServerConfigurator.html)\uB97C \uD1B5\uD574\uC11C Spring\uC5D0 Armeria\uC758 \uAE30\uB2A5\uC744 \uCD94\uAC00\uD560 \uC218 \uC788\uC5B4\uC11C, \uAE30\uC874 Spring\uC5D0\uC11C\uB294 \uC9C0\uC6D0\uD558\uC9C0 \uC54A\uB294 Armeria\uB9CC\uC758 \uAE30\uB2A5\uC744 \uD65C\uC6A9\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC608\uB97C \uB4E4\uC5B4 \uC544\uB798\uC640 \uAC19\uC774 REST API\uB85C \uAD6C\uC131\uB41C \uAE30\uC874 Spring Webflux \uC11C\uBC84\uC5D0 gRPC\uB098 Thrift \uAE30\uB2A5\uC744 \uCD94\uAC00\uD558\uC5EC \uAE30\uC874\uACFC \uB3D9\uC77C\uD55C, \uB2E8\uC77C \uD3EC\uD2B8\uC5D0\uC11C \uC11C\uBE44\uC2A4\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n```\\n@Configuration\\npublic class ArmeriaConfiguration {\\n   // Configure the server by providing an ArmeriaServerConfigurator bean.\\n   @Bean\\n   public ArmeriaServerConfigurator armeriaServerConfigurator() {\\n       // Customize the server using the given ServerBuilder. For example:\\n       return builder -> {\\n           // Add DocService that enables you to send gRPC and Thrift requests from web browser.\\n           builder.serviceUnder(\u201C/docs\u201D, new DocService());\\n           // Log every message which the server receives and responds.\\n           builder.decorator(LoggingService.newDecorator());\\n           // Write access log after completing a request.\\n           builder.accessLogWriter(AccessLogWriter.combined(), false);\\n           // You can also bind asynchronous RPC services such as Thrift and gRPC:\\n           builder.service(THttpService.of(\u2026));\\n           builder.service(GrpcService.builder()\u2026build());\\n       };\\n   }\\n}\\n```\\n\\n\uB610\uD55C \uC774\uC678\uC5D0\uB3C4 \uC55E\uC11C \uC124\uBA85\uB4DC\uB9B0 decorator \uAE30\uB2A5\uC744 \uD65C\uC6A9\uD574\uC11C \uB354\uC6B1\uB354 \uD48D\uC131\uD55C \uC11C\uBE44\uC2A4\uB85C \uB9CC\uB4E4 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n## gRPC \uC2A4\uD2B8\uB9BC \uC9C0\uC6D0\\n\\ngRPC\uB294 [StreamObserver](https://grpc.github.io/grpc-java/javadoc/io/grpc/stub/StreamObserver.html)\uB97C \uC774\uC6A9\uD558\uC5EC \uC2A4\uD2B8\uB9BC\uC744 \uC9C0\uC6D0\uD569\uB2C8\uB2E4([\uCC38\uACE0](https://grpc.io/docs/tutorials/basic/java/#server-side-streaming-rpc)). \uADF8\uB9AC\uACE0 Reactive Streams\uC5D0\uC120 gRPC\uC758 [StreamObserver](https://grpc.github.io/grpc-java/javadoc/io/grpc/stub/StreamObserver.html)\uB85C \uC190\uC27D\uAC8C \uBCC0\uD658\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC608\uC81C\uB97C \uD1B5\uD574\uC11C \uC54C\uC544\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n\uC6B0\uC120 \uC544\uB798\uC640 \uAC19\uC774 protobuf\uB97C \uC774\uC6A9\uD574 \uB370\uC774\uD130\uB97C \uC5B4\uB5A4 \uC2DD\uC73C\uB85C \uC8FC\uACE0\uBC1B\uC744\uC9C0, \uC778\uD130\uD398\uC774\uC2A4\uB97C \uC815\uC758\uD569\uB2C8\uB2E4.\\n\\n```\\nsyntax = \u201Cproto3\u201D;\\npackage users;\\noption java_package = \u201Cusers\u201D;\\n\\nservice UserService {\\n  // Returns all user information\\n  rpc getAllUsers(UserRequest) returns (stream User) {}\\n\\n  // Push to stream of users\\n  rpc pushToUsers(stream User) returns (Result) {}\\n}\\n```\\n\\n\uC804\uCCB4 \uD68C\uC6D0\uC5D0\uAC8C \uBA54\uC77C \uD639\uC740 \uD478\uC2DC \uBA54\uC2DC\uC9C0\uB97C \uBCF4\uB0B4\uACE0 \uC2F6\uB2E4\uBA74 \uBA3C\uC800 \uBAA8\uB4E0 \uC0AC\uC6A9\uC790 \uC815\uBCF4\uB97C \uC870\uD68C\uD574\uC57C \uD558\uB294\uB370\uC694. \uB9CC\uC57D \uD68C\uC6D0 \uC218\uAC00 \uB108\uBB34 \uB9CE\uB2E4\uBA74 \uB370\uC774\uD130\uB97C \uD55C \uBC88\uC5D0 \uC804\uC1A1\uD558\uB294 \uAC8C \uC5B4\uB824\uC6B8 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uADF8\uB7F4 \uB54C \uC544\uB798\uC640 \uAC19\uC740 \uBC29\uBC95\uC73C\uB85C \uB300\uB7C9\uC758 \uC0AC\uC6A9\uC790 \uC815\uBCF4\uB97C \uBC18\uD658\uD558\uB294 \uC2A4\uD2B8\uB9BC \uC11C\uBC84\uB97C gRPC\uB85C \uAD6C\uCD95\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n1. ProjectReactor\uC758 `Flux`\uB97C Publisher\uB85C \uC0AC\uC6A9\uD558\uC5EC \uC800\uC7A5\uC18C\uC5D0\uC11C \uC2A4\uD2B8\uB9BC \uD615\uD0DC\uB85C \uB370\uC774\uD130\uB97C \uC870\uD68C\uD569\uB2C8\uB2E4.\\n2. gRPC\uC758 `StreamObservser`\uB85C \uBCC0\uD658\uD558\uC5EC \uC678\uBD80\uB85C \uC804\uC1A1\uD569\uB2C8\uB2E4.\\n\\n```\\n// Implement interfaces generated by gRPC\\npublic final class UserServiceImpl extends UserServiceImplBase {\\n    @Override\\n    public void getAllUsers(UserRequest request, StreamObserver<User> responseObserver) {\\n        final Flux<User> userPublisher = userRepo.findAll();\\n        publisher.subscribe(responseObserver::onNext,\\n                            responseObserver::onError,\\n                            responseObserver::onCompleted);\\n    }\\n}\\n```\\n\\n`StreamObserver`\uC5D0\uB3C4 Reactive Streams\uC640 \uC720\uC0AC\uD558\uAC8C `onNext`, `onError`, `onCompleted` \uD568\uC218\uAC00 \uC874\uC7AC\uD558\uAE30 \uB54C\uBB38\uC5D0 \uAC01\uAC01\uC758 API\uB97C \uB9E4\uCE6D\uD574\uC11C \uC5F0\uACB0\uD558\uAE30\uB9CC \uD558\uBA74 \uB429\uB2C8\uB2E4.\\n\\n\uC774\uBC88\uC5D0\uB294 \uC218\uC2E0 \uCE21\uC5D0\uC11C \uC804\uCCB4 \uC0AC\uC6A9\uC790\uC758 \uC815\uBCF4\uB97C \uC2A4\uD2B8\uB9BC\uC73C\uB85C \uBC1B\uB294 \uAC83\uC744 \uC0DD\uAC01\uD574 \uBCFC \uAC74\uB370\uC694. [Processor](https://www.reactive-streams.org/reactive-streams-1.0.0-javadoc/org/reactivestreams/Processor.html)\uB97C \uD65C\uC6A9\uD558\uACA0\uC2B5\uB2C8\uB2E4. `Processor`\uB294 \uBCC4\uB3C4\uC758 API\uB97C \uAC00\uC9C0\uACE0 \uC788\uC9C0 \uC54A\uACE0, `Subscriber`\uC640 `Publisher,` \uC774 \uB450 \uAC1C\uC758 \uC778\uD130\uD398\uC774\uC2A4\uB97C \uC0C1\uC18D\uBC1B\uACE0 \uC788\uB294 \uAC8C \uC804\uBD80\uC778\uB370\uC694. \uB370\uC774\uD130\uB97C \uAD6C\uB3C5 \uBC1B\uACE0, \uAD6C\uB3C5\uD55C \uB370\uC774\uD130\uB97C \uB2E4\uC2DC \uBC1C\uD589\uD560 \uB54C \uC720\uC6A9\uD558\uAC8C \uC0AC\uC6A9\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. `StreamObserver`\uC758 `onNext`\uB85C \uB4E4\uC5B4\uC628 \uC0C8\uB85C\uC6B4 \uC0AC\uC6A9\uC790 \uC815\uBCF4\uB97C `Processor`\uC758 `onNext` \uD568\uC218\uB85C \uC804\uB2EC\uD560 \uC218 \uC788\uACE0, \uC774\uB97C \uB2E4\uC2DC \uAD6C\uB3C5\uD574\uC11C \uC6D0\uD558\uB294 \uC791\uC5C5\uC744 \uCD94\uAC00\uB85C \uC218\uD589\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n```\\n@Override\\npublic StreamObserver<User> pushToUsers(StreamObserver<Result> responseObserver) {\\n    Processor<User, User> processor = EmitterProcessor.create();\\n    Publisher<User> publisher = processor;\\n    Subscriber<User> subscriber = processor;\\n    // Push one-by-one by subscribing publisher\\n    ...\\n\\n      return new StreamObserver<User>() {\\n        // subscribe user data\\n        @Override public void onNext(User user) { processor.onNext(user); }\\n        @Override public void onError(Throwable throwable) { processor.onError(throwable); }\\n        @Override public void onCompleted() {\\n            responseObserver.onNext(Result.newBuilder().setStatus(200).build());\\n            responseObserver.onCompleted();\\n        }\\n    };\\n}\\n```\\n\\n\uC791\uC131\uD55C gRPC \uCF54\uB4DC\uB97C Armeria\uC5D0\uC11C \uC2E4\uD589\uD574\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n```\\nimport com.linecorp.armeria.server.Server;\\nimport com.linecorp.armeria.server.grpc.GrpcService;\\n\\n// Add your grpc service to Armeria GrpcService\\nvar grpcService = GrpcService.builder()\\n                             .addService(new UserServiceImpl())\\n                             .build();\\n\\nvar server = Server.builder()\\n                   .http(8080)\\n                   .serviceUnder(\u201C/grpc\u201D, grpcService)\\n                   .serviceUnder(\u201C/docs\u201D, new DocService())\\n                   .build();\\n```\\n\\n\uC774\uB807\uAC8C \uB9CC\uB4E0 \uC2A4\uD2B8\uB9BC \uC11C\uBC84\uB97C \uC774\uC6A9\uD574 \uC791\uC740 \uBA54\uBAA8\uB9AC\uB85C\uB3C4 \uB9CE\uC740 \uC591\uC758 \uB370\uC774\uD130\uB97C \uC2A4\uD2B8\uB9BC \uD615\uD0DC\uB85C \uCC98\uB9AC\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n## \uB9C8\uC774\uD06C\uB85C \uC11C\uBE44\uC2A4\uB97C \uC704\uD55C Armeria\uC758 \uAE30\uB2A5\\n\\nArmeria\uB97C \uD1B5\uD574 Reactive Streams\uB97C \uD65C\uC6A9\uD558\uBA74 \uB9CE\uC740 \uC591\uC758 \uB370\uC774\uD130\uC640 \uD2B8\uB799\uD53D\uC744 \uC720\uC5F0\uD558\uAC8C \uCC98\uB9AC\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uB610\uD55C RPC\uB97C \uD1B5\uD574\uC11C \uB9C8\uC774\uD06C\uB85C \uC11C\uBE44\uC2A4\uAC04 \uD1B5\uC2E0\uB3C4 \uC27D\uAC8C \uCC98\uB9AC\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n\uC774\uC678\uC5D0\uB3C4 \uC544\uB798\uC640 \uAC19\uC774 \uB9C8\uC774\uD06C\uB85C \uC11C\uBE44\uC2A4\uC5D0 \uD544\uC694\uD55C \uB2E4\uC591\uD55C \uAE30\uB2A5\uC744 \uC81C\uACF5\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n- \uD074\uB77C\uC6B0\uB4DC \uD658\uACBD\uC5D0\uC11C \uC11C\uBC84\uC758 \uC704\uCE58\uB97C \uD30C\uC545\uD558\uAE30 \uC704\uD574 Kubernetes \uC720\uD615\uC758 DNS(Domain Name System)\uC640 ZooKeeper\uB97C \uD65C\uC6A9\uD55C \uC11C\uBE44\uC2A4 \uAC80\uC0C9(discovery)\uC744 \uC81C\uACF5([\uCC38\uACE0](/docs/server/service-registration#zookeeper-based-service-registration-with-zookeeperupdatinglistener))\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4.\\n- \uAC80\uC0C9\uB41C \uC11C\uBE44\uC2A4\uB294 \uD074\uB77C\uC774\uC5B8\uD2B8 \uCE21 \uB85C\uB4DC \uBC38\uB7F0\uC2F1\uC73C\uB85C \uC9C1\uC811 \uBD80\uD558\uB97C \uBD84\uC0B0\uD558\uBA70 \uC11C\uBC84\uC640 \uD1B5\uC2E0\uD569\uB2C8\uB2E4. \uC774\uB97C \uD1B5\uD574 \uC7A5\uC560\uC810\uC744 \uC904\uC77C \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n- [L7](https://www.nginx.com/resources/glossary/layer-7-load-balancing/)\uC774 \uC544\uB2CC \uD074\uB77C\uC774\uC5B8\uD2B8\uAC00 \uC9C1\uC811 \uC11C\uBC84 \uC0C1\uD0DC\uB97C \uCCB4\uD06C\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n- \uB85C\uADF8\uB97C \uD655\uC778\uD560 \uB54C \uBD84\uC0B0\uB41C \uC11C\uBC84\uC5D0 \uC811\uADFC\uD558\uC9C0 \uC54A\uACE0\uB3C4 \uD655\uC778\uD560 \uC218 \uC788\uB3C4\uB85D Kafka\uB85C \uC811\uC18D \uB85C\uADF8\uB97C \uC804\uC1A1\uD569\uB2C8\uB2E4.\\n- Micrometer\uB97C \uD65C\uC6A9\uD574\uC11C \uD544\uC694\uD55C \uC218\uCE58\uB97C \uC124\uC815, \uC218\uC9D1\uD558\uC5EC Prometheus\uB098 Netflix\uC758 Atlas\uC640 \uAC19\uC740 \uC560\uD50C\uB9AC\uCF00\uC774\uC158 \uBAA8\uB2C8\uD130\uB9C1 \uD234\uB85C \uC804\uC1A1\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/reactive-streams-armeria-2-7.png)\\n\\n## \uB9C8\uCE58\uBA70\\n\\n\uB450 \uBC88\uC5D0 \uAC78\uCCD0 Reactive Streams\uC640 Armeria\uC5D0 \uB300\uD55C \uB0B4\uC6A9\uC744 \uACF5\uC720\uB4DC\uB838\uC2B5\uB2C8\uB2E4. \uD568\uAED8 \uC0B4\uD3B4\uBCF4\uC558\uB4EF Armeria\uB97C \uC774\uC6A9\uD558\uBA74, Reactive Streams\uC640 \uACE0\uC131\uB2A5, \uBE44\uB3D9\uAE30, RPC, HTTP/2\uB97C \uC9C0\uC6D0\uD558\uBA74\uC11C \uC7A5\uC560\uC5D0 \uD0C4\uB825\uC801\uC778, \uBCF4\uB2E4 \uC548\uC804\uD55C \uC11C\uBC84\uB97C \uAD6C\uCD95\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\nArmeria\uC5D0\uC120 \uD3EC\uC2A4\uD305\uC5D0\uC11C \uC5B8\uAE09\uD55C \uAE30\uB2A5 \uC678\uC5D0 \uB354 \uB9CE\uC740 \uAE30\uB2A5\uC744 \uC81C\uACF5\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uC774\uC640 \uAD00\uB828\uD558\uC5EC Armeria\uC758 [\uACF5\uC2DD \uD648\uD398\uC774\uC9C0](https://line.github.io/armeria/index.html)\uC640 \uC544\uB798 \uB9C1\uD06C\uB97C \uCC38\uACE0\uD558\uC2DC\uAE30 \uBC14\uB78D\uB2C8\uB2E4.\\n\\n- GitHub: [line/armeria](https://github.com/line/armeria)\\n- Twitter: [@armeria_project](https://twitter.com/armeria_project)\\n- Chat: [Discord](https://armeria.dev/s/discord)\\n- [API documentation](https://line.github.io/armeria/apidocs/index.html)\\n- Armeria examples: [line/armeria-examples](https://github.com/line/armeria-examples)\\n\\n---\\n\\n#### Footnotes\\n\\n1. [gRPC \uC11C\uBC84\uB97C Armeria\uC5D0\uC11C \uAD6C\uB3D9\uD558\uB294 \uBC95](https://line.github.io/armeria/server-grpc.html)\uACFC [Thrift \uC11C\uBC84\uB97C Armeria\uC5D0\uC11C \uAD6C\uB3D9\uD558\uB294 \uBC95](https://line.github.io/armeria/server-thrift.html)\uC744 \uCC38\uACE0\uD558\uC2DC\uAE30 \uBC14\uB78D\uB2C8\uB2E4.\\n2. Armeria\uC5D0\uC11C \uAE30\uBCF8\uC801\uC73C\uB85C \uC81C\uACF5\uD558\uB294 \uB2E4\uC591\uD55C decorator\uB294 \uACF5\uC2DD \uBB38\uC11C\uC640 \uC544\uB798 Javadoc\uC5D0\uC11C \uD655\uC778\uD574 \uBCFC \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n   - [SimpleDecoratingHttpService](https://line.github.io/armeria/apidocs/com/linecorp/armeria/server/SimpleDecoratingHttpService.html)\uC640 [SimpleDecoratingClient](https://line.github.io/armeria/apidocs/com/linecorp/armeria/client/SimpleDecoratingClient.html)\uC758 Direct Known Subsclasses \uD56D\uBAA9"},{"id":"/2020/02/18/reactive-streams-armeria-1","metadata":{"permalink":"/blog/ko/2020/02/18/reactive-streams-armeria-1","editUrl":"https://github.com/line/armeria/edit/main/site-new/src/content/blog/ko/2020-02-18-reactive-streams-armeria-1.mdx","source":"@site/src/content/blog/ko/2020-02-18-reactive-streams-armeria-1.mdx","title":"Armeria\uB85C Reactive Streams\uC640 \uB180\uC790! - 1","description":"Reactive Streams\uB780?","date":"2020-05-06T10:00:00.000Z","tags":[],"readingTime":9.51,"hasTruncateMarker":true,"authors":[{"name":"\uC5C4\uC775\uD6C8","title":"LINE Plus\uC5D0\uC11C \uC624\uD508\uC18C\uC2A4 Armeria\uC640 Central Dogma\uB97C \uAC1C\uBC1C\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4.","imageURL":"https://github.com/ikhoon.png","key":"ikhunum","page":null}],"frontMatter":{"date":"2020-05-06T10:00","authors":["ikhunum"],"other_languages":{"ja":"/blog/ja/2020/03/26/reactive-streams-armeria-1","en":"/blog/2020/05/06/reactive-streams-armeria-1"}},"unlisted":false,"prevItem":{"title":"Armeria\uB85C Reactive Streams\uC640 \uB180\uC790! - 2","permalink":"/blog/ko/2020/02/19/reactive-streams-armeria-2"},"nextItem":{"title":"Armeria\uC758 \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4 \uC0AC\uC6A9\uD574 \uBCF4\uAE30","permalink":"/blog/ko/2020/04/27/circuit-breakers-armeria"}},"content":"## Reactive Streams\uB780?\\n\\nLINE+\uC5D0\uC11C \uC624\uD508\uC18C\uC2A4 Armeria\uC640 Central Dogma\uB97C \uAC1C\uBC1C\uD558\uACE0 \uC788\uB294 \uC5C4\uC775\uD6C8\uC785\uB2C8\uB2E4. \uC800\uB294 Reactive Streams\uC758 \uAC1C\uB150\uACFC, Reactive Streams\uB97C \uC624\uD508 \uC18C\uC2A4 \uBE44\uB3D9\uAE30 HTTP/2, RPC, REST \uD074\uB77C\uC774\uC5B8\uD2B8/\uC11C\uBC84 \uB77C\uC774\uBE0C\uB7EC\uB9AC\uC778 Armeria\uC5D0\uC11C \uC0AC\uC6A9\uD558\uB294 \uBC29\uBC95\uC5D0 \uB300\uD574 \uACF5\uC720\uD558\uB824\uACE0 \uD558\uB294\uB370\uC694. \uC774\uBC88 \uD3EC\uC2A4\uD305\uC5D0\uC120 \uBA3C\uC800 Reactive Streams\uC758 \uAC1C\uB150\uC744 \uC54C\uC544\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\nReactive Streams\uB294 \uACF5\uC2DD \uD648\uD398\uC774\uC9C0\uC778 [reactive-streams.org](http://reactive-streams.org/)\uC5D0\uC11C \uC544\uB798\uC640 \uAC19\uC774 \uC815\uC758\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n> Reactive Streams is a standard for asynchronous data processing in a streaming fashion with non-blocking back pressure.\\n\\n\uD648\uD398\uC774\uC9C0\uC5D0\uC120 \uB17C\uBE14\uB85C\uD0B9(Non-blocking) \uBC31 \uD504\uB808\uC154(back pressure)\uB97C \uC774\uC6A9\uD55C \uBE44\uB3D9\uAE30 \uB370\uC774\uD130 \uCC98\uB9AC\uC758 \uD45C\uC900\uC774\uB77C\uACE0 \uB9D0\uD558\uACE0 \uC788\uB294\uB370\uC694. \'\uC2A4\uD2B8\uB9AC\uBC0D \uCC98\uB9AC\', \'\uBE44\uB3D9\uAE30(asynchronous) \uBC29\uC2DD\', \'\uBC31 \uD504\uB808\uC154\', \uADF8\uB9AC\uACE0 \'\uD45C\uC900\'\uC774\uB77C\uB294 \uAC01\uAC01\uC758 \uB2E8\uC5B4\uAC00 \uC758\uBBF8\uD558\uB294 \uBC14\uB97C \uC870\uAE08 \uB354 \uC790\uC138\uD788 \uC54C\uC544\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n{/* truncate */}\\n\\n### \uC2A4\uD2B8\uB9AC\uBC0D \uCC98\uB9AC\\n\\n\uC544\uB798 \uADF8\uB9BC\uC740 \uC804\uD1B5\uC801\uC778 \uB370\uC774\uD130 \uCC98\uB9AC \uBC29\uC2DD\uACFC \uC2A4\uD2B8\uB9AC\uBC0D \uCC98\uB9AC \uBC29\uC2DD\uC744 \uBE44\uAD50\uD55C \uADF8\uB9BC\uC785\uB2C8\uB2E4.\\n\\n![](/img/reactive-streams-armeria-1-1.png)\\n\\n\uC67C\uCABD\uC758 \uC804\uD1B5\uC801\uC778 \uB370\uC774\uD130 \uCC98\uB9AC \uBC29\uC2DD\uC5D0\uC11C\uB294, \uB370\uC774\uD130 \uCC98\uB9AC \uC694\uCCAD\uC774 \uC624\uBA74 \uD398\uC774\uB85C\uB4DC(payload)\uB97C \uBAA8\uB450 \uC560\uD50C\uB9AC\uCF00\uC774\uC158\uC758 \uBA54\uBAA8\uB9AC\uC5D0 \uC800\uC7A5\uD55C \uD6C4\uC5D0 \uB2E4\uC74C \uCC98\uB9AC\uB97C \uD574\uC57C \uD569\uB2C8\uB2E4. \uCD94\uAC00\uB85C \uD544\uC694\uD55C \uB370\uC774\uD130\uB3C4 \uC800\uC7A5\uC18C\uC5D0\uC11C \uC870\uD68C\uD558\uC5EC \uBA54\uBAA8\uB9AC\uC5D0 \uC801\uC7AC\uD574\uC57C \uD569\uB2C8\uB2E4. \uC774 \uBC29\uC2DD\uC758 \uBB38\uC81C\uC810\uC740 \uC804\uB2EC\uB41C \uB370\uC774\uD130\uB294 \uBB3C\uB860 \uC800\uC7A5\uC18C\uC5D0\uC11C \uC870\uD68C\uD55C \uB370\uC774\uD130\uAE4C\uC9C0 \uBAA8\uB4E0 \uB370\uC774\uD130\uAC00 \uC560\uD50C\uB9AC\uCF00\uC774\uC158\uC758 \uBA54\uBAA8\uB9AC\uC5D0 \uC801\uC7AC\uB418\uC5B4\uC57C\uB9CC \uC751\uB2F5 \uBA54\uC2DC\uC9C0\uB97C \uB9CC\uB4E4 \uC218 \uC788\uB2E4\uB294 \uAC83\uC785\uB2C8\uB2E4. \uB9CC\uC57D \uD544\uC694\uD55C \uB370\uC774\uD130\uC758 \uD06C\uAE30\uAC00 \uBA54\uBAA8\uB9AC \uC6A9\uB7C9\uBCF4\uB2E4 \uD06C\uB2E4\uBA74 \'out of memory\' \uC5D0\uB7EC\uAC00 \uBC1C\uC0DD\uD558\uAC8C \uB429\uB2C8\uB2E4. \uADF8\uB9AC\uACE0 \uC11C\uBE44\uC2A4\uB97C \uC6B4\uC601\uD558\uB2E4 \uBCF4\uBA74 \uAF2D \uD558\uB098\uC758 \uC694\uCCAD\uC774 \'out of memory\'\uB97C \uBC1C\uC0DD\uC2DC\uD0A4\uC9C0 \uC54A\uB354\uB77C\uB3C4, \uC21C\uAC04\uC801\uC73C\uB85C \uB9CE\uC740 \uC694\uCCAD\uC774 \uBAB0\uB9AC\uBA74\uC11C \uB2E4\uB7C9\uC758 GC(Garbage Collection)\uAC00 \uBC1C\uC0DD, \uC11C\uBC84\uAC00 \uC815\uC0C1\uC801\uC73C\uB85C \uC751\uB2F5\uD558\uC9C0 \uBABB\uD558\uB294 \uACBD\uC6B0\uAC00 \uC885\uC885 \uB098\uD0C0\uB0A9\uB2C8\uB2E4.\\n\\n\uADF8\uB7F0\uB370 \uB9CE\uC740 \uC591\uC758 \uB370\uC774\uD130\uB97C \uCC98\uB9AC\uD558\uB294 \uC560\uD50C\uB9AC\uCF00\uC774\uC158\uC5D0 \uC2A4\uD2B8\uB9BC \uCC98\uB9AC \uBC29\uC2DD\uC744 \uC801\uC6A9\uD558\uBA74, \uD06C\uAE30\uAC00 \uC791\uC740 \uC2DC\uC2A4\uD15C \uBA54\uBAA8\uB9AC\uB85C\uB3C4 \uB9CE\uC740 \uC591\uC758 \uB370\uC774\uD130\uB97C \uCC98\uB9AC\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC785\uB825 \uB370\uC774\uD130\uC5D0 \uB300\uD55C \uD30C\uC774\uD504 \uB77C\uC778\uC744 \uB9CC\uB4E4\uC5B4 \uB370\uC774\uD130\uAC00 \uB4E4\uC5B4\uC624\uB294 \uB300\uB85C \uBB3C \uD750\uB974\uB4EF\uC774 \uAD6C\uB3C5(subscribe)\uD558\uACE0, \uCC98\uB9AC\uD55C \uB4A4, \uBC1C\uD589(publish)\uAE4C\uC9C0 \uD55C \uBC88\uC5D0 \uC5F0\uACB0\uD558\uC5EC \uCC98\uB9AC\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC774\uB807\uAC8C \uD558\uBA74 \uC11C\uBC84\uB294 \uB9CE\uC740 \uC591\uC758 \uB370\uC774\uD130\uB3C4 \uD0C4\uB825\uC801\uC73C\uB85C \uCC98\uB9AC\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n### \uBE44\uB3D9\uAE30 \uBC29\uC2DD\\n\\n\uBE44\uB3D9\uAE30 \uBC29\uC2DD\uC740 \uB3D9\uAE30(synchronous) \uBC29\uC2DD\uACFC \uBE44\uAD50\uD558\uBA70 \uC0B4\uD3B4\uBCF4\uACA0\uC2B5\uB2C8\uB2E4. \uC544\uB798 \uADF8\uB9BC\uC740 \uB3D9\uAE30 \uBC29\uC2DD\uACFC \uBE44\uB3D9\uAE30 \uBC29\uC2DD\uC758 \uCC98\uB9AC \uACFC\uC815\uC744 \uB098\uD0C0\uB0B8 \uADF8\uB9BC\uC785\uB2C8\uB2E4.\\n\\n![](/img/reactive-streams-armeria-1-2.png)\\n\\n\uB3D9\uAE30 \uBC29\uC2DD\uC5D0\uC120 \uD074\uB77C\uC774\uC5B8\uD2B8\uAC00 \uC11C\uBC84\uC5D0 \uC694\uCCAD\uC744 \uBCF4\uB0B4\uBA74 \uC751\uB2F5\uC744 \uBC1B\uAE30 \uC804\uAE4C\uC9C0 \uBE14\uB85C\uD0B9(blocking)\uB429\uB2C8\uB2E4. \uBE14\uB85C\uD0B9\uB41C\uB2E4\uB294 \uAC83\uC740 \uD604\uC7AC \uC2A4\uB808\uB4DC(thread)\uAC00 \uB2E4\uB978 \uC77C\uC744 \uD558\uC9C0 \uBABB\uD558\uACE0 \uAE30\uB2E4\uB9B0\uB2E4\uB294 \uAC83\uC744 \uC758\uBBF8\uD569\uB2C8\uB2E4. \uB530\uB77C\uC11C \uB450 \uAC1C\uC758 \uC694\uCCAD\uC744 A\uC640 B \uC11C\uBC84\uB85C \uBCF4\uB0B4\uBA74, A\uC758 \uC751\uB2F5\uC774 \uB05D\uB098\uACE0 \uB098\uC11C\uC57C B\uB85C \uC694\uCCAD\uC744 \uBCF4\uB0BC \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uD558\uC9C0\uB9CC \uBE44\uB3D9\uAE30 \uBC29\uC2DD\uC5D0\uC11C\uB294 \uD604\uC7AC \uC2A4\uB808\uB4DC\uAC00 \uBE14\uB85C\uD0B9\uB418\uC9C0 \uC54A\uAE30 \uB54C\uBB38\uC5D0 \uB2E4\uB978 \uC77C\uC744 \uACC4\uC18D\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\nA\uC5D0\uAC8C \uC694\uCCAD\uC744 \uBCF4\uB0B8 \uB4A4 \uB2E4\uB978 \uC77C\uC744 \uCC98\uB9AC\uD560 \uC218\uB3C4 \uC788\uACE0, \uD639\uC740 B\uC5D0\uAC8C \uB610 \uB2E4\uB978 \uC694\uCCAD\uC744 \uBCF4\uB0BC \uC218\uB3C4 \uC788\uC2B5\uB2C8\uB2E4. \uB3D9\uAE30 \uBC29\uC2DD\uACFC \uBE44\uAD50\uD558\uC5EC \uBE44\uB3D9\uAE30 \uBC29\uC2DD\uC758 \uC7A5\uC810\uC744 \uC815\uB9AC\uD558\uBA74 \uC544\uB798\uC640 \uAC19\uC2B5\uB2C8\uB2E4.\\n\\n- \uBE60\uB978 \uC18D\uB3C4 - \uB450 \uAC1C\uC758 \uC694\uCCAD\uC744 \uB3D9\uC2DC\uC5D0 \uBCF4\uB0B4\uAE30 \uB54C\uBB38\uC5D0 \uB354 \uBE60\uB978 \uC751\uB2F5 \uC18D\uB3C4\uB97C \uBCF4\uC5EC\uC904 \uAC83\uC785\uB2C8\uB2E4.\\n- \uC801\uC740 \uB9AC\uC18C\uC2A4 \uC0AC\uC6A9 - \uD604\uC7AC \uC2A4\uB808\uB4DC\uAC00 \uBE14\uB85C\uD0B9\uB418\uC9C0 \uC54A\uACE0 \uB2E4\uB978 \uC5C5\uBB34\uB97C \uCC98\uB9AC\uD560 \uC218 \uC788\uC5B4\uC11C \uB354 \uC801\uC740 \uC218\uC758 \uC2A4\uB808\uB4DC\uB85C \uB354 \uB9CE\uC740 \uC591\uC758 \uC694\uCCAD\uC744 \uCC98\uB9AC\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n### \uBC31 \uD504\uB808\uC154\\n\\n\uBC31 \uD504\uB808\uC154\uC5D0 \uB300\uD574 \uC54C\uC544\uBCF4\uAE30 \uC804\uC5D0 [RxJava](https://github.com/ReactiveX/RxJava)\uB85C \uC720\uBA85\uD574\uC9C4 \uC635\uC800\uBC84 \uD328\uD134([observer patten](http://reactivex.io/documentation/observable.html))\uACFC \uD478\uC2DC(push) \uBC29\uC2DD, \uADF8\uB9AC\uACE0 \uD480(pull) \uBC29\uC2DD\uC5D0 \uB300\uD574\uC11C \uC54C\uC544\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n#### \uD478\uC2DC \uBC29\uC2DD\\n\\n![](/img/reactive-streams-armeria-1-3.png)\\n\\n\uC635\uC800\uBC84 \uD328\uD134\uC5D0\uC11C\uB294 \uBC1C\uD589\uC790(publisher)\uAC00 \uAD6C\uB3C5\uC790(subscriber)\uC5D0\uAC8C \uBC00\uC5B4 \uB123\uB294 \uBC29\uC2DD\uC73C\uB85C \uB370\uC774\uD130\uAC00 \uC804\uB2EC\uB429\uB2C8\uB2E4. \uBC1C\uD589\uC790\uB294 \uAD6C\uB3C5\uC790\uC758 \uC0C1\uD0DC\uB97C \uACE0\uB824\uD558\uC9C0 \uC54A\uACE0 \uB370\uC774\uD130\uB97C \uC804\uB2EC\uD558\uB294 \uB370\uC5D0\uB9CC \uCDA9\uC2E4\uD569\uB2C8\uB2E4. \uB9CC\uC57D \uBC1C\uD589\uC790\uAC00 1\uCD08 \uB3D9\uC548 100\uAC1C\uC758 \uBA54\uC2DC\uC9C0\uB97C \uBCF4\uB0B4\uB294\uB370 \uAD6C\uB3C5\uC790\uB294 1\uCD08\uC5D0 10\uAC1C\uBC16\uC5D0 \uCC98\uB9AC\uD558\uC9C0 \uBABB\uD55C\uB2E4\uBA74 \uC5B4\uB5BB\uAC8C \uD574\uC57C \uD560\uAE4C\uC694? \uD050(queue)\uB97C \uC774\uC6A9\uD574\uC11C \uB300\uAE30 \uC911\uC778 \uC774\uBCA4\uD2B8\uB97C \uC800\uC7A5\uD574\uC57C \uD569\uB2C8\uB2E4.\\n\\n![](/img/reactive-streams-armeria-1-4.png)\\n\\n\uC11C\uBC84\uAC00 \uAC00\uC6A9\uD560 \uC218 \uC788\uB294 \uBA54\uBAA8\uB9AC\uB294 \uD55C\uC815\uB418\uC5B4 \uC788\uC2B5\uB2C8\uB2E4. \uB9CC\uC57D \uCD08\uB2F9 100\uAC1C\uC758 \uBA54\uBAA8\uB9AC\uB97C \uACC4\uC18D \uD478\uC2DC\uD55C\uB2E4\uBA74 \uBC84\uD37C\uB294 \uC21C\uC2DD\uAC04\uC5D0 \uC18C\uBAA8\uB418\uACE0 \uB9D0 \uD150\uB370\uC694. \uBC84\uD37C\uB97C \uB2E4 \uC0AC\uC6A9\uD574\uBC84\uB824\uC11C \uC624\uBC84\uD50C\uB85C(overflow)\uAC00 \uBC1C\uC0DD\uD558\uBA74 \uC5B4\uB5BB\uAC8C \uB420\uAE4C\uC694? \uACE0\uC815 \uAE38\uC774 \uBC84\uD37C\uC640 \uAC00\uBCC0 \uAE38\uC774 \uBC84\uD37C\uB85C \uB098\uB204\uC5B4 \uC0B4\uD3B4\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n- \uACE0\uC815 \uAE38\uC774 \uBC84\uD37C: \uC2E0\uADDC\uB85C \uC218\uC2E0\uB41C \uBA54\uC2DC\uC9C0\uB97C \uAC70\uC808\uD569\uB2C8\uB2E4. \uAC70\uC808\uB41C \uBA54\uC2DC\uC9C0\uB294 \uC7AC\uC694\uCCAD\uD558\uAC8C \uB418\uB294\uB370\uC694. \uC7AC\uC694\uCCAD \uACFC\uC815\uC5D0\uC11C \uB124\uD2B8\uC6CC\uD06C\uC640 CPU \uC5F0\uC0B0 \uBE44\uC6A9\uC774 \uCD94\uAC00\uB85C \uBC1C\uC0DD\uD569\uB2C8\uB2E4.\\n\\n![](/img/reactive-streams-armeria-1-5.png)\\n\\n- \uAC00\uBCC0 \uAE38\uC774 \uBC84\uD37C: \uC774\uBCA4\uD2B8\uB97C \uC800\uC7A5\uD560 \uB54C \'out of memory\' \uC5D0\uB7EC\uAC00 \uBC1C\uC0DD\uD558\uBA74\uC11C \uC11C\uBC84 \uD06C\uB798\uC2DC(crash)\uAC00 \uBC1C\uC0DD\uD569\uB2C8\uB2E4. \'\uB204\uAC00 \uADF8\uB807\uAC8C \uAD6C\uD604\uD558\uACA0\uC5B4?\'\uB77C\uACE0 \uC0DD\uAC01\uD560 \uC218 \uC788\uC9C0\uB9CC, Java\uC5D0\uC11C \uB9CE\uC774 \uC0AC\uC6A9\uB418\uB294 `List`\uAC00 \uAC00\uBCC0 \uAE38\uC774 \uC790\uB8CC \uAD6C\uC870\uD615\uC785\uB2C8\uB2E4. \uC608\uB97C \uB4E4\uC5B4 SQL\uB85C \uB9CE\uC740 \uC591\uC758 \uB370\uC774\uD130\uB97C \uC9C8\uC758\uD558\uBA74 DBMS\uB294 \uBC1C\uD589\uC790\uAC00 \uB418\uACE0 \uC5EC\uB7EC\uBD84\uC758 \uC11C\uBC84\uAC00 \uAD6C\uB3C5\uC790\uAC00 \uB418\uC5B4 `List` \uC790\uB8CC \uAD6C\uC870\uD615\uC5D0 \uB370\uC774\uD130\uB97C \uC804\uBD80 \uB2F4\uC73C\uB824\uACE0 \uD558\uB2E4\uAC00 \uB2E4\uB7C9\uC758 GC\uAC00 \uBC1C\uC0DD\uD558\uBA74\uC11C \uC11C\uBC84\uAC00 \uC815\uC0C1\uC801\uC73C\uB85C \uC751\uB2F5\uD560 \uC218 \uC5C6\uB294 \uC0C1\uD0DC\uC5D0 \uC774\uB97C \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/reactive-streams-armeria-1-6.png)\\n\\n\uC774 \uBB38\uC81C\uB97C \uC5B4\uB5BB\uAC8C \uD574\uACB0\uD560 \uC218 \uC788\uC744\uAE4C\uC694? \uBC1C\uD589\uC790\uAC00 \uB370\uC774\uD130\uB97C \uC804\uB2EC\uD560 \uB54C \uAD6C\uB3C5\uC790\uAC00 \uD544\uC694\uD55C \uB9CC\uD07C\uB9CC \uC804\uB2EC\uD558\uBA74 \uD574\uACB0\uD560 \uC218 \uC788\uC9C0 \uC54A\uC744\uAE4C\uC694? \uC774\uAC8C \uBC14\uB85C \uBC31 \uD504\uB808\uC154\uC758 \uAE30\uBCF8 \uC6D0\uB9AC\uC785\uB2C8\uB2E4.\\n\\n#### \uD480 \uBC29\uC2DD\\n\\n\uD480 \uBC29\uC2DD\uC5D0\uC120 \uAD6C\uB3C5\uC790\uAC00 10\uAC1C\uB97C \uCC98\uB9AC\uD560 \uC218 \uC788\uB2E4\uBA74 \uBC1C\uD589\uC790\uC5D0\uAC8C 10\uAC1C\uB9CC \uC694\uCCAD\uD569\uB2C8\uB2E4. \uBC1C\uD589\uC790\uB294 \uC694\uCCAD\uBC1B\uC740 \uB9CC\uD07C\uB9CC \uC804\uB2EC\uD558\uBA74 \uB418\uACE0, \uAD6C\uB3C5\uC790\uB294 \uB354 \uC774\uC0C1 \'out of memory\' \uC5D0\uB7EC\uB97C \uAC71\uC815\uD558\uC9C0 \uC54A\uC544\uB3C4 \uB429\uB2C8\uB2E4.\\n\\n![](/img/reactive-streams-armeria-1-7.png)\\n\\n\uC5EC\uAE30\uC11C \uC880 \uB354 \uD0C4\uB825\uC801\uC73C\uB85C \uC801\uC6A9\uD558\uC5EC, \uAD6C\uB3C5\uC790\uAC00 \uC774\uBBF8 8\uAC1C\uC758 \uC77C\uC744 \uCC98\uB9AC\uD558\uACE0 \uC788\uB2E4\uBA74 \uCD94\uAC00\uB85C 2\uAC1C\uB9CC \uB354 \uC694\uCCAD\uD558\uC5EC \uC790\uC2E0\uC774 \uD604\uC7AC \uCC98\uB9AC \uAC00\uB2A5\uD55C \uBC94\uC704 \uB0B4\uC5D0\uC11C\uB9CC \uBA54\uC2DC\uC9C0\uB97C \uBC1B\uAC8C \uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uD480 \uBC29\uC2DD\uC5D0\uC120 \uC774\uB807\uAC8C \uC804\uB2EC\uB418\uB294 \uBAA8\uB4E0 \uB370\uC774\uD130\uC758 \uD06C\uAE30\uB97C \uAD6C\uB3C5\uC790\uAC00 \uACB0\uC815\uD569\uB2C8\uB2E4. \uC774\uB7F0 \uB2E4\uC774\uB098\uBBF9 \uD480 \uBC29\uC2DD\uC758 \uB370\uC774\uD130 \uC694\uCCAD\uC744 \uD1B5\uD574\uC11C \uAD6C\uB3C5\uC790\uAC00 \uC218\uC6A9\uD560 \uC218 \uC788\uB294 \uB9CC\uD07C\uB9CC \uB370\uC774\uD130\uB97C \uC694\uCCAD\uD558\uB294 \uBC29\uC2DD\uC774 \uBC31 \uD504\uB808\uC154\uC785\uB2C8\uB2E4.\\n\\n### \uD45C\uC900\\n\\nReactive Streams\uB294 \uD45C\uC900\uD654\uB41C API\uC785\uB2C8\uB2E4. \uC65C \uD45C\uC900\uD654\uAC00 \uD544\uC694\uD588\uACE0 \uC5B4\uB5A4 \uACFC\uC815\uC744 \uD1B5\uD574 \uD45C\uC900\uD654\uAC00 \uB418\uC5C8\uB294\uC9C0 \uC54C\uC544\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\nReactive Streams\uB294 2013\uB144\uC5D0 Netflix\uC640 Pivotal, Lightbend\uC758 \uC5D4\uC9C0\uB2C8\uC5B4\uB4E4\uC774 \uCC98\uC74C \uAC1C\uBC1C\uD558\uAE30 \uC2DC\uC791\uD588\uC2B5\uB2C8\uB2E4.\\nNetflix\uB294 RxJava, Pivotal\uC740 WebFlux, \uADF8\uB9AC\uACE0 Lightbend\uB294 \uBD84\uC0B0 \uCC98\uB9AC \uC561\uD130(actor) \uBAA8\uB378\uC744 \uAD6C\uD604\uD55C Akka\uB97C \uB9CC\uB4E0 \uD68C\uC0AC\uC778\uB370\uC694. \uBAA8\uB450 \uC2A4\uD2B8\uB9BC API\uAC00 \uAF2D \uD544\uC694\uD55C \uD68C\uC0AC\uC600\uC2B5\uB2C8\uB2E4. \uADF8\uB7F0\uB370 \uC2A4\uD2B8\uB9BC\uC740 \uC11C\uB85C \uC720\uAE30\uC801\uC73C\uB85C \uC5EE\uC5EC\uC11C \uD758\uB7EC\uC57C \uC758\uBBF8\uAC00 \uC788\uC2B5\uB2C8\uB2E4. \uB370\uC774\uD130\uAC00 \uC9C0\uC18D\uC801\uC73C\uB85C \uD750\uB974\uAE30 \uC704\uD574\uC11C\uB294 \uC11C\uB85C \uB2E4\uB978 \uD68C\uC0AC\uAC00 \uACF5\uD1B5\uC758 \uC2A4\uD399\uC744 \uC124\uC815\uD558\uACE0 \uAD6C\uD604\uD574\uC57C \uD569\uB2C8\uB2E4. \uADF8\uB798\uC11C \uD45C\uC900\uD654\uAC00 \uD544\uC694\uD588\uC2B5\uB2C8\uB2E4.\\n\\nReactive Streams\uC5D0\uC120 2015\uB144 4\uC6D4\uC5D0 JVM\uC5D0\uC11C \uC0AC\uC6A9\uD558\uAE30 \uC704\uD55C [1.0.0](https://www.reactive-streams.org/announce-1.0.0) \uC2A4\uD399\uC744 \uB9B4\uB9AC\uC2A4\uD588\uC2B5\uB2C8\uB2E4. \uADF8\uB9AC\uACE0 2017\uB144 9\uC6D4\uC5D0, Reactive Streams\uC758 API\uC640 \uC2A4\uD399, \uD480(pull) \uBC29\uC2DD \uC0AC\uC6A9 \uC6D0\uCE59\uC744 \uADF8\uB300\uB85C \uD3EC\uD305\uD574\uC11C [Flow API](https://docs.oracle.com/javase/9/docs/api/java/util/concurrent/Flow.html)\uB77C\uB294 \uC774\uB984\uC73C\uB85C `java.util.concurrent` \uD328\uD0A4\uC9C0 \uC544\uB798 \uD3EC\uD568\uC2DC\uD0A8 Java 9\uC774 \uB9B4\uB9AC\uC2A4\uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uC774\uB294 \uCEE4\uBBA4\uB2C8\uD2F0\uC640 \uC77C\uBD80 \uAE30\uC5C5\uC5D0\uC11C \uC8FC\uB3C4\uD574 \uAC1C\uBC1C\uD588\uB358 Reactive Streams\uAC00 Java\uC758 \uACF5\uC2DD \uAE30\uB2A5\uC774 \uB418\uC5C8\uB2E4\uB294 \uAC83\uC744 \uC758\uBBF8\uD569\uB2C8\uB2E4. \uC774\uC5B4\uC11C 3\uB2EC \uB4A4, Reactive Streams\uC5D0\uC11C Flow\uC640 \uC0C1\uD638 \uBCC0\uD658\uC774 \uAC00\uB2A5\uD55C \uC5B4\uB311\uD130\uB97C \uB9B4\uB9AC\uC2A4\uD558\uBA74\uC11C, \uAE30\uC874\uC5D0 \uB9CC\uB4E4\uC5B4\uC9C4 \uB77C\uC774\uBE0C\uB7EC\uB9AC\uB97C \uC0AC\uC6A9\uD560 \uC218 \uC788\uAC8C \uB418\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/reactive-streams-armeria-1-8.png)\\n\\n## Reactive Streams API\\n\\nReactive Streams\uB294 \uADF8\uB7F4\uB4EF\uD55C \uB2E8\uC5B4\uB85C \uC124\uBA85\uB418\uC5B4 \uBB54\uAC00 \uBCF5\uC7A1\uD560 \uAC83 \uAC19\uC9C0\uB9CC, \uC2E4\uC81C \uB0B4\uBD80\uB294 \uC544\uC8FC \uAC04\uB2E8\uD55C API\uB4E4\uC758 \uC870\uD569\uC73C\uB85C \uAD6C\uC131\uB418\uC5B4 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n```\\npublic interface Publisher<T> {\\n   public void subscribe(Subscriber<? super T> s);\\n}\\n\\npublic interface Subscriber<T> {\\n   public void onSubscribe(Subscription s);\\n   public void onNext(T t);\\n   public void onError(Throwable t);\\n   public void onComplete();\\n}\\n\\npublic interface Subscription {\\n   public void request(long n);\\n   public void cancel();\\n}\\n```\\n\\n- `Publisher`\uC5D0\uB294 `Subscriber`\uC758 \uAD6C\uB3C5\uC744 \uBC1B\uAE30 \uC704\uD55C `subscribe` API \uD558\uB098\uB9CC \uC788\uC2B5\uB2C8\uB2E4.\\n- `Subscriber`\uC5D0\uB294 \uBC1B\uC740 \uB370\uC774\uD130\uB97C \uCC98\uB9AC\uD558\uAE30 \uC704\uD55C `onNext`, \uC5D0\uB7EC\uB97C \uCC98\uB9AC\uD558\uB294 `onError`, \uC791\uC5C5 \uC644\uB8CC \uC2DC \uC0AC\uC6A9\uD558\uB294 `onComplete`, \uADF8\uB9AC\uACE0 \uB9E4\uAC1C \uBCC0\uC218\uB85C `Subscription`\uC744 \uBC1B\uB294 `onSubscribe` API\uAC00 \uC788\uC2B5\uB2C8\uB2E4.\\n- `Subscription`\uC740 n\uAC1C\uC758 \uB370\uC774\uD130\uB97C \uC694\uCCAD\uD558\uAE30 \uC704\uD55C `request`\uC640 \uAD6C\uB3C5\uC744 \uCDE8\uC18C\uD558\uAE30 \uC704\uD55C `cancel` API\uAC00 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n\uC774\uC81C Reactive Streams\uC5D0\uC11C \uC704 API\uB97C \uC0AC\uC6A9\uD558\uB294 \uD750\uB984\uC744 \uC0B4\uD3B4\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n1. `Subscriber`\uAC00 `subscribe` \uD568\uC218\uB97C \uC0AC\uC6A9\uD574 `Publisher`\uC5D0\uAC8C \uAD6C\uB3C5\uC744 \uC694\uCCAD\uD569\uB2C8\uB2E4.\\n2. `Publisher`\uB294 `onSubscribe` \uD568\uC218\uB97C \uC0AC\uC6A9\uD574 `Subscriber`\uC5D0\uAC8C `Subscription`\uC744 \uC804\uB2EC\uD569\uB2C8\uB2E4.\\n\\n   ![](/img/reactive-streams-armeria-1-9.png)\\n\\n3. \uC774\uC81C `Subscription`\uC740 `Subscriber`\uC640 `Publisher` \uAC04 \uD1B5\uC2E0\uC758 \uB9E4\uAC1C\uCCB4\uAC00 \uB429\uB2C8\uB2E4. `Subscriber`\uB294 `Publisher`\uC5D0\uAC8C \uC9C1\uC811 \uB370\uC774\uD130 \uC694\uCCAD\uC744 \uD558\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4. `Subscription`\uC758 `request` \uD568\uC218\uB97C \uD1B5\uD574 `Publisher`\uC5D0\uAC8C \uC804\uB2EC\uD569\uB2C8\uB2E4.\\n4. `Publisher`\uB294 `Subscription`\uC744 \uD1B5\uD574 `Subscriber`\uC758 `onNext`\uC5D0 \uB370\uC774\uD130\uB97C \uC804\uB2EC\uD558\uACE0, \uC791\uC5C5\uC774 \uC644\uB8CC\uB418\uBA74 `onComplete`, \uC5D0\uB7EC\uAC00 \uBC1C\uC0DD\uD558\uBA74 `onError` \uC2DC\uADF8\uB110\uC744 \uC804\uB2EC\uD569\uB2C8\uB2E4.\\n5. `Subscriber`\uC640 `Publisher`, `Subscription`\uC774 \uC11C\uB85C \uC720\uAE30\uC801\uC73C\uB85C \uC5F0\uACB0\uB418\uC5B4 \uD1B5\uC2E0\uC744 \uC8FC\uACE0\uBC1B\uC73C\uBA74\uC11C `subscribe`\uBD80\uD130 `onComplete`\uAE4C\uC9C0 \uC5F0\uACB0\uB418\uACE0, \uC774\uB97C \uD1B5\uD574 \uBC31 \uD504\uB808\uC154\uAC00 \uC644\uC131\uB429\uB2C8\uB2E4.\\n\\n   ![](/img/reactive-streams-armeria-1-10.png)\\n\\n\uBC31 \uD504\uB808\uC154\uAC00 \uC88B\uC740 \uAC74 \uC54C\uACA0\uB294\uB370, \uACFC\uC5F0 \uC5B4\uB5BB\uAC8C \uC0AC\uC6A9\uD558\uB294 \uAC78\uAE4C\uC694?\\nReactive Streams API\uB294 [GitHub](https://github.com/reactive-streams/reactive-streams-jvm/tree/master/api/src/main/java/org/reactivestreams)\uC5D0 \uB4E4\uC5B4\uAC00\uC11C \uC0B4\uD3B4\uBD10\uB3C4 \uC704\uC5D0\uC11C \uC0B4\uD3B4\uBCF8 \uC778\uD130\uD398\uC774\uC2A4\uAC00 \uC804\uBD80\uC785\uB2C8\uB2E4. \uB530\uB85C \uAD6C\uD604\uCCB4\uAC00 \uC5C6\uC2B5\uB2C8\uB2E4.\\n\\n\uADF8\uB807\uB2E4\uBA74 \uC9C1\uC811 \uAD6C\uD604\uD574\uC11C \uC0AC\uC6A9\uD558\uBA74 \uB420\uAE4C\uC694? \uC55E\uC11C \uB098\uC628 \uADDC\uCE59\uB300\uB85C `Publisher` \uC778\uD130\uD398\uC774\uC2A4\uB97C \uAD6C\uD604\uD558\uACE0 \uC774\uB97C \uAD6C\uB3C5\uD560 \uB54C `Subscription`\uC744 \uC0DD\uC131\uD574\uC11C \uB118\uACA8\uC8FC\uB3C4\uB85D \uAD6C\uD604\uD560 \uC218\uB294 \uC788\uC2B5\uB2C8\uB2E4. \uD558\uC9C0\uB9CC \uC774\uAC8C \uC804\uBD80\uAC00 \uC544\uB2D9\uB2C8\uB2E4.\\nReactive Streams\uC5D0\uB294 API \uC678\uC5D0\uB3C4 [\uBA85\uC138\uC11C](https://github.com/reactive-streams/reactive-streams-jvm#specification)\uAC00 \uC788\uB294\uB370\uC694. \uC774 \uBA85\uC138\uC11C\uC5D0\uB294 \uB2E8\uC21C\uD55C \uC778\uD130\uD398\uC774\uC2A4\uC640\uB294 \uB2EC\uB9AC \uAD6C\uD604 \uC2DC \uB530\uB77C\uC57C \uD558\uB294 \uADDC\uCE59\uC774 \uBCF5\uC7A1\uD558\uAC8C \uBA85\uC138\uB418\uC5B4 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/reactive-streams-armeria-1-11.png)\\n\\n\uC774 \uBA85\uC138\uC5D0 \uB9DE\uCDB0 \uC9C1\uC811 \uAD6C\uD604\uD55C \uAE30\uB2A5\uC740 [Reative Streams TCK](https://github.com/reactive-streams/reactive-streams-jvm/tree/master/tck)\uB77C\uB294 \uD234\uB85C \uAC80\uC99D\uD560 \uC218 \uC788\uB294\uB370\uC694. \uD574\uB2F9 \uBD84\uC57C\uC758 \uC804\uBB38\uAC00\uAC00 \uC544\uB2C8\uB77C\uBA74 \uBAA8\uB4E0 \uADDC\uCE59\uC744 \uB9CC\uC871\uD558\uB3C4\uB85D \uAD6C\uD604\uD558\uB294 \uAC8C \uAF64\uB098 \uAE4C\uB2E4\uB85C\uC6B4 \uC77C\uC785\uB2C8\uB2E4. \uD2B9\uD788 `Publisher`\uB97C \uAD6C\uD604\uD558\uB294 \uAC8C \uC5B4\uB835\uC2B5\uB2C8\uB2E4.\\nJava\uC758 \uC720\uBA85\uD55C Reactive Streams \uAD6C\uD604\uCCB4 \uC911 \uD558\uB098\uC778 [Project Reactor](https://projectreactor.io/)\uC758 GitHub\uC5D0 \uC62C\uB77C\uC628 \uC774\uC288\uB97C \uC0B4\uD3B4\uBCF4\uBA74, \uC5B4\uB5A4 \uC0AC\uC6A9\uC790\uAC00 \uC790\uC2E0\uC774 \uB9CC\uB4E0 \uCEE4\uC2A4\uD140 `Publisher`\uAC00 Flux\uC640 \uC798 \uC5F0\uACB0\uB418\uC9C0 \uC54A\uB294\uB2E4\uB294 \uB0B4\uC6A9\uC73C\uB85C \uC774\uC288\uB97C \uC62C\uB824\uB193\uC740 \uAC8C \uC788\uC2B5\uB2C8\uB2E4([\uCC38\uACE0](https://github.com/reactor/reactor-core/issues/482)). \uC774\uC5D0 \uB300\uD55C Project Reactor\uC758 \uB2F5\uBCC0\uC740 \uB2E8\uD638\uD569\uB2C8\uB2E4. \'\uB9CC\uB4E4\uC9C0 \uB9C8\uC138\uC694!\'\uB77C\uACE0 \uB2F5\uBCC0\uD588\uC2B5\uB2C8\uB2E4. \uD559\uC2B5 \uCC28\uC6D0\uC5D0\uC11C \uD1A0\uC774 \uD504\uB85C\uC81D\uD2B8\uB85C \uB9CC\uB4DC\uB294 \uAC83\uC740 \uC800\uB3C4 \uCD94\uCC9C\uD569\uB2C8\uB2E4. \uACF5\uBD80\uB3C4 \uB418\uACE0, \uC88B\uC2B5\uB2C8\uB2E4. \uD558\uC9C0\uB9CC \uC2E4\uC81C \uC6B4\uC601\uC5D0\uC11C \uC0AC\uC6A9\uD560 \uCF54\uB4DC\uB77C\uBA74 \uAC80\uC99D\uB418\uC9C0 \uC54A\uC740 \uCF54\uB4DC\uBCF4\uB2E4\uB294, `Flux.create()`\uC640 \uAC19\uC740 \uC0DD\uC131\uC790 \uD568\uC218\uB97C \uD65C\uC6A9\uD574\uC11C `Publisher`\uB97C \uB9CC\uB4DC\uB294 \uAC8C \uC88B\uB2E4\uACE0 \uC0DD\uAC01\uD569\uB2C8\uB2E4.\\nReactive Streams\uB97C \uC0AC\uC6A9\uD558\uB824\uBA74 \uC9C1\uC811 \uAD6C\uD604\uD558\uB294 \uAC83\uBCF4\uB2E4\uB294 \uC774\uBBF8 \uC798 \uB9CC\uB4E4\uC5B4\uC838\uC11C \uAC80\uC99D\uAE4C\uC9C0 \uBC1B\uC740 \uAD6C\uD604\uCCB4\uB97C \uC0AC\uC6A9\uD558\uB294 \uAC8C \uC88B\uC2B5\uB2C8\uB2E4. \uADF8\uB807\uB2E4\uBA74 \uC774\uB7F0 \uAD6C\uD604\uCCB4\uC5D0\uB294 \uC5B4\uB5A4 \uAC8C \uC788\uC744\uAE4C\uC694?\\n\\n## Reactive Stream \uAD6C\uD604\uCCB4\uC640 \uC0C1\uD638\uC6B4\uC601\uC131(interoperability)\\n\\nReactive Streams\uC5D0\uB294 [\uB2E4\uC591\uD55C \uAD6C\uD604\uCCB4](https://en.wikipedia.org/wiki/Reactive_Streams#Adoption)\uAC00 \uC874\uC7AC\uD569\uB2C8\uB2E4. \uAC01\uAC01\uC758 \uAD6C\uD604\uCCB4\uB294 \uC11C\uB85C \uD2B9\uC131\uC774 \uC870\uAE08\uC529 \uB2E4\uB974\uAE30 \uB54C\uBB38\uC5D0 \uC0C1\uD669\uC5D0 \uB530\uB77C, \uD544\uC694\uC5D0 \uB9DE\uAC8C \uACE8\uB77C\uC11C \uC0AC\uC6A9\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n- \uC21C\uC218\uD558\uAC8C \uC2A4\uD2B8\uB9BC \uC5F0\uC0B0 \uCC98\uB9AC\uB9CC \uD544\uC694\uD558\uB2E4\uBA74 [RxJava](https://github.com/ReactiveX/RxJava)\uB098 [Reactor Core](https://github.com/reactor/reactor-core), [Akka Streams](https://doc.akka.io/docs/akka/current/stream/index.html) \uB4F1\uC744 \uC0AC\uC6A9\uD558\uBA74 \uB429\uB2C8\uB2E4.\\n- \uC800\uC7A5\uC18C\uC758 \uB370\uC774\uD130\uB97C Reactive Streams\uB85C \uC870\uD68C\uD558\uACE0 \uC2F6\uB2E4\uBA74 [ReactiveMongo](http://reactivemongo.org/)\uB098 [Slick](http://scala-slick.org/) \uB4F1\uC744 \uC0AC\uC6A9\uD558\uBA74 \uB429\uB2C8\uB2E4.\\n- \uC6F9 \uD504\uB85C\uADF8\uB798\uBC0D\uACFC \uC5F0\uACB0\uB41C Reactive Streams\uAC00 \uD544\uC694\uD558\uB2E4\uBA74 [Armeria](https://line.github.io/armeria/)\uC640 [Vert.x](https://vertx.io/), [Play Framework](https://www.playframework.com/), [Spring WebFlux](https://docs.spring.io/spring/docs/current/spring-framework-reference/web-reactive.html#webflux)\uB97C \uD65C\uC6A9\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n\uC774\uB807\uAC8C \uAC01\uAC01 \uD2B9\uC131\uC774 \uB2E4\uB978 \uAD6C\uD604\uCCB4\uB4E4\uC740 \uBAA8\uB450 Reactive Streams\uB97C \uD1B5\uD574\uC11C \uC11C\uB85C \uD1B5\uC2E0\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n### Reactive Stream \uC0C1\uD638 \uC6B4\uC601\\n\\n![](/img/reactive-streams-armeria-1-12.png)\\n\\nRxJava\uC758 `Observable`\uB294 Reactive Streams\uB97C \uD1B5\uD574\uC11C Armeria\uC758 `HttpResponse`\uB098 Project Reactor\uC758 `Flux`\uB85C \uBCC0\uD658\uB420 \uC218 \uC788\uACE0, MongoDB\uC758 `DataPublisher`\uB294 Akka Streams\uC758 `Source`\uB97C \uD1B5\uD574 \uC2A4\uD2B8\uB9BC \uC5F0\uC0B0\uC744 \uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n\uC608\uB97C \uB4E4\uC5B4 MongoDB\uC5D0\uC11C \uC870\uD68C\uD55C \uB370\uC774\uD130\uB97C \uC5F0\uC0B0 \uCC98\uB9AC\uD55C \uD6C4 HTTP \uC751\uB2F5\uC73C\uB85C \uBCF4\uB0B8\uB2E4\uACE0 \uAC00\uC815\uD574 \uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\nReactive Streams\uB97C \uC774\uC6A9\uD574\uC11C MongoDB\uC5D0\uC11C \uB370\uC774\uD130\uB97C \uC870\uD68C\uD558\uBA74 \uC6B0\uC120 \uB370\uC774\uD130\uB97C \uAD6C\uB3C5 \uBC1B\uC744 \uC218 \uC788\uB294 `Pulisher`\uB9CC \uBC18\uD658\uB429\uB2C8\uB2E4.\\nSubscriber\uAC00 Subscription\uC744 \uD1B5\uD574 request\uB97C \uD638\uCD9C\uD558\uAE30 \uC804\uAE4C\uC9C4, \uC2E4\uC81C \uB370\uC774\uD130\uB294 \uC804\uB2EC\uB418\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4.\\n\\n```\\n// Initiate MongoDB FindPublisher\\nFindPublisher<Document> mongoDBUsers = mongodbCollection.find();\\n```\\n\\n\uC544\uB798 \uCF54\uB4DC\uC640 \uAC19\uC774`Obsevable`\uC758 `fromPublisher`\uB97C \uD1B5\uD574\uC11C MongoDB\uC758 `FindPublisher`\uC640 \uC5F0\uACB0\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uADF8\uB9AC\uACE0 `map` \uC5F0\uC0B0\uC790\uB97C \uC774\uC6A9\uD574 \uC870\uD68C \uACB0\uACFC\uC5D0\uC11C `age` \uD544\uB4DC\uB97C \uCD94\uCD9C\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n```\\n// MongoDB FindPublisher -> RxJava Observable\\nObservable<Integer> rxJavaAllAges =\\n    Observable.fromPublisher(mongoDBUsers)\\n              .map(document -> document.getInteger(\u201Cage\u201D));\\n```\\n\\nRxJava\uC758 `Observable`\uC740 \uC635\uC800\uBC84 \uD328\uD134\uC73C\uB85C \uAD6C\uD604\uB418\uC5B4 \uC788\uAE30 \uB54C\uBB38\uC5D0, \uC774\uB97C Reactive Streams\uB85C \uBCC0\uD658\uD558\uAE30 \uC704\uD574\uC11C\uB294 \uC544\uB798 \uCF54\uB4DC\uC640 \uAC19\uC774 `toFlowable` \uD568\uC218\uB97C \uC774\uC6A9\uD574\uC57C \uD569\uB2C8\uB2E4. \uBCC0\uD658 \uD6C4 `Flux`\uC758 `from` \uD568\uC218\uB97C \uC774\uC6A9\uD574 RxJava\uC758 `Flowable`\uACFC `Flux`\uB97C \uC5F0\uACB0\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n```\\n// RxJava Observable -> Reactor Flux\\nFlux<HttpData> fluxHttpData =\\n    Flux.from(rxJavaAllAges.toFlowable(BackpressureStrategy.DROP))\\n        .map(age -> HttpData.ofAscii(age.toString()));\\n```\\n\\nFlux \uC790\uB8CC \uAD6C\uC870\uB97C HTTP \uC751\uB2F5\uC73C\uB85C \uC0AC\uC6A9\uD558\uB824\uBA74 \uC544\uB798\uC640 \uAC19\uC774 \uB370\uC774\uD130 \uC55E\uC5D0 HTTP \uD5E4\uB354\uB97C \uBD99\uC5EC\uC57C \uD569\uB2C8\uB2E4. \uADF8 \uD6C4 Armeria\uC758 HTTP \uC751\uB2F5\uC73C\uB85C \uC0AC\uC6A9\uD558\uAE30 \uC704\uD574 `HttpResponse.of`\uB97C \uD638\uCD9C\uD574 Flux\uC640 \uC5F0\uACB0\uD569\uB2C8\uB2E4.\\n\\n```\\n// Reactor Flux -> Armeria HttpResponse\\nHttpResponse.of(Flux.concat(httpHeaders, fluxHttpData));\\n```\\n\\n\uC55E\uC11C\uB3C4 \uC5B8\uAE09\uD588\uC9C0\uB9CC \uBA85\uC2EC\uD560 \uAC83\uC740, \uC77C\uBC18\uC801\uC778 `Iterator`\uC640\uB294 \uB2EC\uB9AC \uC544\uC9C1 \uC2E4\uC81C \uC5F0\uC0B0(\uBCC0\uD658, \uC870\uC791, \uACC4\uC0B0 \uB4F1)\uC740 \uC804\uD600 \uC77C\uC5B4\uB098\uC9C0 \uC54A\uC558\uB2E4\uB294 \uC810\uC785\uB2C8\uB2E4. \uB2E8\uC9C0 \uB370\uC774\uD130\uAC00 \uC5B4\uB5BB\uAC8C `Subscriber`\uC5D0\uAC8C \uD758\uB7EC\uAC08\uC9C0 \uADF8 \uD589\uC704\uB97C \uAE30\uC220\uD55C \uAC83\uBFD0\uC785\uB2C8\uB2E4.\\nReactive Streams\uC5D0\uC11C\uB294 `Subscriber`\uAC00 \uB370\uC774\uD130\uB97C \uC694\uCCAD\uD558\uAE30 \uC804\uAE4C\uC9C0\uB294 \uC544\uBB34\uB7F0 \uB370\uC774\uD130\uB3C4 \uC804\uC1A1\uD558\uC9C0 \uC54A\uC544\uC57C \uD569\uB2C8\uB2E4.\\n\\n## \uB9C8\uCE58\uBA70\\n\\n\uC774\uBC88 \uD3EC\uC2A4\uD305\uC5D0\uC11C\uB294 Reactive Streams\uC640 \uADF8 \uAD6C\uD604\uCCB4, \uADF8\uB9AC\uACE0 \uC0C1\uD638\uC6B4\uC601\uC131\uC5D0 \uB300\uD574 \uC54C\uC544\uBCF4\uC558\uC2B5\uB2C8\uB2E4.\\nReactive Streams\uB97C \uC6F9 \uD504\uB85C\uADF8\uB798\uBC0D\uC5D0\uC11C \uD65C\uC6A9\uD558\uAE30 \uC704\uD574\uC11C\uB294 HTTP \uC694\uCCAD\uACFC \uC751\uB2F5\uC5D0 \uBC31 \uD504\uB808\uC154\uB97C \uC774\uC6A9\uD574\uC57C \uD569\uB2C8\uB2E4. \uC774\uB97C \uD1B5\uD574 \uC720\uC785\uB418\uB294 \uD2B8\uB798\uD53D\uC758 \uC591\uC5D0 \uD0C4\uB825\uC801\uC73C\uB85C \uBC18\uC751\uD574\uC57C \uD558\uB294\uB370\uC694. [\uB2E4\uC74C \uD3EC\uC2A4\uD305](/blog/ko/2020/02/19/reactive-streams-armeria-2)\uC5D0\uC120 \uC774\uC640 \uAD00\uB828\uD574 Armeria\uC5D0\uC11C Reactive Streams\uB97C \uC5B4\uB5BB\uAC8C \uC0AC\uC6A9\uD558\uACE0 \uC788\uB294\uC9C0 \uC790\uC138\uD788 \uC54C\uC544\uBCF4\uACA0\uC2B5\uB2C8\uB2E4. \uB9CE\uC774 \uAE30\uB300\uD574\uC8FC\uC138\uC694!"},{"id":"/2020/04/27/circuit-breakers-armeria","metadata":{"permalink":"/blog/ko/2020/04/27/circuit-breakers-armeria","editUrl":"https://github.com/line/armeria/edit/main/site-new/src/content/blog/ko/2020-04-27-circuit-breakers-armeria.mdx","source":"@site/src/content/blog/ko/2020-04-27-circuit-breakers-armeria.mdx","title":"Armeria\uC758 \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4 \uC0AC\uC6A9\uD574 \uBCF4\uAE30","description":"\uC548\uB155\uD558\uC138\uC694.","date":"2020-04-27T00:00:00.000Z","tags":[],"readingTime":5.47,"hasTruncateMarker":true,"authors":[{"name":"\uC8FC\uC2B9\uD658","title":"LINE\uC5D0\uC11C OpenChat \uC11C\uBE44\uC2A4\uC758 \uBC31\uC5D4\uB4DC \uAC1C\uBC1C\uC744 \uB2F4\uB2F9\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4.","imageURL":"/img/author-seunghwanjoo.jpeg","key":"seunghwanjoo","page":null}],"frontMatter":{"authors":["seunghwanjoo"],"other_languages":{"en":"/blog/2020/07/08/circuit-breakers-armeria"}},"unlisted":false,"prevItem":{"title":"Armeria\uB85C Reactive Streams\uC640 \uB180\uC790! - 1","permalink":"/blog/ko/2020/02/18/reactive-streams-armeria-1"},"nextItem":{"title":"\uC0DD\uC560 \uCCAB \uC624\uD508 \uC18C\uC2A4 \uAE30\uC5EC \uACBD\uD5D8(feat. Armeria)","permalink":"/blog/ko/2019/12/24/my-first-opensource-contribution-to-armeria"}},"content":"\uC548\uB155\uD558\uC138\uC694.\\nLINE\uC5D0\uC11C OpenChat \uC11C\uBE44\uC2A4\uC758 \uBC31\uC5D4\uB4DC\uB97C \uAC1C\uBC1C\uD558\uACE0 \uC788\uB294 \uC8FC\uC2B9\uD658\uC785\uB2C8\uB2E4. \uC774\uBC88 \uAE00\uC5D0\uC11C\uB294 \uAC04\uB2E8\uD55C \uCF54\uB4DC \uC608\uC81C\uC640 \uD568\uAED8 Armeria\uC758 \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4 \uAE30\uB2A5\uC744 \uC0AC\uC6A9\uD574 \uBCF8 \uB0B4\uC6A9\uC744 \uACF5\uC720\uD558\uACE0\uC790 \uD569\uB2C8\uB2E4.\\n\\n{/* truncate */}\\n\\n## \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4\uB780?\\n\\n\uB9CC\uC57D \uC608\uC0C1\uCE58 \uBABB\uD55C \uC7A5\uC560(\uB124\uD06C\uC6CC\uD06C \uC774\uC288 \uD639\uC740 \uC11C\uBC84 \uB2E4\uC6B4 \uB4F1)\uAC00 \uBC1C\uC0DD\uD558\uC5EC \uC5B4\uB5A4 \uC6D0\uACA9 \uC11C\uBC84 \uD558\uB098\uAC00 \uC694\uCCAD\uC5D0 \uC751\uB2F5\uD558\uC9C0 \uBABB\uD558\uB294 \uC0C1\uD0DC\uB77C\uACE0 \uAC00\uC815\uD574 \uBCF4\uACA0\uC2B5\uB2C8\uB2E4. \uC774\uB54C \uD574\uB2F9 \uC11C\uBC84\uB85C \uC694\uCCAD\uC744 \uBCF4\uB0B8 \uD074\uB77C\uC774\uC5B8\uD2B8\uB294 \uD0C0\uC784\uC544\uC6C3\uC774 \uBC1C\uC0DD\uD560 \uB54C\uAE4C\uC9C0 \uC751\uB2F5\uC744 \uAE30\uB2E4\uB9AC\uAC70\uB098 \uACC4\uC18D \uBB34\uC758\uBBF8\uD55C \uC694\uCCAD\uC744 \uBCF4\uB0B4\uBA70 \uC790\uC6D0\uC744 \uB0AD\uBE44\uD558\uAC8C \uB420 \uAC83\uC785\uB2C8\uB2E4.\\nMSA(Microservice Architecture)\uC5D0\uC11C\uB294 \uC774 \uD074\uB77C\uC774\uC5B8\uD2B8\uAC00 \uB610 \uB2E4\uB978 \uB204\uAD70\uAC00\uC758 \uC11C\uBC84\uAC00 \uB420 \uC218\uB3C4 \uC788\uB294\uB370\uC694. \uADF8\uB807\uB2E4\uBA74 \uC774 \uC11C\uBC84\uC758 \uD074\uB77C\uC774\uC5B8\uD2B8 \uC5ED\uC2DC \uB611\uAC19\uC740 \uBB38\uC81C\uB97C \uACAA\uAC8C \uB420 \uAC83\uC785\uB2C8\uB2E4. \uC774\uB807\uAC8C \uC7A5\uC560\uAC00 \uACC4\uC18D \uC804\uD30C\uB418\uBA70 \uD55C \uC6D0\uACA9 \uC11C\uBC84\uC5D0\uC11C \uBC1C\uC0DD\uD55C \uC7A5\uC560\uAC00 \uBAA8\uB4E0 \uC2DC\uC2A4\uD15C\uC5D0 \uD070 \uC601\uD5A5\uC744 \uC904 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC774\uB7F0 \uBB38\uC81C\uB97C \uD574\uACB0\uD558\uAE30 \uC704\uD574 \uB4F1\uC7A5\uD55C \uAC1C\uB150\uC774 \uBC14\uB85C \'\uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4(circuit breaker)\'\uC785\uB2C8\uB2E4.\\n\\n\uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4\uB780, \uD074\uB77C\uC774\uC5B8\uD2B8\uC5D0\uC11C \uC5B4\uB5A4 \uC6D0\uACA9 \uC11C\uBC84\uB85C \uC804\uC1A1\uD55C \uC694\uCCAD\uC758 \uC2E4\uD328\uC728\uC774 \uD2B9\uC815 \uC784\uACC4\uCE58(threshold)\uB97C \uB118\uC5B4\uC11C\uBA74, \uC774 \uC11C\uBC84\uC5D0 \uBB38\uC81C\uAC00 \uC788\uB2E4\uACE0 \uD310\uB2E8\uD558\uC5EC \uB354 \uC774\uC0C1 \uBB34\uC758\uBBF8\uD55C \uC694\uCCAD\uC744 \uC804\uC1A1\uD558\uC9C0 \uC54A\uACE0 \uBE60\uB974\uAC8C \uC5D0\uB7EC\uB97C \uBC1C\uC0DD\uC2DC\uD0A4\uB294 \uBC29\uBC95(fail fast)\uC785\uB2C8\uB2E4. \uC774 \uBC29\uBC95\uC73C\uB85C \uC55E\uC11C \uC5B8\uAE09\uD55C \uBB38\uC81C\uB97C \uBC29\uC9C0\uD558\uC5EC \uC7A5\uC560 \uADDC\uBAA8\uB97C \uCD5C\uC18C\uD654\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4(\uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4\uC758 \uAC1C\uB150\uC740 \'[\uBD84\uC0B0 \uC11C\uBE44\uC2A4 \uD658\uACBD\uC5D0 \uB300\uD55C Circuit Breaker \uC801\uC6A9](/blog/ko/2016/07/24/circuit-breakers-for-distributed-services)\' \uBE14\uB85C\uADF8\uC5D0 \uC798 \uC124\uBA85\uB418\uC5B4 \uC788\uC73C\uB2C8 \uCC38\uACE0\uD558\uC2DC\uAE30 \uBC14\uB78D\uB2C8\uB2E4).\\n\\n## \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4\uC758 \uC0C1\uD0DC\\n\\n\uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4\uC5D0\uB294 \uCD1D 3\uAC00\uC9C0 \uC0C1\uD0DC\uAC00 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/circuit-breakers-armeria-1.png)\\n\\n- `CLOSED`: \uC694\uCCAD\uC758 \uC2E4\uD328\uC728\uC774 \uC815\uD574 \uB193\uC740 \uC784\uACC4\uCE58\uBCF4\uB2E4 \uB0AE\uC740 \uC815\uC0C1\uC801\uC778 \uC0C1\uD0DC.\\n- `OPEN`: \uC694\uCCAD\uC758 \uC2E4\uD328\uC728\uC774 \uC815\uD574 \uB193\uC740 \uC784\uACC4\uCE58\uB97C \uB118\uC5B4\uC120 \uC0C1\uD0DC. \uC694\uCCAD\uC744 \uC804\uC1A1\uD558\uC9C0 \uC54A\uACE0 \uBC14\uB85C \uC5D0\uB7EC\uB97C \uBC1C\uC0DD\uC2DC\uD0B4(fail fast).\\n- `HALF_OPEN`: `OPEN` \uC0C1\uD0DC\uC5D0\uC11C \uC8FC\uAE30\uC801\uC73C\uB85C \uC694\uCCAD\uC744 \uC804\uC1A1\uD558\uC5EC \uC751\uB2F5\uC744 \uD655\uC778\uD558\uB294 \uC0C1\uD0DC. \uC131\uACF5\uD558\uBA74 `CLOSED` \uC0C1\uD0DC\uB85C \uC804\uD658\uD558\uACE0 \uC2E4\uD328\uD558\uBA74 `OPEN` \uC0C1\uD0DC\uB97C \uC720\uC9C0.\\n\\n## Armeria\uC758 \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4\\n\\nLINE\uC5D0\uC11C \uC6B4\uC601\uD558\uB294 [Netty](https://netty.io/) \uAE30\uBC18\uC758 \uBE44\uB3D9\uAE30 \uB9C8\uC774\uD06C\uB85C \uC11C\uBE44\uC2A4 \uD504\uB808\uC784\uC6CC\uD06C \uC624\uD508\uC18C\uC2A4, [Armeria](https://github.com/line/armeria)\uC5D0\uC11C\uB294 \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4 \uAE30\uB2A5\uC744 \uC9C1\uC811 \uAD6C\uD604\uD558\uC5EC \uC81C\uACF5\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uC774\uB97C \uC774\uC6A9\uD574 \uC9C1\uC811 \uB85C\uADF8\uB97C \uC0B4\uD3B4\uBCF4\uBA70 \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4\uC758 \uB3D9\uC791\uC744 \uD655\uC778\uD574 \uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n### \uC900\uBE44\uD558\uAE30\\n\\n\uBA3C\uC800, \uD14C\uC2A4\uD2B8\uB97C \uC704\uD574 \uAC04\uB2E8\uD558\uAC8C \uC694\uCCAD\uACFC \uC751\uB2F5\uC744 \uC8FC\uACE0\uBC1B\uC744 \uC11C\uBC84 2\uB300, Server1\uACFC Server2\uB97C \uC900\uBE44\uD569\uB2C8\uB2E4.\\n\\n\uD074\uB77C\uC774\uC5B8\uD2B8\uAC00 Server1\uC73C\uB85C `/hello` \uC694\uCCAD\uC744 \uBCF4\uB0B4\uBA74, Server1\uC740 Server2\uB85C `/world` \uC694\uCCAD\uC744 \uBCF4\uB0C5\uB2C8\uB2E4.\\nServer2\uAC00 Server1\uC73C\uB85C \uC751\uB2F5\uC744 \uBCF4\uB0B4\uBA74 Server1\uC740 \uADF8 \uC751\uB2F5\uC744 \uB2E4\uC2DC \uD074\uB77C\uC774\uC5B8\uD2B8\uC5D0\uAC8C \uBC18\uD658\uD569\uB2C8\uB2E4.\\nServer1\uC740 \uD074\uB77C\uC774\uC5B8\uD2B8\uC758 \uC11C\uBC84\uC774\uBA74\uC11C Server2\uC758 \uD074\uB77C\uC774\uC5B8\uD2B8\uC774\uAE30\uB3C4 \uD569\uB2C8\uB2E4.\\n\\n![](/img/circuit-breakers-armeria-2.png)\\n\\n#### Server2 \uAD6C\uD604 \uCF54\uB4DC\\n\\n\uC0C1\uB300\uC801\uC73C\uB85C \uAD6C\uD604\uC774 \uAC04\uB2E8\uD55C, Server1\uC758 \uC751\uB2F5\uC744 \uBC1B\uC744 Server2\uC758 \uAD6C\uD604 \uCF54\uB4DC\uBD80\uD130 \uBCF4\uACA0\uC2B5\uB2C8\uB2E4. `/world`\uB85C \uC804\uC1A1\uB41C \uC694\uCCAD\uC5D0 \uB300\uD55C \uC751\uB2F5\uC73C\uB85C \uC131\uACF5(200)\uACFC \uC2E4\uD328(500)\uB97C \uBC88\uAC08\uC544 \uBC18\uD658\uD558\uB3C4\uB85D \uAC04\uB2E8\uD558\uAC8C \uAD6C\uD604\uD588\uC2B5\uB2C8\uB2E4.\\n\\n```java title=\\"Server2Application.java\\"\\n@SpringBootApplication\\npublic class Server2Application {\\n\\n    private static final AtomicInteger REQ_CNT = new AtomicInteger();\\n\\n    public static void main(String[] args) {\\n        ServerBuilder sb = Server.builder();\\n        sb.http(5008);\\n        sb.decorator(LoggingService.newDecorator());\\n\\n        sb.service(\\"/world\\", (ctx, res) -> {\\n            if (REQ_CNT.addAndGet(1) % 2 == 0) {\\n                return HttpResponse.of(HttpStatus.INTERNAL_SERVER_ERROR);\\n            }\\n            return HttpResponse.of(HttpStatus.OK);\\n        });\\n\\n        Server server = sb.build();\\n        CompletableFuture<Void> future = server.start();\\n        future.join();\\n    }\\n}\\n```\\n\\n#### Server1 \uAD6C\uD604 \uCF54\uB4DC\\n\\nServer1\uC758 \uAD6C\uD604 \uCF54\uB4DC\uC785\uB2C8\uB2E4.\\nServer2\uB294 `ServerBuilder`\uB97C \uC774\uC6A9\uD558\uC5EC \uAC04\uB2E8\uD558\uAC8C \uAD6C\uD604\uD55C \uD6C4, Server1\uC740 \uD074\uB77C\uC774\uC5B8\uD2B8\uC758 \uC694\uCCAD\uC744 \uBC1B\uC744 \uC11C\uBE44\uC2A4\uC640 Server2\uB85C \uC694\uCCAD\uC744 \uBCF4\uB0BC \uD074\uB77C\uC774\uC5B8\uD2B8\uB97C \uBAA8\uB450 \uBE48(bean)\uC73C\uB85C \uB9CC\uB4E4\uC5B4 \uC0AC\uC6A9\uD569\uB2C8\uB2E4.\\n\\n```java title=\\"Server1Application.java\\"\\n@SpringBootApplication\\n@Import(Server1Context.class)\\npublic class Server1Application {\\n\\n    public static void main(String[] args) {\\n        SpringApplication.run(Server1Application.class, args);\\n    }\\n}\\n```\\n\\n```java title=\\"Server1Context.java\\"\\n@Configuration\\npublic class Server1Context {\\n\\n    @Bean\\n    public HttpServiceRegistrationBean httpService(WebClient webClient) {\\n        return new HttpServiceRegistrationBean()\\n                .setService((ctx, req) -> webClient.get(\\"/world\\"))\\n                .setServiceName(\\"httpService\\")\\n                .setRoute(Route.builder()\\n                               .path(\\"/hello\\")\\n                               .methods(HttpMethod.GET)\\n                               .build());\\n    }\\n\\n    @Bean\\n    public WebClient webClient() {\\n        CircuitBreakerStrategy strategy = CircuitBreakerStrategy.onServerErrorStatus();\\n\\n        // CircuitBreaker \uC124\uC815!!!\\n        CircuitBreaker circuitBreaker = CircuitBreaker\\n                .builder(\\"test-circuit-breaker\\")\\n                .counterSlidingWindow(Duration.ofSeconds(10))\\n                .circuitOpenWindow(Duration.ofSeconds(5))\\n                .failureRateThreshold(0.3)\\n                .minimumRequestThreshold(5)\\n                .trialRequestInterval(Duration.ofSeconds(3))\\n                .build();\\n\\n        return WebClient\\n                .builder(\\"http://localhost:5008\\")\\n                .decorator(LoggingClient.newDecorator())\\n                .decorator(CircuitBreakerHttpClient.newDecorator(circuitBreaker, strategy))\\n                .build();\\n    }\\n}\\n```\\n\\nArmeria\uC5D0\uC11C `CircuitBreaker`\uB97C \uAD6C\uD604\uD560 \uB54C \uC8FC\uC758\uD574\uC57C \uD560 \uC810\uC740, \uD074\uB77C\uC774\uC5B8\uD2B8 \uAC1D\uCCB4\uB294 \uAC01\uC790 \uC790\uC2E0\uB9CC\uC758 `CircuitBreaker`\uB97C \uAC00\uC9C4\uB2E4\uB294 \uC810\uC785\uB2C8\uB2E4. \uB9CC\uC57D Server2\uB85C \uC804\uC1A1\uB418\uB294 \uB9E4 \uC694\uCCAD\uB9C8\uB2E4 \uD074\uB77C\uC774\uC5B8\uD2B8 \uAC1D\uCCB4\uB97C \uC0C8\uB85C \uC0DD\uC131\uD558\uACE0 \uC694\uCCAD\uC774 \uB05D\uB09C \uD6C4\uC5D0 \uC18C\uBA78\uB418\uB294 \uBC29\uC2DD\uC73C\uB85C \uAD6C\uD604\uD588\uB2E4\uBA74, \uAC01 \uAC1D\uCCB4\uC5D0 \uC5F0\uACB0\uB41C `CircuitBreaker`\uB294 \uC0AC\uC2E4\uC0C1 \uBB34\uC758\uBBF8\uD574\uC9D1\uB2C8\uB2E4. \uB530\uB77C\uC11C Server2\uB85C \uC694\uCCAD\uC744 \uBCF4\uB0BC `WebClient`\uB97C \uBE48(bean)\uC73C\uB85C \uB9CC\uB4E4\uC5B4\uC11C Server2\uB85C \uC804\uC1A1\uB418\uB294 \uBAA8\uB4E0 \uC694\uCCAD\uC5D0 \uB300\uD574 \uB3D9\uC77C\uD55C `WebClient` \uAC1D\uCCB4\uB97C \uC7AC\uC0AC\uC6A9\uD558\uB3C4\uB85D \uAD6C\uD604\uD55C \uD6C4, Armeria\uC5D0\uC11C \uC81C\uACF5\uD558\uB294 [Decorator](https://line.github.io/armeria/client-decorator.html)\uB97C \uC774\uC6A9\uD574 \uC774 `WebClient` \uAC1D\uCCB4\uC5D0 \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4\uB97C \uC801\uC6A9\uD588\uC2B5\uB2C8\uB2E4.\\n\\n\uC704 \uCF54\uB4DC\uC5D0\uC11C `CircuitBreaker`\uC5D0 \uC124\uC815\uD55C \uAC01 \uD544\uB4DC\uB97C \uD558\uB098\uC529 \uC0B4\uD3B4\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n- `counterSlidingWindow`(10s): \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4\uC5D0\uC11C \uC694\uCCAD\uC758 \uC131\uACF5/\uC2E4\uD328\uC758 \uC218\uB97C \uCE21\uC815\uD558\uB294 \uC2DC\uAC04 \uAC04\uACA9\uC785\uB2C8\uB2E4. \uC989, \uC704 \uCF54\uB4DC\uC5D0\uC120 10\uCD08 \uB3D9\uC548\uC758 \uC9D1\uACC4\uB97C \uBC14\uD0D5\uC73C\uB85C \uC5B4\uB5A4 \uC0C1\uD0DC\uB85C \uC804\uD658 \uB610\uB294 \uC720\uC9C0\uD560\uC9C0 \uD310\uB2E8\uD569\uB2C8\uB2E4.\\n- `circuitOpenWindow`(5s): \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4\uAC00 `OPEN` \uC0C1\uD0DC\uB85C \uC720\uC9C0\uB418\uB294 \uC2DC\uAC04\uC785\uB2C8\uB2E4. \uC704 \uCF54\uB4DC\uC5D0\uC120 `OPEN` \uC0C1\uD0DC\uAC00 \uB418\uBA74 5\uCD08 \uB3D9\uC548 \uC678\uBD80 \uC11C\uBC84\uB85C \uC694\uCCAD\uC744 \uBCF4\uB0B4\uC9C0 \uC54A\uACE0 \uBC14\uB85C \uC5D0\uB7EC(FailFastException)\uB97C \uBC1C\uC0DD\uC2DC\uD0B5\uB2C8\uB2E4.\\n- `failureRateThreshold`(0.3): `OPEN` \uC0C1\uD0DC\uB85C \uC804\uD658\uB418\uAE30 \uC704\uD55C \uC694\uCCAD \uC2E4\uD328\uC728\uC785\uB2C8\uB2E4. `circuitOpenWindow`\uC5D0\uC11C \uC124\uC815\uD55C \uC2DC\uAC04 \uB3D9\uC548 0.3(30%) \uBE44\uC728 \uC774\uC0C1\uC73C\uB85C \uC694\uCCAD\uC774 \uC2E4\uD328\uD574\uC57C `OPEN` \uC0C1\uD0DC\uB85C \uC804\uD658\uB429\uB2C8\uB2E4.\\n- `minimumRequestThreshold`(5): \uCE21\uC815\uC5D0 \uD544\uC694\uD55C \uC694\uCCAD\uC758 \uCD5C\uC18C \uAC1C\uC218\uC785\uB2C8\uB2E4. \uC2E4\uD328\uC728\uC774 `failureRateThreshold`\uBCF4\uB2E4 \uB192\uB2E4\uACE0 \uD574\uB3C4, \uADF8 \uAC12\uC774 \uCD5C\uC18C 5\uAC1C \uC774\uC0C1\uC758 \uC694\uCCAD\uC5D0 \uB300\uD55C \uACB0\uACFC\uAC12\uC77C \uB54C\uB9CC `OPEN` \uC0C1\uD0DC\uB85C \uC804\uD658\uB429\uB2C8\uB2E4.\\n- `trialRequestInterval`(3s): `HALF_OPEN` \uC0C1\uD0DC\uB85C \uC720\uC9C0\uB418\uB294 \uC2DC\uAC04\uC785\uB2C8\uB2E4. 3\uCD08 \uB3D9\uC548\uC740 `OPEN` \uC0C1\uD0DC\uC77C \uB54C\uC640 \uB9C8\uCC2C\uAC00\uC9C0\uB85C `FailFastException` \uC5D0\uB7EC\uB97C \uBC1C\uC0DD\uC2DC\uD0A4\uB294 \uD55C\uD3B8, \uC678\uBD80 \uC11C\uBC84\uB85C\uB3C4 \uC694\uCCAD\uC744 \uC804\uC1A1\uD558\uBA70 \uC11C\uBC84\uAC00 \uC815\uC0C1\uC73C\uB85C \uB3CC\uC544\uC654\uB294\uC9C0 \uD655\uC778\uD569\uB2C8\uB2E4. 3\uCD08 \uB3D9\uC548 \uC694\uCCAD\uC744 \uC804\uC1A1\uD558\uBA74\uC11C \uC131\uACF5 \uC751\uB2F5\uC744 \uBC1B\uC73C\uBA74 \uC989\uC2DC `CLOSED` \uC0C1\uD0DC\uB85C \uC804\uD658\uB418\uACE0, \uBAA8\uB450 \uC2E4\uD328\uD558\uBA74 \uB2E4\uC2DC `OPEN` \uC0C1\uD0DC\uB85C \uC804\uD658\uB429\uB2C8\uB2E4.\\n\\n### \uD14C\uC2A4\uD2B8\\n\\n\uC544\uB798\uC640 \uAC19\uC774 \uD130\uBBF8\uB110\uC5D0\uC11C [loadtest](https://www.npmjs.com/package/loadtest) \uB77C\uC774\uBE0C\uB7EC\uB9AC\uB97C \uC774\uC6A9\uD558\uC5EC \uC9C0\uC18D\uC801\uC73C\uB85C Server1\uC5D0 \uC694\uCCAD\uC744 \uBCF4\uB0B4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n```\\n$ loadtest http://127.0.0.1:5007/hello --rps 1\\n```\\n\\nServer1\uC758 \uB85C\uADF8\uB97C \uC0B4\uD3B4\uBCF4\uBA74 \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4\uC758 \uB3D9\uC791\uC744 \uB208\uC73C\uB85C \uD655\uC778\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC11C\uBC84\uAC00 \uCC98\uC74C \uC2E4\uD589\uB420 \uB54C\uB294 \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4\uC758 \uCD08\uAE30 \uC0C1\uD0DC\uAC00 `CLOSED`\uC785\uB2C8\uB2E4.\\n\\n![](/img/circuit-breakers-armeria-3.png)\\n\\n_03:03:41.830_ \uCD08\uC5D0 \uCE21\uC815\uB41C \uC804\uCCB4 5\uAC1C\uC758 \uC694\uCCAD \uC911 \uC2E4\uD328\uD55C \uC694\uCCAD \uC218\uB294 \uB450 \uAC1C\uC774\uACE0, \uC2E4\uD328\uC728\uC740 2/5 = 0.4\uC785\uB2C8\uB2E4. \uC2E4\uD328\uC728\uC774 \uC55E\uC11C \uC124\uC815\uD55C 0.3(`failureRateThreshold`)\uBCF4\uB2E4 \uD06C\uACE0, \uCE21\uC815\uC5D0 \uC0AC\uC6A9\uD55C \uC694\uCCAD \uC218\uB3C4 5(`minimumRequestThreshold`) \uC774\uC0C1\uC774\uBBC0\uB85C \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4\uB294 `OPEN` \uC0C1\uD0DC\uB85C \uC804\uD658\uB429\uB2C8\uB2E4.\\n\\n![](/img/circuit-breakers-armeria-4.png)\\n\\n\uC774\uD6C4 _03:03:41.830_ ~ _03:03:47.824_, \uC57D 5\uCD08(`circuitOpenWindow`) \uAC04 Server2\uB85C \uC694\uCCAD\uC774 \uC804\uC1A1\uB418\uC9C0 \uC54A\uACE0 `FailFastException` \uC5D0\uB7EC\uAC00 \uACC4\uC18D \uBC1C\uC0DD\uD569\uB2C8\uB2E4(Server2\uC758 \uB85C\uADF8\uB97C \uBCF4\uBA74 \uD574\uB2F9 \uC2DC\uAC04\uC5D0 \uC694\uCCAD\uC774 \uB4E4\uC5B4\uC624\uC9C0 \uC54A\uC740 \uAC83\uC744 \uD655\uC778\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4).\\n\\n![](/img/circuit-breakers-armeria-5.png)\\n\\n_03:03:47.824_ \uCD08\uC5D0 `HALF_OPEN` \uC0C1\uD0DC\uB85C \uC804\uD658\uB418\uACE0, \uD074\uB77C\uC774\uC5B8\uD2B8\uAC00 \uBCF4\uB0B8 \uC694\uCCAD\uC774 Server2\uB85C \uC804\uC1A1\uB429\uB2C8\uB2E4. \uC774\uB54C \uC804\uC1A1\uB41C \uC694\uCCAD\uC774 \uC6B4 \uC88B\uAC8C 200 \uC751\uB2F5\uC744 \uBC1B\uC73C\uBA74\uC11C `CLOSED` \uC0C1\uD0DC\uB85C \uC804\uD658\uB429\uB2C8\uB2E4.\\n\\n![](/img/circuit-breakers-armeria-6.png)\\n\\n\uB2E4\uC2DC `CLOSED`\uAC00 \uB418\uC5B4\uC11C \uC774 \uACFC\uC815\uC744 \uB610 \uBC18\uBCF5\uD569\uB2C8\uB2E4. _03:03:47.827_ ~ _03:03:56.824_, \uC57D 10\uCD08(`counterSlidingWindow`) \uB3D9\uC548 \uC2E4\uD328\uC728\uC744 \uCE21\uC815\uD569\uB2C8\uB2E4. \uC774\uBC88\uC5D0 \uCE21\uC815\uD55C \uC2E4\uD328\uC728\uC740 4/8 = 0.5\uC774\uBBC0\uB85C, \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4\uB294 \uB2E4\uC2DC `OPEN` \uC0C1\uD0DC\uB85C \uC804\uD658\uB429\uB2C8\uB2E4.\\n\\n![](/img/circuit-breakers-armeria-7.png)\\n\\n\uC704\uC640 \uAC19\uC774 \uAC04\uB2E8\uD55C \uD14C\uC2A4\uD2B8\uB97C \uD1B5\uD574 Armeria \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4\uC758 \uB3D9\uC791\uC744 \uC9C1\uC811 \uD655\uC778\uD574 \uBCF4\uBA74\uC11C, \uC5EC\uB7EC \uC124\uC815 \uC635\uC158\uC758 \uC758\uBBF8\uC640 \uADF8\uC5D0 \uB530\uB978 \uB3D9\uC791\uC744 \uBCF4\uB2E4 \uC27D\uAC8C \uC774\uD574\uD560 \uC218 \uC788\uC5C8\uC2B5\uB2C8\uB2E4. \uB610\uD55C \uAC04\uB2E8\uD55C \uC124\uC815\uC73C\uB85C\uB3C4 \uC644\uBCBD\uD788 \uB3D9\uC791\uD558\uB294 \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4 \uD074\uB77C\uC774\uC5B8\uD2B8\uB97C \uAD6C\uD604\uD560 \uC218 \uC788\uB2E4\uB294 \uC810\uB3C4 \uC54C\uAC8C \uB418\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\n> Armeria \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4\uC5D0 \uAD00\uD55C \uBCF4\uB2E4 \uC790\uC138\uD55C \uB0B4\uC6A9\uC740 https://armeria.dev/docs/client-circuit-breaker/ \uB97C \uCC38\uACE0\uD558\uC2DC\uAE30 \uBC14\uB78D\uB2C8\uB2E4.\\n\\n## \uB9C8\uCE58\uBA70\\n\\nArmeria\uC5D0\uC11C\uB294 \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4 \uC678\uC5D0\uB3C4 MSA\uC5D0 \uD544\uC694\uD55C \uD074\uB77C\uC774\uC5B8\uD2B8 \uCE21 \uB85C\uB4DC \uBC38\uB7F0\uC2F1\uC774\uB098 auto-retry\uC640 \uAC19\uC740 \uC5EC\uB7EC \uC720\uC6A9\uD55C \uAE30\uB2A5\uC744 \uC81C\uACF5\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uC2E4\uC81C \uC800\uD76C OpenChat \uC11C\uBC84 \uAC1C\uBC1C\uC5D0\uB3C4 Armeria\uB97C \uC0AC\uC6A9\uD558\uACE0 \uC788\uB294\uB370\uC694. \uB355\uBD84\uC5D0 \uB9CE\uC740 \uAE30\uB2A5\uC744 \uD3B8\uD558\uAC8C \uC0AC\uC6A9\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uC9C0\uAE08 \uC774 \uC21C\uAC04\uC5D0\uB3C4 \uAC1C\uBC1C\uC790\uC758 \uBAA9\uC18C\uB9AC\uC5D0 \uADC0\uB97C \uAE30\uC6B8\uC774\uBA70 \uC0C8\uB85C\uC6B4 \uAE30\uB2A5\uC744 \uCD94\uAC00\uD558\uACE0 \uAC1C\uC120\uD558\uACE0 \uC788\uB294 Armeria \uC624\uD508\uC18C\uC2A4 \uAC1C\uBC1C \uD300\uC5D0\uAC8C \uAC10\uC0AC\uC758 \uB9D0\uC744 \uC804\uD558\uBA70 \uC774 \uAE00\uC744 \uB9C8\uCE69\uB2C8\uB2E4."},{"id":"/2019/12/24/my-first-opensource-contribution-to-armeria","metadata":{"permalink":"/blog/ko/2019/12/24/my-first-opensource-contribution-to-armeria","editUrl":"https://github.com/line/armeria/edit/main/site-new/src/content/blog/ko/2019-12-24-my-first-opensource-contribution-to-armeria.mdx","source":"@site/src/content/blog/ko/2019-12-24-my-first-opensource-contribution-to-armeria.mdx","title":"\uC0DD\uC560 \uCCAB \uC624\uD508 \uC18C\uC2A4 \uAE30\uC5EC \uACBD\uD5D8(feat. Armeria)","description":"\uB4E4\uC5B4\uAC00\uBA70","date":"2019-12-24T00:00:00.000Z","tags":[],"readingTime":5.75,"hasTruncateMarker":true,"authors":[{"name":"\uAC15\uC6B0\uC9C4","title":"\uD638\uAE30\uC2EC\uC774 \uB9CE\uACE0 \uB2E4\uC591\uD55C \uACBD\uD5D8\uC744 \uCD94\uAD6C\uD558\uB294 \uAC1C\uBC1C\uC790\uC785\uB2C8\uB2E4.","imageURL":"/img/author-woojinkang.png","key":"woojinkang","page":null}],"frontMatter":{"authors":["woojinkang"]},"unlisted":false,"prevItem":{"title":"Armeria\uC758 \uC11C\uD0B7 \uBE0C\uB808\uC774\uCEE4 \uC0AC\uC6A9\uD574 \uBCF4\uAE30","permalink":"/blog/ko/2020/04/27/circuit-breakers-armeria"},"nextItem":{"title":"GitHub Contributions \uADF8\uB798\uD504\uB97C \uD478\uB987\uD478\uB987\uD558\uAC8C \uB9CC\uB4E4\uC5B4\uBCF4\uC544\uC694(feat. Armeria Sprint)","permalink":"/blog/ko/2019/05/09/armeria-sprint-1"}},"content":"## \uB4E4\uC5B4\uAC00\uBA70\\n\\n\uC774\uBC88 \uAE00\uC740 LINE\uC5D0\uC11C \uC9C4\uD589\uB410\uB358 [Armeria Sprint](/blog/ko/2019/05/09/armeria-sprint-1) \uCC38\uAC00 \uD6C4\uAE30\uC785\uB2C8\uB2E4. \'\uC9E7\uC740\' \uC2A4\uD504\uB9B0\uD2B8\uB97C \uAC70\uCE5C \uB4A4 \'\uAE34\' \uB9AC\uBDF0 \uACFC\uC815\uC744 \uAC70\uCE58\uBA70 \uD558\uB098\uC758 \uAE30\uB2A5\uC744 \uC644\uC131\uD558\uACE0 \uACB0\uAD6D \uB9B4\uB9AC\uC2A4\uAE4C\uC9C0 \uC774\uB904\uB0B8, \uAE38\uACE0 \uD5D8\uB09C(?)\uD588\uB358 \uC624\uD508 \uC18C\uC2A4 \uAE30\uC5EC \uACBD\uD5D8\uC744 \uACF5\uC720\uD558\uB824\uACE0 \uD569\uB2C8\uB2E4.\\n\\n\uC5B4\uB290 \uB0A0, LINE\uC5D0\uC11C \uAC1C\uBC1C\uD558\uACE0 \uC788\uB294 \uC624\uD508 \uC18C\uC2A4\uC778 Armeria\uC5D0\uC11C \uC2A4\uD504\uB9B0\uD2B8 \uCC38\uC5EC\uC790\uB97C \uBAA8\uC9D1\uD55C\uB2E4\uB294 \uBA54\uC77C\uC744 \uBC1B\uC558\uC2B5\uB2C8\uB2E4. \uD638\uAE30\uC2EC \uBC18, \uC120\uCC29\uC21C\uC774\uB77C\uACE0 \uD558\uB2C8 \uC77C\uB2E8 \uC9C0\uC6D0\uD558\uC790\uB294 \uB9C8\uC74C \uBC18\uC73C\uB85C \uB0B4\uC6A9\uB3C4 \uC790\uC138\uD788 \uD655\uC778\uD558\uC9C0 \uC54A\uACE0 \uC2E0\uCCAD\uD574 \uBC84\uB838\uC2B5\uB2C8\uB2E4. \uC2E0\uCCAD\uD558\uACE0 \uB09C \uD6C4 \uB0B4\uC6A9\uC744 \uD655\uC778\uD574 \uBCF4\uB2C8 \uC9E7\uC740 \uAE30\uAC04 \uB3D9\uC548 \uBA58\uD1A0\uC640 \uBA58\uD2F0\uB85C \uD65C\uB3D9\uD558\uBA74\uC11C Armeria\uC5D0 \uCF54\uB4DC \uAE30\uC5EC\uB97C \uD560 \uC218 \uC788\uB294 \uAE30\uD68C\uB97C \uC81C\uACF5\uD574 \uC8FC\uB294 \uC88B\uC740 \uD65C\uB3D9\uC774\uC5C8\uC2B5\uB2C8\uB2E4. \uB2E4\uB9CC \uC81C\uAC00 Armeria\uC5D0 \uB300\uD55C \uC9C0\uC2DD\uC774 \uC804\uD600 \uC5C6\uC5B4\uC11C \uACE0\uBBFC\uD588\uB294\uB370\uC694. \uB2E4\uD589\uD788 \uC0AC\uB0B4\uC5D0\uC11C \uC9C4\uD589\uB418\uB294 OJT(On the Job Training)\uB97C \uD1B5\uD574\uC11C Armeria \uC18C\uAC1C\uB97C \uC9C1\uC811 \uB4E4\uC744 \uC218 \uC788\uB294 \uAE30\uD68C\uAC00 \uCC3E\uC544\uC654\uC2B5\uB2C8\uB2E4.\\nOJT\uC5D0 \uCC38\uC11D\uD558\uC5EC Armeria\uC5D0 \uB300\uD55C \uC124\uBA85\uC744 \uB4E3\uACE0 \uB098\uB2C8 \uAC71\uC815 \uBC18, \uC124\uB818 \uBC18\uC774 \uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uC774\uB807\uAC8C \uD070 \uC624\uD508 \uC18C\uC2A4\uC5D0 \uAE30\uC5EC\uD574 \uBCFC \uAE30\uD68C\uAC00 \uC0DD\uACA8 \uC88B\uAE34 \uD588\uC9C0\uB9CC, \uC815\uB9D0 \uB0B4\uAC00 \uB9C8\uBB34\uB9AC\uAE4C\uC9C0 \uC798 \uD560 \uC218 \uC788\uC744\uAE4C \uD558\uB294 \uAC71\uC815\uC774 \uC55E\uC130\uC2B5\uB2C8\uB2E4.\\n\\n{/* truncate */}\\n\\n## \uC774\uC288 \uC120\uC815\uC5D0\uC11C PR \uB4F1\uB85D\uAE4C\uC9C0\\n\\n\uBAA8\uC784\uC5D0 \uCC38\uC11D\uD558\uAE30 \uC804\uC5D0, \uC2A4\uD504\uB9B0\uD2B8\uB97C \uD1B5\uD574\uC11C \uC2A4\uC2A4\uB85C \uB2EC\uC131\uD558\uACE0 \uC2F6\uC740 \uBAA9\uD45C\uC5D0 \uB300\uD574\uC11C \uC0DD\uAC01\uD574 \uBCF4\uC558\uC2B5\uB2C8\uB2E4. \uCCAB \uBC88\uC9F8 \uBAA9\uD45C\uB294 \'\uB3C4\uC804\uC744 \uD1B5\uD574 \uC131\uC7A5\uD558\uAE30\'\uC600\uACE0, \uB450 \uBC88\uC9F8\uB294 \'\uBAA9\uD45C\uB97C \uC27D\uAC8C \uC124\uC815\uD558\uB294 \uD55C\uC774 \uC788\uB354\uB77C\uB3C4 \uB05D\uAE4C\uC9C0 \uD3EC\uAE30\uD558\uC9C0 \uC54A\uAE30\'\uC600\uC2B5\uB2C8\uB2E4. \uBAA9\uD45C\uB97C \uC124\uC815\uD55C \uD6C4\uC5D0 \uBA54\uC77C\uB85C \uC548\uB0B4\uB41C \uAC04\uB2E8\uD55C \uC0AC\uC804 \uC900\uBE44\uB97C \uD655\uC778\uD55C \uB4A4, \uC124\uB808\uB294 \uB9C8\uC74C\uC73C\uB85C \uBAA8\uC784\uC5D0 \uCC38\uC11D\uD588\uC2B5\uB2C8\uB2E4.\\n\\n### \uAC04\uB2E8\uD558\uAC8C \uC2DC\uC791\uD55C \uCCAB \uBC88\uC9F8 \uBAA8\uC784\\n\\n\uCCAB \uBC88\uC9F8 \uBAA8\uC784\uC5D0\uC120 \uC55E\uC73C\uB85C \uAC1C\uBC1C\uD574\uC57C \uD560 \uC774\uC288 \uC911\uC5D0\uC11C \'good-first-issue\'\uB85C \uC124\uC815\uB41C \uC0C1\uB300\uC801\uC73C\uB85C \uC26C\uC6B4(?) \uC774\uC288\uB4E4\uC5D0 \uB300\uD574\uC11C \uC124\uBA85\uC744 \uB4E3\uACE0, \uC2A4\uD504\uB9B0\uD2B8\uC5D0 \uCC38\uC5EC\uD55C \uC0AC\uB78C\uB4E4\uC774 \uC790\uC2E0\uC774 \uAC1C\uBC1C\uD574 \uBCF4\uACE0 \uC2F6\uC740 \uAC83\uC744 \uACE0\uB974\uB294 \uC790\uB9AC\uAC00 \uB9C8\uB828\uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uC800\uB294 \uC2A4\uC2A4\uB85C \uC124\uC815\uD55C \uB450 \uBC88\uC9F8 \uBAA9\uD45C\uB97C \uB5A0\uC62C\uB9AC\uBA70 \'good-first-issue\' \uC911\uC5D0\uC11C\uB3C4 \uAC00\uC7A5 \uAC04\uB2E8\uD574 \uBCF4\uC600\uB358 [\u2018Show Armeria version in DocService](https://github.com/line/armeria/issues/685)\u2019\uB97C \uACE8\uB77C\uC11C \uC9C4\uD589\uD588\uC2B5\uB2C8\uB2E4. \uC774\uC288\uC5D0 \uB300\uD574\uC11C \uAC04\uB2E8\uD558\uAC8C \uC124\uBA85\uD558\uC790\uBA74, \uC81C\uBAA9 \uADF8\uB300\uB85C \'Document Service\'\uC5D0 \uD604\uC7AC Armeria\uC758 \uBC84\uC804\uC744 \uD45C\uC2DC\uD558\uB294 \uC791\uC5C5\uC774\uC5C8\uC2B5\uB2C8\uB2E4(\uB2F9\uC2DC \uC124\uBA85\uB9CC \uB4E3\uACE0\uB294 \uC815\uB9D0 \uC27D\uAC8C \uB05D\uB0A0 \uC904 \uC54C\uC558\uC2B5\uB2C8\uB2E4 :) ). \uAC1C\uBC1C\uC740 \uB2E4\uC74C \uBAA8\uC784 \uB54C \uC9C4\uD589\uD558\uAE30\uB85C \uD558\uACE0 \uCCAB \uBC88\uC9F8 \uBAA8\uC784\uC774 \uB9C8\uBB34\uB9AC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\n### \uAC1C\uBC1C\uC744 \uC2DC\uC791\uD574 PR \uB4F1\uB85D\uAE4C\uC9C0 \uB9C8\uCE5C \uB450 \uBC88\uC9F8 \uBAA8\uC784\\n\\n\uB450 \uBC88\uC9F8 \uBAA8\uC778 \uC790\uB9AC\uC5D0\uC11C\uB294 \uBC14\uB85C \uAC1C\uBC1C\uC774 \uC9C4\uD589\uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uAD81\uAE08\uD55C \uC810\uC774 \uC788\uC73C\uBA74 \uADFC\uCC98 \uBA58\uD1A0\uC5D0\uAC8C \uCC3E\uC544\uAC00 \uBB3C\uC5B4\uBCF4\uAC70\uB098 \uB3C4\uC6C0\uC744 \uC694\uCCAD\uD558\uBA74 \uB41C\uB2E4\uB294 \uC124\uBA85\uACFC \uD568\uAED8 \uACE0\uB3C5\uD55C \uAC1C\uBC1C \uC2DC\uAC04\uC774 \uC2DC\uC791\uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uC800\uB294 \uAC00\uC7A5 \uAC04\uB2E8\uD574 \uBCF4\uC774\uB294 \uC774\uC288\uB97C \uC120\uD0DD\uD588\uC9C0\uB9CC, \uADF8\uB7FC\uC5D0\uB3C4 \uAC70\uB300\uD55C \uC591\uC758 \uCF54\uB4DC \uC55E\uC5D0\uC11C \uBB34\uC5C7\uBD80\uD130 \uC2DC\uC791\uD574\uC57C \uD560\uC9C0 \uAC10\uC774 \uC798 \uC624\uC9C0 \uC54A\uC558\uC2B5\uB2C8\uB2E4. \uAC8C\uB2E4\uAC00 \uC81C \uC774\uC288\uB294 \uB108\uBB34\uB098 \uAC04\uB2E8\uD55C \uC774\uC288\uC600\uAE30 \uB54C\uBB38\uC5D0 \uBCC4\uB2E4\uB978 \uC124\uBA85\uC774 \uC5C6\uC5B4\uC11C \uD63C\uC790\uC11C \uB059\uB059\uB300\uACE0 \uC788\uC5C8\uB294\uB370\uC694. \uADF8\uB807\uAC8C \uC2DC\uAC04\uC774 \uD758\uB7EC\uAC00 \uBC84\uB9AC\uB294 \uAC8C \uC544\uAE4C\uC6CC\uC11C \uADFC\uCC98\uC5D0 \uACC4\uC2E0 \uBA58\uD1A0 \uB2D8\uAED8 \uB3C4\uC6C0\uC744 \uC694\uCCAD\uD588\uC2B5\uB2C8\uB2E4. \uBA58\uD1A0 \uB2D8\uC740 \uD574\uB2F9 \uC774\uC288\uC5D0 \uB300\uD574 \uC790\uC138\uD558\uAC8C \uC124\uBA85\uD574 \uC8FC\uBA70 \uAC00\uC7A5 \uCC98\uC74C\uC5D0 \uD574\uC57C \uD560, \uD504\uB85C\uC81D\uD2B8 \uC138\uD305\uACFC \uC81C\uAC00 \uAC1C\uBC1C\uD574\uC57C \uD558\uB294 \uBD80\uBD84\uC744 \uD30C\uC545\uD558\uB294 \uC791\uC5C5\uAE4C\uC9C0 \uB3C4\uC640\uC8FC\uC168\uC2B5\uB2C8\uB2E4.\\n\\n\uC5B4\uB290 \uC815\uB3C4 \uAC00\uC774\uB4DC\uB97C \uBC1B\uACE0 \uB098\uB2C8 \uD63C\uC790\uC11C\uB3C4 \uCDA9\uBD84\uD788 \uAC1C\uBC1C\uC744 \uC9C4\uD589\uD560 \uC218 \uC788\uAC8C \uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uBC84\uC804\uACFC \uAD00\uB828\uB41C \uC18C\uC2A4 \uCF54\uB4DC\uB97C \uC0B4\uD3B4\uBCF4\uBA74\uC11C \uD654\uBA74\uC758 \uC5B4\uB290 \uACF3\uC5D0 \uBC84\uC804\uC744 \uD45C\uC2DC\uD558\uBA74 \uAC00\uC7A5 \uC88B\uC744\uC9C0 \uACE0\uBBFC\uD588\uC2B5\uB2C8\uB2E4. \uC81C\uC77C \uC798 \uBCF4\uC774\uBA74\uC11C \uC5B4\uC0C9\uD558\uC9C0 \uC54A\uC740 \uACF3\uC5D0 \uC704\uCE58\uC2DC\uD0A4\uBA74 \uC88B\uC744 \uAC83 \uAC19\uC544\uC11C \uCD5C\uC0C1\uB2E8 \uD0C0\uC774\uD2C0 \uC606\uC5D0 \uBC84\uC804 \uD45C\uC2DC\uB97C \uCD94\uAC00\uD574\uB3C4 \uB418\uB294\uC9C0 \uBA58\uD1A0\uC640 \uC0C1\uC758\uD55C \uB4A4 \uBE60\uB974\uAC8C \uCD94\uAC00\uD574 \uBCF4\uC558\uC2B5\uB2C8\uB2E4. \uC815\uB9D0 \uAC04\uB2E8\uD558\uAC8C \uCD94\uAC00\uD560 \uC218 \uC788\uC5C8\uB294\uB370\uC694. \uCD94\uAC00\uD558\uACE0 \uB098\uB2C8 \uD55C \uAC00\uC9C0 \uAC70\uC2AC\uB9AC\uB294 \uBD80\uBD84\uC774 \uC788\uC5C8\uC2B5\uB2C8\uB2E4. \uBC84\uC804\uC740 \'0.84.0-SNAPSHOT\'\uC640 \uAC19\uC740 \uD615\uC2DD\uC73C\uB85C \uD45C\uC2DC\uB418\uC5C8\uB294\uB370\uC694. \uB4A4\uC5D0 \uBD88\uD544\uC694\uD558\uAC8C \uBD99\uC5B4 \uC788\uB294 \'SNAPSHOT\' \uD14D\uC2A4\uD2B8\uB97C \uC81C\uAC70\uD558\uBA74 \uB354 \uAE54\uB054\uD574\uC9C8 \uAC83 \uAC19\uC558\uC2B5\uB2C8\uB2E4. \uADF8\uB798\uC11C \'SNAPSHOT\' \uD14D\uC2A4\uD2B8\uB97C \uC9C0\uC6B0\uACE0 \uBC84\uC804\uACFC \uAD00\uB828\uB41C \uC22B\uC790\uB9CC \uD45C\uC2DC\uB418\uB3C4\uB85D \uB2E4\uC2DC \uC218\uC815\uD55C \uB4A4, \uB4DC\uB514\uC5B4 \uCCAB \uC624\uD508 \uC18C\uC2A4 PR(pull request)\uC778 [Show armeria version in doc service #685](https://github.com/line/armeria/pull/1744)\uB97C \uB4F1\uB85D\uD588\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/my-first-opensource-contribution-to-armeria-1.png)\\n\\n\uC9C1\uC811 \uC9C4\uD589\uD558\uBA74\uC11C \uC624\uD508 \uC18C\uC2A4\uC5D0\uB3C4 \uC774\uB807\uAC8C \uAC04\uB2E8\uD558\uAC8C \uB05D\uB098\uB294 \uC774\uC288\uAC00 \uC788\uB2E4\uB294 \uC810\uC5D0 \uB180\uB790\uACE0, \uD55C\uD3B8\uC73C\uB860 \uC624\uD508 \uC18C\uC2A4\uC5D0 \uAE30\uC5EC\uD558\uB294 \uAC74 \uC544\uBB34\uB098 \uD560 \uC218 \uC5C6\uB294 \uC5B4\uB824\uC6B4 \uAC70\uB77C\uACE0 \uC0DD\uAC01\uD588\uB358 \uC81C \uC9E7\uC740 \uC0DD\uAC01\uC774 \uBD80\uB044\uB7FD\uAC8C \uB290\uAEF4\uC84C\uC2B5\uB2C8\uB2E4.\\n\\n## \uC624\uD508 \uC18C\uC2A4 \uAE30\uC5EC\uC758 \uC9C4\uC815\uD55C \uC2DC\uC791, \uB9AC\uBDF0\\n\\n\'\uC624\uD508 \uC18C\uC2A4 \uAE30\uC5EC\uB294 \uB9AC\uBDF0\uB97C \uBC1B\uC73C\uBA74\uC11C \uC2DC\uC791\uB41C\uB2E4\'\uB77C\uB294 \uB9D0\uACFC \uD568\uAED8, \uC55E\uC73C\uB85C\uB294 \uB9AC\uBDF0\uB97C \uD1B5\uD574\uC11C \uC628\uB77C\uC778\uC5D0\uC11C \uB9CC\uB098\uC790\uACE0 \uC804\uB2EC\uBC1B\uACE0 \uC2A4\uD504\uB9B0\uD2B8\uAC00 \uC885\uB8CC\uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uC0AC\uC2E4 \uADF8 \uB9D0\uC744 \uB4E4\uC73C\uBA74\uC11C\uB3C4 \uC18D\uC73C\uB85C\uB294 \'\uC774\uB807\uAC8C \uAC04\uB2E8\uD55C \uC774\uC288\uB2C8 \uC27D\uAC8C \uB05D\uB0A0 \uC218 \uC788\uACA0\uC9C0\'\uB77C\uACE0 \uC0DD\uAC01\uD588\uC2B5\uB2C8\uB2E4.\\n\\n\uD558\uB098\uC758 PR\uC774 \uBA38\uC9C0(merge)\uB418\uAE30 \uC704\uD574\uC11C\uB294 CI(Continuous Integration)\uB97C \uD1B5\uACFC\uD55C \uD6C4 \uBA54\uC778\uD14C\uC774\uB108\uC758 \uC2B9\uC778(approve)\uC744 \uBC1B\uC544\uC57C \uD569\uB2C8\uB2E4.\\nPR\uC744 \uB4F1\uB85D\uD558\uC790\uB9C8\uC790 \uCC98\uC74C \uB2EC\uB838\uB358 \uCF54\uBA58\uD2B8\uB294 \uAC1C\uBC1C\uC6A9 \uCF54\uB4DC\uB97C \uC81C\uC678\uD574 \uB2EC\uB77C\uB294 \uB0B4\uC6A9\uC774\uC5C8\uC2B5\uB2C8\uB2E4. \uAC1C\uBC1C\uD558\uAE30 \uC704\uD574 \uC124\uC815\uC744 \uBCC0\uACBD\uD574 \uB450\uC5C8\uB358 \uAC83\uC744 \uAE5C\uBE61 \uC78A\uACE0 \uAC1C\uBC1C\uC6A9 \uCF54\uB4DC\uAC00 \uD3EC\uD568\uB41C \uC0C1\uD0DC\uB85C PR\uC744 \uC62C\uB9AC\uB294 \uBC14\uB78C\uC5D0 CI \uACFC\uC815\uC5D0\uC11C \uAE30\uBCF8\uC801\uC73C\uB85C \uC9C4\uD589\uB418\uB294 \uAC80\uC0AC\uC5D0\uC11C \uC5D0\uB7EC\uB97C \uC758\uBBF8\uD558\uB294 \uBE68\uAC04\uBD88\uC774 \uD45C\uC2DC\uB418\uC5C8\uACE0, \uAD00\uB828 \uB0B4\uC6A9\uC744 \uD655\uC778\uD55C \uB9AC\uBDF0\uC5B4\uAC00 \uB0A8\uACA8\uC900 \uCF54\uBA58\uD2B8\uC600\uC2B5\uB2C8\uB2E4. \uB2E4\uD589\uD788 \uBB38\uC81C\uAC00 \uB418\uC5C8\uB358 \uBD80\uBD84\uC744 \uAE08\uBC29 \uBC1C\uACAC\uD574 \uBE60\uB974\uAC8C \uC218\uC815\uD560 \uC218 \uC788\uC5C8\uC2B5\uB2C8\uB2E4. \uADF8 \uCF54\uBA58\uD2B8\uB97C \uC2DC\uC791\uC73C\uB85C \uAC04\uB2E8\uD558\uAC8C \uB05D\uB0A0 \uAC70\uB77C\uACE0 \uC0DD\uAC01\uD588\uB358 \uC81C \uC791\uC5C5\uC5D0 \uC5EC\uB7EC \uCF54\uBA58\uD2B8\uAC00 \uB2EC\uB9AC\uAE30 \uC2DC\uC791\uD588\uC2B5\uB2C8\uB2E4. \uB9AC\uBDF0\uC5B4\uB4E4\uC774 \uC5EC\uB7EC \uAC00\uC9C0 \uAC1C\uC120 \uC0AC\uD56D\uC744 \uC81C\uC2DC\uD574 \uC8FC\uC5C8\uACE0, \uADF8\uAC78 \uBCF4\uBA70 \uB4DC\uB514\uC5B4 \uC624\uD508 \uC18C\uC2A4 \uAE30\uC5EC\uAC00 \uC2DC\uC791\uB418\uC5C8\uB2E4\uB294 \uAC83\uC744 \uB290\uB084 \uC218 \uC788\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\n### \uC790\uC720\uB85C\uC6B4 \uC758\uACAC \uC81C\uC2DC\uB97C \uD1B5\uD55C \uAC1C\uC120\\n\\n\uC624\uD508 \uC18C\uC2A4 \uAE30\uC5EC\uB97C \uACBD\uD5D8\uD558\uBA74\uC11C \uB290\uB07C\uAC8C \uB41C \uC810 \uC911 \uD558\uB098\uB294, \uC218\uD3C9\uC801\uC778 \uAD00\uACC4\uB97C \uD1B5\uD574 \uC790\uC720\uB86D\uAC8C \uC758\uACAC\uC744 \uC81C\uC2DC\uD558\uB294 LINE\uC758 \uBB38\uD654\uAC00 \uC624\uD508 \uC18C\uC2A4\uC5D0\uC11C\uB3C4 \uADF8\uB300\uB85C \uB098\uD0C0\uB098\uACE0 \uC788\uC5C8\uB2E4\uB294 \uC810\uC785\uB2C8\uB2E4. \uC88B\uC740 \uC544\uC774\uB514\uC5B4\uAC00 \uB5A0\uC624\uB974\uBA74 \uB204\uAD6C\uB098 \uCF54\uBA58\uD2B8\uB97C \uD1B5\uD574\uC11C \uC790\uC720\uB86D\uAC8C \uC758\uACAC\uC744 \uC81C\uC2DC\uD558\uACE0, \uC774\uB97C \uD1B5\uD574 \uC624\uD508 \uC18C\uC2A4\uAC00 \uB354 \uC88B\uC740 \uBC29\uD5A5\uC73C\uB85C \uB098\uC544\uAC08 \uC218 \uC788\uB2E4\uB294 \uC810\uC774 \uD765\uBBF8\uB85C\uC6E0\uC2B5\uB2C8\uB2E4.\\n\\n\uC81C\uAC00 \uB9E1\uC740 \uC791\uC5C5\uC740 \uAC04\uB2E8\uD558\uAC8C \uBC84\uC804\uB9CC \uD45C\uC2DC\uD558\uB294 \uAC83\uC774\uC5C8\uB294\uB370\uC694. \uBA54\uC778\uD14C\uC774\uB108 \uBD84\uC774 \uCD94\uAC00\uB85C \uBAA8\uB4C8\uBCC4 \uCEE4\uBC0B \uB0A0\uC9DC, \uCEE4\uBC0B \uD574\uC2DC(hash), \uD574\uB2F9 \uBAA8\uB4C8\uC758 \uC0C1\uD0DC \uB4F1 \uB2E4\uB978 \uC720\uC6A9\uD55C \uC815\uBCF4\uB97C \uD568\uAED8 \uBCF4\uC5EC\uC8FC\uBA74 \uC5B4\uB5BB\uACA0\uB0D0\uACE0 \uC758\uACAC\uC744 \uC81C\uC2DC\uD574 \uC8FC\uC5C8\uC2B5\uB2C8\uB2E4. \uC800\uB294 \uCF54\uBA58\uD2B8\uB97C \uD655\uC778\uD558\uACE0 \uC5B4\uB514\uC5D0 \uBCF4\uC5EC \uC8FC\uBA74 \uC88B\uC744\uC9C0 \uACE0\uBBFC\uD588\uC2B5\uB2C8\uB2E4. \uCC98\uC74C DocService\uC5D0 \uC811\uADFC\uD558\uBA74 \uC544\uB798\uC640 \uAC19\uC740 \uBA54\uC778 \uD398\uC774\uC9C0\uAC00 \uB098\uD0C0\uB098\uB294\uB370\uC694. \uAC04\uB2E8\uD55C \uD658\uC601 \uBA54\uC2DC\uC9C0\uC640 \uC9E7\uC740 \uC124\uBA85\uC774 \uD45C\uC2DC\uB41C \uC0C1\uB2E8 \uC678\uC758 \uB098\uBA38\uC9C0 \uACF5\uAC04\uC774 \uBE44\uC5B4 \uC788\uC5B4\uC11C \uD5C8\uC804\uD574 \uBCF4\uC600\uC2B5\uB2C8\uB2E4. \uC800\uB294 \uBA54\uC778 \uD398\uC774\uC9C0\uC758 \uBE48 \uACF5\uAC04\uC5D0 \uCF54\uBA58\uD2B8\uC5D0\uC11C \uC5B8\uAE09\uB41C \uC815\uBCF4\uB4E4\uC744 \uD45C\uC2DC\uD558\uBA74 \uC5B4\uB5BB\uACA0\uB0D0\uACE0 \uC758\uACAC\uC744 \uC81C\uC2DC\uD588\uACE0, \'Sounds like a good idea!\'\uB77C\uB294 \uAE0D\uC815\uC801\uC778 \uD53C\uB4DC\uBC31\uC744 \uBC1B\uC558\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/my-first-opensource-contribution-to-armeria-2.png)\\n\\n\uC544\uB798\uC640 \uAC19\uC774 \uD5C8\uC804\uD574 \uBCF4\uC600\uB358 \uBA54\uC778 \uD398\uC774\uC9C0\uC5D0 **Version information**\uC774\uB77C\uB294 \uD0C0\uC774\uD2C0\uACFC \uD568\uAED8 \uD45C \uD615\uC2DD\uC758 \uBC84\uC804 \uC815\uBCF4\uB97C \uCD94\uAC00\uD558\uB2C8 \uD654\uBA74\uC774 \uC720\uC6A9\uD55C \uC815\uBCF4\uB85C \uAC00\uB4DD \uCC2C \uB290\uB08C\uC785\uB2C8\uB2E4. \uCD94\uAC00 \uC791\uC5C5\uC744 \uC9C4\uD589\uD558\uBA74\uC11C \uAC00\uC7A5 \uAE30\uC5B5\uC5D0 \uB0A8\uC558\uB358 \uAC74 \uB9C8\uC9C0\uB9C9 \uCEE4\uBC0B \uC2DC\uAC01\uC744 \uBCF4\uC5EC\uC8FC\uB294 **Commit Time** \uCEEC\uB7FC \uAC12 \uD45C\uC2DC \uD615\uC2DD\uC758 \uBCC0\uD654 \uACFC\uC815\uC785\uB2C8\uB2E4. \uCC98\uC74C\uC5D0 \uD574\uB2F9 \uCEEC\uB7FC\uC740 \uC27D\uAC8C \uC2DC\uAC04\uC744 \uC54C\uC544\uBCF4\uAE30 \uD798\uB4E0 \uC22B\uC790\uB85C \uD45C\uC2DC\uB418\uC5C8\uB294\uB370\uC694. \uC774\uB97C \uC0AC\uC6A9\uC790\uAC00 \uC27D\uAC8C \uC778\uC9C0\uD560 \uC218 \uC788\uB294 UTC String \uD615\uC2DD\uC73C\uB85C \uBCC0\uACBD\uD588\uC2B5\uB2C8\uB2E4. \uADF8 \uD6C4 \uBA54\uC778\uD14C\uC774\uB108 \uBD84\uC774 \uD604\uC7AC \uCEE4\uBC0B \uC2DC\uC810\uC5D0\uC11C \uC5BC\uB9C8\uB098 \uC2DC\uAC04\uC774 \uD758\uB800\uB294\uC9C0 \uC0AC\uC6A9\uC790\uB4E4\uC774 \uB354 \uC27D\uAC8C \uC54C\uC544\uBCFC \uC218 \uC788\uB294 \uBC29\uBC95\uC744 \uC81C\uC548\uD574 \uC8FC\uC5B4\uC11C \uC774\uB97C \uC801\uC6A9\uD588\uB294\uB370\uC694. \uC801\uC6A9\uD558\uBA74\uC11C \uCD94\uAC00\uB85C \uAE30\uC874 UTC String \uD615\uC2DD\uC73C\uB85C \uBCF4\uC5EC\uC92C\uB358 \uAC12\uC744 \uB9D0\uD48D\uC120(tooltip)\uC73C\uB85C \uC62E\uACA8 \uC0AC\uC6A9\uC790\uAC00 \uCEEC\uB7FC \uAC12\uC5D0 \uB9C8\uC6B0\uC2A4\uB97C \uC62C\uB9AC\uBA74 \uC815\uD655\uD55C \uC2DC\uAC04\uC744 \uD568\uAED8 \uD655\uC778\uD560 \uC218 \uC788\uB3C4\uB85D \uBCC0\uACBD\uD588\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/my-first-opensource-contribution-to-armeria-3.png)\\n\\n\uC774\uB807\uAC8C \uCD94\uAC00 \uAC1C\uBC1C\uC744 \uC9C4\uD589\uD558\uBA74\uC11C Armeria\uC5D0\uC11C \uC0AC\uC6A9\uC790 \uD3B8\uC758\uC131\uC744 \uB9CE\uC774 \uACE0\uB824\uD558\uBA70 \uAC1C\uBC1C\uD558\uACE0 \uC788\uB2E4\uB294 \uAC83\uC744 \uB290\uB084 \uC218 \uC788\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\n## \uCC2C\uB780\uD55C \uACB0\uACFC\\n\\n\uCC98\uC74C \uC2DC\uC791\uC740 \uD604\uC7AC \uBC84\uC804\uC744 \uD45C\uC2DC\uD558\uB294 \uAC83\uBFD0\uC774\uC5C8\uC9C0\uB9CC, \uC790\uC720\uB86D\uAC8C \uC758\uACAC\uC744 \uC8FC\uACE0\uBC1B\uC73C\uBA70 \uAC1C\uBC1C\uD558\uB294 \uACFC\uC815\uC744 \uAC70\uCCD0\uC11C \uCD5C\uC885\uC801\uC73C\uB85C\uB294 \uAC01 \uBAA8\uB4C8\uBCC4 \uBC84\uC804 \uAD00\uB828 \uC815\uBCF4 \uD45C\uC2DC\uAE4C\uC9C0 \uCD94\uAC00\uD558\uAC8C \uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uC81C\uAC00 \uCD94\uAC00\uD55C \uAE30\uB2A5\uC740 CI\uB97C \uD1B5\uACFC\uD55C \uB4A4 \uBAA8\uB4E0 \uBA54\uC778\uD14C\uC774\uB108\uC758 \uC2B9\uC778\uC744 \uBC1B\uC544 \uBA38\uC9C0\uB418\uC5C8\uACE0, 0.91.0 \uBC84\uC804\uC73C\uB85C \uB9C8\uCE68\uB0B4 \uB9B4\uB9AC\uC2A4\uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uAE30\uC5EC\uC790(contributor) \uBA85\uB2E8\uC5D0\uC11C \uC81C ID\uB97C \uD655\uC778\uD588\uC744 \uB54C\uB294 \uC815\uB9D0 \uB9D0\uB85C \uD45C\uD604\uD560 \uC218 \uC5C6\uC744 \uB9CC\uD07C \uAE30\uBEE4\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/my-first-opensource-contribution-to-armeria-4.png)\\n\\n\uD574\uB2F9 \uC774\uC288\uB97C \uCC98\uB9AC\uD558\uB294 \uB3D9\uC548 \uB9AC\uBDF0\uC5B4\uC640 \uCD1D 66\uAC1C\uC758 \uCF54\uBA58\uD2B8\uB97C \uC8FC\uACE0\uBC1B\uC558\uC2B5\uB2C8\uB2E4. \uC911\uAC04\uC5D0 \uC7A0\uC2DC \uC78A\uACE0 \uC788\uB2E4\uAC00 \uB9AC\uB9C8\uC778\uB354\uB97C \uBC1B\uACE0 \uB2E4\uC2DC \uC2DC\uC791\uD558\uAE30\uB3C4 \uD588\uB294\uB370\uC694. \uADF8\uB7EC\uB2E4 \uBCF4\uB2C8 \uC57D 5\uAC1C\uC6D4\uC774\uB77C\uB294 \uAE34 \uC2DC\uAC04\uC774 \uC18C\uC694\uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uC624\uB79C \uC2DC\uAC04\uC774 \uAC78\uB838\uC9C0\uB9CC, \uAFB8\uC900\uD788 \uC800\uB97C \uCC3E\uC544\uC8FC\uC2E0 \uBA54\uC778\uD14C\uC774\uB108 \uBD84\uB4E4\uC758 \uB3C4\uC6C0\uC744 \uBC1B\uC544 \uD3EC\uAE30\uD558\uC9C0 \uC54A\uACE0 \uC9C0\uC18D\uC801\uC73C\uB85C \uAC1C\uBC1C\uD55C \uB355\uBD84\uC5D0 \uACB0\uAD6D \uC624\uD508 \uC18C\uC2A4\uC5D0 \uAE30\uC5EC\uD560 \uC218 \uC788\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\n## \uB9C8\uCE58\uBA70\\n\\n\uD638\uAE30\uC2EC\uC73C\uB85C \uC2DC\uC791\uD588\uC9C0\uB9CC, \uAC1C\uBC1C\uC744 \uC9C4\uD589\uD558\uBA70 \uC624\uD508 \uC18C\uC2A4 \uC0DD\uD0DC\uACC4\uC5D0 \uB300\uD574 \uC880 \uB354 \uAE4A\uC774 \uC54C\uAC8C \uB41C \uC88B\uC740 \uACBD\uD5D8\uC774\uC5C8\uC2B5\uB2C8\uB2E4. \uAF3C\uAF3C\uD558\uAC8C \uCF54\uB4DC\uB97C \uB9AC\uBDF0\uD558\uBA70 \uAC1C\uC120\uD574\uC57C \uD560 \uBD80\uBD84\uC744 \uC9DA\uC5B4\uC8FC\uACE0 \uB354 \uC88B\uC740 \uBC29\uBC95\uACFC \uB354 \uC88B\uC740 \uCF54\uB4DC\uB97C \uC870\uC5B8\uD574 \uC900 \uB9CE\uC740 \uBD84\uB4E4 \uB355\uBD84\uC5D0 \uC131\uC7A5\uD560 \uC218 \uC788\uB294 \uAE30\uD68C\uB97C \uC798 \uC7A1\uC744 \uC218 \uC788\uC5C8\uACE0, \uC2A4\uC2A4\uB85C \uC124\uC815\uD55C \uBAA9\uD45C\uB97C \uB2EC\uC131\uD558\uAC8C \uB418\uC5B4 \uC544\uC8FC \uB9CC\uC871\uC2A4\uB7EC\uC6E0\uC2B5\uB2C8\uB2E4.\\n\\nArmeria \uC2A4\uD504\uB9B0\uD2B8\uB97C \uD1B5\uD574 \uC624\uD508 \uC18C\uC2A4\uC5D0 \uAE30\uC5EC\uD574 \uBCF4\uBA74\uC11C \uC624\uD508 \uC18C\uC2A4\uC5D0 \uB300\uD55C \uB450\uB824\uC6C0\uC744 \uC774\uACA8\uB0BC \uC218 \uC788\uC5C8\uC2B5\uB2C8\uB2E4. \uC55E\uC73C\uB85C \uC8FC\uAE30\uC801\uC73C\uB85C, \uB354 \uB9CE\uC774 \uC624\uD508 \uC18C\uC2A4\uC5D0 \uAE30\uC5EC\uD558\uB824\uACE0 \uD569\uB2C8\uB2E4. \uBE60\uB978 \uD53C\uB4DC\uBC31\uACFC \uD568\uAED8 \uB9C8\uC9C0\uB9C9\uAE4C\uC9C0 \uD3EC\uAE30\uD558\uC9C0 \uC54A\uACE0 \uB3C4\uC640\uC8FC\uC2E0 \uBAA8\uB4E0 \uBD84\uB4E4\uAED8 \uC774 \uC790\uB9AC\uB97C \uBE4C\uB824 \uAC10\uC0AC\uC758 \uC778\uC0AC\uB97C \uB4DC\uB9BD\uB2C8\uB2E4."},{"id":"/2019/05/09/armeria-sprint-1","metadata":{"permalink":"/blog/ko/2019/05/09/armeria-sprint-1","editUrl":"https://github.com/line/armeria/edit/main/site-new/src/content/blog/ko/2019-05-09-armeria-sprint-1.mdx","source":"@site/src/content/blog/ko/2019-05-09-armeria-sprint-1.mdx","title":"GitHub Contributions \uADF8\uB798\uD504\uB97C \uD478\uB987\uD478\uB987\uD558\uAC8C \uB9CC\uB4E4\uC5B4\uBCF4\uC544\uC694(feat. Armeria Sprint)","description":"\uB4E4\uC5B4\uAC00\uBA70","date":"2019-05-09T00:00:00.000Z","tags":[],"readingTime":6,"hasTruncateMarker":true,"authors":[{"name":"\uC774\uC11C\uC5F0","title":"LINE\uC5D0\uC11C \uC624\uD508\uC18C\uC2A4\uB97C \uB2F4\uB2F9\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4.","imageURL":"https://github.com/syleeeee.png","key":"seoyeonlee","page":null}],"frontMatter":{"authors":["seoyeonlee"],"other_languages":{"en":"/blog/2019/05/14/armeria-sprint-1","ja":"/blog/ja/2019/06/21/armeria-sprint-1"}},"unlisted":false,"prevItem":{"title":"\uC0DD\uC560 \uCCAB \uC624\uD508 \uC18C\uC2A4 \uAE30\uC5EC \uACBD\uD5D8(feat. Armeria)","permalink":"/blog/ko/2019/12/24/my-first-opensource-contribution-to-armeria"},"nextItem":{"title":"\uC624\uD508\uC18C\uC2A4 Armeria\uC758 \uAE30\uC5EC\uC790\uB97C \uC704\uD55C \uC774\uBCA4\uD2B8\uB97C \uC9C4\uD589\uD558\uC600\uC2B5\uB2C8\uB2E4","permalink":"/blog/ko/2019/04/16/thank-you-for-contributing-to-armeria"}},"content":"## \uB4E4\uC5B4\uAC00\uBA70\\n\\n\uC548\uB155\uD558\uC138\uC694. \uD639\uC2DC \uB3C5\uC790\uBD84\uB4E4 \uC911\uC5D0\uC11C [GitHub contribution graph](https://help.github.com/en/articles/viewing-contributions-on-your-profile#contributions-calendar)\uC5D0 \uAC00\uBB44\uC774 \uC628 \uBD84\uB4E4\uC774 \uACC4\uC2E0\uAC00\uC694? \uC774\uBC88 \uAE00\uC5D0\uC11C\uB294 \uAC00\uBB44\uC744 \uBB3C\uB7EC\uAC00\uAC8C \uD560 Armeria Sprint \uD589\uC0AC\uB97C \uC18C\uAC1C\uD558\uACE0 \uADF8 \uD6C4\uAE30\uB97C \uACF5\uC720\uD558\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n\uC885\uC885 \uAE30\uC220 \uCEE8\uD37C\uB7F0\uC2A4\uC758 \uC2A4\uCF00\uC904\uC5D0\uC11C \'\uC2A4\uD504\uB9B0\uD2B8(sprint)\'\uB77C\uB294 \uC77C\uC815\uC744 \uBCF4\uC2E0 \uC801\uC774 \uC788\uC744 \uAC81\uB2C8\uB2E4(\uC608\uB97C \uB4E4\uBA74, [PYCON Development Sprint](https://us.pycon.org/2019/community/sprints/)). \uD639\uC740 \uC560\uC790\uC77C(agile) \uAC1C\uBC1C \uBC29\uBC95\uB860\uC5D0 \uB4F1\uC7A5\uD558\uB294 \uB2E8\uC5B4\uB77C\uC11C \uC2A4\uD504\uB9B0\uD2B8\uB77C\uB294 \uB2E8\uC5B4\uB97C \uCE5C\uC219\uD558\uAC8C \uB290\uB07C\uB294 \uBD84\uB4E4\uB3C4 \uB9CE\uC744 \uAC70\uB77C\uACE0 \uC0DD\uAC01\uD558\uB294\uB370\uC694. \uADF8\uB7FC \uC624\uD508\uC18C\uC2A4 \uC2A4\uD504\uB9B0\uD2B8\uB780 \uBB34\uC5C7\uC778\uC9C0, \uADF8\uB9AC\uACE0 \uC624\uD508\uC18C\uC2A4 \uC2A4\uD504\uB9B0\uD2B8\uC778 \'Armeria Sprint\'\uC5D0\uC11C\uB294 \uC5B4\uB5A4 \uD65C\uB3D9\uC774 \uC9C4\uD589\uB418\uC5C8\uB294\uC9C0 \uC18C\uAC1C\uD574\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/armeria-sprint-1-1.png)\\n\\n{/* truncate */}\\n\\n## \uC624\uD508\uC18C\uC2A4 \uC2A4\uD504\uB9B0\uD2B8\uAC00 \uBB50\uC8E0?\\n\\n\uC624\uD508\uC18C\uC2A4 \uC2A4\uD504\uB9B0\uD2B8\uB780 \uC624\uD508\uC18C\uC2A4\uC5D0 \uAD00\uC2EC\uC788\uB294 \uC0AC\uB78C\uB4E4\uC774 \uBAA8\uC5EC\uC11C \uC624\uD508\uC18C\uC2A4\uC5D0 \uAE30\uC5EC\uD574 \uBCF4\uB294 \uAC83\uC774\uB77C\uACE0 \uC815\uC758\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4(\uC624\uD508\uC18C\uC2A4 \uAE30\uC5EC\uC5D0 \uB300\uD574\uC11C\uB294 [\uC9C0\uB09C \uD3EC\uC2A4\uD305](/blog/ko/2019/04/16/thank-you-for-contributing-to-armeria)\uC5D0\uC11C \uB354\uC6B1 \uC790\uC138\uD788 \uB2E4\uB8E8\uACE0 \uC788\uC73C\uB2C8 \uCC38\uACE0\uD574\uC8FC\uC138\uC694). \uD589\uC0AC\uB9C8\uB2E4 \uD3B8\uCC28\uAC00 \uC788\uACA0\uC9C0\uB9CC \uBCF4\uD1B5 \uC9C4\uD589 \uAE30\uAC04\uC744 \uD558\uB8E8 \uC815\uB3C4\uB85C \uC7A1\uACE0 \uC624\uC804\uC5D0\uB294 \uB2E4\uAC19\uC774 \uBAA8\uC5EC\uC11C \uAC01\uC790 \uD560 \uC77C(\uC5B4\uB5A4 \uC774\uC288\uB97C \uB9E1\uC544\uC11C \uD560\uC9C0)\uC744 \uC815\uD558\uACE0 \uC624\uD6C4\uC5D0\uB294 \uC9D1\uC911\uD574\uC11C \uCF54\uB529\uC744 \uD569\uB2C8\uB2E4.\\n\\n\uCC38\uC5EC\uD558\uB294 \uC0AC\uB78C\uC740 \uD06C\uAC8C \uBA58\uD1A0\uC640 \uBA58\uD2F0\uB85C \uB098\uB20C \uC218 \uC788\uB294\uB370\uC694. \uBA58\uD1A0\uB294 \uC8FC\uB85C \uC2A4\uD504\uB9B0\uD2B8\uC5D0\uC11C \uB2E4\uB8E8\uAE30\uB85C \uD55C \uC624\uD508\uC18C\uC2A4\uC5D0 \uC9C1\uC811 \uAE30\uC5EC\uD574\uBCF8 \uACBD\uD5D8\uC774 \uC788\uB294 \uC0AC\uB78C\uC774 \uB9E1\uACE0, \uC544\uC9C1 \uACBD\uD5D8\uC740 \uC5C6\uC9C0\uB9CC \uC774\uBC88 \uAE30\uD68C\uC5D0 \uAE30\uC5EC\uD574 \uBCF4\uAE30\uB85C \uB9C8\uC74C\uBA39\uACE0 \uCC38\uAC00 \uC2E0\uCCAD\uD55C \uC0AC\uB78C\uC774 \uBA58\uD2F0\uAC00 \uB429\uB2C8\uB2E4. \uC774\uBC88 \uC624\uD508\uC18C\uC2A4 \uC2A4\uD504\uB9B0\uD2B8\uC5D0\uC11C\uB294 \uBA54\uC778\uD14C\uC774\uB108 \uC138 \uBD84\uAED8\uC11C \uC9C1\uC811 \uBA58\uD1A0\uB85C \uB098\uC130\uC2B5\uB2C8\uB2E4.\\n\\n### \uC65C \uD558\uB294 \uAC70\uC608\uC694?\\n\\n\uC624\uD508\uC18C\uC2A4\uC5D0 \uAE30\uC5EC\uD574 \uBCF4\uACE0 \uC2F6\uC5B4\uB3C4 \uAC1C\uC778 \uC2DC\uAC04\uC744 \uB530\uB85C \uB0B4\uC5B4 \uC791\uC5C5\uD558\uB294 \uAC8C \uC0AC\uC2E4 \uC26C\uC6B4 \uC77C\uC740 \uC544\uB2D9\uB2C8\uB2E4. \uB610\uD55C \uC9C8\uBB38\uAC70\uB9AC\uB4E4\uC774 \uB9CE\uC740\uB370 \uC624\uD508\uC18C\uC2A4\uB294 \uC9C8\uBB38\uC744 \uC5B4\uB514\uC5D0 \uD574\uC57C \uD560\uC9C0 \uBAB0\uB77C \uB9DD\uC124\uC774\uB294 \uACBD\uC6B0\uB3C4 \uC788\uACE0, \uD63C\uC790\uC11C \uD558\uB294 \uAC83\uBCF4\uB2E4\uB294 \uC5EC\uB7FF\uC774 \uBAA8\uC600\uC744 \uB54C \uC870\uAE08 \uB354 \uC5F4\uC2EC\uD788 \uD574\uBCFC \uC218 \uC788\uB294 \uD798\uC774 \uC0DD\uAE30\uB294 \uACBD\uC6B0\uB3C4 \uB9CE\uC2B5\uB2C8\uB2E4. \uC624\uD508\uC18C\uC2A4 \uC2A4\uD504\uB9B0\uD2B8\uB294 \uC774\uB807\uAC8C \uD3C9\uC18C\uC5D0 \uB9C8\uC74C\uC740 \uC788\uC5C8\uC9C0\uB9CC \uD63C\uC790\uC11C\uB294 \uC624\uD508\uC18C\uC2A4\uC5D0 \uAE30\uC5EC\uD560 \uC2DC\uAC04\uC744 \uB0B4\uC9C0 \uBABB\uD588\uAC70\uB098, \uC624\uD508\uC18C\uC2A4 \uAE30\uC5EC\uB97C \uCC98\uC74C \uC2DC\uB3C4\uD574\uBCF4\uB294 \uC0AC\uB78C\uB4E4\uC744 \uB3D5\uAE30 \uC704\uD574 \uC5F4\uB9AC\uB294 \uD589\uC0AC\uC785\uB2C8\uB2E4.\\n\\n\uC0C8\uB85C\uC6B4 \uAE30\uC5EC\uC790\uB4E4\uC758 \uCC38\uC5EC\uB294 \uC624\uD508\uC18C\uC2A4 \uCEE4\uBBA4\uB2C8\uD2F0\uB97C \uB354\uC6B1 \uD48D\uC131\uD558\uAC8C \uB9CC\uB4ED\uB2C8\uB2E4. \uBA58\uD1A0\uB4E4\uC758 \uC785\uC7A5\uC5D0\uC11C\uB3C4 \uC5EC\uB7EC \uC0AC\uB78C\uB4E4\uC744 \uC9C1\uC811 \uB9CC\uB098 \uADF8\uB4E4\uC758 \uC9C8\uBB38\uC5D0 \uB2F5\uD558\uBA74\uC11C \uADF8\uB3D9\uC548 \uC0C8\uB85C\uC6B4 \uAE30\uC5EC\uC790\uB4E4\uC774 \uCC38\uC5EC\uD558\uAE30 \uC5B4\uB824\uC6E0\uB358 \uC7A5\uBCBD\uC774 \uBB34\uC5C7\uC774\uC5C8\uB294\uC9C0 \uD655\uC778\uD574 \uBCFC \uC218 \uC788\uB294 \uC18C\uC911\uD55C \uAE30\uD68C\uAC00 \uB429\uB2C8\uB2E4.\\n\\n## Armeria Sprint \uC815\uB9AC\\n\\n\uC774\uBC88 \uD589\uC0AC\uB294 LINE \uAC1C\uBC1C\uC790\uB97C \uB300\uC0C1\uC73C\uB85C \uCC38\uAC00\uC790\uB97C \uBAA8\uC9D1\uD588\uC2B5\uB2C8\uB2E4. \uBA58\uD1A0\uC640 \uBA58\uD2F0\uC758 \uBE44\uC728\uC744 \uACE0\uB824\uD574 \uC18C\uC218\uC758 \uC778\uC6D0\uB9CC \uCC38\uAC00\uC2E0\uCCAD\uC744 \uBC1B\uC558\uB294\uB370\uC694. \uAE08\uBC29 \uB9C8\uAC10\uB418\uACE0 \uCD94\uAC00\uB85C \uB300\uAE30 \uC904\uC744 \uC11C\uB294 \uBAA8\uC2B5\uC5D0 \uAE5C\uC9DD \uB180\uB790\uC2B5\uB2C8\uB2E4. \uCC38\uAC00 \uC2E0\uCCAD\uC744 \uD558\uB294 \uAC83\uBD80\uD130 \uC54C \uC218 \uC788\uB4EF\uC774 \uBAA8\uB450\uB4E4 \uC5F4\uC815\uC774 \uAC00\uB4DD\uD558\uC168\uC2B5\uB2C8\uB2E4. \uD589\uC0AC\uB294 \uC774\uD2C0\uC5D0 \uB098\uB204\uC5B4\uC11C \uCCAB\uC9F8 \uB0A0\uC5D0\uB294 \uD658\uC601 \uC138\uC158\uC774 2\uC2DC\uAC04 \uB3D9\uC548 \uC9C4\uD589\uB418\uC5C8\uACE0, \uB458\uC9F8 \uB0A0\uC5D0\uB294 \uC2A4\uD504\uB9B0\uD2B8\uAC00 4\uC2DC\uAC04 \uB3D9\uC548 \uC9C4\uD589\uB418\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\n### Welcome Session\\n\\n\uD658\uC601 \uC138\uC158\uC5D0\uC120 \uCC38\uAC00\uC790\uB4E4\uC774 \uAC01\uC790 \uC790\uAE30 \uC18C\uAC1C\uB97C \uD55C \uB4A4, \uC544\uB798\uC758 \uB0B4\uC6A9\uC744 \uAC00\uBCCD\uAC8C \uB2E4\uB8E8\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\n#### \uC624\uD508\uC18C\uC2A4\uC5D0 \uAE30\uC5EC\uD558\uAE30 \uC804\uC5D0 \uC77D\uC5B4\uBCF4\uC544\uC57C \uD560 \uAC83\\n\\n- [Contributing](https://github.com/line/armeria/blob/master/CONTRIBUTING.md)\\n  - \uD504\uB85C\uC81D\uD2B8\uC5D0 \uAE30\uC5EC\uD558\uB294 \uBC29\uBC95\uC774\uB098 \uAE30\uC5EC\uD560 \uB54C \uC9C0\uCF1C\uC57C \uD560 \uADDC\uCE59\uC774 \uC124\uBA85\uB418\uC5B4 \uC788\uB294 \uBB38\uC11C\uC785\uB2C8\uB2E4.\\n  - Armeria\uC5D0\uC11C\uB294 \uC774\uB7F0 \uC0AC\uD56D\uB4E4\uC744 [Checklist for your pull request](https://github.com/line/armeria/blob/master/CONTRIBUTING.md#checklist-for-your-pull-request)\uB85C \uC815\uB9AC\uD574 \uB193\uC558\uC2B5\uB2C8\uB2E4. \uC798 \uD655\uC778\uD574\uB450\uBA74 \uCF54\uB4DC \uB9AC\uBDF0\uC5D0 \uAC78\uB9AC\uB294 \uC2DC\uAC04\uC744 \uB2E8\uCD95\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n- [Contributor License Agreement](https://cla-assistant.io/line/armeria)\\n  - \uD3C9\uC18C\uC5D0\uB294 \uADF8\uB0E5 \uC9C0\uB098\uCCE4\uC744 \uBC95\uD55C \uBB38\uC11C\uC785\uB2C8\uB2E4. \uC624\uD508\uC18C\uC2A4\uC5D0\uC11C\uB294 \uBCF4\uD1B5 \uAE30\uC5EC\uB97C \uBC1B\uAE30 \uC804\uC5D0 \uC11C\uBA85\uC744 \uC694\uAD6C\uD569\uB2C8\uB2E4.\\n  - \uC11C\uBA85 \uB0B4\uC6A9\uC744 \uC9E7\uAC8C \uC138 \uC904\uB85C \uC694\uC57D\uD574\uBCF4\uC558\uC2B5\uB2C8\uB2E4(\uD504\uB85C\uC81D\uD2B8\uB9C8\uB2E4 \uB0B4\uC6A9\uC740 \uB2E4\uB97C \uC218 \uC788\uC2B5\uB2C8\uB2E4).\\n    - \uC11C\uBA85\uC758 \uBAA9\uC801\uC740 \uAE30\uC5EC\uC790\uC640 \uD504\uB85C\uC81D\uD2B8, \uC720\uC800\uB97C \uBCF4\uD638\uD558\uAE30 \uC704\uD568\uC785\uB2C8\uB2E4.\\n    - \uC11C\uBA85\uC744 \uC644\uB8CC\uD558\uBA74 \uC5EC\uB7EC\uBD84\uC740 \uAC01\uC790\uAC00 \uAE30\uC5EC\uD55C \uBD80\uBD84\uC744 Armeria \uD504\uB85C\uC81D\uD2B8\uC640 \uB3D9\uC77C\uD55C \uC870\uAC74\uC73C\uB85C \uACF5\uAC1C\uD558\uB294 \uAC83\uC5D0 \uB3D9\uC758\uD558\uAC8C \uB429\uB2C8\uB2E4.\\n    - \uC5EC\uB7EC\uBD84\uC758 \uAE30\uC5EC\uB294 \uD604\uC7AC \uC0C1\uD0DC \uADF8\uB300\uB85C Armeria \uD504\uB85C\uC81D\uD2B8\uC5D0 \uBC18\uC601\uB420 \uAC83\uC774\uBA70 \uC5B4\uB5A4 \uBC84\uADF8\uB098 \uACB0\uD568\uC774 \uC788\uC5B4\uB3C4 \uADF8\uC5D0 \uB300\uD55C \uCC45\uC784\uC740 \uC9C0\uC9C0 \uC54A\uC544\uB3C4 \uB429\uB2C8\uB2E4.\\n- [Code of Conduct](https://github.com/line/armeria/blob/master/CODE_OF_CONDUCT.md)\\n  - \uCEE4\uBBA4\uB2C8\uD2F0\uC5D0\uC11C \uC900\uC218\uD574\uC57C \uD560 \uD589\uB3D9 \uADDC\uBC94\uC785\uB2C8\uB2E4. \uC624\uD508\uC18C\uC2A4\uC758 \uAE30\uBCF8 \uC815\uC2E0\uC778 \'\uC790\uC720\'\uB97C \uCD94\uAD6C\uD558\uAE30 \uC704\uD574\uC11C \uAF2D \uC9C0\uCF1C\uC57C \uD558\uB294 \uD589\uB3D9 \uADDC\uBC94\uC744 \uC124\uBA85\uD558\uB294 \uBB38\uC11C\uC785\uB2C8\uB2E4.\\n\\n#### \uD560 \uC77C \uC815\uD558\uAE30\\n\\n\uCCAB\uB0A0 \uBAA8\uC774\uB294 \uAC00\uC7A5 \uD070 \uC774\uC720\uAC00 \uBC14\uB85C \uAC01\uC790 \uD560 \uC77C\uC744 \uC815\uD558\uAE30 \uC704\uD574\uC11C\uC600\uB294\uB370\uC694. \uB2E4\uAC19\uC774 \uBAA8\uC5EC \uCD08\uC2EC\uC790\uB97C \uAE30\uB2E4\uB9AC\uB294 \uC774\uC288\uB4E4([good-first-issues](https://github.com/line/armeria/issues?q=is%3Aopen+is%3Aissue+label%3Agood-first-issue))\uC744 \uD568\uAED8 \uD655\uC778\uD574 \uBCF4\uC558\uC2B5\uB2C8\uB2E4. \uC774\uC288\uB9C8\uB2E4 \uAC01\uAC01 \uC124\uBA85\uC774 \uC4F0\uC5EC\uC788\uAE34 \uD558\uC9C0\uB9CC, \uC5B4\uB5A4 \uBC30\uACBD\uC774\uB098 \uD750\uB984\uC5D0\uC11C \uC774\uB7F0 \uC774\uC288\uAC00 \uBC1C\uACAC\uB418\uC5C8\uB294\uC9C0 \uB610\uB294 \uD574\uB2F9 \uC774\uC288\uB97C \uD574\uACB0\uD558\uAE30 \uC704\uD574 \uC5B4\uB5A4 \uAE30\uC220 \uBC30\uACBD\uC9C0\uC2DD\uC774 \uD544\uC694\uD558\uACE0 \uC5B4\uB5A4 \uBD80\uBD84\uC744 \uBD10\uC57C\uD558\uB294\uC9C0 \uB4F1 \uC870\uAE08 \uB354 \uC790\uC138\uD55C \uC124\uBA85\uC744 \uB4E4\uC744 \uC218 \uC788\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\n\uC5B4\uB5A4 \uC774\uC288\uB97C \uB9E1\uC744\uC9C0 \uB9C8\uC74C\uC744 \uC815\uD588\uB2E4\uBA74, \uC7AC\uBE68\uB9AC \uD574\uB2F9 \uC774\uC288\uC5D0 \'I am working on this.\' \uB610\uB294 \'I\'ll handle this issue.\' \uB4F1\uC758 \uB313\uAE00\uC744 \uB0A8\uACA8 \uB2E4\uB978 \uC0AC\uB78C\uACFC \uC774\uC288\uAC00 \uACB9\uCE58\uC9C0 \uC54A\uB3C4\uB85D \uD45C\uC2DC\uD569\uB2C8\uB2E4.\\n\\n#### \uAC1C\uBC1C \uD658\uACBD \uC124\uC815\uD558\uAE30\\n\\n\uBAA8\uB450\uAC00 \uC774\uC288\uB97C \uACE0\uB978 \uB4A4, \uB2E4 \uD568\uAED8 \uCC28\uADFC\uCC28\uADFC \uAC1C\uBC1C \uD658\uACBD\uC744 \uC124\uC815\uD588\uC2B5\uB2C8\uB2E4([\uAC1C\uBC1C \uD658\uACBD \uC124\uC815 \uBC29\uBC95](https://github.com/line/armeria/blob/master/CONTRIBUTING.md#setting-up-your-ide)).\\n\\n![](/img/armeria-sprint-1-2.jpg)\\n\\n\uAC1C\uBC1C \uD658\uACBD\uC744 \uC124\uC815\uD560 \uB54C \'fork&clone\uC774 \uB2E4 \uB41C \uC0AC\uB78C\uC740 \uBB3C\uBCD1\uC744 \uB215\uD600\uC11C \uD45C\uC2DC\uD574\uC8FC\uC138\uC694.\'\uB77C\uB294 \uC18C\uC18C\uD55C \uD65C\uB3D9\uAE4C\uC9C0 \uB354\uD574\uC84C\uC2B5\uB2C8\uB2E4.\\n\\n### \uC2A4\uD504\uB9B0\uD2B8 \uACB0\uACFC\\n\\n\uC774\uBC88 \uC2A4\uD504\uB9B0\uD2B8\uB97C \uD1B5\uD574 \uC0C8\uB85C open\uD55C pull request\uB4E4\uC785\uB2C8\uB2E4.\\n\\n- [#1742](https://github.com/line/armeria/pull/1742) Allow using wildcards with RequestContextExportingAppender\\n- [#1743](https://github.com/line/armeria/pull/1743) Provide a way to create a client with an Endpoint rather than with a URI\\n- [#1744](https://github.com/line/armeria/pull/1744) Show armeria version in doc service\\n- [#1745](https://github.com/line/armeria/pull/1745) Enable to convert JSON format request to String\\n- [#1747](https://github.com/line/armeria/pull/1747) Introduce \'export-as-curl\' button to a debug request window\\n\\n![](/img/armeria-sprint-1-3.jpeg)\\n\\n\uBD80\uB044\uB7FC \uB9CE\uC740 \uCC38\uAC00\uC790\uB4E4\uC758 \uCD08\uC0C1\uAD8C\uC740 \uC800\uD76C\uAC00 \uC9C0\uCF1C \uB4DC\uB9AC\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n![](/img/armeria-sprint-1-4.jpeg)\\n\\n\uB0B4 \uB7A9\uD0D1\uC740 \uB0B4\uAC00 \uC9C0\uD0A8\uB2E4! \uC11C\uC788\uB294 \uD55C\uC774 \uC788\uB354\uB77C\uB3C4 \uD53C\uC790\uB294 \uB7A9\uD0D1\uACFC \uBA40\uB9AC\uBA40\uB9AC~\\n\\n### \uD6C4\uAE30\\n\\n#### \uCC38\uAC00\uC790\uB4E4\uC758 \uD6C4\uAE30\\n\\n- \uD3B8\uD558\uAC8C \uBB3C\uC5B4\uBCFC \uC218 \uC788\uB294 \uBA58\uD1A0\uAC00 \uD568\uAED8 \uC788\uB2E4\uB294 \uC810, \uADF8\uB9AC\uACE0 \uC11C\uB85C \uBC30\uB824\uD574\uC8FC\uB294 \uBAA8\uC2B5\uC774 \uC88B\uC558\uC2B5\uB2C8\uB2E4. \uC624\uD508\uC18C\uC2A4\uC5D0 \uB300\uD55C \uB9C9\uC5F0\uD55C \uB450\uB824\uC6C0\uC744 \uC904\uC77C \uC218 \uC788\uB294 \uC774\uB7F0 \uAE30\uD68C\uAC00 \uC55E\uC73C\uB85C\uB294 \uB354 \uB9CE\uC558\uC73C\uBA74 \uC88B\uACA0\uC2B5\uB2C8\uB2E4.\\n- \uC124\uBA85\uC73C\uB85C\uB294 \uBD84\uBA85 \uC26C\uC6CC \uBCF4\uC5EC\uC11C \uC774\uC288\uB97C \uACE8\uB790\uB294\uB370 \uC544\uBB34\uB798\uB3C4 \uBA58\uD1A0\uC758 \uAF80\uC784\uC5D0 \uB118\uC5B4\uAC04 \uAC83 \uAC19\uC2B5\uB2C8\uB2E4(\u314B\u314B). \uADF8\uB807\uC9C0\uB9CC \uC624\uD508\uC18C\uC2A4\uC5D0 \uAE30\uC5EC\uD574\uBCF4\uB294 \uC2DC\uAC04\uC744 \uAC00\uC9C8 \uC218 \uC788\uB2E4\uB294 \uC810\uC774 \uAD49\uC7A5\uD788 \uC88B\uC558\uC2B5\uB2C8\uB2E4.\\n- \uAC1C\uBC1C\uC790\uB77C\uBA74 \uB204\uAD6C\uB098 \uD55C \uBC88\uCBE4\uC740 \'\uC624\uD508\uC18C\uC2A4\uC5D0 \uAE30\uC5EC\uD574\uBD10\uC57C\uC9C0\'\uD558\uACE0 \uC0DD\uAC01\uD574 \uBD24\uC744\uD150\uB370\uC694. \uC774\uB807\uAC8C \uC2DC\uC791\uD574\uBCFC \uC218 \uC788\uB294 \uAE30\uD68C\uAC00 \uC788\uC5B4\uC11C \uC88B\uC558\uC2B5\uB2C8\uB2E4.\\n- \uB9C9\uC0C1 \uD574\uACB0\uD558\uACE0 \uBCF4\uB2C8 \uC2E4\uC81C \uCF54\uB529\uD55C \uAC74 \uBA87 \uC904 \uC548\uB41C \uAC83 \uAC19\uC544\uC694. \uADF8\uB807\uC9C0\uB9CC \uC0DD\uAC01\uD574 \uBCFC \uAC70\uB9AC\uAC00 \uB9CE\uC740 \uC774\uC288\uC600\uC2B5\uB2C8\uB2E4.\\n- \uC774\uC288\uC5D0 \uB300\uD55C \uC124\uBA85\uC740 \uC26C\uC6E0\uB294\uB370\uC694. \uAE30\uC874 \uCF54\uB4DC\uB97C \uC774\uD574\uD558\uB294\uB370 \uC2DC\uAC04\uC774 \uC624\uB798 \uAC78\uB9B0 \uAC83 \uAC19\uC2B5\uB2C8\uB2E4. Armeria\uC758 \uCF54\uB4DC\uB098 \uAD6C\uC870\uB97C \uC804\uBC18\uC801\uC73C\uB85C \uD6D1\uC5B4\uBCF4\uB294 \uC2DC\uAC04\uC774 \uBA3C\uC800 \uC788\uC73C\uBA74 \uC870\uAE08 \uB354 \uC27D\uAC8C \uC811\uADFC\uD560 \uC218 \uC788\uC744 \uAC83 \uAC19\uC2B5\uB2C8\uB2E4.\\n- \uADF8\uB3D9\uC548 \uB2E4\uB978 \uC624\uD508\uC18C\uC2A4\uC5D0 \uAE30\uC5EC\uD574\uBCF4\uB824\uACE0 \uBA87 \uBC88 \uC2DC\uB3C4\uB97C \uD55C \uC801\uC774 \uC788\uB294\uB370 \uB9E4\uBC88 \uC2E4\uD328\uD588\uC2B5\uB2C8\uB2E4. \uC774\uBC88\uC5D0\uB294 \uBA58\uD1A0\uAC00 \uC606\uC5D0 \uC788\uC73C\uB2C8 \uC27D\uAC8C \uAE30\uC5EC\uD560 \uC218 \uC788\uC5C8\uC2B5\uB2C8\uB2E4.\\n- \uD300\uC5D0\uC11C Armeria\uB97C \uC0AC\uC6A9 \uC911\uC785\uB2C8\uB2E4. \uAC1C\uBC1C\uD558\uB2E4\uAC00 \uBB54\uAC00 \uD544\uC694\uD55C \uAC83\uC774 \uC788\uC744 \uB54C\uAC00 \uC788\uB294\uB370\uC694. \uADF8\uB7F4 \uB54C \uC55E\uC73C\uB85C\uB294 \uC9C1\uC811 \uAE30\uC5EC\uD574\uC11C \uACE0\uCCD0\uBCF4\uBA74 \uC88B\uACA0\uB2E4\uACE0 \uC0DD\uAC01\uD574\uC11C \uCC38\uC5EC\uD558\uAC8C \uB418\uC5C8\uC2B5\uB2C8\uB2E4. \uCF54\uB4DC\uB97C \uC77D\uC73C\uBA74\uC11C \uACF5\uBD80\uB97C \uC870\uAE08 \uB354 \uD574\uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n- \uC800\uC5D0\uAC8C\uB294 \uC774\uC288\uC5D0 \uC811\uADFC\uD558\uB294 \uAC83\uC774 \uC870\uAE08 \uC5B4\uB835\uAC8C \uB290\uAEF4\uC84C\uC2B5\uB2C8\uB2E4. \uADF8\uB807\uC9C0\uB9CC \uC774\uBC88 \uAE30\uD68C\uC5D0 \uAE30\uBCF8\uAE30\uB97C \uB2E4\uC9C0\uAC8C \uB41C \uAC83 \uAC19\uC544 \uC88B\uC558\uC2B5\uB2C8\uB2E4.\\n- \uC5B4\uB290 \uC815\uB3C4 \uAE30\uB2A5 \uAD6C\uD604\uC740 \uB2E4 \uB41C \uAC83 \uAC19\uC740\uB370 pull request\uB97C \uC5F4\uAE30 \uC804\uC5D0 \uC2DC\uAC04\uC774 \uB05D\uB098\uC11C \uC544\uC27D\uC2B5\uB2C8\uB2E4. \uC815\uB9AC\uD574\uC11C \uC870\uB9CC\uAC04 pull request \uC5F4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n#### \uBA58\uD1A0\uB4E4\uC758 \uD6C4\uAE30\\n\\n- \uC624\uD508\uC18C\uC2A4 \uAC1C\uBC1C\uC744 \uC5B4\uB824\uC6CC\uD558\uC2DC\uB294 \uBD84\uB4E4\uC5D0\uAC8C - \uC5B4\uB5A4 \uC774\uC288\uB97C \uBCF4\uACE0 \uC5B4\uB5BB\uAC8C \uD574\uACB0\uD560 \uC218 \uC788\uC744\uC9C0 \uC798 \uBAA8\uB974\uACA0\uB2E4\uBA74, \uC5B4\uB5BB\uAC8C \uD574\uACB0\uD558\uBA74 \uC88B\uC744\uC9C0 \uADF8 \uC774\uC288\uC5D0 \uB313\uAE00\uC744 \uB0A8\uAE30\uB294 \uAC83\uBD80\uD130\uAC00 \uC624\uD508\uC18C\uC2A4 \uAE30\uC5EC\uC758 \uC2DC\uC791\uC785\uB2C8\uB2E4. \uB108\uBB34 \uAC71\uC815\uD558\uC9C0 \uB9D0\uACE0 \uB9C8\uAD6C \uBB3C\uC5B4\uBCF4\uC138\uC694. \uADF8\uB7F0 \uC9C8\uBB38\uB4E4\uC774 \uC800\uD76C\uC5D0\uAC8C\uB294 \uB9CE\uC740 \uB3C4\uC6C0\uC774 \uB429\uB2C8\uB2E4.\\n- \uC774\uBC88 \uAE30\uD68C\uB85C \uC624\uD508\uC18C\uC2A4\uC5D0 \uAD00\uC2EC\uC774 \uC788\uB294 \uAC1C\uBC1C\uC790 \uB3D9\uB8CC\uB4E4\uC774 \uC774\uB807\uAC8C\uB098 \uB9CE\uC558\uB2E4\uB294 \uAC83\uC744 \uC54C \uC218 \uC788\uC5C8\uC2B5\uB2C8\uB2E4. \uD568\uAED8 \uAC19\uC740 \uACF5\uAC04\uC5D0\uC11C \uC11C\uB85C \uB3C4\uC6B8 \uC218 \uC788\uC5B4\uC11C \uBFCC\uB4EF\uD588\uC2B5\uB2C8\uB2E4(Star\uB294 \uBAA8\uB450 \uC78A\uC9C0 \uC54A\uC73C\uC168\uC8E0?).\\n- \uCC98\uC74C \uD574\uBCF4\uB294 \uD589\uC0AC\uB77C\uC11C \uC870\uAE08 \uAC71\uC815\uC744 \uD588\uB294\uB370 \uCC38\uAC00\uC790 \uBAA8\uB450 \uAD49\uC7A5\uD788 \uC9C4\uC9C0\uD558\uAC8C \uC784\uD574\uC8FC\uC154\uC11C \uAC10\uC0AC\uD558\uB2E4\uB294 \uB9D0\uC500\uC744 \uB4DC\uB9AC\uACE0 \uC2F6\uC2B5\uB2C8\uB2E4. \uD589\uC0AC \uC2DC\uAC04\uC740 \uB05D\uB0AC\uC9C0\uB9CC \uC9C8\uBB38\uC774 \uC788\uC744 \uB54C\uB294 \uC5B8\uC81C\uB4E0\uC9C0 GitHub\uC774\uB098 Slack\uC5D0 \uB0A8\uACA8\uC8FC\uC138\uC694.\\n- \uBB3C\uB860 \uC624\uB298 pull request\uB97C \uC5EC\uB294 \uAC83\uB9CC\uC73C\uB85C\uB3C4 \uD070 \uC9C4\uC804\uC774\uC5C8\uC9C0\uB9CC, \uC2DC\uC791\uC740 \uC9C0\uAE08\uBD80\uD130\uB77C\uACE0 \uB9D0\uC500\uB4DC\uB9AC\uACE0 \uC2F6\uC2B5\uB2C8\uB2E4. \uD2B9\uD788 \uCF54\uB4DC \uB9AC\uBDF0\uB97C \uD1B5\uD574\uC11C \uAC1C\uBC1C \uC2E4\uB825\uC774 \uB9CE\uC774 \uC131\uC7A5\uD558\uAE30 \uB54C\uBB38\uC5D0 \uD3EC\uAE30\uD558\uC9C0 \uB9D0\uACE0 \uBA38\uC9C0(merge)\uB418\uAE30\uAE4C\uC9C0 \uC5F4\uC2EC\uD788 \uB530\uB77C\uC640 \uC8FC\uC2DC\uBA74 \uC88B\uACA0\uC2B5\uB2C8\uB2E4.\\n- \uAE30\uC5EC\uC790\uB97C \uC9C1\uC811 \uB9CC\uB098 \uD568\uAED8 \uBB38\uC81C\uB97C \uD574\uACB0\uD558\uB294 \uC2DC\uAC04\uC774 \uAD49\uC7A5\uD788 \uB73B\uAE4A\uC5C8\uC2B5\uB2C8\uB2E4. \uC55E\uC73C\uB85C\uB3C4 \uC774\uB7F0 \uD589\uC0AC\uB97C \uC790\uC8FC\uD558\uBA74 \uC88B\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n## \uC815\uB9AC\uD558\uBA70\\n\\n\uCC38\uAC00\uC790 \uC5EC\uB7EC\uBD84\uB4E4 \uBAA8\uB450 \uACE0\uC0DD \uB9CE\uC73C\uC168\uC2B5\uB2C8\uB2E4. \uC774\uBC88 \uD589\uC0AC\uAC00 \uD568\uAED8 \uC131\uC7A5\uD558\uB294 \uC2DC\uAC04\uC774 \uB418\uC5C8\uAE38 \uBC14\uB78D\uB2C8\uB2E4. \uBAA8\uB450\uB4E4 \uC990\uAC81\uAC8C \uCC38\uC5EC\uD574\uC8FC\uC154\uC11C \uAC10\uC0AC\uB4DC\uB9AC\uBA70, \uB2E4\uC74C\uC5D0 \uB354\uC6B1 \uC54C\uCC2C \uD589\uC0AC\uB85C \uB3CC\uC544\uC624\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n\uC800\uB294 \uC774\uB7F0 \uC885\uB958\uC758 \uD589\uC0AC\uB97C \uCC98\uC74C \uC9C4\uD589\uD574\uBCF4\uC558\uB294\uB370\uC694. \uC544\uB798 \uB450 \uBB38\uC11C\uC5D0\uC11C \uD070 \uB3C4\uC6C0\uC744 \uBC1B\uC558\uC2B5\uB2C8\uB2E4. \uC774 \uAE00\uC744 \uD1B5\uD574\uC11C \uC544\uB798 \uB450 \uBB38\uC11C\uB97C \uC791\uC131\uD558\uC2E0 \uBD84\uB4E4\uAED8\uB3C4 \uAC10\uC0AC\uC758 \uC778\uC0AC\uB97C \uB4DC\uB9BD\uB2C8\uB2E4.\\n\\n- [Open Source Contribution Sprint Guide by DRUD](https://github.com/drud/sprint_guide)\\n- [The In-Person Event Handbook by opensource-events](https://opensourceevents.github.io/) ([\uD55C\uAD6D\uC5B4 \uBC88\uC5ED\uBCF8](https://muchtrans.com/translations/in-person-event-handbook.ko.html))"},{"id":"/2019/04/16/thank-you-for-contributing-to-armeria","metadata":{"permalink":"/blog/ko/2019/04/16/thank-you-for-contributing-to-armeria","editUrl":"https://github.com/line/armeria/edit/main/site-new/src/content/blog/ko/2019-04-16-thank-you-for-contributing-to-armeria.mdx","source":"@site/src/content/blog/ko/2019-04-16-thank-you-for-contributing-to-armeria.mdx","title":"\uC624\uD508\uC18C\uC2A4 Armeria\uC758 \uAE30\uC5EC\uC790\uB97C \uC704\uD55C \uC774\uBCA4\uD2B8\uB97C \uC9C4\uD589\uD558\uC600\uC2B5\uB2C8\uB2E4","description":"\uB4E4\uC5B4\uAC00\uBA70","date":"2019-04-16T00:00:00.000Z","tags":[],"readingTime":9.23,"hasTruncateMarker":true,"authors":[{"name":"\uC774\uC11C\uC5F0","title":"LINE\uC5D0\uC11C \uC624\uD508\uC18C\uC2A4\uB97C \uB2F4\uB2F9\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4.","imageURL":"https://github.com/syleeeee.png","key":"seoyeonlee","page":null}],"frontMatter":{"authors":["seoyeonlee"],"other_languages":{"en":"/blog/2019/04/16/thank-you-for-contributing-to-armeria","ja":"/blog/ja/2019/05/23/thank-you-for-contributing-to-armeria"}},"unlisted":false,"prevItem":{"title":"GitHub Contributions \uADF8\uB798\uD504\uB97C \uD478\uB987\uD478\uB987\uD558\uAC8C \uB9CC\uB4E4\uC5B4\uBCF4\uC544\uC694(feat. Armeria Sprint)","permalink":"/blog/ko/2019/05/09/armeria-sprint-1"},"nextItem":{"title":"Channel Gateway\uC5D0 CircuitBreaker \uC801\uC6A9","permalink":"/blog/ko/2016/08/04/applying-circuitbreaker-to-channel-gateway"}},"content":"## \uB4E4\uC5B4\uAC00\uBA70\\n\\n\uC548\uB155\uD558\uC138\uC694.\\nLINE\uC5D0\uC11C \uC624\uD508\uC18C\uC2A4\uB97C \uB2F4\uB2F9\uD558\uACE0 \uC788\uB294 \uC774\uC11C\uC5F0\uC785\uB2C8\uB2E4. \uC774\uBC88 \uAE00\uC5D0\uC11C\uB294 LINE\uC5D0\uC11C \uC774\uBC88\uC5D0 \uCC98\uC74C \uC2DC\uD589\uD55C \uC774\uBCA4\uD2B8\uC778 \'Armeria contributor reward\'\uB97C \uC18C\uAC1C\uD558\uACE0 \uADF8 \uD6C4\uAE30\uB97C \uACF5\uC720\uB4DC\uB9AC\uB824\uACE0 \uD569\uB2C8\uB2E4. \uCC38\uACE0\uB85C \uC774\uBC88 \uAE00\uC5D0\uC11C\uB294 Armeria\uC5D0 \uB300\uD55C \uAE30\uC220\uC801\uC778 \uC124\uBA85\uC740 \uD558\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4. \uAE30\uC220\uC5D0 \uB300\uD55C \uC790\uC138\uD55C \uC124\uBA85\uC740 [\uACF5\uC2DD \uD648\uD398\uC774\uC9C0](https://line.github.io/armeria)\uC5D0\uC11C \uD655\uC778\uD558\uC2E4 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n[Armeria](https://github.com/line/armeria) \uD504\uB85C\uC81D\uD2B8\uB294 LINE\uC5D0\uC11C \uAC1C\uBC1C\uD558\uC5EC \uC624\uD508\uC18C\uC2A4\uB85C \uACF5\uAC1C\uD55C \uD504\uB85C\uC81D\uD2B8\uC785\uB2C8\uB2E4. \uBE44\uB85D \uC2DC\uC791\uC740 LINE\uC5D0\uC11C \uD588\uC9C0\uB9CC, Armeria\uAC00 \uC9C0\uAE08\uC758 \uBAA8\uC2B5\uC744 \uAC16\uCD94\uAE30\uAE4C\uC9C0\uB294 LINE \uBC16 \uC5EC\uB7EC \uAE30\uC5EC\uC790(contributor)\uBD84\uB4E4\uC758 \uC5F4\uC815\uC801\uC778 \uCC38\uC5EC\uAC00 \uD070 \uC5ED\uD560\uC744 \uB2F4\uB2F9\uD588\uC2B5\uB2C8\uB2E4. \uC774\uC5D0 \uC800\uD76C\uB294 \uAE30\uC5EC\uC790\uB4E4\uC5D0\uAC8C \uAC10\uC0AC\uC758 \uB73B\uC744 \uC804\uD558\uACE0\uC790 \uC774\uBC88 \uC774\uBCA4\uD2B8\uB97C \uAE30\uD68D\uD558\uAC8C \uB418\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\n\uBCF8 \uB0B4\uC6A9\uC73C\uB85C \uB4E4\uC5B4\uAC00\uAE30 \uC804\uC5D0 \'\uC624\uD508\uC18C\uC2A4 \uAE30\uC5EC\'\uAC00 \uBB34\uC5C7\uC778\uC9C0 \uBA3C\uC800 \uC815\uB9AC\uD574\uBCF4\uC558\uC2B5\uB2C8\uB2E4.\\n\\n{/* truncate */}\\n\\n## \uC624\uD508\uC18C\uC2A4 \uAE30\uC5EC\uB780?\\n\\n\uD68C\uC0AC\uC5D0\uC11C \uD504\uB85C\uC81D\uD2B8\uB97C \uC9C4\uD589\uD558\uBA74 \uAC1C\uBC1C\uD300, \uAE30\uD68D\uD300, \uC0AC\uC5C5\uD300, \uB514\uC790\uC778\uD300 \uB4F1 \uC5EC\uB7EC \uBD84\uC57C\uC758 \uC0AC\uB78C\uB4E4\uC774 \uD568\uAED8 \uBAA8\uC5EC \uC77C\uC744 \uD569\uB2C8\uB2E4. \uC624\uD508\uC18C\uC2A4 \uD504\uB85C\uC81D\uD2B8\uB3C4 \uC774\uC640 \uB9C8\uCC2C\uAC00\uC9C0\uC785\uB2C8\uB2E4. \uAC1C\uBC1C \uC774\uC678\uC5D0\uB3C4 \uD14C\uC2A4\uD2B8, \uD64D\uBCF4, \uB514\uC790\uC778, \uADF8\uB9AC\uACE0 \uBB38\uC11C\uD654 \uB4F1\uC758 \uC791\uC5C5\uC774 \uBAA8\uB450 \uBAA8\uC5EC \uD558\uB098\uC758 \uD6CC\uB96D\uD55C \uC624\uD508\uC18C\uC2A4\uB97C \uB9CC\uB4E4\uC5B4 \uB0C5\uB2C8\uB2E4. \uAC04\uD639 \uC624\uD508\uC18C\uC2A4 \uAE30\uC5EC\uB97C \uC881\uC740 \uC758\uBBF8\uB85C\uB9CC \uD574\uC11D\uD558\uC5EC \uC9C1\uC811 \uC791\uC131\uD55C \uCF54\uB4DC\uAC00 \uD504\uB85C\uC81D\uD2B8 \uCF54\uB4DC\uC5D0 \uBA38\uC9C0(merge)\uB418\uB294 \uAC83\uB9CC\uC73C\uB85C \uD55C\uC815\uD560 \uB54C\uAC00 \uC788\uB294\uB370\uC694. \uC55E\uC11C \uC774\uC57C\uAE30\uD55C \uAC83\uCC98\uB7FC \uC624\uD508\uC18C\uC2A4\uAC00 \uB9CC\uB4E4\uC5B4\uC9C0\uB294 \uACFC\uC815\uC5D0\uB294 \uB2E8\uC9C0 \'\uCF54\uB529\'\uB9CC \uD3EC\uD568\uB418\uB294 \uAC83\uC740 \uC544\uB2D9\uB2C8\uB2E4. **\uC624\uD508\uC18C\uC2A4\uC758 \uC131\uC7A5\uACFC \uC720\uC9C0\uC5D0 \uB3C4\uC6C0\uB418\uB294 \uBAA8\uB4E0 \uD65C\uB3D9**\uC774 \uC624\uD508\uC18C\uC2A4 \uAE30\uC5EC\uC5D0 \uD3EC\uD568\uB41C\uB2E4\uACE0 \uBCFC \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC624\uD508\uC18C\uC2A4 \uD504\uB85C\uC81D\uD2B8\uB97C \uC8FC\uC81C\uB85C \uBC1C\uD45C\uD574\uC11C \uB354 \uB9CE\uC740 \uC0AC\uC6A9\uC790\uB97C \uD655\uBCF4\uD558\uB294 \uD65C\uB3D9, \uBB38\uC11C\uD654\uC5D0 \uCC38\uC5EC\uD574 \uC815\uAD50\uD558\uACE0 \uC815\uD655\uD55C \uBB38\uC11C \uC791\uC131\uC5D0 \uB3C4\uC6C0\uC744 \uC8FC\uB294 \uD65C\uB3D9, \uC0C8\uB85C\uC6B4 \uC544\uC774\uB514\uC5B4\uB97C \uC81C\uC548\uD574 \uBB38\uC81C \uD574\uACB0\uC5D0 \uB3C4\uC6C0\uC744 \uC8FC\uB294 \uD65C\uB3D9, \uBC84\uADF8 \uB9AC\uD3EC\uD305, \uB85C\uACE0\uB098 UI \uB514\uC790\uC778\uC5D0 \uB3C4\uC6C0\uC744 \uC8FC\uB294 \uD65C\uB3D9 \uBAA8\uB450\uAC00 \uC624\uD508\uC18C\uC2A4 \uAE30\uC5EC\uC5D0 \uD3EC\uD568\uB429\uB2C8\uB2E4.\\n\\n\uADF8\uB807\uB2E4\uBA74 \uC65C \uC624\uD508\uC18C\uC2A4 \uC138\uACC4\uC5D0\uC11C\uB294 \uAE30\uC5EC\uC790\uB97C \uC18C\uC911\uD558\uAC8C \uC0DD\uAC01\uD560\uAE4C\uC694? \uADF8\uB0E5 \uC81C\uC791\uC790\uAC00 \uB9C8\uC74C\uB300\uB85C \uD558\uBA74 \uC548 \uB418\uB294 \uAC78\uAE4C\uC694?\\n\\n### \uC624\uD508\uC18C\uC2A4 \uAE30\uC5EC\uAC00 \uC911\uC694\uD55C \uC774\uC720 - \uC81C\uC791\uC790\uC758 \uAD00\uC810\\n\\n\uC624\uD508\uC18C\uC2A4 \uB9CC\uB4DC\uB294 \uC0AC\uB78C\uB4E4\uACFC \uC9C1\uC811 \uC774\uC57C\uAE30\uB97C \uB098\uB204\uC5B4\uBCF4\uBA74, \uADF8\uB4E4\uC740 \uD56D\uC0C1 \uD504\uB85C\uC81D\uD2B8\uAC00 \uC544\uC9C1 \uC644\uBCBD\uD558\uC9C0 \uC54A\uC73C\uBA70 \uC0AC\uC6A9\uC790 \uD53C\uB4DC\uBC31\uC744 \uC911\uC2EC\uC73C\uB85C \uB354\uC6B1 \uBC1C\uC804\uD574\uC57C \uD55C\uB2E4\uACE0 \uC0DD\uAC01\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uC624\uD508\uC18C\uC2A4 \uC6B4\uB3D9\uC758 \uB300\uD45C\uC801 \uC778\uBB3C\uC778 [\uC5D0\uB9AD \uB808\uC774\uBA3C\uB4DC](https://ko.wikipedia.org/wiki/%EC%97%90%EB%A6%AD_%EB%A0%88%EC%9D%B4%EB%A8%BC%EB%93%9C)\uAC00 \uC4F4 \uAE00, \'[\uC131\uB2F9\uACFC \uC2DC\uC7A5](https://en.wikipedia.org/wiki/The_Cathedral_and_the_Bazaar)\'\uC744 \uC77D\uC5B4\uBCF4\uBA74 \uC624\uD508\uC18C\uC2A4 \uAC1C\uBC1C \uBC29\uBC95\uC5D0 \uB300\uD574 \uC790\uC138\uD788 \uB098\uC624\uB294\uB370\uC694. \uD575\uC2EC\uC740 \uC0AC\uC6A9\uC790\uB97C \uD3EC\uD568\uD55C \uB9CE\uC740 \uC0AC\uB78C\uB4E4\uC758 \uCC38\uC5EC\uAC00 \uC18C\uD504\uD2B8\uC6E8\uC5B4\uB97C \uB354\uC6B1 \uBC1C\uC804\uC2DC\uD0A8\uB2E4\uB294 \uAC83\uC785\uB2C8\uB2E4.\\n\\n\uC74C\uC2DD\uC810\uC744 \uC608\uB85C \uB4E4\uC5B4\uBCFC\uAE4C\uC694? \uB0B4\uAC00 \uC2DD\uB2F9 \uC8FC\uC778\uC774\uACE0 \uC74C\uC2DD\uC744 \uB9CC\uB4E4\uC5B4 \uD310\uB2E4\uACE0 \uC0DD\uAC01\uD574\uBD05\uC2DC\uB2E4. \uB0B4\uAC00 \uB9CC\uB4E0 \uC74C\uC2DD\uC774 \uC5B4\uB5A4 \uC0AC\uB78C\uC5D0\uAC8C\uB294 \uC801\uB2F9\uD558\uACE0 \uB610 \uC5B4\uB5A4 \uC0AC\uB78C\uC5D0\uAC8C\uB294 \uB2EC\uAC70\uB098 \uB9F5\uAC70\uB098 \uC2F1\uAC70\uC6B8 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uB610\uD55C \uB0B4\uAC00 \uB9CC\uB4E0 \uC74C\uC2DD\uACFC \uC880 \uB354 \uC798 \uC5B4\uC6B8\uB9AC\uB294 \uC2DD\uAE30\uB098 \uC2DD\uD0C1 \uD639\uC740 \uD50C\uB808\uC774\uD305 \uBC29\uBC95\uC744 \uC54C\uACE0 \uC788\uB294 \uC0AC\uB78C\uC774 \uC788\uC744 \uC218\uB3C4 \uC788\uC2B5\uB2C8\uB2E4. \uC74C\uC2DD\uC774 \uC880 \uB354 \uB3CB\uBCF4\uC774\uB294 \uBA54\uB274\uD310 \uB808\uC774\uC544\uC6C3\uC744 \uC54C\uACE0 \uC788\uB294 \uC0AC\uB78C\uB3C4 \uC788\uACA0\uC8E0. \uC774\uB7F0 \uC720\uC6A9\uD55C \uD53C\uB4DC\uBC31\uB4E4\uC744 \uBC14\uB85C \uC804\uB2EC\uBC1B\uC744 \uC218 \uC788\uB2E4\uBA74 \uC5B4\uB5A8\uAE4C\uC694? \uB610\uD55C \uADF8\uB7F0 \uC720\uC6A9\uD55C \uD53C\uB4DC\uBC31\uC744 \uC804\uB2EC\uD55C \uC0AC\uB78C\uC774 \uC9C1\uC811 \uC801\uC6A9\uD560 \uC218 \uC788\uAC8C \uB9CC\uB4E0\uB2E4\uBA74 \uC5B4\uB5A8\uAE4C\uC694? \uC880 \uB354 \uBA4B\uC9C4 \uC2DD\uB2F9\uC774 \uB420 \uAC00\uB2A5\uC131\uC774 \uD06C\uACA0\uC8E0? \uC544\uB9C8 \uB9DB\uC9D1\uC73C\uB85C \uC18C\uBB38\uB098\uC9C0 \uC54A\uC744\uAE4C\uC694?\\n\\n\uC624\uD508\uC18C\uC2A4\uB294 \uC0AC\uC6A9\uC790 \uD53C\uB4DC\uBC31\uC744 \uBC14\uD0D5\uC73C\uB85C \uAC1C\uBC1C\uD574 \uB098\uAC04\uB2E4\uACE0 \uB9D0\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC624\uD508\uC18C\uC2A4\uB85C \uACF5\uAC1C\uD574 \uB193\uACE0 \uC0AC\uC6A9\uC790 \uD53C\uB4DC\uBC31\uC744 \uBB34\uC2DC\uD55C\uB2E4\uBA74 \uADF8 \uC624\uD508\uC18C\uC2A4\uB294 \uC0AC\uC6A9\uC790\uB97C \uC810\uC810 \uC783\uAC8C \uB420 \uAC83\uC785\uB2C8\uB2E4. \uC0AC\uC6A9\uD558\uB294 \uC0AC\uB78C\uC774 \uC904\uC5B4\uB4E4\uBA74 \uC81C\uD488\uC758 \uAC00\uCE58\uB294 \uAC19\uC774 \uC904\uC5B4\uB4E4 \uC218\uBC16\uC5D0 \uC5C6\uC2B5\uB2C8\uB2E4. \uB610\uD55C \uC0AC\uC6A9\uC790 \uD53C\uB4DC\uBC31\uC744 \uBB34\uC2DC\uD558\uC9C0 \uC54A\uACE0 \uBC1B\uC544\uB4E4\uC778\uB2E4\uACE0 \uD574\uB3C4 \uB9CC\uC57D \uD63C\uC790\uC11C \uBAA8\uB4E0 \uAC83\uC744 \uAC10\uB2F9\uD558\uB824\uACE0 \uD55C\uB2E4\uBA74 \uC5ED\uC2DC \uBB38\uC81C\uAC00 \uBC1C\uC0DD\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC0AC\uC6A9\uC790\uAC00 \uB298\uC5B4\uB098\uBA74 \uD53C\uB4DC\uBC31\uB3C4 \uD568\uAED8 \uB298\uC5B4\uB098\uAC8C \uB420 \uD150\uB370\uC694. \uB298\uC5B4\uB09C \uD53C\uB4DC\uBC31\uC744 \uCC38\uC5EC\uC790\uB4E4\uC758 \uB3C4\uC6C0\uC5C6\uC774 \uD63C\uC790\uC11C \uBAA8\uB450 \uC751\uB2F5\uD558\uB294 \uAC74 \uC810\uC810 \uC5B4\uB824\uC6CC\uC9C8 \uD14C\uACE0, \uADF8\uB807\uAC8C \uD488\uC9C8\uC774 \uC800\uD558\uB418\uBA70 \uACB0\uAD6D \uC0AC\uC6A9\uC790\uB294 \uAC10\uC18C\uD558\uAC8C \uB420 \uAC83\uC785\uB2C8\uB2E4. \uACB0\uAD6D \uADF8 \uC624\uD508\uC18C\uC2A4\uB294 \uC8FD\uC740 \uC624\uD508\uC18C\uC2A4\uB77C\uACE0 \uBD88\uB9AC\uACA0\uC8E0.\\n\\n\uC0AC\uC6A9\uC790 \uD53C\uB4DC\uBC31\uC744 \uC911\uC2EC\uC73C\uB85C \uAC1C\uBC1C\uD560 \uB550 \uC0AC\uC6A9\uC790\uC640 \uC81C\uC791\uC790 \uAC04\uC758 \uC6D0\uD65C\uD55C \uCEE4\uBBA4\uB2C8\uCF00\uC774\uC158\uC774 \uAE30\uBCF8 \uBC14\uD0D5\uC774 \uB429\uB2C8\uB2E4. \uD53C\uB4DC\uBC31\uC774 \uC2E0\uC18D\uD558\uAC8C \uBC18\uC601\uB418\uBA74 \uADF8\uC5D0 \uB9DE\uCDB0 \uC0AC\uC6A9\uC790\uAC00 \uC810\uC810 \uB298\uC5B4\uB098\uACE0, \uADF8 \uC0AC\uC6A9\uC790\uAC00 \uB2E4\uC2DC \uAC1C\uBC1C\uC790\uAC00 \uB418\uB294 \uC120\uC21C\uD658\uC758 \uAD6C\uC870\uAC00 \uD0C4\uD0C4\uD55C \uCEE4\uBBA4\uB2C8\uD2F0\uB97C \uD615\uC131\uD558\uBA70 \uC624\uD508\uC18C\uC2A4\uB97C \uC9C0\uD0F1\uD558\uAC8C \uB429\uB2C8\uB2E4.\\n\\n\uC5EC\uAE30\uAE4C\uC9C0 \uC624\uD508\uC18C\uC2A4 \uC81C\uC791\uC790\uC758 \uAD00\uC810\uC5D0\uC11C \uC124\uBA85\uC744 \uC801\uC5B4\uBCF4\uC558\uB294\uB370\uC694. \uC624\uD508\uC18C\uC2A4 \uAC1C\uBC1C\uC5D0 \uCC38\uC5EC\uD558\uB294 \uCC38\uC5EC\uC790\uC758 \uC785\uC7A5\uC5D0\uC11C\uB3C4 \uD55C\uBC88 \uC0DD\uAC01\uD574 \uBCF4\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n### \uC624\uD508\uC18C\uC2A4 \uAE30\uC5EC\uAC00 \uC911\uC694\uD55C \uC774\uC720 - \uCC38\uC5EC\uC790\uC758 \uAD00\uC810\\n\\n\uC6B0\uC120 \uC694\uAD6C \uC0AC\uD56D\uC744 \uBE68\uB9AC \uC804\uB2EC\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uCC38\uC5EC\uC790\uB4E4\uC774 \uD65C\uBC1C\uD558\uAC8C \uD65C\uB3D9\uD558\uB294 \uC624\uD508\uC18C\uC2A4\uB294 \uC9C8\uBB38\uC744 \uB0A8\uAE30\uBA74 \uB2E4\uB978 \uC0AC\uC6A9\uC790\uB098 \uBA54\uC778\uD14C\uC774\uB108(maintainer)\uAC00 \uBE60\uB974\uAC8C \uC751\uB2F5\uD574\uC90D\uB2C8\uB2E4. \uC9C8\uBB38\uD55C \uB4A4 \uB2F5\uC744 \uBE68\uB9AC \uBC1B\uC544\uBCFC \uC218 \uC788\uB2E4\uBA74 \uC624\uD508\uC18C\uC2A4\uB97C \uB354\uC6B1 \uC27D\uAC8C \uC0AC\uC6A9\uD560 \uC218 \uC788\uACA0\uC8E0? \uB610 \uACE0\uCE58\uACE0 \uC2F6\uC740 \uBD80\uBD84\uC774 \uC788\uB2E4\uBA74 \uB2E4\uB978 \uC0AC\uB78C\uC774 \uD574\uC904 \uB54C\uAE4C\uC9C0 \uAE30\uB2E4\uB9AC\uC9C0 \uC54A\uACE0 \uC9C1\uC811 \uACE0\uCCD0\uBCFC \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uD63C\uC790 \uC218\uC815\uD55C \uBD80\uBD84\uC740 \uB9AC\uBDF0\uB97C \uD1B5\uD574 \uC758\uACAC\uC744 \uBC1B\uC544\uBCFC \uC218 \uC788\uACE0\uC694. \uC774\uB807\uAC8C \uC624\uD508\uC18C\uC2A4\uC5D0 \uCC38\uC5EC\uD55C \uC774\uB825\uC740 \uACE0\uC2A4\uB780\uD788 \uB0A8\uC544\uC11C \uB204\uAD6C\uB098 \uBCFC \uC218 \uC788\uAC8C \uACF5\uAC1C\uB429\uB2C8\uB2E4. \uC774\uB7F0 \uC774\uB825\uB4E4\uC740 \uAC1C\uBC1C\uC790 \uCC44\uC6A9 \uACFC\uC815\uC5D0\uC11C \uCF54\uB529 \uD14C\uC2A4\uD2B8\uBCF4\uB2E4 \uB354\uC6B1 \uD6A8\uACFC\uC801\uC73C\uB85C \uC790\uC2E0\uC744 \uBCF4\uC5EC\uC904 \uC218 \uC788\uB2E4\uB294 \uC7A5\uC810\uC774 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n\uD639\uC2DC \uADF8\uB3D9\uC548 \uC624\uD508\uC18C\uC2A4 \uD504\uB85C\uC81D\uD2B8\uB294 \uCD08\uACE0\uC218 \uAC1C\uBC1C\uC790\uB4E4\uB9CC \uCC38\uC5EC\uD558\uB294 \uAC70\uB77C\uACE0 \uC0DD\uAC01\uD574\uC11C \uC18C\uADF9\uC801\uC778 \uD0DC\uB3C4\uB85C \uADF8\uC800 \uBC14\uB77C\uB9CC \uBCF4\uACE0 \uC788\uC9C0\uB294 \uC54A\uC73C\uC168\uB098\uC694? \uC774\uBC88 \uAE30\uD68C\uC5D0 \uAD00\uC2EC \uC788\uAC8C \uC9C0\uCF1C\uBCF4\uB358 \uD504\uB85C\uC81D\uD2B8\uC758 issue \uBAA9\uB85D\uC5D0\uC11C \'good-first-issue\', \'first-timers-only\' \uD639\uC740 \'help-wanted\' \uAC19\uC740 label\uC774 \uBD99\uC740 \uAC83\uB4E4\uC744 \uCC3E\uC544 \uD55C\uBC88 \uC2DC\uC791\uD574\uBCF4\uBA74 \uC5B4\uB5A8\uAE4C\uC694?\\n\\n## Armeria contributor reward \uC18C\uAC1C\\n\\n\uC774\uBC88 \uD589\uC0AC\uC758 \uBAA9\uD45C\uB294 \uAC10\uC0AC \uC778\uC0AC\uB97C \uB4DC\uB9AC\uBA70 \uAE30\uC5EC\uC790\uB4E4\uACFC \uAD50\uB958\uD558\uB294 \uAC83\uC774\uC5C8\uC2B5\uB2C8\uB2E4. \uC624\uD508\uC18C\uC2A4 \uD504\uB85C\uC81D\uD2B8\uB2E4 \uBCF4\uB2C8 \uAC1C\uBC1C\uC5D0 \uCC38\uC5EC\uD558\uACE0 \uACC4\uC2E0 \uBD84\uB4E4\uC774 \uC804 \uC138\uACC4 \uAC01\uC9C0\uC5D0 \uD769\uC5B4\uC838 \uC788\uC5B4\uC11C \uC18C\uD1B5\uC774 \uC8FC\uB85C \uD14D\uC2A4\uD2B8\uB85C\uB9CC \uC774\uB904\uC84C\uB294\uB370\uC694. \uB298 \uCF54\uBA58\uD2B8\uB85C \uC9E7\uAC8C LGTM(Looks Good To Me) \uD639\uC740 :thumbsup:\uC73C\uB85C\uB9CC \uB9C8\uC74C\uC744 \uC804\uD558\uB294 \uAC83\uC774 \uBD80\uC871\uD558\uB2E4\uACE0 \uC0DD\uAC01\uD558\uACE0 \uC788\uC5C8\uC2B5\uB2C8\uB2E4. \uADF8\uB798\uC11C \uC774\uBC88\uC5D0\uB294 \uAE30\uC5EC\uC790\uBD84\uB4E4\uC5D0\uAC8C \uAC1C\uBCC4\uC801\uC73C\uB85C \uC774\uBA54\uC77C\uC744 \uBCF4\uB0B4 \uC778\uC0AC\uB97C \uB4DC\uB9AC\uACE0 \uC18C\uC815\uC758 \uC120\uBB3C\uC744 \uC804\uB2EC\uD558\uC600\uC2B5\uB2C8\uB2E4.\\n\\n\uC544\uB798\uB294 \uAE30\uC5EC\uC790\uB4E4\uC758 [GitHub profile picture](https://help.github.com/articles/personalizing-your-profile/#changing-your-profile-picture)\uB97C \uD65C\uC6A9\uD55C \uC774\uBCA4\uD2B8 \uC774\uBBF8\uC9C0\uC785\uB2C8\uB2E4.\\nArmeria\uC758 \uB85C\uACE0\uCC98\uB7FC \'\uD551\uD06C \uD551\uD06C\'\uD55C \uC0C9\uAC10\uC774 \uCC38 \uC608\uC058\uC8E0?\\n\\n![](/img/thank-you-for-contributing-to-armeria-1.png)\\n\\n### \uAE30\uC5EC\uC790\uB4E4\uC758 \uCC38\uC5EC\\n\\nGitHub\uC5D0\uC11C\uB294 \uAE30\uC5EC\uC790\uB4E4\uC758 \uD65C\uB3D9 \uD604\uD669\uC744 [\uADF8\uB798\uD504](https://github.com/line/armeria/graphs/contributors)\uB85C \uBCFC \uC218 \uC788\uB294\uB370\uC694. \uADF8\uB798\uD504 \uB0B4\uC6A9\uC744 \uC544\uB798\uC640 \uAC19\uC774 \uC815\uB9AC\uD574\uBD24\uC2B5\uB2C8\uB2E4. \uD604\uC7AC\uAE4C\uC9C0 60\uBA85\uC774 \uB118\uB294 \uAE30\uC5EC\uC790\uB4E4\uC774 \uC57D 1,350\uBC88\uC758 \uCEE4\uBC0B\uC744 \uD1B5\uD574 \uC57D 457,000\uC904\uC744 \uCD94\uAC00\uD558\uACE0 \uC57D 257,500\uC904\uC744 \uC0AD\uC81C\uD574\uC8FC\uC168\uC2B5\uB2C8\uB2E4. \uC22B\uC790\uB85C \uBCF4\uB2C8 \uB2E4\uC591\uD55C \uC0AC\uB78C\uB4E4\uC758 \uD65C\uBC1C\uD55C \uCC38\uC5EC\uAC00 \uB354\uC6B1 \uC2E4\uAC10\uB098\uB124\uC694.\\n\\n![](/img/thank-you-for-contributing-to-armeria-2.png)\\n\\n\uAE30\uC5EC\uC790\uB4E4\uC774 \uC5B4\uB5A4 \uBD80\uBD84\uC5D0 \uAE30\uC5EC\uD574\uC8FC\uC168\uB294\uC9C0 \uC870\uAE08 \uB354 \uC790\uC138\uD558\uAC8C \uC0B4\uD3B4\uBCFC\uAE4C\uC694?\\n\\n- Your contribution led Armeria\'s annotated service to a whole new level.\\n- Your Retrofit integration module was one of the greatest additions in Armeria\'s history.\\n- HTTP redirection is now easier than ever with Armeria thanks to your contribution.\\n- Your work on implementing the high quality circuit breaker in Armeria is considered as an all-time legend.\\n- Your optimization of weighted round-robin load balancing algorithm was very clever idea that it was worth of a prize.\\n- We appreciate your initial groundwork, especially on the client-side, which made today\'s Armeria.\\n- Thank you for promoting Armeria to the developer communities and we appreciate your contribution to the project!\\n- Your documentation clean-up made us look way better than ever.\\n- Your help with fixing the bug made Armeria more stable than ever.\\n- Although your part was small, your dedication saved many of our days.\\n\\n\uC774 \uC678\uC5D0\uB3C4 \uB9CE\uC740 \uAE30\uC5EC\uC790\uB4E4\uC774 \uB2E4\uC591\uD558\uAC8C \uCC38\uC5EC\uD574 \uC8FC\uC168\uB294\uB370\uC694. \uAE30\uC5EC\uC790 \uAC01\uAC01\uC5D0\uAC8C \uAC1C\uBCC4\uC801\uC73C\uB85C \uAC10\uC0AC \uBA54\uC2DC\uC9C0\uB97C \uC804\uB2EC\uD558\uC600\uC2B5\uB2C8\uB2E4.\\n\\n### \uC218\uC0C1 \uC18C\uAC10\\n\\n\uD504\uB85C\uC81D\uD2B8 \uAE30\uC5EC\uB3C4\uB97C \uBCF4\uC5EC\uC8FC\uB294 [\uADF8\uB798\uD504](https://github.com/line/armeria/graphs/contributors)\uC5D0 \uB098\uD0C0\uB098\uB4EF \uD504\uB85C\uC81D\uD2B8 \uC624\uB108(owner)\uB97C \uC81C\uC678\uD558\uACE0 \uAC00\uC7A5 \uB9CE\uC774 \uAE30\uC5EC\uD574\uC900 \uAE30\uC5EC\uC790\uB294 [@anuraaga](https://github.com/line/armeria/commits?author=anuraaga) \uB2D8\uC785\uB2C8\uB2E4. \uC774\uBC88 \uD589\uC0AC\uB97C \uC9C4\uD589\uD558\uBA74\uC11C [@anuraaga](https://github.com/line/armeria/commits?author=anuraaga) \uB2D8\uC5D0\uAC8C \uC9E7\uAC8C\uB098\uB9C8 \uC18C\uAC10\uC744 \uC5EC\uCB64\uBCFC \uC218 \uC788\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\nQ. \uC9E7\uAC8C \uC790\uAE30 \uC18C\uAC1C \uBD80\uD0C1\uB4DC\uB9B4\uAED8\uC694.\\n\\nA. \uC548\uB155\uD558\uC138\uC694. \uB2E4\uB4E4 \'Rag\'\uB77C\uACE0 \uBD88\uB7EC\uC8FC\uC2DC\uB294 Anuraag\uC785\uB2C8\uB2E4. \uC800\uB294 \uC5EC\uB7EC \uB300\uADDC\uBAA8 \uC11C\uBC84 \uC0AC\uC774\uB4DC \uD504\uB85C\uC81D\uD2B8\uB97C \uC218\uD589\uD574 \uC628 \uC18C\uD504\uD2B8\uC6E8\uC5B4 \uC5D4\uC9C0\uB2C8\uC5B4\uC785\uB2C8\uB2E4. \uCC98\uC74C Armeria\uB97C \uC54C\uAC8C \uB41C \uAC74 LINE Shop \uD300\uC5D0\uC11C \uADFC\uBB34\uD560 \uB54C\uC778\uB370\uC694. \uC815\uB9D0 \uC5C4\uCCAD\uB09C \uC6B0\uC5F0\uC774\uC5C8\uC2B5\uB2C8\uB2E4. \uC81C\uAC00 \uD300\uC5D0 \uD569\uB958\uD55C \uB4A4 \uAE30\uC874 [Thrift](https://thrift.apache.org/) \uB77C\uC774\uBE0C\uB7EC\uB9AC\uB97C \uB300\uCCB4\uD560 \uC644\uC804\uD55C \uAE30\uB2A5\uC774 \uAC16\uCDB0\uC9C4(full-featured) [RPC](https://en.wikipedia.org/wiki/Remote_procedure_call) \uD504\uB808\uC784\uC6CC\uD06C\uAC00 \uD544\uC694\uD588\uAC70\uB4E0\uC694. \uADF8\uB7F0\uB370 \uADF8\uB54C \uB9C8\uCE68 [@trustin](https://github.com/trustin)(Trustin, \uD504\uB85C\uC81D\uD2B8 \uC624\uB108)\uC774 \uBC14\uB85C \uADF8\uAC78 \uBAA9\uC801\uC73C\uB85C Armeria \uD504\uB85C\uC81D\uD2B8\uB97C \uC2DC\uC791\uD588\uB354\uB77C\uACE0\uC694. \uADF8\uB798\uC11C \uADF8 \uC774\uD6C4\uB85C, \uC2EC\uC9C0\uC5B4 LINE\uC744 \uB5A0\uB09C \uD6C4\uC5D0\uB3C4 \uC800\uB294 \uBAA8\uB4E0 \uD504\uB85C\uC81D\uD2B8\uC5D0\uC11C Armeria\uB97C \uC0AC\uC6A9\uD558\uACE0 \uC788\uC73C\uBA70 \uC81C\uAC00 \uAE30\uC5EC\uD560 \uC218 \uC788\uB294 \uBD80\uBD84\uC774 \uC788\uB2E4\uBA74 \uAFB8\uC900\uD788 \uAE30\uC5EC\uB3C4 \uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4.\\n\\nQ.\\nArmeria\uB97C \uC5B4\uB5BB\uAC8C \uC0AC\uC6A9\uD558\uACE0 \uACC4\uC2E0\uAC00\uC694?\\n\\nA. \uC800\uB294 \uC5C5\uBB34\uC5D0\uC11C\uB098 \uAC1C\uC778\uC801\uC73C\uB85C\uB098 \uBAA8\uB4E0 \uC11C\uBC84 \uC0AC\uC774\uB4DC \uB2C8\uC988(needs)\uC5D0 Armeria\uB97C \uC0AC\uC6A9\uD569\uB2C8\uB2E4. \uC800\uD76C \uD68C\uC0AC [Infostellar](https://www.infostellar.net/)\uB294 \uC704\uC131 \uD1B5\uC2E0\uC744 \uC704\uD55C \uAE00\uB85C\uBC8C \uB124\uD2B8\uC6CC\uD06C \uC778\uD504\uB77C\uC2A4\uD2B8\uB7ED\uCC98\uB97C \uAD6C\uCD95\uD558\uACE0 \uC788\uB294\uB370\uC694. \uC77C\uBC18\uC801\uC778 API \uC694\uAD6C\uC0AC\uD56D\uC744 \uB9CC\uC871\uD574\uC57C \uD558\uB294 \uAC83\uC740 \uBB3C\uB860 \uC544\uC8FC \uB9CE\uC740 \uC591\uC758 \uB370\uC774\uD130\uB3C4 \uC804\uC1A1\uD574\uC57C \uD569\uB2C8\uB2E4. \uC800\uD76C \uC544\uD0A4\uD14D\uCC98\uB294 \uD45C\uC900 \uC11C\uBE44\uC2A4 \uAE30\uBC18 \uC544\uD0A4\uD14D\uCC98\uB97C \uB530\uB974\uB294\uB370\uC694. \uB9CE\uC740 \uC11C\uBC84\uAC00 [Kubernetes](https://kubernetes.io/)\uC5D0\uC11C \uC2E4\uD589\uB418\uBA74\uC11C Armeria\uB97C \uC0AC\uC6A9\uD574\uC11C [gRPC](https://grpc.io/) API\uB97C \uC5F4\uC5B4 \uB193\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uB610\uD55C Armeria\uC758 \uC815\uC801 \uD30C\uC77C \uC11C\uBE44\uC2A4 \uAE30\uB2A5\uACFC gRPC-Web \uC9C0\uC6D0\uC744 \uD1B5\uD574 \uC81C\uACF5\uB418\uB294 \uC6F9 \uD504\uB860\uD2B8\uC5D4\uB4DC\uB3C4 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n\uC5C5\uBB34\uC5D0\uC11C \uBFD0\uB9CC \uC544\uB2C8\uB77C \uC8FC\uB9D0\uC5D0 \uAC1C\uC778\uC801\uC73C\uB85C \uC9C4\uD589\uD558\uB294 \uD504\uB85C\uC81D\uD2B8\uC5D0\uC11C\uB3C4 Armeria\uB97C \uC0AC\uC6A9\uD569\uB2C8\uB2E4. \uC81C\uAC8C \uD544\uC694\uD55C \uC720\uC2A4\uCF00\uC774\uC2A4\uC5D0 \uB530\uB77C \uB2E4\uC591\uD55C \uD06C\uAE30\uC758 \uD504\uB85C\uC81D\uD2B8\uC5D0\uC11C Armeria\uB97C \uD6A8\uACFC\uC801\uC73C\uB85C \uC0AC\uC6A9\uD560 \uC218 \uC788\uC5B4 \uAE30\uC058\uB124\uC694. :)\\n\\nQ.\\nArmeria\uC5D0\uC11C \uAC00\uC7A5 \uC88B\uC740 \uC810\uC744 \uAF3D\uC544\uBCF8\uB2E4\uBA74?\\n\\nA. \uC81C \uC0DD\uAC01\uC5D0 Armeria\uC758 \uAC00\uC7A5 \uD070 \uC7A5\uC810\uC740 \uAC1C\uBC1C\uC790\uC758 \uC0DD\uC0B0\uC131\uC5D0 \uCD08\uC810\uC744 \uB9DE\uCDC4\uB2E4\uB294 \uC810\uC785\uB2C8\uB2E4.\\nTrustin\uC740 \uBAA8\uB4E0 \uAC1C\uBC1C\uC790\uC758 \uC694\uAD6C \uC0AC\uD56D\uC744 \uB9CC\uC871\uC2DC\uD0AC \uB9CC\uD55C \uD504\uB85C\uC81D\uD2B8\uB97C \uB9CC\uB4E4\uC5B4\uB0C8\uC2B5\uB2C8\uB2E4.\\nArmeria\uB294 \uAD49\uC7A5\uD788 \uC720\uC5F0\uD558\uACE0, \uBAA8\uBC94 \uC0AC\uB840\uB97C \uBCF4\uC5EC\uC8FC\uBA70, \uAC1C\uBC1C\uC790\uB4E4\uC774 \'\uBE44\uB3D9\uAE30(asynchronous) \uD504\uB85C\uADF8\uB798\uBC0D\'\uACFC \uAC19\uC740 \uCD5C\uC2E0 \uD2B8\uB80C\uB4DC\uB97C \uC811\uD558\uAC8C \uD574\uC90D\uB2C8\uB2E4. \uC800\uB294 \uBA54\uC778\uD14C\uC774\uB108\uAC00 \uAD49\uC7A5\uD788 \uC774\uB860\uC801\uC778 \uC811\uADFC\uC744 \uCDE8\uD558\uB294 \uD504\uB808\uC784\uC6CC\uD06C\uB098 \uB77C\uC774\uBE0C\uB7EC\uB9AC\uB97C \uBD24\uB294\uB370\uC694. \uADF8\uB7F0 \uC2DD\uC73C\uB85C \uC6B4\uC601\uD558\uBA74 \uC885\uC885 \uAC1C\uBC1C\uC790\uAC00 \uC544\uB2C8\uB77C \uBA54\uC778\uD14C\uC774\uB108\uAC00 \uC6D0\uD558\uB294 \uBC29\uD5A5\uC73C\uB85C \uCD08\uC810\uC774 \uB9DE\uCDB0\uC9C0\uBA74\uC11C \uC815\uC791 \uAC1C\uBC1C\uC790\uB4E4\uC740 \uC0AC\uC6A9\uD558\uAE30 \uC5B4\uB824\uC6B4 \uB77C\uC774\uBE0C\uB7EC\uB9AC\uAC00 \uB418\uB354\uAD70\uC694.\\nArmeria\uB294 Slack \uCC44\uB110\uC5D0\uC11C \uC644\uC804\uD55C \uC9C0\uC6D0\uC744 \uC81C\uACF5\uD558\uB294 \uB4F1 \uAC1C\uBC1C\uC790\uC758 \uC694\uAD6C\uC5D0 \uCD08\uC810\uC744 \uC798 \uB9DE\uCD94\uACE0 \uC788\uC5B4\uC11C \uB2E4\uC591\uD55C \uC2A4\uD399\uD2B8\uB7FC\uC758 \uAC1C\uBC1C\uC790\uB4E4\uC5D0\uAC8C \uC720\uC6A9\uD560 \uAC70\uB77C\uACE0 \uC0DD\uAC01\uD569\uB2C8\uB2E4.\\n\\n\uB610\uD55C Armeria\uB294 \uC81C\uAC00 \uBCF8 \uD504\uB808\uC784\uC6CC\uD06C \uC911 \uAC00\uC7A5 \uC720\uC5F0\uD55C \uC11C\uBC84 \uD504\uB808\uC784\uC6CC\uD06C\uC785\uB2C8\uB2E4. \uB3D9\uC77C\uD55C TCP \uD3EC\uD2B8\uB85C gRPC, \uC815\uC801 \uD30C\uC77C(static files), [metrics](https://dzone.com/articles/metrics-for-microservices), [DocService](https://line.github.io/armeria/server-docservice.html#server-docservice)\uC640 \uAE30\uD0C0 \uCEE8\uD150\uCE20\uB97C \uBAA8\uB450 \uC81C\uACF5\uD560 \uC218 \uC788\uB2E4\uB294 \uC810\uC740 \uC815\uB9D0 \uD070 \uC131\uACFC\uB77C\uACE0 \uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\nQ.\\nArmeria \uAC1C\uBC1C\uC5D0 \uCC38\uC5EC\uD558\uBA74\uC11C \uD798\uB4E4\uC5C8\uB358 \uC801\uC774 \uC788\uC73C\uC2E0\uAC00\uC694?\\n\\nA.\\nArmeria \uAC1C\uBC1C\uD558\uBA74\uC11C \uD2B9\uBCC4\uD788 \uD798\uB4E4\uC5C8\uB358 \uC801\uC740 \uC5C6\uC2B5\uB2C8\uB2E4.\\nArmeria\uB294 \uBB38\uC11C\uD654\uAC00 \uC798 \uB418\uC5B4 \uC788\uACE0, IDE(\uD1B5\uD569 \uAC1C\uBC1C \uD658\uACBD, Integrated Development Environment) \uC124\uC815\uB3C4 \uB530\uB77C\uD558\uAE30 \uC27D\uAC8C \uB418\uC5B4 \uC788\uC73C\uBA70, \uC0C1\uB0E5\uD55C \uB9AC\uBDF0\uC5B4\uB4E4 \uB355\uBD84\uC5D0 PR(Pull Request)\uB3C4 \uC6D0\uD65C\uD788 \uC9C4\uD589\uB429\uB2C8\uB2E4. \uC544\uC8FC \uC7A0\uC2DC\uC9C0\uB9CC \uB9B4\uB9AC\uC2A4\uAC00 \uC880 \uB290\uB9AC\uAC8C \uC9C4\uD589\uB418\uB294 \uAC83 \uAC19\uB2E4\uACE0 \uB290\uB080 \uC801\uC740 \uC788\uC2B5\uB2C8\uB2E4. \uBC84\uADF8\uC218\uC815(bugfix)\uC774 \uBA38\uC9C0(merge)\uB294 \uB418\uC5C8\uB294\uB370 \uB9B4\uB9AC\uC2A4\uB294 \uB418\uC9C0 \uC54A\uC544\uC11C \uBC84\uADF8\uC218\uC815\uC774 \uD3EC\uD568\uB41C \uC2A4\uB0C5\uC0F7(snapshot)\uC744 \uBC30\uD3EC\uD55C \uC801\uC774 \uC788\uAC70\uB4E0\uC694. \uD558\uC9C0\uB9CC \uCD5C\uADFC\uC5D0\uB294 \uC790\uC8FC \uB9B4\uB9AC\uC2A4\uB418\uACE0 \uC788\uC5B4\uC11C \uADF8\uB7F0 \uAE30\uBD84\uC744 \uB290\uB07C\uC9C0 \uC54A\uACE0 \uC788\uC2B5\uB2C8\uB2E4. :)\\n\\n\uC0AC\uC18C\uD55C \uAC83 \uD558\uB098 \uC5B8\uAE09\uD558\uC790\uBA74, \uC81C \uC0DD\uAC01\uC5D4 \uBC14\uAFB8\uAE30 \uC5B4\uB824\uC6B8 \uAC83 \uAC19\uC740\uB370\uC694. \uC800\uB294 import\uD55C \uCF54\uB4DC \uC124\uC815\uC744 \uC0AC\uC6A9\uD558\uB294\uB370\uB3C4 \uACF5\uBC31 \uD3EC\uB9F7\uC744 \uC81C\uB300\uB85C \uC801\uC6A9\uD558\uB294 \uB370 \uC5B4\uB824\uC6C0\uC744 \uACAA\uC2B5\uB2C8\uB2E4.\\nTrustin\uC774 \uC81C\uAC00 \uB193\uCE5C \uBA87\uBA87 \uACF5\uBC31 \uC774\uC288\uB97C \uBC1C\uACAC\uD558\uACE0 \uB098\uC911\uC5D0 \uB2E4\uB978 PR\uC744 \uD1B5\uD574 \uC218\uC815\uD558\uB294 \uAC83\uC744 \uC9C0\uCF1C\uBCFC \uB54C \uD2B9\uD788 \uB2F9\uD639\uC2A4\uB7FD\uB124\uC694. ;) \uC790\uB3D9 \uD3EC\uB9F7\uD130(formatter)\uB97C \uC0AC\uC6A9\uD558\uBA74 \uAC1C\uBC1C \uC911 \uAC71\uC815\uAC70\uB9AC\uB97C \uD558\uB098 \uC904\uC77C \uC218 \uC788\uC744 \uAC83 \uAC19\uC2B5\uB2C8\uB2E4.\\n\\nQ. \uD504\uB85C\uC81D\uD2B8\uC640 \uAD00\uB828\uD574 \uC55E\uC73C\uB85C \uACC4\uD68D\uD558\uACE0 \uC788\uAC70\uB098 \uAE30\uB300\uD558\uB294 \uAC83\uC774 \uC788\uB098\uC694?\\n\\nA. \uC800\uB294 \uAC1C\uC778\uC801\uC73C\uB85C \uC720\uC6A9\uD560 \uAC83 \uAC19\uC740 \uAE30\uB2A5\uC744 \uBC1C\uACAC\uD558\uBA74 \uCF54\uB4DC\uC5D0 \uAE30\uC5EC\uD558\uB294 \uB4F1 \uACC4\uC18D Armeria\uB97C \uC0AC\uC6A9\uD560 \uACC4\uD68D\uC785\uB2C8\uB2E4. \uC0AC\uC2E4 \uC774\uAC74 \uC88B\uC740 \uC9C8\uBB38\uC774\uC5D0\uC694. \uBE44\uB85D \uC800\uB294 \uD504\uB85C\uC81D\uD2B8\uC5D0 \uB300\uD55C \uAE30\uB300\uAC00 \uBB34\uC5C7\uC778\uC9C0 \uBA85\uD655\uD558\uAC8C \uC54C\uC9C4 \uBABB\uD558\uC9C0\uB9CC\uC694.\\nArmeria\uC5D4 \uAE30\uB2A5 \uC694\uCCAD\uC774 \uB9CE\uC774 \uB4E4\uC5B4\uC635\uB2C8\uB2E4. \uADF8 \uC911\uC5D4 \uC885\uC885 \uC81C\uD55C\uB41C \uBC94\uC704\uC758 \uAE30\uC220\uC744 \uC0AC\uC6A9\uD558\uB294 \uC694\uCCAD\uB3C4 \uC788\uC2B5\uB2C8\uB2E4. \uC9C0\uAE08 \uBA38\uB9AC\uC5D0 \uB5A0\uC624\uB974\uB294 [\uC0AC\uB840](https://github.com/line/armeria/issues/194)\uB294 \uB354 \uB9CE\uC740 [service discovery](https://microservices.io/patterns/client-side-discovery.html) \uBA54\uCEE4\uB2C8\uC998\uC744 \uC704\uD55C \uC9C0\uC6D0\uC744 \uCD94\uAC00\uD558\uB294 \uAC74\uC774\uB124\uC694. \uB610\uD55C [Spring Security](https://spring.io/projects/spring-security)\uB97C \uAE30\uBCF8\uC801\uC73C\uB85C \uC9C0\uC6D0\uD560 \uC9C0 \uC5EC\uBD80\uB3C4 \uC788\uC2B5\uB2C8\uB2E4. \uC800\uB294 \uC804 \uC138\uACC4\uC758 \uBAA8\uB4E0 \uAE30\uC220\uC744 \uC9C0\uC6D0\uD558\uB294 \uAC83\uC774 Armeria\uC758 \uBC94\uC704\uB294 \uC544\uB2C8\uB77C\uACE0 \uC0DD\uAC01\uD558\uB294\uB370\uC694. \uC120\uC744 \uC5B4\uB5BB\uAC8C \uADF8\uC5B4\uC57C \uD560\uC9C0 \uBAA8\uB974\uACA0\uC2B5\uB2C8\uB2E4.\\n\\nQ. \uC624\uD508\uC18C\uC2A4(\uB610\uB294 \uC624\uD508\uC18C\uC2A4 \uAE30\uC5EC\uC5D0 \uB300\uD574) \uD558\uC2E4 \uB9D0\uC500\uC774 \uC788\uB2E4\uBA74?\\n\\nA. \uC800\uB294 \uC624\uD508\uC18C\uC2A4\uAC00 \uB108\uBB34 \uC88B\uC2B5\uB2C8\uB2E4! \uC81C \uC0DD\uAC01\uC5D0 \uC624\uD508\uC18C\uC2A4\uB294 \uAC1C\uBC1C\uC790\uB4E4\uC5D0\uAC8C \uC720\uC6A9\uD55C \uAE30\uC220\uC744 \uB9CC\uB4E4\uC5B4\uB0B4\uAE30\uB3C4 \uD558\uBA74\uC11C, \uB610\uD55C \uAC15\uB825\uD55C \uCEE4\uBBA4\uB2C8\uD2F0\uB97C \uB9CC\uB4E4\uC5B4\uC8FC\uB294 \uC77C\uB3C4 \uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uC624\uD508\uC18C\uC2A4\uB97C \uD1B5\uD574 \uB9CE\uC740 \uCE5C\uAD6C\uB4E4\uC744 \uB9CC\uB098\uAC8C \uB418\uC5B4 \uC815\uB9D0 \uB180\uB78D\uACE0 \uD589\uBCF5\uD569\uB2C8\uB2E4. \uC800\uB294 \uC55E\uC73C\uB85C\uB3C4 \uAFB8\uC900\uD788 \uC624\uD508\uC18C\uC2A4 \uD65C\uB3D9\uC744 \uD558\uBA70 \uB354 \uB9CE\uC740 \uC0AC\uB78C\uB4E4\uC744 \uB9CC\uB098\uAC8C \uB418\uAE38 \uBC14\uB77C\uACE0 \uC788\uACE0\uC694. \uC8FC\uC704\uC5D0 \uC2DC\uAC04 \uC5EC\uC720\uAC00 \uB418\uC2DC\uB294 \uBD84\uB4E4\uC5D0\uAC90 \uBCF8\uC778\uC774 \uC88B\uC544\uD558\uB294 \uC800\uC7A5\uC18C\uC5D0 PR \uD55C\uBC88 \uBCF4\uB0B4\uBCF4\uB77C\uACE0 \uB3C5\uB824\uD560 \uAC70\uC5D0\uC694.\\n\\nQ. \uB9C8\uC9C0\uB9C9\uC73C\uB85C \uB354 \uD558\uACE0 \uC2F6\uC740 \uC774\uC57C\uAE30\uAC00 \uC788\uC73C\uC2E4\uAE4C\uC694?\\n\\nA. \uC774\uB7F0 \uC774\uBCA4\uD2B8\uAC00 \uC5F4\uB824\uC11C \uC815\uB9D0 \uC990\uAC81\uB124\uC694.\\nLINE\uACFC \uAC19\uC740 \uC120\uB3C4 \uAE30\uC5C5\uC5D0\uC11C \uC624\uD508\uC18C\uC2A4 \uD655\uC7A5\uC5D0 \uC911\uC810\uC744 \uB450\uB294 \uAC74 \uAD49\uC7A5\uD55C \uC77C\uC785\uB2C8\uB2E4. \uAE30\uC5C5\uB4E4\uC774 \uC18C\uC2A4\uCF54\uB4DC \uBA87 \uAC1C \uB0B4\uB193\uB294 \uAC83\uC740 \uC26C\uC6B8 \uC218 \uC788\uB294\uB370\uC694. \uC774\uB807\uAC8C \uC2E4\uC81C\uB85C \uC0DD\uD0DC\uACC4 \uC790\uCCB4\uB97C \uC9C0\uC6D0\uD558\uB294 \uAC74 \uC808\uB300 \uC27D\uC9C0 \uC54A\uAC70\uB4E0\uC694. \uC624\uD508\uC18C\uC2A4 \uCEE4\uBBA4\uB2C8\uD2F0\uB97C \uAD6C\uCD95\uD558\uB294\uB370 \uB3C4\uC6C0\uC744 \uC8FC\uC154\uC11C \uC815\uB9D0 \uACE0\uB9D9\uC2B5\uB2C8\uB2E4.\\n\\n## \uB9C8\uCE58\uBA70\\n\\n\uC800\uB294 \uC774\uBC88\uC5D0 \'Armeria contributor reward\'\uB97C \uC9C4\uD589\uD558\uBA74\uC11C \uC774\uBCA4\uD2B8\uB97C \uCC98\uC74C \uC9C4\uD589\uD574 \uBD24\uB294\uB370\uC694. \uC5EC\uB7EC\uAC00\uC9C0 \uC0C8\uB85C\uC6B4 \uACBD\uD5D8\uC774 \uC990\uAC70\uC6B4 \uAE30\uC5B5\uC73C\uB85C \uB0A8\uC558\uC2B5\uB2C8\uB2E4. \uC774\uB7F0 \uC990\uAC70\uC6B4 \uACBD\uD5D8\uC774 \uC624\uD508\uC18C\uC2A4\uC758 \uB9E4\uB825\uC774 \uC544\uB2D0\uAE4C \uC2F6\uC2B5\uB2C8\uB2E4.\\n\\nArmeria\uC5D0\uC11C \uC0C8\uB85C\uC6B4 \uACBD\uD5D8\uC744 \uC313\uC544\uBCF4\uACE0 \uC2F6\uC73C\uC2E0\uAC00\uC694? \'[good-first-issue](https://github.com/line/armeria/issues?q=is%3Aopen+is%3Aissue+label%3Agood-first-issue)\'\uB97C \uD55C\uBC88 \uB458\uB7EC\uBCF4\uC138\uC694. \uC774\uBBF8 Armeria\uC5D0 \uC775\uC219\uD558\uC2E0\uAC00\uC694? \uD604\uC7AC 1.0.0 \uBC84\uC804 \uB9B4\uB9AC\uC2A4\uB97C \uC704\uD574 \uD544\uC694\uD55C \uAC83\uB4E4\uC744 \uC815\uB9AC\uD558\uACE0 \uC788\uB294\uB370\uC694. \uAD00\uB828\uD558\uC5EC [\uC774\uACF3](https://github.com/line/armeria/issues/1704)\uC5D0\uC11C \uC544\uC774\uB514\uC5B4\uB97C \uACF5\uC720\uD574\uBCF4\uC138\uC694.\\n\\nArmeria\uC5D0\uC11C\uB294 \uB354\uC6B1 \uB9CE\uC740 \uC0AC\uC6A9\uC790\uC640 \uAE30\uC5EC\uC790\uB97C \uD655\uBCF4\uD558\uAE30 \uC704\uD574 \uB2E4\uC591\uD55C \uD504\uB85C\uADF8\uB7A8\uC744 \uAE30\uD68D\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uC55E\uC73C\uB85C \uC9C4\uD589\uD560 \uC774\uBCA4\uD2B8\uB3C4 \uC774\uBC88\uACFC \uB9C8\uCC2C\uAC00\uC9C0\uB85C \uC774\uACF3, [LINE Engineering blog](https://engineering.linecorp.com/ko/blog/)\uC640 [\uACF5\uC2DD Slack](https://line-armeria.slack.com/join/shared_invite/enQtNjIxNDU1ODU1MTI2LTgwMzk0MzVhOGRhZjJiY2ExODc0MzNhYzIxZDFlYjM5OGRjNTE1MzYzYzQ4MzNhNGY2ZDM0NThhMTRmZmQ3ZjQ)\uC5D0\uC11C \uC18C\uC2DD\uC744 \uC804\uD574\uB4DC\uB9AC\uACA0\uC2B5\uB2C8\uB2E4."},{"id":"/2016/08/04/applying-circuitbreaker-to-channel-gateway","metadata":{"permalink":"/blog/ko/2016/08/04/applying-circuitbreaker-to-channel-gateway","editUrl":"https://github.com/line/armeria/edit/main/site-new/src/content/blog/ko/2016-08-04-applying-circuitbreaker-to-channel-gateway.mdx","source":"@site/src/content/blog/ko/2016-08-04-applying-circuitbreaker-to-channel-gateway.mdx","title":"Channel Gateway\uC5D0 CircuitBreaker \uC801\uC6A9","description":"\uB4E4\uC5B4\uAC00\uAE30\uC5D0 \uC55E\uC11C","date":"2016-08-04T00:00:00.000Z","tags":[],"readingTime":5.64,"hasTruncateMarker":true,"authors":[{"name":"\uC2E0\uC885\uD6C8","title":"\uC800\uB294 \uADC0\uCC2E\uC740 \uC77C\uC744 \uC2EB\uC5B4\uD569\uB2C8\uB2E4. \uADC0\uCC2E\uC740 \uC77C\uC744 \uC904\uC774\uAE30 \uC704\uD574\uC11C \uACC4\uC18D \uACE0\uBBFC\uD558\uC9C0\uC694. \uADF8\uB798\uC11C, \uD504\uB85C\uADF8\uB798\uBC0D\uC744 \uC88B\uC544\uD558\uB294\uB370 \uC660\uC9C0 \uC77C\uC774 \uB354 \uB298\uC5B4\uB09C \uAC83 \uAC19\uC740 \uB290\uB08C\uC740 \uC800\uB9CC\uC758 \uB290\uB08C\uC774\uACA0\uC9C0\uC694?","imageURL":"/img/author-shinjonghun.png","key":"shinjonghun","page":null}],"frontMatter":{"authors":["shinjonghun"],"other_languages":{"en":"/blog/2016/08/04/applying-circuitbreaker-to-channel-gateway","ja":"/blog/ja/2016/08/04/applying-circuitbreaker-to-channel-gateway"}},"unlisted":false,"prevItem":{"title":"\uC624\uD508\uC18C\uC2A4 Armeria\uC758 \uAE30\uC5EC\uC790\uB97C \uC704\uD55C \uC774\uBCA4\uD2B8\uB97C \uC9C4\uD589\uD558\uC600\uC2B5\uB2C8\uB2E4","permalink":"/blog/ko/2019/04/16/thank-you-for-contributing-to-armeria"},"nextItem":{"title":"\uBD84\uC0B0 \uC11C\uBE44\uC2A4 \uD658\uACBD\uC5D0 \uB300\uD55C Circuit Breaker \uC801\uC6A9","permalink":"/blog/ko/2016/07/24/circuit-breakers-for-distributed-services"}},"content":"## \uB4E4\uC5B4\uAC00\uAE30\uC5D0 \uC55E\uC11C\\n\\n[Circuit Breaker\uC5D0 \uB300\uD55C \uC18C\uAC1C \uBE14\uB85C\uADF8](/blog/ko/2016/07/24/circuit-breakers-for-distributed-services)\uB97C \uC77D\uC9C0 \uC54A\uC558\uB2E4\uBA74 \uBA3C\uC800 \uC77D\uC5B4\uBCF4\uC2DC\uAE38 \uAD8C\uC7A5\uD569\uB2C8\uB2E4.\\n\\n## Channel Gateway\uC5D0 CircuitBreaker \uC801\uC6A9\uD558\uAE30\\n\\nChannel Gateway \uC11C\uBC84\uC5D0\uC11C\uB294 LINE\uC758 \uB2E4\uC591\uD55C \uC11C\uBC84\uB4E4\uC758 \uAE30\uB2A5\uC744 CP(Contents Provider)\uB4E4\uC5D0\uAC8C \uC81C\uACF5\uD558\uB294 \uC5ED\uD560\uC744 \uB9E1\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uADF8\uB7EC\uB2E4\uBCF4\uB2C8 Channel Gateway \uC11C\uBC84\uB4E4\uC740 \uC5F0\uACB0\uB41C \uC11C\uBC84\uB4E4\uC5D0 \uC601\uD5A5\uC744 \uB9CE\uC774 \uBC1B\uAC8C \uB429\uB2C8\uB2E4. \uADF8\uB9AC\uACE0, \uADF8\uB7EC\uD55C \uC601\uD5A5\uB4E4\uC740 \uC27D\uAC8C \uC804\uCCB4 Channel Gateway \uC11C\uBC84\uB4E4\uC5D0\uAC8C \uC804\uD30C\uB429\uB2C8\uB2E4.\\n\\n![](/img/applying-circuitbreaker-to-channel-gateway-1.png)\\n\\n{/* truncate */}\\n\\n\uC774 \uBB38\uC81C\uB97C \uD574\uACB0\uD558\uAE30 \uC704\uD558\uC5EC \uACE0\uBBFC\uD558\uB358 \uC911\uC5D0 CircuitBreaker\uC5D0 \uAD00\uD55C \uB0B4\uC6A9\uC744 \uB4E4\uC5C8\uC2B5\uB2C8\uB2E4. \uD2B9\uC815 \uC11C\uBC84\uC5D0\uC11C \uC7A5\uC560\uAC00 \uBC1C\uC0DD\uD560 \uACBD\uC6B0 CircuitBreaker\uAC00 \uC774\uB97C \uAC10\uC9C0\uD558\uACE0 \uADF8 \uC11C\uBC84\uB85C \uC694\uCCAD\uD558\uB294 \uD638\uCD9C\uC744 \uCC28\uB2E8\uD558\uBA74 \uBB38\uC81C\uB97C \uCDA9\uBD84\uD788 \uD574\uACB0\uD560 \uC218 \uC788\uB2E4\uACE0 \uC0DD\uAC01\uD588\uC2B5\uB2C8\uB2E4. \uADF8\uB798\uC11C Channel Gateway\uC5D0 CircuitBreaker\uB97C \uC801\uC6A9\uD558\uAE30\uB85C \uD588\uC2B5\uB2C8\uB2E4.\\n\\nChannel Gateway\uB97C \uC704\uD55C CircuitBreaker\uB97C \uC9C1\uC811 \uAD6C\uD604\uD560 \uC218\uB3C4 \uC788\uC5C8\uC9C0\uB9CC, [Armeria](http://line.github.io/armeria/)\uC5D0\uB294 CircuitBreaker\uAC00 \uD6CC\uB96D\uD558\uAC8C \uB9CC\uB4E4\uC5B4\uC838 \uC788\uC5C8\uC2B5\uB2C8\uB2E4.\\nArmeria\uC758 CircuitBreaker\uB294 \uC5EC\uB7EC \uAC00\uC9C0 \uC635\uC158\uB4E4\uC744 \uC6D0\uD558\uB294 \uB300\uB85C \uC124\uC815\uD558\uC5EC `CircuitBreakerBuilder`\uB97C \uD1B5\uD574 \uAD6C\uD604\uB41C `CircuitBreaker` \uAC1D\uCCB4\uB97C \uC5BB\uC744 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC774 \uAC1D\uCCB4\uB97C \uD1B5\uD558\uC5EC Channel Gateway\uC5D0 \uB9DE\uAC8C \uCEE4\uC2A4\uD130\uB9C8\uC774\uC988\uD560 \uC218 \uC788\uAC8C \uAD6C\uD604\uB418\uC5B4 \uC788\uC5B4\uC11C \uC5B4\uB835\uC9C0 \uC54A\uAC8C \uC801\uC6A9\uD560 \uC218 \uC788\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\n## CircuitBreaker\uC758 \uC560\uB108\uD14C\uC774\uC158 \uC0AC\uC6A9\\n\\ntalk-channel-gateway \uC18C\uC2A4\uCF54\uB4DC\uC5D0\uC11C CircuitBreaker\uB294 `@CircuitBreakable` \uC560\uB108\uD14C\uC774\uC158\uC744 \uC0AC\uC6A9\uD558\uC5EC \uC801\uC6A9\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n```\\n@CircuitBreakable(CircuitBreakerGroup.HBASE_CLIENT_USER_SETTINGS)\\npublic ChannelSettings findBy(String mid) {\\n    ...\\n}\\n```\\n\\n\uC704\uC640 \uAC19\uC774 \uC801\uC6A9\uD55C \uACBD\uC6B0, `findBy()` \uBA54\uC11C\uB4DC\uAC00 \uD638\uCD9C\uB420 \uB54C\uB9C8\uB2E4 \uC131\uACF5/\uC2E4\uD328\uB97C \uAC10\uC2DC\uD558\uACE0, \uADF8 \uACB0\uACFC\uC5D0 \uB530\uB77C CircuitBreaker\uAC00 \uC5F4\uB9AC\uAC70\uB098 \uB2EB\uD788\uAC8C \uB429\uB2C8\uB2E4.\\nHBASE_CLIENT_USER_SETTINGS\uB294 CircuitBreaker\uB85C \uBB36\uC77C \uADF8\uB8F9\uC744 \uC9C0\uC815\uD558\uB294 \uAC83\uC73C\uB85C\uC11C, \uBA54\uC11C\uB4DC\uB4E4\uC758 \uC2E4\uD328\uC728\uC744 \uACC4\uC0B0\uD560 \uB54C\uB3C4 \uADF8\uB8F9 \uC804\uCCB4\uC758 \uD638\uCD9C \uD68C\uC218 \uB300\uBE44 \uC2E4\uD328 \uD68C\uC218\uB85C \uACC4\uC0B0\uD558\uACE0, CircuitBreaker\uAC00 \uC5F4\uB9AC\uAC70\uB098 \uB2EB\uD790 \uB54C\uB3C4 \uD568\uAED8 \uC5F4\uB9AC\uAC70\uB098 \uB2EB\uD788\uAC8C \uB429\uB2C8\uB2E4.\\nCircuitBreaker\uC758 \uC124\uC815\uC740 `CircuitBreakerGroup`\uC774\uB77C\uB294 enum \uAC1D\uCCB4\uC5D0\uC11C \uB2E4\uC74C\uACFC \uAC19\uC774 \uC124\uC815\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n```\\npublic enum CircuitBreakerGroup implements ExceptionFilter {\\n\\n    SAMPLE_DEFAULT {\\n    },\\n    SAMPLE_API {\\n        @Override\\n        protected ExceptionFilter exceptionFilter() {\\n            return cause -> !(cause instanceof AuthenticationException\\n                              || cause instanceof ApiPermissionException\\n                              || cause instanceof ImproperRequestException);\\n        }\\n    },\\n    HBASE_CLIENT_CHANNEL_MATRIX {\\n    },\\n    HBASE_CLIENT_USER_SETTINGS {\\n    };\\n\\n    protected ExceptionFilter exceptionFilter() {\\n        return cause -> true;\\n    }\\n\\n    public CircuitBreaker circuitBreaker(CircuitBreakerListener listener) {\\n        return new CircuitBreakerBuilder(name()).exceptionFilter(exceptionFilter())\\n                                                .listener(listener)\\n                                                .build();\\n    }\\n\\n    @Override\\n    public boolean shouldDealWith(Throwable throwable) throws Exception {\\n        return exceptionFilter().shouldDealWith(throwable);\\n    }\\n}\\n```\\n\\nChannel Gateway\uC5D0\uC11C\uB294 `ExceptionFilter`\uB97C \uCEE4\uC2A4\uD130\uB9C8\uC774\uC988\uD558\uC5EC \uC0AC\uC6A9\uD558\uC600\uC2B5\uB2C8\uB2E4. \uADF8 \uC678\uC758 \uC635\uC158\uB4E4\uC740 Armeria\uC758 \uAE30\uBCF8 \uC635\uC158\uC744 \uADF8\uB300\uB85C \uC0AC\uC6A9\uD558\uC600\uC2B5\uB2C8\uB2E4. \uB9CC\uC57D, \uB2E4\uB978 \uC635\uC158\uB4E4\uC744 \uBCC0\uACBD\uD558\uC5EC \uC0AC\uC6A9\uD558\uACE0 \uC2F6\uB2E4\uBA74 `circuitBreaker()` \uBA54\uC11C\uB4DC\uB97C \uC218\uC815\uD558\uC5EC \uC0AC\uC6A9\uD560 \uC218 \uC788\uC744 \uAC83\uC785\uB2C8\uB2E4.\\n\\nArmeria\uC5D0\uC11C\uB294 \uAE30\uBCF8\uC801\uC73C\uB85C \uC5B4\uB5A0\uD55C \uC608\uC678\uB77C\uB3C4 \uBC1C\uC0DD\uD560 \uACBD\uC6B0 \uC2E4\uD328\uB85C \uAC04\uC8FC\uD558\uB3C4\uB85D \uB418\uC5B4 \uC788\uC2B5\uB2C8\uB2E4. \uD558\uC9C0\uB9CC, Channel Gateway\uC5D0\uC11C\uB294 \uAD8C\uD55C\uC774 \uC5C6\uB294 \uACBD\uC6B0 \uB4F1\uC744 \uC608\uC678\uB85C \uCC98\uB9AC\uD558\uC5EC \uBC18\uD658\uD574\uC8FC\uAE30 \uB54C\uBB38\uC5D0 \uC774\uB97C \uAD6C\uBD84\uD560 \uD544\uC694\uAC00 \uC788\uC5C8\uC2B5\uB2C8\uB2E4. \uADF8\uB798\uC11C, `ExceptionFilter`\uB97C \uCEE4\uC2A4\uD130\uB9C8\uC774\uC988\uD558\uC5EC \uC0AC\uC6A9\uD558\uC600\uC2B5\uB2C8\uB2E4. \uADF8\uB9AC\uACE0, CircuitBreaker\uC758 \uC0C1\uD0DC\uAC00 \uBCC0\uD560 \uB54C\uB9C8\uB2E4 \uB85C\uADF8\uB97C \uC313\uC744 \uC218 \uC788\uB3C4\uB85D Channel Gateway\uB97C \uC704\uD55C \uC774\uBCA4\uD2B8 \uB9AC\uC2A4\uB108\uB3C4 \uCD94\uAC00\uD558\uC600\uC2B5\uB2C8\uB2E4.\\n\\n\uC560\uB108\uD14C\uC774\uC158\uC5D0 \uC801\uC6A9\uD558\uB294 \uADF8\uB8F9\uC740 enum \uAC1D\uCCB4\uB85C \uC9C0\uC815\uD560 \uC218 \uC788\uC73C\uBA70, enum \uAC1D\uCCB4 \uAD6C\uD604 \uBD80\uBD84\uC5D0\uC11C \uADF8\uB8F9\uBCC4\uB85C \uB2E4\uB978 \uC124\uC815\uC744 \uD560 \uC218 \uC788\uB3C4\uB85D \uD558\uC600\uC2B5\uB2C8\uB2E4.\\n\\n## CircuitBreaker\uC5D0\uC11C proceed() \uAD6C\uD604\\n\\n[Aspect](https://en.wikipedia.org/wiki/AspectJ) \uAC1D\uCCB4\uC758 `proceed()` \uCF54\uB4DC\uB294 \uB2E4\uC74C\uACFC \uAC19\uC2B5\uB2C8\uB2E4.\\n\\n```\\npublic class CircuitBreakerAspect implements Ordered {\\n\\n        private final Map&lt;CircuitBreakerGroup, CircuitBreaker> circuitBreakers =\\n                new EnumMap&lt;>(CircuitBreakerGroup.class);\\n\\n        @PostConstruct\\n        public void initialize() {\\n\\n            final CircuitBreakerListener listener =\\n            new CircuitBreakerListenerImpl(circuitBreakerLogger);\\n            for (CircuitBreakerGroup group : CircuitBreakerGroup.values()) {\\n                circuitBreakers.put(group, group.circuitBreaker(listener));\\n            }\\n        }\\n\\n        public Object proceed(final ProceedingJoinPoint pjp,\\n               final CircuitBreakable circuitBreakable) throws Throwable {\\n\\n            final CircuitBreakerGroup group = circuitBreakable.value();\\n            final CircuitBreaker circuitBreaker = circuitBreakers.get(group);\\n\\n            if (circuitBreaker.canRequest()) {\\n                final Object result;\\n\\n                try {\\n                    result = pjp.proceed();\\n                } catch (Throwable e) {\\n                    if (group.shouldDealWith(e)) {\\n                        circuitBreaker.onFailure(e);\\n                    } else {\\n                        circuitBreaker.onSuccess();\\n                    }\\n                    throw e;\\n                }\\n\\n                circuitBreaker.onSuccess();\\n                return result;\\n            } else {\\n                throw CircuitBreakerException.circuitBroken();\\n            }\\n        }\\n    }\\n```\\n\\n\uCF54\uB4DC\uB294 \uBE44\uAD50\uC801 \uAC04\uB2E8\uD569\uB2C8\uB2E4. `CircuitBreaker.canRequest()`\uB97C \uD1B5\uD574 CircuitBreaker\uAC00 \uC5F4\uB824 \uC788\uB2E4\uBA74 \uC608\uC678\uB97C \uBC1C\uC0DD\uC2DC\uD0B5\uB2C8\uB2E4. \uADF8\uB807\uC9C0 \uC54A\uB2E4\uBA74 \uBA54\uC11C\uB4DC\uB97C \uC815\uC0C1\uC801\uC73C\uB85C \uD638\uCD9C\uD569\uB2C8\uB2E4. \uD638\uCD9C\uD55C \uACB0\uACFC \uC608\uC678\uAC00 \uBC1C\uC0DD\uD588\uACE0, \uADF8 \uC608\uC678\uAC00 \uC2E4\uD328\uB85C \uCC98\uB9AC\uD574\uC57C \uD558\uB294 \uACBD\uC6B0\uB77C\uBA74 CircuitBreaker\uC5D0\uAC8C \uC2E4\uD328\uD588\uB2E4\uACE0 \uC54C\uB824\uC90D\uB2C8\uB2E4. \uADF8\uB807\uC9C0 \uC54A\uB2E4\uBA74 CircuitBreaker\uC5D0\uAC8C \uC131\uACF5\uD588\uB2E4\uACE0 \uC54C\uB824\uC8FC\uAE30\uB9CC \uD558\uBA74 \uB429\uB2C8\uB2E4. \uCC38\uACE0\uB85C \uC2E4\uC81C \uC801\uC6A9\uB41C \uCF54\uB4DC\uC5D0\uB294 CircuitBreaker\uAC00 \uC798 \uC801\uC6A9\uB418\uC5C8\uB294\uC9C0 \uD655\uC778\uD558\uAE30 \uC704\uD55C IMON Logger1\uC640 \uAD00\uB828\uB41C \uCF54\uB4DC\uAC00 \uB4E4\uC5B4\uC788\uC2B5\uB2C8\uB2E4. \uD558\uC9C0\uB9CC, \uC5EC\uAE30\uC5D0\uC11C\uB294 CircuitBreaker \uBD80\uBD84\uC5D0 \uC9D1\uC911\uD560 \uC218 \uC788\uB3C4\uB85D \uC0DD\uB7B5\uD558\uC600\uC2B5\uB2C8\uB2E4.\\n\\n_1: IMON Logger: IMON\uC740 LINE \uC0AC\uB0B4\uC758 \uB2E4\uC591\uD55C \uC11C\uBE44\uC2A4\uB4E4\uC744 \uBAA8\uB2C8\uD130\uB9C1\uD558\uAE30 \uC704\uD55C \uC2DC\uC2A4\uD15C\uC73C\uB85C, IMON Logger\uB294 IMON\uC73C\uB85C \uB300\uC0C1 \uC11C\uBE44\uC2A4\uC758 \uD1B5\uACC4\uC9C0\uD45C \uBC0F \uB85C\uADF8\uB4E4\uC744 \uCDE8\uD569\uD558\uC5EC \uC804\uC1A1\uD558\uB294 \uAE30\uB2A5\uC744 \uD558\uACE0 \uC788\uB2E4._\\n\\n## CircuitBreaker\uC758 \uC124\uC815 \uBCC0\uACBD \uBA54\uC11C\uB4DC\\n\\nCircuitBreaker \uAC1D\uCCB4\uB97C \uB9CC\uB4E4\uC5B4\uC8FC\uB294 `CircuitBreakerBuilder`\uC5D0\uB294 CircuitBreaker\uC758 \uC124\uC815\uC744 \uBCC0\uACBD\uD560 \uC218 \uC788\uB294 \uC5EC\uB7EC \uAC00\uC9C0 \uBA54\uC11C\uB4DC\uB97C \uC81C\uACF5\uD569\uB2C8\uB2E4. \uAC00\uB2A5\uD558\uBA74 \uAE30\uBCF8 \uC124\uC815 \uADF8\uB300\uB85C \uC0AC\uC6A9\uD558\uB294 \uAC83\uC744 \uCD94\uCC9C\uD558\uC9C0\uB9CC CircuitBreaker\uC5D0 \uB300\uD574\uC11C \uC880 \uB354 \uC774\uD574\uD558\uAE30 \uC27D\uB3C4\uB85D \uC124\uC815\uB4E4\uC5D0 \uB300\uD574\uC11C \uC124\uBA85\uB4DC\uB9B4\uAE4C \uD569\uB2C8\uB2E4.\\n\\n| \uBA54\uC11C\uB4DC                      | \uD30C\uB77C\uBBF8\uD130               | \uAE30\uBCF8\uAC12                  | \uC124\uBA85                                                                                                                                                                                                                                                                                                                                                                                                                                                  |\\n| --------------------------- | ---------------------- | ----------------------- | ----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------- |\\n| failureRateThreshold        | double                 | 0.8                     | CircuitBreaker\uB97C \uC5F4\uC9C0 \uB9D0\uC9C0 \uD310\uB2E8\uD560 \uB54C \uC0AC\uC6A9\uD558\uAE30 \uC704\uD55C \uC2E4\uD328\uC728\uC785\uB2C8\uB2E4. `counterSlidingWindow` \uC2DC\uAC04 \uB3D9\uC548\uC758 \uC2E4\uD328\uC728\uC774 \uC774 \uAC12\uBCF4\uB2E4 \uB192\uC744 \uACBD\uC6B0 CircuitBreaker\uAC00 \uC5F4\uB9AC\uAC8C \uB429\uB2C8\uB2E4. \uAE30\uBCF8\uAC12 \uADF8\uB300\uB85C \uC0AC\uC6A9\uD560 \uACBD\uC6B0 80% \uC774\uC0C1 \uC2E4\uD328\uD558\uAC8C \uB418\uBA74 CircuitBreaker\uAC00 \uC5F4\uB9AC\uAC8C \uB429\uB2C8\uB2E4. \uB2E4\uC2DC \uB9D0\uD574 \uC131\uACF5\uD558\uB294 \uBE44\uC728\uC774 20% \uBBF8\uB9CC\uC774\uBA74 CircuitBreaker\uAC00 \uC5F4\uB9AC\uAC8C \uB429\uB2C8\uB2E4.                                                                                                                              |\\n| minimumRequestThreshold     | long                   | 10                      | CircuitBreaker\uB97C \uC5F4\uC9C0 \uB9D0\uC9C0 \uD310\uB2E8\uD560 \uCD5C\uC18C\uC758 \uD638\uCD9C \uD68C\uC218\uC785\uB2C8\uB2E4. `counterSlidingWindow` \uC2DC\uAC04 \uB3D9\uC548\uC758 \uD638\uCD9C \uD68C\uC218\uAC00 \uC774 \uAC12 \uBBF8\uB9CC\uC77C \uB54C\uB294 CircuitBreaker\uB97C \uC5F4\uC9C0 \uB9D0\uC9C0 \uD310\uB2E8\uD558\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4.                                                                                                                                                                                                                                                                              |\\n| circuitOpenWindow           | Duration               | 10\uCD08                    | CircuitBreaker\uAC00 Open \uC0C1\uD0DC\uB85C \uBC14\uB010 \uD6C4 Half-Open \uC0C1\uD0DC\uB85C \uBC14\uB00C\uAE30\uAE4C\uC9C0\uC758 \uC2DC\uAC04\uC785\uB2C8\uB2E4. CircuitBreaker\uAC00 \uC5F4\uB9B0 \uD6C4\uC5D0\uB294 `circuitOpenWindow` \uC2DC\uAC04\uB9CC\uD07C \uD750\uB978 \uD6C4\uC5D0 Half-Open \uC0C1\uD0DC\uB85C \uBC14\uB00C\uC5B4\uC11C \uD638\uCD9C\uC744 \uD14C\uC2A4\uD2B8\uD558\uAC8C \uB429\uB2C8\uB2E4.                                                                                                                                                                                                                                                |\\n| circuitOpenWindowMillis     | long                   | 10000                   |\\n| trialRequestInterval        | Duration               | 3\uCD08                     | Half-Open \uC0C1\uD0DC\uC5D0\uC11C \uC694\uCCAD\uD55C \uD638\uCD9C\uC5D0 Closed\uC751\uB2F5\uC774 \uC5C6\uC744 \uACBD\uC6B0, \uD638\uCD9C\uC744 \uC7AC\uC2DC\uB3C4\uD558\uAE30 \uC704\uD574 \uAE30\uB2E4\uB9AC\uB294 \uC2DC\uAC04\uC785\uB2C8\uB2E4. `trialRequestInterval` \uC2DC\uAC04 \uC548\uC5D0 \uC751\uB2F5\uC774 \uC62C \uACBD\uC6B0\uC5D0\uB294 \uADF8 \uACB0\uACFC\uC5D0 \uB530\uB77C\uC11C Closed\uB098 Open \uC0C1\uD0DC\uB85C \uBC14\uB00C\uAC8C \uB429\uB2C8\uB2E4. \uB9CC\uC57D, Open \uC0C1\uD0DC\uB85C \uBC14\uB00C\uC5C8\uB2E4\uBA74 \uB2E4\uC2DC `circuitOpenWindow` \uC2DC\uAC04\uB9CC\uD07C \uAE30\uB2E4\uB838\uB2E4\uAC00 \uD638\uCD9C\uC744 \uD14C\uC2A4\uD2B8\uD558\uAC8C \uB429\uB2C8\uB2E4. \uD558\uC9C0\uB9CC, \uC694\uCCAD\uD55C \uD638\uCD9C\uC774 `trialRequestInterval` \uC2DC\uAC04 \uB3D9\uC548 \uC5B4\uB290 \uC751\uB2F5\uB3C4 \uC624\uC9C0 \uC54A\uB294\uB2E4\uBA74 \uB2E4\uC2DC \uD638\uCD9C\uC744 \uC2DC\uB3C4\uD558\uAC8C \uB429\uB2C8\uB2E4.                       |\\n| trialRequestIntervalMillis  | long                   | 3000                    |\\n| counterSlidingWindow        | Duration               | 20\uCD08                    | CircuitBreaker\uB97C \uC5F4\uC9C0 \uB9D0\uC9C0 \uD310\uB2E8\uD560 \uB54C \uCD5C\uADFC `counterSlidngWindow` \uC2DC\uAC04\uB9CC\uD07C\uC758 \uAE30\uB85D\uC744 \uAC00\uC9C0\uACE0 \uD310\uB2E8\uD569\uB2C8\uB2E4. \uAE30\uBCF8\uAC12 \uADF8\uB300\uB85C \uC0AC\uC6A9\uD558\uAC8C \uB418\uBA74 \uCD5C\uADFC 20\uCD08 \uB3D9\uC548\uC758 \uD638\uCD9C \uACB0\uACFC\uB4E4\uB9CC\uC73C\uB85C \uD310\uB2E8\uD558\uAC8C \uB429\uB2C8\uB2E4.                                                                                                                                                                                                                                                                  |\\n| counterSlidingWindowMillis  | long                   | 20000                   |\\n| counterUpdateInterval       | Duration               | 1\uCD08                     | CircuitBreaker\uC5D0\uC11C\uB294 \uD638\uCD9C\uC758 \uACB0\uACFC\uB97C `SlidingWindowCounter`\uB97C \uD1B5\uD574\uC11C \uBCF4\uAD00\uD558\uACE0 \uC788\uB294\uB370 \uC774\uB54C, \uBCF4\uAD00\uD558\uB294 \uB2E8\uC704\uC758 \uC2DC\uAC04\uC744 \uC758\uBBF8\uD569\uB2C8\uB2E4. \uAE30\uBCF8\uAC12 \uADF8\uB300\uB85C \uC0AC\uC6A9\uD558\uAC8C \uB418\uBA74 1\uCD08 \uB2E8\uC704\uB85C \uAE30\uB85D\uC744 \uAC00\uC9C0\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uC608\uB97C \uB4E4\uBA74, \uCD5C\uADFC 20\uCD08 \uC804 = \uC131\uACF5 20\uD68C, \uC2E4\uD328 0\uD68C / \uCD5C\uADFC 19\uCD08 \uC804 = \uC131\uACF5 25\uD68C, \uC2E4\uD328 1\uD68C / ... / \uCD5C\uADFC 1\uCD08 \uC804 = \uC131\uACF5 21\uD68C, \uC2E4\uD328 0\uD68C \uB4F1\uC758 \uAE30\uB85D\uC744 \uAC00\uC9C0\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uC774 1\uCD08 \uB2E8\uC704\uC758 \uAE30\uB85D\uC744 \uAC00\uC9C0\uACE0 `counterSlidingWindow` \uC2DC\uAC04\uB9CC\uD07C\uC744 \uACC4\uC0B0\uD558\uC5EC \uC2E4\uD328\uC728\uC744 \uACC4\uC0B0\uD558\uAC8C \uB429\uB2C8\uB2E4. |\\n| counterUpdateIntervalMillis | long                   | 1000                    |\\n| exceptionFilter             | ExceptionFilter        | \uBAA8\uB4E0 \uC608\uC678\uB97C \uC2E4\uD328\uB85C \uAC04\uC8FC | \uC608\uC678\uAC00 \uBC1C\uC0DD\uD588\uC744 \uB54C, \uADF8 \uC608\uC678\uB97C \uC2E4\uD328\uB85C \uAC04\uC8FC\uD560\uC9C0 \uC5EC\uBD80\uB97C \uBC18\uD658\uD558\uB294 \uAC1D\uCCB4\uC785\uB2C8\uB2E4. \uAE30\uBCF8\uAC12\uC744 \uADF8\uB300\uB85C \uC0AC\uC6A9\uD558\uAC8C \uB418\uBA74 \uBAA8\uB4E0 \uC608\uC678\uB97C \uC2E4\uD328\uB85C \uAC04\uC8FC\uD569\uB2C8\uB2E4.                                                                                                                                                                                                                                                                                                                |\\n| listener                    | CircuitBreakerListener |                         | CircuitBreaker\uC758 \uC0C1\uD0DC\uAC00 \uBC14\uB00C\uAC70\uB098, `counterUpdateInterval` \uC2DC\uAC04\uC774 \uC9C0\uB098\uAC70\uB098, CircuitBreaker\uAC00 \uC5F4\uB824\uC11C \uD638\uCD9C\uC774 \uAC70\uBD80\uB420 \uB54C\uC5D0 \uB300\uD55C \uC774\uBCA4\uD2B8\uB97C \uC218\uC2E0\uD560 \uC218 \uC788\uB294 \uB9AC\uC2A4\uB108\uC785\uB2C8\uB2E4.                                                                                                                                                                                                                                                                                      |\\n\\n## \uB9C8\uBB34\uB9AC\uD558\uBA70\\n\\n\uC608\uC804\uC5D0\uB294 Channel Gateway\uC758 \uC5B4\uB5A4 \uBD80\uBD84\uC5D0 \uC7A5\uC560\uAC00 \uBC1C\uC0DD\uD55C\uB2E4\uBA74 \uC190\uC4F0\uAE30 \uC804\uC5D0 \uB108\uBB34 \uD070 \uD53C\uD574\uAC00 \uBC1C\uC0DD\uD558\uC600\uC2B5\uB2C8\uB2E4. \uC77C\uBD80\uC5D0\uC11C \uC2DC\uC791\uB41C \uC7A5\uC560\uAC00 Thread Full \uD604\uC0C1\uC744 \uBC1C\uC0DD\uC2DC\uD0A4\uACE0, \uACB0\uAD6D \uC804\uCCB4 \uC11C\uBE44\uC2A4\uC5D0 \uC601\uD5A5\uC744 \uBBF8\uCCE4\uAE30 \uB54C\uBB38\uC785\uB2C8\uB2E4. \uD558\uC9C0\uB9CC, \uC774\uC81C\uB294 CircuitBreaker\uAC00 \uADF8 \uBD80\uBD84\uC744 \uCC28\uB2E8\uD568\uC73C\uB85C\uC11C \uC880 \uB354 \uC5EC\uC720\uB86D\uAC8C \uB300\uCC98\uD560 \uC218 \uC788\uC744 \uAC83\uC785\uB2C8\uB2E4.\\n\\n\uB9C8\uC9C0\uB9C9\uC73C\uB85C \uC704 \uC124\uC815\uB4E4\uC744 \uC774\uC6A9\uD558\uC5EC CircuitBreaker\uC758 \uB3D9\uC791 \uBC29\uC2DD\uC744 \uC124\uBA85\uD558\uB294 \uAC83\uC73C\uB85C \uB9C8\uBB34\uB9AC \uC9C0\uC744\uAE4C \uD569\uB2C8\uB2E4.\\n\\n- \uCC98\uC74C CircuitBreaker\uC758 \uC0C1\uD0DC\uB294 *Closed*\uC785\uB2C8\uB2E4.\\n- _Closed_ : \uD638\uCD9C\uC744 \uC218\uD589\uD55C \uD6C4 `exceptionFilter`\uC5D0 \uB530\uB77C \uB2E4\uC74C\uACFC \uAC19\uC774 \uB3D9\uC791\uD569\uB2C8\uB2E4.\\n  - \uACB0\uACFC\uAC00 \uC131\uACF5\uD588\uB2E4\uBA74 \uC131\uACF5\uD588\uB2E4\uB294 \uAE30\uB85D\uC744 \uB0A8\uAE30\uACE0 _Closed_ \uC0C1\uD0DC\uB85C \uAC11\uB2C8\uB2E4.\\n  - \uACB0\uACFC\uAC00 \uC2E4\uD328\uD588\uB2E4\uBA74 `counterSlidingWindow` \uC2DC\uAC04 \uB3D9\uC548\uC758 \uD638\uCD9C \uACB0\uACFC\uB97C \uD655\uC778\uD574\uC11C\\n    - `minimumRequestThreshold` \uAC1C\uC218\uBCF4\uB2E4 \uB9CE\uACE0, \uC2E4\uD328\uC728\uC774 `failureRateThreshold` \uC774\uC0C1\uC774\uB77C\uBA74 _Open_ \uC0C1\uD0DC\uB85C \uAC11\uB2C8\uB2E4.\\n    - \uADF8\uB807\uC9C0 \uC54A\uB2E4\uBA74 _Closed_ \uC0C1\uD0DC\uB85C \uC720\uC9C0\uB429\uB2C8\uB2E4.\\n- _Open_ : `circuitOpenWindow` \uC2DC\uAC04\uC774 \uC9C0\uB098\uBA74 _Half-Open_ \uC0C1\uD0DC\uB85C \uBC14\uB00C\uAC8C \uB429\uB2C8\uB2E4.\\n- _Half-Open_ : \uCC98\uC74C \uB4E4\uC5B4\uC624\uB294 \uD638\uCD9C\uC744 \uC218\uD589\uD55C \uD6C4 `exceptionFilter`\uC5D0 \uB530\uB77C \uB2E4\uC74C\uACFC \uAC19\uC774 \uB3D9\uC791\uD569\uB2C8\uB2E4.\\n  - \uACB0\uACFC\uAC00 \uC131\uACF5\uD588\uB2E4\uBA74 _Closed_ \uC0C1\uD0DC\uB85C \uBC14\uB01D\uB2C8\uB2E4.\\n  - \uACB0\uACFC\uAC00 \uC2E4\uD328\uD588\uB2E4\uBA74 _Open_ \uC0C1\uD0DC\uB85C \uBC14\uB01D\uB2C8\uB2E4.\\n  - `trialRequestInterval` \uC2DC\uAC04 \uC548\uC5D0 \uC751\uB2F5\uC774 \uC5C6\uB2E4\uBA74 _Half-Open_ \uC0C1\uD0DC\uC5D0\uC11C \uADF8 \uB2E4\uC74C \uCC98\uC74C\uC73C\uB85C \uB4E4\uC5B4\uC624\uB294 \uD638\uCD9C \uACB0\uACFC\uC5D0 \uB530\uB978 \uBD84\uAE30 \uCC98\uB9AC\uB97C \uD569\uB2C8\uB2E4.\\n\\n## \uC800\uC790 \uC18C\uAC1C\\n\\n\uC2E0\uC885\uD6C8: \uC800\uB294 \uADC0\uCC2E\uC740 \uC77C\uC744 \uC2EB\uC5B4\uD569\uB2C8\uB2E4. \uADC0\uCC2E\uC740 \uC77C\uC744 \uC904\uC774\uAE30 \uC704\uD574\uC11C \uACC4\uC18D \uACE0\uBBFC\uD558\uC9C0\uC694. \uADF8\uB798\uC11C, \uD504\uB85C\uADF8\uB798\uBC0D\uC744 \uC88B\uC544\uD558\uB294\uB370 \uC660\uC9C0 \uC77C\uC774 \uB354 \uB298\uC5B4\uB09C \uAC83 \uAC19\uC740 \uB290\uB08C\uC740 \uC800\uB9CC\uC758 \uB290\uB08C\uC774\uACA0\uC9C0\uC694?"},{"id":"/2016/07/24/circuit-breakers-for-distributed-services","metadata":{"permalink":"/blog/ko/2016/07/24/circuit-breakers-for-distributed-services","editUrl":"https://github.com/line/armeria/edit/main/site-new/src/content/blog/ko/2016-07-24-circuit-breakers-for-distributed-services.mdx","source":"@site/src/content/blog/ko/2016-07-24-circuit-breakers-for-distributed-services.mdx","title":"\uBD84\uC0B0 \uC11C\uBE44\uC2A4 \uD658\uACBD\uC5D0 \uB300\uD55C Circuit Breaker \uC801\uC6A9","description":"LINE\uC758 \uC5D4\uC9C0\uB2C8\uC5B4 Ono\uC785\uB2C8\uB2E4.","date":"2016-07-24T00:00:00.000Z","tags":[],"readingTime":4.14,"hasTruncateMarker":true,"authors":[{"name":"Ono Yuichi","title":"LINE \uC5D4\uC9C0\uB2C8\uC5B4\uC785\uB2C8\uB2E4.","imageURL":"/img/author-onoyuichi.png","key":"onoyuichi","page":null}],"frontMatter":{"authors":["onoyuichi"],"other_languages":{"en":"/blog/2016/07/24/circuit-breakers-for-distributed-services","ja":"/blog/ja/2016/07/14/circuit-breakers-for-distributed-services"}},"unlisted":false,"prevItem":{"title":"Channel Gateway\uC5D0 CircuitBreaker \uC801\uC6A9","permalink":"/blog/ko/2016/08/04/applying-circuitbreaker-to-channel-gateway"},"nextItem":{"title":"Armeria \uC624\uD508\uC18C\uC2A4\uD654 \uC774\uC57C\uAE30","permalink":"/blog/ko/2016/04/13/open-sourcing-armeria"}},"content":"LINE\uC758 \uC5D4\uC9C0\uB2C8\uC5B4 Ono\uC785\uB2C8\uB2E4.\\n\uC774\uBC88 \uBE14\uB85C\uADF8\uC5D0\uC11C\uB294 LINE\uC758 \uC11C\uBC84\uC5D0\uC11C \uC2E4\uC81C\uB85C \uB3C4\uC785\uC744 \uC2DC\uC791\uD55C \'Circuit Breaker\'\uB77C\uB294 \uC2DC\uC2A4\uD15C\uC5D0 \uB300\uD574 \uC18C\uAC1C\uD558\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n## Circuit Breaker\uB780?\\n\\nLINE\uC744 \uBE44\uB86F\uD55C \uCD5C\uADFC\uC758 Web \uBC0F App\uC758 \uBC31\uC5D4\uB4DC \uC11C\uBC84 \uC2DC\uC2A4\uD15C\uC740 \uC5EC\uB7EC \uAC1C\uC758 \uC11C\uBE44\uC2A4\uAC00 API\uB098 RPC\uB85C \uC5F0\uACB0\uB41C \uB124\uD2B8\uC6CC\uD06C\uB85C \uAD6C\uC131\uB418\uC5B4 \uC788\uC2B5\uB2C8\uB2E4.\\n\uB9CC\uC57D \uC774 \uB124\uD2B8\uC6CC\uD06C \uC911 \uD558\uB098\uAC00 \uAC11\uC790\uAE30 \uC804\uD600 \uC751\uB2F5\uD558\uC9C0 \uC54A\uAC8C \uB418\uB294 \uC0C1\uD669\uC774 \uBC1C\uC0DD\uD558\uBA74 \uC5B4\uB5BB\uAC8C \uB420\uAE4C\uC694?\\n\uB3D9\uC791\uD558\uC9C0 \uC54A\uB294 \uC11C\uBE44\uC2A4 \uC811\uC18D \uC2DC \uD0C0\uC784\uC544\uC6C3\uB420 \uB54C\uAE4C\uC9C0 \uCC28\uB2E8\uB418\uC5B4, \uC758\uC874\uC131\uC774 \uC788\uB294 \uC11C\uBE44\uC2A4\uAE4C\uC9C0 \uC5F0\uC1C4\uC801\uC73C\uB85C \uBA48\uCD9C \uAC00\uB2A5\uC131\uC774 \uC788\uC2B5\uB2C8\uB2E4.\\n\uB9CC\uC57D \uB124\uD2B8\uC6CC\uD06C \uC804\uCCB4\uB97C \uD30C\uC545\uD558\uACE0 \uC788\uB294 \uC0AC\uB78C\uC774 \uC544\uBB34\uB3C4 \uC5C6\uB2E4\uBA74, \uADFC\uBCF8\uC801\uC778 \uC6D0\uC778\uC774 \uC5B4\uB290 \uC11C\uBE44\uC2A4\uC5D0 \uC788\uB294\uC9C0\uB97C \uC54C\uC544\uB0B4\uAE30\uAE4C\uC9C0 \uC2DC\uAC04\uC774 \uAC78\uB9AC\uAC8C \uB429\uB2C8\uB2E4.\\n\\n![-BG-](/img/circuit-breakers-for-distributed-services-1.png)\\n\\n{/* truncate */}\\n\\n\uC6B0\uB9AC\uB294 \uC774\uB7EC\uD55C \uC5F0\uC1C4\uC801\uC778 \uC7A5\uC560 \uBC1C\uC0DD\uC744 \uB9C9\uC544\uC57C \uD569\uB2C8\uB2E4.\\n\uC801\uC5B4\uB3C4 \uAC00\uC7A5 \uC911\uC694\uD55C \uAE30\uB2A5\uC5D0 \uC601\uD5A5\uC774 \uAC00\uC9C0 \uC54A\uB3C4\uB85D \uD574\uC57C \uD558\uB294\uB370, \uADF8\uB7EC\uAE30 \uC704\uD574\uC11C\uB294 \uC7A5\uC560\uAC00 \uBC1C\uC0DD\uD55C \uC11C\uBE44\uC2A4\uC5D0 \uB300\uD55C \uC811\uC18D \uCC28\uB2E8\uC774 \uD544\uC694\uD569\uB2C8\uB2E4.\\n\\n![-BG-](/img/circuit-breakers-for-distributed-services-2.png)\\n\\n\uC774 \uC2DC\uC2A4\uD15C\uC744 \uC790\uB3D9\uD654\uD55C \uAC83\uC774 \uBC14\uB85C Circuit Breaker\uC785\uB2C8\uB2E4.\\nhttp://martinfowler.com/bliki/CircuitBreaker.html\\n\\n\uC704 \uB9C1\uD06C\uC5D0 \uC788\uB294 \uB9C8\uD2F4 \uD30C\uC6B8\uB7EC\uC758 \uAE00\uC5D0 \uC790\uC138\uD55C \uC124\uBA85\uC774 \uC788\uC73C\uB2C8 \uC5EC\uAE30\uC11C\uB294 \uAC04\uB2E8\uD558\uAC8C\uB9CC \uC18C\uAC1C\uD558\uACA0\uC2B5\uB2C8\uB2E4.\\n\\nCircuit Breaker\uB780, \uC6D0\uACA9 \uC811\uC18D\uC758 \uC131\uACF5/\uC2E4\uD328\uB97C \uCE74\uC6B4\uD2B8\uD558\uC5EC \uC5D0\uB7EC\uC728(failure rate)\uC774 \uC784\uACC4\uCE58\uB97C \uB118\uC5B4\uC130\uC744 \uB54C \uC790\uB3D9\uC801\uC73C\uB85C \uC811\uC18D\uC744 \uCC28\uB2E8\uD558\uB294 \uC2DC\uC2A4\uD15C\uC785\uB2C8\uB2E4.\\nCircuit Breaker\uB294 \uC0C1\uD0DC \uBA38\uC2E0(State Machine)\uC73C\uB85C \uB098\uD0C0\uB0BC \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC811\uC18D \uC131\uACF5\uACFC \uC2E4\uD328 \uC774\uBCA4\uD2B8\uAC00 \uBC1C\uC0DD\uD560 \uB54C\uB9C8\uB2E4 \uB0B4\uBD80 \uC0C1\uD0DC\uB97C \uC5C5\uB370\uC774\uD2B8\uD558\uC5EC \uC790\uB3D9\uC801\uC73C\uB85C \uC7A5\uC560\uB97C \uAC80\uCD9C\uD558\uACE0 \uBCF5\uAD6C \uC5EC\uBD80\uB97C \uD310\uB2E8\uD569\uB2C8\uB2E4.\\n\\n![](/img/circuit-breakers-for-distributed-services-3.png)\\n\\n\uAC01\uAC01\uC758 \uC0C1\uD0DC\uC640 \uC774\uB3D9 \uC870\uAC74\uC740 \uC544\uB798\uC640 \uAC19\uC2B5\uB2C8\uB2E4.\\n\\n**CLOSED**\\n\\n\uCD08\uAE30 \uC0C1\uD0DC\uC785\uB2C8\uB2E4. \uBAA8\uB4E0 \uC811\uC18D\uC740 \uD3C9\uC18C\uC640 \uAC19\uC774 \uC2E4\uD589\uB429\uB2C8\uB2E4.\\n\\n**OPEN**\\n\\n\uC5D0\uB7EC\uC728\uC774 \uC784\uACC4\uCE58\uB97C \uB118\uC5B4\uC11C\uBA74 OPEN \uC0C1\uD0DC\uAC00 \uB429\uB2C8\uB2E4. \uBAA8\uB4E0 \uC811\uC18D\uC740 \uCC28\uB2E8(fail fast)\uB429\uB2C8\uB2E4.\\n\\n**HALF_OPEN**\\n\\nOPEN \uD6C4 \uC77C\uC815 \uC2DC\uAC04\uC774 \uC9C0\uB098\uBA74 HALF_OPEN \uC0C1\uD0DC\uAC00 \uB429\uB2C8\uB2E4. \uC811\uC18D\uC744 \uC2DC\uB3C4\uD558\uC5EC \uC131\uACF5\uD558\uBA74 CLOSED, \uC2E4\uD328\uD558\uBA74 OPEN\uC73C\uB85C \uB418\uB3CC\uC544\uAC11\uB2C8\uB2E4.\\n\\n## Circuit Breaker for Armeria\\n\\n[Armeria](http://line.github.io/armeria/)\uB294 LINE\uC774 \uC624\uD508\uC18C\uC2A4\uB85C \uACF5\uAC1C\uD55C Netty \uAE30\uBC18\uC758 \uBE44\uB3D9\uAE30 Thrift \uD074\uB77C\uC774\uC5B8\uD2B8/\uC11C\uBC84 \uB77C\uC774\uBE0C\uB7EC\uB9AC\uC785\uB2C8\uB2E4.\\nArmeria\uC758 \uC7A5\uC810\uC740 decorator\uB97C \uD1B5\uD574 \uAE30\uB2A5\uC744 \uAC04\uD3B8\uD558\uAC8C \uD655\uC7A5\uD560 \uC218 \uC788\uB2E4\uB294 \uC810\uC785\uB2C8\uB2E4. \uADF8\uB9AC\uACE0 Armeria 0.13.0\uBD80\uD130 Circuit Breaker\uB97C decorator\uB85C \uCD94\uAC00\uD560 \uC218 \uC788\uAC8C \uB418\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\nCircuit Breaker\uB97C \uC0AC\uC6A9\uD55C Thrift Client \uCD08\uAE30\uD654\uB294 \uC544\uB798\uC640 \uAC19\uC774 \uC9C4\uD589\uD569\uB2C8\uB2E4.\\n\\n```\\nIface helloClient = new ClientBuilder(\\"tbinary+http://127.0.0.1:8080/hello\\")\\n                     .decorator(\\n                      CircuitBreakerClient.newDecorator(\\n                          new CircuitBreakerBuilder(\\"hello\\").build()\\n                      )\\n                     )\\n                     .build(Iface.class);\\n```\\n\\n\uC27D\uAC8C \uCD08\uAE30\uD654\uB97C \uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uADF8\uB9AC\uACE0 \uC774 Thrift Client\uB97C \uD638\uCD9C\uD558\uB294 \uCF54\uB4DC\uB294 \uC544\uB798\uC640 \uAC19\uC2B5\uB2C8\uB2E4.\\n\\n```\\ntry {\\n    helloClient.hello(\\"line\\");\\n} catch (TException e) {\\n    // error handling\\n} catch (FailFastException e) {\\n   // fallback code\\n}\\n```\\n\\nCircuit Breaker\uAC00 \uC7A5\uC560\uB97C \uAC10\uC9C0\uD558\uBA74 Thrift Client\uAC00 FailFastException\uC744 \uC804\uC1A1\uD558\uBBC0\uB85C, \uC801\uC808\uD55C \uB300\uCCB4(fallback) \uCF54\uB4DC\uB97C \uC2E4\uD589\uD569\uB2C8\uB2E4. \uBE44\uB3D9\uAE30 Client\uC758 \uACBD\uC6B0\uB3C4 \uB3D9\uC77C\uD569\uB2C8\uB2E4.\\n\\n```\\nhelloClient.hello(\\"line\\", new AsyncMethodCallback() {\\n  public void onComplete(Object response) {\\n     // response handling\\n  }\\n  public void onError(Exception e) {\\n     if (e instanceof TException) {\\n         // error handling\\n     } else if (e instanceof FailFastException) {\\n         // fallback code\\n     }\\n }\\n});\\n```\\n\\n## Grouping\\n\\n\uC704 \uC608\uC2DC\uC5D0\uC11C\uB294 \uD558\uB098\uC758 Thrift \uC11C\uBE44\uC2A4\uC5D0 \uD558\uB098\uC758 Circuit Breaker\uB97C \uD560\uB2F9\uD588\uC2B5\uB2C8\uB2E4. \uC774 \uACBD\uC6B0, \uB3D9\uC77C\uD55C \uC11C\uBE44\uC2A4 \uC911 \uD558\uB098\uC758 \uBA54\uC11C\uB4DC\uAC00 \uC6D0\uC778\uC774 \uB418\uC5B4 Circuit\uC774 \uCC28\uB2E8\uB418\uC5C8\uC744 \uB54C \uB2E4\uB978 \uBAA8\uB4E0 \uBA54\uC11C\uB4DC\uB3C4 \uCC28\uB2E8\uB418\uAC8C \uB429\uB2C8\uB2E4. \uC774\uB294 \uC624\uD788\uB824 \uC7A5\uC560 \uBC94\uC704\uB97C \uD655\uB300\uC2DC\uD0A4\uAC8C \uB418\uBBC0\uB85C \uBC14\uB78C\uC9C1\uD55C \uB3D9\uC791\uC774 \uC544\uB2D9\uB2C8\uB2E4. \uB530\uB77C\uC11C Armeria\uC5D0\uC11C\uB294 Circuit Breaker\uC758 \uC778\uC2A4\uD134\uC2A4\uB97C \uD560\uB2F9\uD560 \uBC94\uC704\uB97C \uC120\uD0DD\uD560 \uC218 \uC788\uB294 \uADF8\uB8F9\uD551 \uAE30\uB2A5\uC744 \uC81C\uACF5\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n\uADF8\uB8F9\uD551\uC5D0\uB294 \uB2E4\uC74C\uC758 3\uC885\uB958\uAC00 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n**Per Method**\\n\\n\uBA54\uC11C\uB4DC\uBCC4\uB85C \uD558\uB098\uC758 Circuit Breaker\uB97C \uD560\uB2F9\uD569\uB2C8\uB2E4.\\n\\n**Per Host**\\n\\n\uC6D0\uACA9 \uD638\uC2A4\uD2B8\uBCC4\uB85C \uD558\uB098\uC758 Circuit Breaker\uB97C \uD560\uB2F9\uD569\uB2C8\uB2E4.\\n\\n**Per Host and Method**\\n\\n\uC6D0\uACA9 \uD638\uC2A4\uD2B8\uC640 \uBA54\uC11C\uB4DC\uBCC4\uB85C \uD558\uB098\uC758 Circuit Breaker\uB97C \uD560\uB2F9\uD569\uB2C8\uB2E4.\\n\\n![-BG-](/img/circuit-breakers-for-distributed-services-4.png)\\n\\n## Failure Rate\\n\\nCircuit Breaker\uB97C \uC6B4\uC6A9\uD560 \uB54C\uB294 \uC5B4\uB5A4 \uC0C1\uD0DC\uB97C \uC7A5\uC560\uB85C \uAC04\uC8FC\uD560 \uAC83\uC778\uC9C0 \uC870\uAC74\uC744 \uBA85\uD655\uD558\uAC8C \uC815\uC758\uD574\uC57C \uD569\uB2C8\uB2E4.\\nArmeria\uC5D0\uC11C\uB294 \uC77C\uC815 \uC2DC\uAC04 \uB0B4\uC5D0 \uCC98\uB9AC\uD55C \uB9AC\uD018\uC2A4\uD2B8 \uC911 \uC5D0\uB7EC\uC728(Failure Rate)\uC774 < Failure Rate Threshold > \uC774\uC0C1\uC778 \uACBD\uC6B0\uB97C \uC7A5\uC560 \uC0C1\uD0DC\uB85C \uCDE8\uAE09\uD569\uB2C8\uB2E4. \uB2E8, \uB9AC\uD018\uC2A4\uD2B8 \uC218\uAC00 \uB108\uBB34 \uC801\uC744 \uACBD\uC6B0(\uC2E4\uD589 \uC9C1\uD6C4\uC758 \uACFC\uB3C4 \uC0C1\uD0DC \uB4F1)\uC5D0\uB294 \uC5D0\uB7EC\uC728\uC774 \uC548\uC815\uC801\uC774\uC9C0 \uC54A\uC544\uC11C \uC7A5\uC560\uB97C \uC624\uAC10\uC9C0\uD558\uAC8C \uB420 \uAC00\uB2A5\uC131\uC774 \uC788\uC2B5\uB2C8\uB2E4. \uB530\uB77C\uC11C \uB9AC\uD018\uC2A4\uD2B8 \uC218\uAC00 < Minimum Request Threshold > \uC774\uD558\uC778 \uACBD\uC6B0\uC5D0\uB294 \uC7A5\uC560 \uD310\uC815\uC744 \uD558\uC9C0 \uC54A\uB3C4\uB85D \uC124\uC815\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uADF8\uB9AC\uACE0 \uC5D0\uB7EC \uBE44\uC728\uC744 \uCE74\uC6B4\uD2B8\uD558\uB294 \uC2DC\uAC04\uC758 \uAE38\uC774\uB294 < Sliding Window >\uB85C \uC124\uC815\uD569\uB2C8\uB2E4.\\nFailure Rate\uC640 Sliding Window\uC758 \uAD00\uACC4\uB294 \uC544\uB798 \uADF8\uB9BC\uC73C\uB85C \uB098\uD0C0\uB0BC \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n![-BG-](/img/circuit-breakers-for-distributed-services-5.png)\\n\\n## Monitoring\\n\\nCircuit Breaker Listener\uB97C \uD1B5\uD574 Circuit Breaker\uC758 \uC0C1\uD0DC \uBCC0\uD654\uB97C \uBAA8\uB2C8\uD130\uB9C1\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC544\uB798\uC758 \uCF54\uB4DC\uB294 Armeria\uAC00 \uC81C\uACF5\uD558\uB294 Dropwizard Metrics \uAE30\uBC18\uC758 Listener\uB97C \uC0AC\uC6A9\uD55C \uC608\uC785\uB2C8\uB2E4. \uBB3C\uB860 \uCEE4\uC2A4\uD130\uB9C8\uC774\uC988\uB41C \uBAA8\uB2C8\uD130\uB9C1 \uC2DC\uC2A4\uD15C\uC5D0 \uB9DE\uCD98 Listener\uB97C \uAD6C\uD604\uD558\uB294 \uAC83\uB3C4 \uAC00\uB2A5\uD569\uB2C8\uB2E4.\\n\\n```\\nMetricRegistry registry = new MetricRegistry();\\n\\nIface helloClient = new ClientBuilder(\\"tbinary+http://127.0.0.1:8080/hello\\")\\n       .decorator(\\n        CircuitBreakerClient.newDecorator(\\n          new CircuitBreakerBuilder(\\"hello\\")\\n            .listener(new DropwizardMetricsCircuitBreakerListener(registry, \\"hello\\"))\\n            .build()\\n        )\\n       )\\n       .build(Iface.class);\\n```\\n\\n## Armeria\uC758 Circuit Breaker\uB97C \uB2E8\uB3C5\uC73C\uB85C \uC0AC\uC6A9\uD558\uAE30\\n\\n\uC9C0\uAE08\uAE4C\uC9C0\uB294 Armeria\uC758 Thrift Client\uC640 Circuit Breaker \uD328\uD0A4\uC9C0\uB97C \uC870\uD569\uD574\uC11C \uC0AC\uC6A9\uD558\uB294 \uBC29\uBC95\uC744 \uC18C\uAC1C\uD588\uB294\uB370, Circuit Breaker \uD328\uD0A4\uC9C0\uB97C \uB2E8\uB3C5\uC73C\uB85C \uC0AC\uC6A9\uD558\uB294 \uAC83\uB3C4 \uAC00\uB2A5\uD569\uB2C8\uB2E4.\\n\\nCircuit Breaker \uD328\uD0A4\uC9C0\uB97C \uB2E8\uB3C5\uC73C\uB85C \uC0AC\uC6A9\uD560 \uACBD\uC6B0, \uC911\uC694\uD55C API\uB294 \uC544\uB798\uC758 3\uAC00\uC9C0\uC785\uB2C8\uB2E4.\\n\\n**CircuitBreaker#canRequest()**\\n\\nCircuit Breaker\uC758 \uC0C1\uD0DC\uB97C \uD655\uC778\uD569\uB2C8\uB2E4.\\nCircuit\uC774 \uCC28\uB2E8\uB418\uC5B4 \uC788\uB294 \uACBD\uC6B0\uC5D0\uB294 false\uB97C \uBC18\uD658\uD569\uB2C8\uB2E4.\\n\\n**CircuitBreaker#onSuccess()**\\n\\n\uC11C\uBE44\uC2A4 \uC811\uC18D\uC774 \uC815\uC0C1\uC801\uC73C\uB85C \uC774\uB8E8\uC5B4\uC84C\uC74C\uC744 \uAE30\uB85D\uD569\uB2C8\uB2E4.\\n\\n**CircuitBreaker#onFailure() \uB610\uB294 CircuitBreaker#onFailure(Throwable t)**\\n\\n\uC11C\uBE44\uC2A4 \uC811\uC18D\uC774 \uC2E4\uD328\uD588\uC74C\uC744 \uAE30\uB85D\uD569\uB2C8\uB2E4.\\n\\n\uC544\uB798\uC758 \uC0D8\uD50C \uCF54\uB4DC\uC5D0\uC11C\uB294 \uBA3C\uC800 canRequest()\uB85C Circuit\uC758 \uC0C1\uD669\uC744 \uD655\uC778\uD558\uACE0, \uBB38\uC81C\uAC00 \uC5C6\uC73C\uBA74 remote service access\uB97C \uC2E4\uD589\uD569\uB2C8\uB2E4. \uADF8\uB9AC\uACE0 \uADF8 \uACB0\uACFC\uC5D0 \uB530\uB77C onSuccess \uB610\uB294 onFailure\uB97C \uD638\uCD9C\uD569\uB2C8\uB2E4. \uC5EC\uAE30\uC5D0\uC11C\uB294 \uC608\uC678 \uBC1C\uC0DD \uC5EC\uBD80\uB97C \uACB0\uACFC\uC758 \uC870\uAC74\uC73C\uB85C \uC124\uC815\uD588\uB294\uB370, \uC774 \uC870\uAC74\uC740 \uC0C1\uD669\uC5D0 \uB9DE\uCDB0 \uC790\uC720\uB86D\uAC8C \uC815\uC758\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC608\uB97C \uB4E4\uC5B4, remote service access\uAC00 \uC77C\uC815 \uC2DC\uAC04 \uC774\uC0C1 \uAC78\uB9B0 \uACBD\uC6B0\uC5D0\uB294 \uC608\uC678\uAC00 \uBC1C\uC0DD\uD558\uC9C0 \uC54A\uC558\uB354\uB77C\uB3C4 \uC5D0\uB7EC\uB85C \uCE74\uC6B4\uD2B8\uD558\uB3C4\uB85D \uD560 \uC218\uB3C4 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n```\\nif (circuitBreaker.canRequest()) {\\n   try {\\n       // remote service access\\n\\n       circuitBreaker.onSuccess();\\n   } catch (Exception e) {\\n       circuitBreaker.onFailure(e);\\n   }\\n} else {\\n   // fail fast\\n}\\n```\\n\\n\uC774\uC0C1\uC73C\uB85C Armeria\uC758 Circuit Breaker \uAE30\uB2A5\uC5D0 \uB300\uD55C \uC18C\uAC1C\uB97C \uB9C8\uCE58\uACA0\uC2B5\uB2C8\uB2E4.\\nLINE \uB0B4\uC5D0\uC11C\uC758 \uC2E4\uC81C \uC0AC\uB840\uB3C4 \uC870\uB9CC\uAC04 \uC18C\uAC1C\uD558\uB3C4\uB85D \uD558\uACA0\uC2B5\uB2C8\uB2E4."},{"id":"/2016/04/13/open-sourcing-armeria","metadata":{"permalink":"/blog/ko/2016/04/13/open-sourcing-armeria","editUrl":"https://github.com/line/armeria/edit/main/site-new/src/content/blog/ko/2016-04-13-open-sourcing-armeria.mdx","source":"@site/src/content/blog/ko/2016-04-13-open-sourcing-armeria.mdx","title":"Armeria \uC624\uD508\uC18C\uC2A4\uD654 \uC774\uC57C\uAE30","description":"Armeria\uB294 Java 8 \uBC0F Netty \uC0C1\uC5D0 \uBE44\uB3D9\uAE30 RPC/API \uD074\uB77C\uC774\uC5B8\uD2B8-\uC11C\uBC84\uB97C \uAD6C\uD604\uD55C \uAC83\uC785\uB2C8\uB2E4.","date":"2016-04-13T00:00:00.000Z","tags":[],"readingTime":8.41,"hasTruncateMarker":true,"authors":[{"name":"\uC774\uD76C\uC2B9(Trustin)","title":"Netty \uD504\uB85C\uC81D\uD2B8 \uCC3D\uC2DC\uC790\uC774\uC790 Apache MINA \uD504\uB85C\uC81D\uD2B8 \uACF5\uB3D9 \uCC3D\uC2DC\uC790\uC785\uB2C8\uB2E4.","imageURL":"https://github.com/trustin.png","key":"trustin","page":null}],"frontMatter":{"authors":["trustin"],"other_languages":{"en":"/blog/2016/04/13/open-sourcing-armeria","ja":"/blog/ja/2016/04/13/open-sourcing-armeria"}},"unlisted":false,"prevItem":{"title":"\uBD84\uC0B0 \uC11C\uBE44\uC2A4 \uD658\uACBD\uC5D0 \uB300\uD55C Circuit Breaker \uC801\uC6A9","permalink":"/blog/ko/2016/07/24/circuit-breakers-for-distributed-services"}},"content":"import Head from \'@docusaurus/Head\';\\n\\n\\n[Armeria](http://line.github.io/armeria/)\uB294 Java 8 \uBC0F [Netty](http://netty.io/) \uC0C1\uC5D0 \uBE44\uB3D9\uAE30 RPC/API \uD074\uB77C\uC774\uC5B8\uD2B8-\uC11C\uBC84\uB97C \uAD6C\uD604\uD55C \uAC83\uC785\uB2C8\uB2E4.\\nLINE\uC740 \uC791\uB144 11\uC6D4 Armeria\uB97C Apache License 2.0\uC774 \uC801\uC6A9\uB418\uB294 \uC624\uD508\uC18C\uC2A4 \uD504\uB85C\uC81D\uD2B8\uB85C \uBC30\uD3EC\uD588\uC2B5\uB2C8\uB2E4.\\nArmeria\uB294 HTTP/2\uB97C \uC138\uC158 \uB808\uC774\uC5B4 \uD504\uB85C\uD1A0\uCF5C\uB85C \uC0AC\uC6A9\uD558\uB294 \uACE0\uC131\uB2A5\uC758 \uBE44\uB3D9\uAE30 Thrift \uD074\uB77C\uC774\uC5B8\uD2B8/\uC11C\uBC84\uB97C \uAD6C\uCD95\uD558\uAE30 \uC704\uD574 \uB9CC\uB4E0 \uD504\uB85C\uC81D\uD2B8\uC774\uC9C0\uB9CC, \uAE30\uBCF8\uC801\uC73C\uB85C \uD504\uB85C\uD1A0\uCF5C\uC758 \uC81C\uC57D\uC744 \uBC1B\uC9C0 \uC54A\uC73C\uBA70 \uD655\uC7A5\uC131\uC774 \uB6F0\uC5B4\uB0A9\uB2C8\uB2E4. (\uC608\uB97C \uB4E4\uC5B4, HTTP/2\uB97C \uD1B5\uD574 \uC815\uC801 \uD30C\uC77C \uB514\uB809\uD1A0\uB9AC\uB97C \uCC98\uB9AC\uD558\uB294 \uB3D9\uC2DC\uC5D0 Java EE \uC6F9 \uC560\uD50C\uB9AC\uCF00\uC774\uC158\uC744 \uC2E4\uD589\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.)\\n\\n{/* truncate */}\\n\\n\uC774 \uBE14\uB85C\uADF8\uC5D0\uC11C\uB294 \uAE30\uC220\uC801 \uCE21\uBA74\uC5D0 \uCD08\uC810\uC744 \uB9DE\uCD94\uAE30 \uBCF4\uB2E4\uB294 \uB0B4\uBD80 \uD504\uB85C\uC81D\uD2B8\uB97C \uC624\uD508\uC18C\uC2A4\uB85C \uB9CC\uB4E4\uC5B4\uAC00\uBA74\uC11C \uACAA\uC5C8\uB358 \uACFC\uC815\uC744 \uC18C\uAC1C\uD558\uACE0\uC790 \uD569\uB2C8\uB2E4.\\nArmeria\uC758 \uAE30\uC220\uC801 \uB0B4\uC6A9\uC744 \uC54C\uACE0 \uC2F6\uC73C\uC2DC\uB2E4\uBA74 \uC9C0\uB09C 2\uC6D4 \uAC1C\uBC1C\uC790\uB4E4\uC744 \uB300\uC0C1\uC73C\uB85C \uAC1C\uCD5C\uD55C \uC81C14\uD68C LINE Developer Meetup\uC5D0\uC11C \uBC1C\uD45C\uD55C \uC2AC\uB77C\uC774\uB4DC \uC790\uB8CC\uB97C \uCC38\uACE0 \uBC14\uB78D\uB2C8\uB2E4.\\n\\n<Head>\\n  <script\\n    async\\n    className=\\"speakerdeck-embed-script\\"\\n    src=\\"https://speakerdeck.com/assets/embed.js\\"\\n  ><\/script>\\n</Head>\\n<div\\n  className=\\"deck-embed js-deck-embed\\"\\n  style={{ aspectRatio: \'1024/640\' }}\\n  data-ratio=\\"1.6\\"\\n  data-state=\\"processed\\"\\n>\\n  <div\\n    className=\\"speakerdeck-embed\\"\\n    data-title=\\"false\\"\\n    data-skip-resize=\\"true\\"\\n    data-id=\\"8d645c29ce33400e8360e61fd0250f91\\"\\n    data-name=\\"Armeria: LINE\'s next generation RPC layer\\"\\n    data-ratio=\\"1.6\\"\\n    data-host=\\"speakerdeck.com\\"\\n  />\\n</div>\\n\\n## \uD504\uB85C\uC81D\uD2B8 \uC774\uB825 \uC815\uB9AC\\n\\n\uB0B4\uBD80 \uD504\uB85C\uC81D\uD2B8\uB97C \uC791\uC5C5\uD558\uB2E4 \uBCF4\uBA74 \uACF5\uAC1C \uD504\uB85C\uC81D\uD2B8\uB77C\uBA74 \uACB0\uCF54 \uB178\uCD9C\uD558\uC9C0 \uC54A\uC744 \uC544\uB798\uC640 \uAC19\uC740 \uBCC0\uACBD \uC774\uB825\uC774 \uB2E4\uC218 \uD3EC\uD568\uB418\uAE30 \uB9C8\uB828\uC785\uB2C8\uB2E4.\\n\\n- \uAE30\uBC00 \uC815\uBCF4(\uC774\uC288 \uBC88\uD638, \uD638\uC2A4\uD2B8\uBA85, \uB0B4\uBD80 URL \uB4F1)\\n- \uBB34\uC758\uBBF8\uD558\uAC70\uB098 \uBD88\uD655\uC2E4\uD558\uAC8C \uC791\uC131\uB41C \uCEE4\uBC0B \uBA54\uC2DC\uC9C0(\u201Cblah blah\u201D, \u201CWIP\u201D, \u201CWTF\u201D \uB4F1)\\n- \uC800\uC791\uAD8C \uACE0\uC9C0 \uD5E4\uB354\\n\\n\uB9AC\uD3EC\uC9C0\uD1A0\uB9AC\uC5D0 \uC774\uB7F0 \uBB38\uAD6C\uB97C \uC218\uC815\uD558\uB294 \uCEE4\uBC0B\uC744 \uCD94\uAC00\uD55C\uB2E4 \uD558\uB354\uB77C\uB3C4 \uD504\uB85C\uC81D\uD2B8\uC758 \uC774\uB825\uC774 \uC628\uC804\uD788 \uB0A8\uAE30 \uB54C\uBB38\uC5D0 \uADF8\uB7EC\uD55C \uC791\uC5C5\uC740 \uC544\uBB34 \uC18C\uC6A9\uC774 \uC5C6\uC2B5\uB2C8\uB2E4. \uB530\uB77C\uC11C \uC774\uB825 \uB0B4\uC6A9\uC744 \'\uCCAD\uC18C\'\uD574\uC57C \uC815\uBCF4\uAC00 \uC608\uAE30\uCE58 \uC54A\uAC8C \uC720\uCD9C\uB418\uB294 \uC0C1\uD669\uC744 \uD53C\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC774\uB97C \uC704\uD574 \uC120\uD0DD \uAC00\uB2A5\uD55C \uBC29\uBC95\uC740 \uB450 \uAC00\uC9C0\uC785\uB2C8\uB2E4.\\n\\n\uD55C \uAC00\uC9C0 \uBC29\uBC95\uC740 \uBCC0\uACBD \uC774\uB825\uC744 \uC77C\uC77C\uC774 \uAC80\uD1A0\uD558\uBA74\uC11C \uC218\uC815\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4. \uC774 \uACBD\uC6B0 [`git filter-branch`](https://git-scm.com/docs/git-filter-branch) \uAC19\uC740 \uBA85\uB839\uC5B4\uB97C \uC0AC\uC6A9\uD574\uC11C \uC790\uB3D9\uD654\uD558\uBA74 \uC77C\uC744 \uC5B4\uB290 \uC815\uB3C4 \uC904\uC77C \uC218 \uC788\uC9C0\uB9CC \uBCC0\uACBD \uC774\uB825\uC744 \uD558\uB098\uC529 \uAF3C\uAF3C\uD558\uAC8C \uC0B4\uD3B4\uBD10\uC57C\uB9CC \uD569\uB2C8\uB2E4.\\n\\n\uB610 \uB2E4\uB978 \uBC29\uBC95\uC740 \uC678\uBD80\uC5D0 \uACF5\uAC1C\uD558\uBA74 \uC548\uB418\uB294 \uC815\uBCF4\uB97C \uBAA8\uB450 \uC228\uAE30\uACE0 \uC5EC\uB7EC \uBCC0\uACBD \uC774\uB825\uC744 \uD558\uB098\uC758 \uCEE4\uBC0B\uC73C\uB85C \uC555\uCD95\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4. \uC774 \uBC29\uBC95\uC740 \uCCAB \uBC88\uC9F8 \uBC29\uBC95\uBCF4\uB2E4 \uAC04\uB2E8\uD558\uAE34 \uD558\uC9C0\uB9CC \uBAA8\uB4E0 \uC774\uB825\uC744 \uC783\uAC8C \uB429\uB2C8\uB2E4. \uAE30\uC874 \uC774\uB825\uC774 \uBAA8\uB450 \uC5C6\uC5B4\uC9C0\uAE30 \uB54C\uBB38\uC5D0 \uB098\uC911\uC5D0 \uCF54\uB4DC\uB97C \uC65C \uC774\uB807\uAC8C \uC37C\uB294\uC9C0 \uAE30\uC5B5\uB098\uC9C0 \uC54A\uC544\uB3C4 \uC54C\uC544\uB0BC \uBC29\uB3C4\uAC00 \uC5C6\uC2B5\uB2C8\uB2E4.\\n\\n\uD504\uB85C\uC81D\uD2B8 \uC774\uB825\uC774 \uBE44\uAD50\uC801 \uC9E7\uACE0 \uC798 \uC815\uC758\uB41C \uCF54\uB529 \uC2A4\uD0C0\uC77C \uAC00\uC774\uB4DC\uC5D0 \uB9DE\uCDB0 \uCF54\uB4DC\uB97C \uC791\uC131\uD588\uB2E4\uBA74 \uCCAB \uBC88\uC9F8 \uBC29\uBC95\uC744 \uC120\uD0DD\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uD558\uC9C0\uB9CC \uC2DC\uAC04\uC740 \uBD80\uC871\uD558\uACE0 \uAC80\uD1A0\uD560 \uBD84\uB7C9\uC774 \uB108\uBB34 \uB9CE\uB2E4\uBA74 \uC800\uD76C\uAC00 \uADF8\uB7AC\uB358 \uAC83\uCC98\uB7FC \uBAA8\uB4E0 \uC774\uB825\uC744 \uB2E8 \uD558\uB098\uC758 \uCEE4\uBC0B\uC73C\uB85C \uC904\uC774\uB294 \uCD5C\uD6C4\uC758 \uBC29\uBC95\uC744 \uC120\uD0DD\uD560 \uAC83\uC785\uB2C8\uB2E4.\\n\\n\uD558\uC9C0\uB9CC \uC694\uC998\uC740 \uCF54\uB4DC\uB97C \uD55C \uC0AC\uB78C\uC774 \uC791\uC131\uD558\uC9C0 \uC54A\uAE30 \uB54C\uBB38\uC5D0 \uC774 \uBC29\uBC95\uB3C4 \uBB38\uC81C\uAC00 \uC788\uC2B5\uB2C8\uB2E4. \uCEE4\uBC0B\uC744 \uD558\uB098\uB9CC \uB0A8\uACA8\uB450\uBA74 \uD6CC\uB96D\uD55C \uAE30\uB7C9\uC744 \uBC1C\uD718\uD558\uC5EC \uD611\uC5C5\uC5D0 \uAE30\uC5EC\uD55C \uC5EC\uB7EC \uC0AC\uB78C\uB4E4\uC758 \uB178\uB825\uACFC \uACF5\uB85C\uB97C \uC5B4\uB5BB\uAC8C \uC778\uC815\uD560 \uC218 \uC788\uACA0\uC2B5\uB2C8\uAE4C? \uC800\uD76C\uB294 \uACB0\uAD6D \uC544\uB798\uCC98\uB7FC \uCEE4\uBC0B \uBA54\uC2DC\uC9C0\uB97C \uB0A8\uAE30\uB294 \uBC29\uC2DD\uC73C\uB85C \uAC10\uC0AC\uB97C \uD45C\uC2DC\uD560 \uC218 \uBC16\uC5D0 \uC5C6\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\n```\\nSubject: Initial import\\n\\nThis commit contains the collective work of the following enthusiastic\\ncontributors at LINE Corporation:\\n- Anuraag Agrawal  @anuraaga\\n- Heon Jeong       @blmarket\\n- Young-tae Seok   @delegacy\\n- Su-ahn Lee       @inch772\\n- Woo-jung Choi    @sophiechoi\\n- Trustin Lee      @trustin\\n- Yuichi Ono\\n```\\n\\n\uC9C0\uAE08 \uB3CC\uC774\uCF1C\uBCF4\uBA74 \uCEE4\uBC0B \uBA54\uC2DC\uC9C0\uC5D0 \uC81C \uAC10\uC0AC\uC758 \uB9C8\uC74C\uC744 \uC880\uB354 \uC801\uADF9\uC801\uC73C\uB85C \uD45C\uD604\uD588\uC5B4\uC57C \uD588\uB2E4\uB294 \uC0DD\uAC01\uC774 \uB4ED\uB2C8\uB2E4. \uC774 \uAE00\uC744 \uD1B5\uD574 \uBAA8\uB4E0 \uBD84\uB4E4\uC758 \uB3C4\uC6C0\uC5D0 \uB2E4\uC2DC \uD55C\uBC88 \uC9C4\uC2EC\uC73C\uB85C \uAC10\uC0AC\uB4DC\uB9BD\uB2C8\uB2E4!\\n\\n## API \uBB38\uC11C \uC791\uC131\\n\\n\uD504\uB85C\uC81D\uD2B8\uB97C \uBC31\uC9C0 \uC0C1\uD0DC\uC5D0\uC11C \uCC98\uC74C \uC2DC\uC791\uD560 \uB54C\uC5D0\uB294, \uD2B9\uD788 \uC120\uB840\uB85C \uC0BC\uC744 \uB9CC\uD55C \uD15C\uD50C\uB9BF\uC774 \uC5C6\uB294 \uACBD\uC6B0\uC5D0\uB294, \uCF54\uB4DC\uB97C \uC2E0\uC18D\uD558\uAC8C \uC791\uC131\uD574\uC11C \uBE60\uB978 \uC2DC\uC77C \uB0B4\uC5D0 \uACF5\uAC1C\uD560 \uD544\uC694\uAC00 \uC788\uC2B5\uB2C8\uB2E4. \uADF8\uB798\uC57C\uB9CC \uC124\uACC4 \uC774\uC288\uB098 \uBC84\uADF8\uB97C \uCD08\uBC18\uC5D0 \uBC1C\uACAC\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uADF8\uB7F0\uB370 \uC774 \uB2E8\uACC4\uB97C \uBC18\uBCF5\uD558\uB294 \uACFC\uC815\uC5D0\uC11C API \uBCC0\uACBD\uC774 \uB04A\uC784\uC5C6\uC774 \uBC1C\uC0DD\uD558\uAC8C \uB418\uB294\uB370, \uC774\uB97C \uAD6C\uD604\uD558\uB294 \uB370 \uC9D1\uC911\uD558\uB2E4 \uBCF4\uBA74 API \uBB38\uC11C\uD654 \uC791\uC5C5\uC740 \uB4A4\uB85C \uBBF8\uB8E8\uAC8C \uB418\uACE0 \uC5B8\uC820\uAC00\uB294 \uBA54\uC6CC\uC57C \uD558\uB294 \uAD6C\uBA4D\uC73C\uB85C \uB0A8\uAC8C \uB429\uB2C8\uB2E4. (\uC0AC\uC2E4 \uBB38\uC11C\uB97C \uC791\uC131\uD558\uB294 \uC77C\uBCF4\uB2E4 \uCF54\uB4DC\uB97C \uC4F0\uB294 \uAC8C \uD6E8\uC52C \uB354 \uC7AC\uBBF8\uC788\uAE30\uB3C4 \uD558\uACE0\uC694.)\\n\\n\uD558\uC9C0\uB9CC \uC801\uC808\uD55C \uBB38\uC11C\uD654\uB294 \uC624\uD508\uC18C\uC2A4 \uD504\uB85C\uC81D\uD2B8\uC5D0\uC11C \uC544\uC8FC \uC911\uC694\uD569\uB2C8\uB2E4. \uC0AC\uB78C\uB4E4\uC740 \uC544\uC8FC \uC808\uBC15\uD558\uC9C0 \uC54A\uC740 \uD55C \uBB38\uC11C\uAC00 \uC81C\uACF5\uB418\uC9C0 \uC54A\uB294 \uC624\uD508\uC18C\uC2A4 \uC18C\uD504\uD2B8\uC6E8\uC5B4\uB97C \uC0AC\uC6A9\uD558\uB824 \uD558\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4. \uBB38\uC11C\uD654\uAC00 \uC81C\uB300\uB85C \uB418\uC5B4 \uC788\uC9C0 \uC54A\uB2E4\uBA74 \uB204\uAC00 \uADF8\uB7F0 \uC624\uD508\uC18C\uC2A4\uB97C \uC120\uD0DD\uD558\uACA0\uC2B5\uB2C8\uAE4C? \uC774 \uC138\uC0C1\uC5D0\uB294 \uC720\uC0AC\uD55C \uD504\uB85C\uC81D\uD2B8\uAC00 \uC774\uBBF8 \uB9CE\uC774 \uC788\uC73C\uB2C8\uAE4C\uC694!\\n\\n\uACB0\uAD6D\uC740 \uB098\uC911\uC5D0 \uC6B0\uB9AC \uC2A4\uC2A4\uB85C\uAC00 \uB0A8\uACA8\uB450\uC5C8\uB358 \uAD6C\uBA4D\uC744 \uBAA8\uB450 \uBA54\uC6CC\uC57C \uD588\uC2B5\uB2C8\uB2E4. \uC800\uD76C\uB294 \uADF8\uAC78 \'\uAE30\uC220 \uBD80\uCC44(technical debt)\'\uB77C\uB294 \uC6A9\uC5B4\uB97C \uBCF8\uB530 \'\uBB38\uC11C\uD654 \uBD80\uCC44(documentation debt)\'\uB77C \uBD88\uB800\uC2B5\uB2C8\uB2E4. \uC194\uC9C1\uD558\uAC8C \uACE0\uBC31\uD558\uC790\uBA74 \uADF8 \uBE5A\uC744 \uAC1A\uB294 \uC77C\uC740 \uACB0\uCF54 \uC720\uCF8C\uD55C \uACBD\uD5D8\uC774 \uC544\uB2C8\uC5C8\uC2B5\uB2C8\uB2E4. \uD558\uC9C0\uB9CC \uC77C\uB2E8 \uC81C\uB300\uB85C \uBB38\uC11C\uD654 \uC791\uC5C5\uC744 \uD574\uB193\uACE0 \uB098\uB2C8 \uBE5A\uC744 \uCD5C\uC18C\uD55C\uC73C\uB85C \uC720\uC9C0\uD558\uB294 \uC77C\uC774 \uC218\uC6D4\uD574\uC84C\uC2B5\uB2C8\uB2E4. \uC774\uC81C\uB294 \uD37C\uBE14\uB9AD \uBA54\uC11C\uB4DC\uB098 \uD074\uB798\uC2A4\uB97C \uC0C8\uB85C \uC4F0\uACE0 \uB098\uBA74 \uB9AC\uBDF0\uB97C \uC9C4\uD589\uD558\uBA74\uC11C \uBB38\uC11C\uD654 \uC791\uC5C5\uC744 \uD568\uAED8 \uD558\uBA74 \uB429\uB2C8\uB2E4. \uC774\uAC74 \uADE0\uD615\uC7A1\uD78C \uBAB8\uB9E4\uB97C \uC720\uC9C0\uD558\uB294 \uAC83\uACFC \uBE44\uC2B7\uD569\uB2C8\uB2E4. \uC77C\uB2E8 \uC88B\uC740 \uBAB8\uB9E4\uAC00 \uB2E4\uB4EC\uC5B4\uC9C0\uBA74 \uADF8 \uB2E4\uC74C\uBD80\uD130\uB294 \uC26C\uC6CC\uC9C0\uB294 \uC6D0\uB9AC\uC785\uB2C8\uB2E4.\\n\\n## \uC6F9\uC0AC\uC774\uD2B8 \uAD6C\uCD95\\n\\nGithub\uB294 \uD504\uB85C\uC81D\uD2B8\uB97C \uC81C\uACF5\uD558\uAE30\uC5D0 \uC801\uD569\uD55C \uACF5\uAC04\uC774\uC9C0\uB9CC \uAC00\uB2A5\uD558\uBA74 \uC804\uC6A9 \uC6F9\uC0AC\uC774\uD2B8\uB97C \uD65C\uC6A9\uD558\uB294 \uAC83\uC774 \uB354 \uB0AB\uC2B5\uB2C8\uB2E4. \uD504\uB85C\uC81D\uD2B8 \uC6F9\uC0AC\uC774\uD2B8\uAC00 \uC788\uC73C\uBA74 \uC6D0\uD558\uB294 \uC815\uBCF4\uB97C \uC6D0\uD558\uB294 \uBC29\uC2DD\uC73C\uB85C \uAD6C\uC131\uD558\uACE0 \uC81C\uACF5\uD560 \uC218 \uC788\uC73C\uBA70 \uD504\uB85C\uC81D\uD2B8\uC758 \uC131\uACA9\uC744 \uD55C\uCE35 \uB354 \uC2DC\uAC01\uC801\uC774\uACE0 \uD6A8\uACFC\uC801\uC73C\uB85C \uC54C\uB9B4 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n\uD558\uC9C0\uB9CC \uC6F9\uC0AC\uC774\uD2B8 \uAD6C\uCD95\uC740 \uAC04\uB2E8\uD55C \uC791\uC5C5\uC774 \uC544\uB2D9\uB2C8\uB2E4. \uADF8\uB798\uC11C \uCF54\uB4DC \uBA87 \uC904 \uC801\uC5B4\uB123\uB294 \uAC83 \uC774\uC0C1\uC758 \uC2DC\uAC04\uC744 \uD22C\uC790\uD558\uC9C0 \uC54A\uC73C\uBA74\uC11C\uB3C4 \uD655\uC7A5 \uAC00\uB2A5\uD55C \uBC29\uC2DD\uC73C\uB85C \uC6F9\uC0AC\uC774\uD2B8\uB97C \uAC1C\uBC1C, \uC720\uC9C0 \uAD00\uB9AC\uD560 \uC218 \uC788\uB294 \uC218\uB2E8\uC744 \uCC3E\uC544 \uBCF4\uC558\uC2B5\uB2C8\uB2E4.\\n\\n\uB2E4\uD589\uD788 \uBA87\uBA87 \uC5D4\uC9C0\uB2C8\uC5B4\uAC00 \uC81C\uACF5\uD55C \uD6CC\uB96D\uD55C \uC624\uD508\uC18C\uC2A4 \uC6F9\uC0AC\uC774\uD2B8 \uC0DD\uC131 \uD234\uC774 \uC788\uC5C8\uC2B5\uB2C8\uB2E4. \uC774 \uD234 \uB355\uBD84\uC5D0 \uB514\uC790\uC774\uB108\uB97C \uB35C \uAD34\uB86D\uD788\uBA74\uC11C HTML, CSS\uB97C \uC9C1\uC811 \uB2E4\uB8F0 \uC218 \uC788\uC5C8\uC2B5\uB2C8\uB2E4.\\nArmeria\uC758 \uACBD\uC6B0\uB294 [Sphinx](http://www.sphinx-doc.org/en/stable/)\uB97C \uC120\uD0DD\uD588\uACE0 \uC774\uC640 \uB354\uBD88\uC5B4 [sphinx-maven-plugin](http://trustin.github.io/sphinx-maven-plugin/)\uACFC [Read the Docs theme](http://read-the-docs.readthedocs.org/en/latest/)\uC744 \uC0AC\uC6A9\uD568\uC73C\uB85C\uC368 \uBE4C\uB4DC \uD504\uB85C\uC138\uC2A4\uC5D0 \uC6F9\uC0AC\uC774\uD2B8 \uC0DD\uC131\uAE4C\uC9C0 \uD3EC\uD568\uD588\uC2B5\uB2C8\uB2E4. \uC774\uBC16\uC5D0\uB3C4 [Awestruct](http://awestruct.org/), [Jekyll](https://jekyllrb.com/) \uAC19\uC740 \uC720\uC0AC\uD55C \uC6A9\uB3C4\uC758 \uD234\uC774 \uB2E4\uC591\uD558\uAC8C \uC788\uC2B5\uB2C8\uB2E4. \uC6F9\uC0AC\uC774\uD2B8 \uAD6C\uCD95\uC5D0 \uAD00\uC2EC\uC788\uB294 \uBD84\uB4E4\uC740 \uC774\uB7F0 \uD234\uC744 \uC0AC\uC6A9\uD574 \uBCF8\uB2E4\uBA74 \uBCF8\uC778\uC5D0\uAC8C \uC801\uD569\uD55C \uAC83\uC744 \uC120\uD0DD\uD558\uB294 \uB370 \uB9CE\uC740 \uB3C4\uC6C0\uC774 \uB420 \uAC83\uC785\uB2C8\uB2E4.\\n\\n## \uB85C\uACE0 \uC81C\uC791\\n\\n![](/img/open-sourcing-armeria-1.png)\\n\\nArmeria\uC758 \uB85C\uACE0\\n\\n\uB85C\uACE0\uB294 \uD504\uB85C\uC81D\uD2B8\uC758 \uC815\uC218\uC785\uB2C8\uB2E4. \uB85C\uACE0\uB294 \uADF8 \uD504\uB85C\uC81D\uD2B8\uAC00 \uBB34\uC5C7\uC744 \uC704\uD55C \uAC83\uC778\uC9C0, \uC5B4\uB5A4 \uBC29\uD5A5\uC73C\uB85C \uB098\uC544\uAC08 \uAC83\uC778\uC9C0 \uC2DC\uAC01\uC801\uC73C\uB85C \uADF8\uB9AC\uACE0 \uC0C1\uC9D5\uC801\uC73C\uB85C \uC54C\uB824\uC8FC\uB294 \uC218\uB2E8\uC785\uB2C8\uB2E4. \uB610\uD55C \uC0AC\uB78C\uB4E4\uC774 \uD504\uB85C\uC81D\uD2B8\uB97C \uB354 \uC798 \uAE30\uC5B5\uD558\uAC8C \uB9CC\uB4DC\uB294 \uC5F0\uC0C1 \uD6A8\uACFC\uB3C4 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n\uC774\uCC98\uB7FC \uD504\uB85C\uC81D\uD2B8\uC5D0 \uC911\uB300\uD55C \uC601\uD5A5\uC744 \uBBF8\uCE58\uAE30 \uB54C\uBB38\uC5D0 \uB514\uC790\uC774\uB108\uB294 \uC5EC\uB7EC \uCE21\uBA74\uC744 \uC2E0\uC911\uD558\uAC8C \uAC80\uD1A0\uD558\uACE0 \uD504\uB85C\uD1A0\uD0C0\uC785\uC744 \uB9CE\uC774 \uB9CC\uB4E4\uC5B4 \uBD10\uC57C \uD569\uB2C8\uB2E4. \uC6B4\uC88B\uAC8C\uB3C4 \uC0B0\uC5C5 \uB514\uC790\uC778\uAE4C\uC9C0 \uC804\uACF5\uD55C \uB3D9\uB8CC\uAC00 \uB54C\uB9DE\uCDB0 \uC785\uC0AC\uD55C \uB355\uBD84\uC5D0 \uB3C4\uC6C0\uC744 \uBC1B\uC744 \uC218 \uC788\uC5C8\uC2B5\uB2C8\uB2E4. \uBCF8\uC778\uC758 \uC5C5\uBB34\uB85C \uBC14\uC058\uC2E0 \uC640\uC911\uC5D0\uB3C4 \uC2DC\uAC04\uC744 \uB0B4\uC5B4 \uB3C4\uC640\uC8FC\uC154\uC11C \uB108\uBB34 \uACE0\uB9C8\uC6E0\uC2B5\uB2C8\uB2E4. \uB2E4\uC74C\uC5D0\uB3C4 \uC774\uBC88 \uBABB\uC9C0 \uC54A\uAC8C \uB6F0\uC5B4\uB09C \uB85C\uACE0\uB97C \uB9CC\uB4E4\uC5B4 \uC8FC\uC2E4\uAC70\uB77C \uBBFF\uC2B5\uB2C8\uB2E4.\\n\\n## \uB77C\uC774\uC120\uC2A4\uC758 \uBC95\uC801 \uD6A8\uB825\uACFC \uCC45\uC784\uC5D0 \uB300\uD55C \uAC80\uD1A0\\n\\n\uC624\uD508\uC18C\uC2A4 \uC18C\uD504\uD2B8\uC6E8\uC5B4\uC5D0 \uB300\uD55C \uAC1C\uB150\uC740 \uCEF4\uD4E8\uD305 \uAE30\uC220\uC758 \uC2DC\uCD08\uBD80\uD130 \uC874\uC7AC\uD574 \uC654\uC2B5\uB2C8\uB2E4. \uD558\uC9C0\uB9CC \uC0AC\uB78C\uB4E4\uC774 \uC624\uD508\uC18C\uC2A4 \uB77C\uC774\uC120\uC2A4\uC5D0 \uAD00\uC2EC\uC744 \uAC00\uC9C0\uAC8C \uB41C \uAC74 \uCD5C\uADFC\uC785\uB2C8\uB2E4. \uC5B4\uB5A4 \uC0AC\uB78C\uB4E4\uC740 \uBB34\uB8CC\uB85C \uC0AC\uC6A9 \uAC00\uB2A5\uD55C \uD504\uB85C\uC81D\uD2B8\uB77C \uD558\uB354\uB77C\uB3C4 \uB204\uAD70\uAC00\uC5D0\uAC8C \uC18C\uC720\uAD8C\uC774 \uC788\uB2E4\uB294 \uC0AC\uC2E4\uC744 \uAC04\uACFC\uD558\uB294 \uAC83 \uAC19\uC2B5\uB2C8\uB2E4.\\nArmeria \uD504\uB85C\uC81D\uD2B8\uC5D0\uC11C\uB294 \uBC95\uC801 \uBB38\uC81C\uAC00 \uBC1C\uC0DD\uD560 \uC18C\uC9C0\uB97C \uBC29\uC9C0\uD558\uAE30 \uC704\uD574 Armeria\uC5D0 \uC0AC\uC6A9\uB41C \uC624\uD508\uC18C\uC2A4 \uC18C\uD504\uD2B8\uC6E8\uC5B4\uC758 \uB77C\uC774\uC120\uC2A4 \uADDC\uC815\uC744 \uC704\uBC18\uD558\uC9C0 \uC54A\uB3C4\uB85D \uAC01\uBCC4\uD788 \uC8FC\uC758\uB97C \uAE30\uC6B8\uC600\uC2B5\uB2C8\uB2E4.\\n\\n\uADF8 \uC77C\uD658\uC73C\uB85C \uD504\uB85C\uC81D\uD2B8 \uB9AC\uD3EC\uC9C0\uD1A0\uB9AC\uC5D0 \uBAA8\uB4E0 \uB77C\uC774\uC120\uC2A4 \uADDC\uC815 \uD30C\uC77C\uACFC \uC694\uC57D\uBB38\uC744 \uD3EC\uD568\uD574\uC11C Armeria\uAC00 \uC5B4\uB5A4 \uC18C\uD504\uD2B8\uC6E8\uC5B4\uB85C\uBD80\uD130 \uB3C4\uC6C0\uC744 \uBC1B\uC558\uB294\uC9C0 \uC774\uC6A9\uC790\uC5D0\uAC8C \uD655\uC2E4\uD788 \uBC1D\uD788\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uB610\uD55C Armeria \uB0B4\uC5D0\uC11C \uC774\uB7EC\uD55C \uC624\uD508\uC18C\uC2A4 \uC18C\uD504\uD2B8\uC6E8\uC5B4\uC758 \uC5B4\uB5A4 \uBD80\uBD84\uC744 \uC218\uC815\uD588\uACE0 \uC7AC\uBC30\uD3EC\uD588\uB294\uC9C0 \uAD6C\uCCB4\uC801\uC73C\uB85C \uBA85\uC2DC\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4.\\n\\nArmeria\uB294 \uC18C\uC720 \uC8FC\uCCB4\uAC00 \uC788\uB294 \uC624\uD508\uC18C\uC2A4 \uD504\uB85C\uC81D\uD2B8\uC774\uAE30 \uB54C\uBB38\uC5D0 \uACF5\uC815\uD558\uACE0 \uBA85\uD655\uD55C \uADDC\uC815\uC5D0 \uC758\uAC70\uD558\uC5EC \uB77C\uC774\uC120\uC2A4\uB97C \uBD80\uC5EC\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uB2E4\uC74C\uACFC \uAC19\uC740 \uD2B9\uC9D5\uC744 \uAC10\uC548\uD558\uC5EC \uC5EC\uB7EC \uB77C\uC774\uC120\uC2A4 \uC911\uC5D0\uC11C [Apache License 2.0](<https://tldrlegal.com/license/apache-license-2.0-(apache-2.0)>)\uC744 \uC120\uD0DD\uD588\uC2B5\uB2C8\uB2E4.\\n\\n- Apache License 2.0 \uB77C\uC774\uC120\uC2A4\uB97C \uC0AC\uC6A9\uD558\uB294 \uC18C\uD504\uD2B8\uC6E8\uC5B4\uB294 \uBB34\uB8CC\uB85C \uC0AC\uC6A9, \uC7AC\uC0DD\uC0B0, \uC218\uC815, \uBC30\uD3EC, \uD310\uB9E4\uD560 \uC218 \uC788\uC73C\uBA70 \uC6D0\uBCF8 \uC18C\uC2A4 \uCF54\uB4DC\uB97C \uD3EC\uD568\uD560 \uD544\uC694\uAC00 \uC5C6\uC2B5\uB2C8\uB2E4.\\n- \uC624\uD508\uC18C\uC2A4\uC758 \uD2B9\uD5C8 \uB77C\uC774\uC120\uC2A4 \uBD80\uC5EC \uBC0F \uD2B9\uD5C8 \uCE68\uD574\uC5D0 \uAD00\uD55C \uC870\uD56D(Grant of Patent License)\uC774 \uBA85\uC2DC\uB418\uC5B4 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n\uC0AC\uB78C\uB4E4\uC774 \uC885\uC885 \uAC04\uACFC\uD558\uB294 \uB610 \uB2E4\uB978 \uC911\uC694\uD55C \uBD80\uBD84\uC740 CLA(Contributor License Agreement)\uC785\uB2C8\uB2E4.\\nCLA\uB294 \uC678\uBD80\uC778\uC73C\uB85C\uBD80\uD130 \uB3C4\uC6C0\uC744 \uBC1B\uC744 \uB54C \uD544\uC694\uD569\uB2C8\uB2E4. \uC608\uB97C \uB4E4\uC5B4, \uC678\uBD80\uC778\uC774 \uC5B4\uB5A4 \uAE30\uB2A5\uC744 \uC81C\uC548\uD558\uB294 pull request\uB97C \uBCF4\uB0C8\uB294\uB370 \uC5EC\uB7EC\uBD84\uC758 \uD504\uB85C\uC81D\uD2B8\uC5D0 \uBCD1\uD569\uD558\uACE0 \uC2F6\uB2E4\uBA74 \uD574\uB2F9 \uC81C\uCD9C\uC790\uB85C\uBD80\uD130 \uC774 \uC11C\uC57D\uC5D0 \uB3D9\uC758\uD558\uB294 \uC11C\uBA85\uC744 \uBC1B\uC544\uC57C \uD569\uB2C8\uB2E4.\\nCLA\uB294 \uC774 \uBE14\uB85C\uADF8\uC758 \uC8FC\uC81C\uC5D0\uC11C \uBC97\uC5B4\uB098\uB294 \uB0B4\uC6A9\uC774\uBBC0\uB85C \uC5EC\uAE30\uC5D0\uC11C \uC790\uC138\uD788 \uC124\uBA85\uD558\uC9C0\uB294 \uC54A\uACA0\uC2B5\uB2C8\uB2E4. \uB300\uC2E0 \uAD00\uB828 \uC815\uBCF4\uB97C \uC81C\uACF5\uD558\uB294 \uC0AC\uC774\uD2B8\uB97C \uC18C\uAC1C\uD569\uB2C8\uB2E4. [OSS Watch](http://oss-watch.ac.uk/resources/cla) \uBC0F [CLAHub](https://www.clahub.com/pages/why_cla) \uB9C1\uD06C\uB97C \uCC38\uACE0\uD574 \uC8FC\uC138\uC694.\\n\\n\uBC95\uC801 \uAC80\uD1A0\uB97C \uAC70\uCE58\uB294 \uACFC\uC815\uC740 \uC5B4\uB824\uC6CC \uBCF4\uC774\uAE30\uB3C4 \uD558\uACE0 \uC2DC\uAC04\uC774 \uB9CE\uC774 \uAC78\uB9B4 \uAC83 \uAC19\uC9C0\uB9CC \uC2E4\uC0C1\uC740 \uADF8\uB807\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4. \uB300\uBD80\uBD84 \uD55C \uBC88\uB9CC \uC644\uC218\uD558\uBA74 \uB418\uB294 \uC791\uC5C5\uC774\uACE0 \uBC95\uBB34 \uBD80\uC11C\uC758 \uB3D9\uB8CC \uC9C1\uC6D0\uC774 \uC6B0\uB9AC\uB97C \uB300\uC2E0\uD574\uC11C \uC131\uC2EC\uC131\uC758\uAECF \uACE8\uCE58 \uC544\uD508 \uBC95\uC801 \uBB38\uC81C\uB97C \uCC98\uB9AC\uD574 \uC90D\uB2C8\uB2E4. \uC870\uAE08\uC774\uB77C\uB3C4 \uC11D\uC5F0\uCE58 \uC54A\uC740 \uC810\uC774 \uC788\uB2E4\uBA74 \uBC14\uB85C \uBC95\uBB34 \uBD80\uC11C\uB97C \uBC29\uBB38\uD558\uC5EC \uC804\uBB38\uAC00\uC5D0\uAC8C \uB3C4\uC6C0\uC744 \uAD6C\uD558\uC138\uC694.\\n\\n## \uB2E4\uC591\uD55C \uC624\uD508\uC18C\uC2A4 \uD504\uB85C\uC81D\uD2B8 \uAC04\uC758 \uD611\uC5C5\\n\\n\uC624\uD508\uC18C\uC2A4 \uD504\uB85C\uC81D\uD2B8\uB97C \uC774\uC6A9\uD558\uB2E4 \uBCF4\uBA74 \uBC84\uADF8\uB97C \uBC1C\uACAC\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uBC84\uADF8\uB97C \uBC1C\uACAC\uD55C \uB2F9\uC0AC\uC790\uAC00 \uC2A4\uC2A4\uB85C \uD574\uACB0\uCC45\uC744 \uAC15\uAD6C\uD560 \uC218\uB3C4 \uC788\uC9C0\uB9CC \uADF8\uB807\uC9C0 \uBABB\uD55C \uACBD\uC6B0\uB3C4 \uC788\uC2B5\uB2C8\uB2E4. \uC6D0\uB798 \uD504\uB85C\uC81D\uD2B8\uC5D0\uC11C \uC5EC\uB7EC\uBD84\uB9CC\uC758 \uD504\uB85C\uC81D\uD2B8 \uD3EC\uD06C(fork)\uB97C \uB9CC\uB4E4\uC5B4 \uC9C1\uC811 \uC218\uC815\uD558\uACE0 \uAD00\uB9AC\uD560 \uC218\uB3C4 \uC788\uC2B5\uB2C8\uB2E4. \uD558\uC9C0\uB9CC \uADF8\uAC83\uBCF4\uB2E4 \uC5C5\uC2A4\uD2B8\uB9BC(upstream)\uC5D0 \uBCC0\uACBD\uC744 \uC81C\uC548\uD558\uB294 \uAC83\uC774 \uC5B8\uC81C\uB098 \uB354 \uB098\uC740 \uC811\uADFC\uBC95\uC785\uB2C8\uB2E4. \uADF8\uB807\uC9C0 \uC54A\uC73C\uBA74 \uC5EC\uB7EC\uBD84\uC774 \uC9C0\uC18D\uC801\uC73C\uB85C \uD504\uB85C\uC81D\uD2B8\uB97C \uAD00\uB9AC\uD574\uC57C \uD569\uB2C8\uB2E4. \uB610\uD55C \uC5C5\uC2A4\uD2B8\uB9BC\uC5D0 \uAE30\uC5EC\uD558\uBA74 \uC624\uD508\uC18C\uC2A4 \uC5C5\uACC4\uC5D0\uC11C \uBCF8\uC778\uC758 \uD65C\uB3D9\uC744 \uC54C\uB9B4 \uC218 \uC788\uACE0 \uB2E4\uB978 \uC0AC\uB78C\uB4E4\uACFC \uD611\uC5C5\uD558\uBA74\uC11C \uB354\uC6B1 \uC7AC\uBBF8\uB97C \uCC3E\uC744 \uC218\uB3C4 \uC788\uC2B5\uB2C8\uB2E4. \uB458 \uB2E4 \uC5EC\uB7EC\uBD84\uC758 \uACBD\uB825\uC5D0 \uB9E4\uC6B0 \uAE0D\uC815\uC801\uC778 \uD6A8\uACFC\uB97C \uC904 \uAC83\uC785\uB2C8\uB2E4.\\n\\n\uC774\uBC88\uC5D0 Armeria\uB97C \uAC1C\uBC1C\uD558\uB294 \uB3D9\uC548 Netty \uD504\uB85C\uC81D\uD2B8\uC5D0\uC11C \uBC1C\uACAC\uD55C \uC5EC\uB7EC \uC774\uC288\uB97C \uBCF4\uACE0\uD558\uACE0 \uC77C\uBD80 \uC774\uC288\uC758 \uACBD\uC6B0 \uC218\uC815 \uC791\uC5C5\uC744 \uB3D5\uAE30\uB3C4 \uD588\uC2B5\uB2C8\uB2E4.\\n\\n- HTTP/1\uACFC 2\\n  - [#4785](https://github.com/netty/netty/pull/4785) - Fix missing trailing data on HTTP client upgrade\\n  - [#4582](https://github.com/netty/netty/pull/4582) - Revamp InboundHttp2ToHttpAdapter builder API\\n  - [#4574](https://github.com/netty/netty/pull/4574) - Revamp the Http2ConnectionHandler builder API\\n  - [#4525](https://github.com/netty/netty/pull/4525) - Fix the incorrect usage/value of \\"Connection: upgrade\\"\\n  - [#4524](https://github.com/netty/netty/pull/4524) - Fix IllegalReferenceCountException caused by HttpClientCodec.upgradeFrom()\\n  - [#4523](https://github.com/netty/netty/pull/4523) - Relax the sanity check in HttpClientUpgradeHandler\\n  - [#4428](https://github.com/netty/netty/pull/4428) - Reject the first SETTINGS ack on HTTP/2 Preface\\n  - [#4210](https://github.com/netty/netty/pull/4210) - Http2ConnectionHandler does not close the stream 1 (HTTP_UPGRADE_STREAM_ID)\\n  - [#3876](https://github.com/netty/netty/pull/3876) - Lazily instantiate HttpServerUpgradeHandler.UpgradeCodec\\n- DNS\\n  - [#4946](https://github.com/netty/netty/pull/4946) - Fix potential infinite loop when resolving CNAME records\\n  - [#4837](https://github.com/netty/netty/pull/4837) - Preserve the host name of address when parsing /etc/hosts file\\n  - [#4665](https://github.com/netty/netty/pull/4665) - Netty\'s DNS resolution should take into account system domain name\\n  - [#4541](https://github.com/netty/netty/pull/4541) - Don\'t cycle dns servers while cycling dns record types.\\n- \uAE30\uD0C0\\n  - [#4547](https://github.com/netty/netty/pull/4547) - NPE in PooledByteBufAllocator.newDirectBuffer()\\n  - [#4419](https://github.com/netty/netty/pull/4419) - Fix a bug where DefaultPromise.toString() says \\"incomplete\\" when it\'s done\\n\\n\uC5EC\uB7EC \uD504\uB85C\uC81D\uD2B8\uC758 \uAC1C\uBC1C\uC790\uB4E4\uACFC \uD568\uAED8 \uC791\uC5C5\uD55C \uB355\uBD84\uC5D0 Armeria\uC5D0\uC11C \uC0AC\uC6A9\uD55C \uC624\uD508\uC18C\uC2A4\uC758 \uD504\uB85C\uC81D\uD2B8 \uD3EC\uD06C\uB97C \uBCC4\uB3C4\uB85C \uC720\uC9C0 \uAD00\uB9AC\uD558\uB294 \uBD80\uB2F4\uC744 \uC904\uC77C \uC218 \uC788\uC5C8\uACE0, \uC624\uD508\uC18C\uC2A4 \uCEE4\uBBA4\uB2C8\uD2F0\uC5D0\uC11C Armeria \uD504\uB85C\uC81D\uD2B8\uBFD0 \uC544\uB2C8\uB77C \uD504\uB85C\uC81D\uD2B8\uC5D0 \uCC38\uC5EC\uD55C \uAD6C\uC131\uC6D0\uC758 \uD65C\uB3D9\uC744 \uB110\uB9AC \uC54C\uB9AC\uB294 \uAE30\uD68C\uB97C \uB204\uB9B4 \uC218 \uC788\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\n## \uB3C4\uC804\uC790\uB97C \uCC3E\uC2B5\uB2C8\uB2E4!\\n\\n\uAC1C\uBC1C \uC131\uACFC\uBB3C\uC744 \uACF5\uC720\uD558\uBA70 \uCEE4\uBBA4\uB2C8\uD2F0\uC5D0 \uAE30\uC5EC\uD558\uACE0 \uB2E4\uC591\uD55C \uD504\uB85C\uC81D\uD2B8 \uAC1C\uBC1C\uC790\uB4E4\uACFC \uD611\uC5C5\uD558\uB294 \uACFC\uC815\uC774 \uC990\uAC70\uC6CC \uBCF4\uC774\uC9C0 \uC54A\uC73C\uC2ED\uB2C8\uAE4C?\\nArmeria\uB294 \uC544\uC9C1 \uD504\uB85C\uC81D\uD2B8 \uCD08\uAE30 \uB2E8\uACC4\uC774\uAE30 \uB54C\uBB38\uC5D0 \uB85C\uB4DC\uB9F5\uC5D0 \uB530\uB77C \uD5A5\uD6C4 \uC0C8\uB85C\uC6B4 \uAE30\uB2A5\uC744 \uCD94\uAC00\uD560 \uC608\uC815\uC785\uB2C8\uB2E4. \uD604\uC7AC \uAD6C\uC0C1 \uC911\uC778 \uAE30\uB2A5\uC740 \uB2E4\uC74C\uACFC \uAC19\uC2B5\uB2C8\uB2E4.\\n\\n- \uD074\uB77C\uC774\uC5B8\uD2B8 \uAE30\uBC18\uC758 \uB85C\uB4DC \uBC38\uB7F0\uC2F1\\n- Reactive Streams\uC744 \uD1B5\uD55C \uB300\uC6A9\uB7C9 \uCEE8\uD150\uD2B8 \uC2A4\uD2B8\uB9AC\uBC0D\\n- Redis, MySQL \uB4F1 \uB354\uC6B1 \uB2E4\uC591\uD55C \uD504\uB85C\uD1A0\uCF5C \uC9C0\uC6D0\\n- \uAD00\uB9AC\uC640 \uBAA8\uB2C8\uD130\uB9C1\uC744 \uD1B5\uD569\uC801\uC73C\uB85C \uC218\uD589\uD558\uB294 \uC6F9 \uCF58\uC194\\n- \uBB38\uC11C\uD654\uC640 \uCF54\uB4DC \uC0DD\uC131\uC744 \uB354\uC6B1 \uD6A8\uC728\uC801\uC73C\uB85C \uD560 \uC218 \uC788\uB294 \uC0C8\uB85C\uC6B4 Thrift \uCEF4\uD30C\uC77C\uB7EC\\n\\nLINE\uC740 \uB2E4\uB978 \uD504\uB85C\uC81D\uD2B8\uB4E4\uB3C4 \uC624\uD508\uC18C\uC2A4\uB85C \uBC30\uD3EC\uD558\uAE30 \uC704\uD574 \uC900\uBE44\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uB610\uD55C LINE \uC5D4\uC9C0\uB2C8\uC5B4\uB294 \uD68C\uC0AC\uC758 \uC774\uC775\uC744 \uCD94\uAD6C\uD558\uB294 \uB370 \uADF8\uCE58\uC9C0 \uC54A\uACE0 \uC7A5\uAE30\uC801\uC73C\uB85C \uB9CE\uC740 \uC774\uB4E4\uC5D0\uAC8C \uB3C4\uC6C0\uC744 \uB418\uB294 \uC77C\uC744 \uBAA9\uD45C\uB85C \uC0BC\uACE0 \uC788\uC2B5\uB2C8\uB2E4.\\nLINE\uC5D0 \uC9C0\uC6D0\uD558\uC5EC \uD568\uAED8 \uD504\uB85C\uC81D\uD2B8\uB97C \uB9CC\uB4E4\uACE0 \uC138\uC0C1\uC774 \uB180\uB784 \uB9CC\uD55C \uC77C\uC5D0 \uB3C4\uC804\uD574 \uBCF4\uC138\uC694!\\n\\n[\uCC44\uC6A9 \uC815\uBCF4](http://recruit.linepluscorp.com/lineplus/career/detail/20000312)\\n\\n## \uC800\uC790 \uC18C\uAC1C\\n\\n[\uC774\uD76C\uC2B9(Trustin)\uB2D8](https://github.com/trustin)\uC740 [Netty \uD504\uB85C\uC81D\uD2B8](http://netty.io/) \uCC3D\uC2DC\uC790\uC774\uC790 [Apache MINA \uD504\uB85C\uC81D\uD2B8](http://mina.apache.org/) \uACF5\uB3D9 \uCC3D\uC2DC\uC790\uB85C\uC11C, \uD604\uC7AC LINE\uC5D0\uC11C \uD50C\uB7AB\uD3FC \uC18C\uD504\uD2B8\uC6E8\uC5B4 \uC5D4\uC9C0\uB2C8\uC5B4\uB85C \uC7AC\uC9C1 \uC911\uC785\uB2C8\uB2E4."}]}}')}}]);